INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 1, 'Sin clasificar', 'Pregunta asociada a la imagen 1. Varón de 65 años, sin antecedentes de interés, que consulta por tos, dolor torácico, fiebre, sudoración nocturna y disnea. En la radiografía de tórax se observa un derrame pleural unilateral izquierdo, por lo que se realiza una TC torácica que confirma el derrame pleural y donde además se observa un engrosamiento pleural y micronódulos subpleurales en el lóbulo superior izquierdo. Ante este hallazgo se decide realizar una toracoscopia con biopsia pleural, cuya histología se muestra en la figura. ¿Cuál es el diagnóstico anatomopatológico de la lesión pleural?:', 'Infiltración por adenocarcinoma.', 'Inflamación aguda con abscesificación.', 'Inflamación granulomatosa.', 'Mesotelioma.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 2, 'Sin clasificar', 'Pregunta asociada a la imagen 2. Varón de 20 años, de constitución longilínea, que presenta desde hace unos 15 meses disnea de grandes esfuerzos que progresa a pequeños esfuerzos, con palpitaciones y dolor precordial. Fallece de forma súbita subiendo escaleras. En la necropsia se encuentra un vaso con la imagen de la figura. De las siguientes ¿cuál es la enfermedad más probable?:', 'Embolia pulmonar.', 'Traumatismo torácico con afectación de la aorta y el corazón.', 'Necrosis quística de la media y síndrome de Marfan.', 'Síndrome dislipémico familiar con grave aterosclerosis. - 1', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 3, 'Sin clasificar', 'Pregunta asociada a la imagen 3. Mujer de 81 años que consulta por ictericia, dolor epigástrico, astenia y anorexia. La TC abdominal muestra en la cabeza del páncreas una lesión sólida, mal delimitada, de 24 x 24 mm, que contacta focalmente con la vena mesentérica superior y comporta dilatación de la vía biliar. No se observa un claro contacto con otras estructuras vasculares principales. Con la sospecha de proceso neoformativo se indica la intervención quirúrgica. Se muestra una imagen macroscópica y una microscópica de la lesión pancreática. El estudio inmunohistoquímico realizado en la pieza de resección muestra positividad para citoqueratina 7 y negatividad para sinaptofisina, tripsina, CK20 y CDX2. ¿Cuál es el diagnóstico anatomopatológico de la lesión pancreática?:', 'Adenocarcinoma ductal.', 'Cistadenoma seroso.', 'Neoplasia mucinosa quística.', 'Pancreatitis autoinmune asociada a enfermedad por IgG4.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 4, 'Sin clasificar', 'Pregunta asociada a la imagen 4. Se realizó una biopsia hepática en una paciente de 37 años con obesidad y alteración de las transaminasas (figura 2014) que demostró una intensa esteatosis que afectaba al 70% de los hepatocitos. A los 7 años, tras ser diagnosticada de esclerosis múltiple y ganar peso, se repitió la biopsia (figura 2021). ¿Cuál de las siguientes afirmaciones describe mejor la evolución?:', 'La esteatosis es menos intensa en la segunda biopsia, lo que es signo de buen pronóstico.', 'En la segunda biopsia no hay datos de inflamación ni degeneración balonizante, lo que es signo de buen pronóstico.', 'La segunda biopsia muestra una situación estable.', 'La presencia de fibrosis en puentes demuestra la progresión de la enfermedad.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 5, 'Sin clasificar', 'Pregunta asociada a la imagen 5. Mujer de 90 años de edad que presenta desde hace un mes y medio la lesión de la imagen. La lesión ha crecido rápidamente, sangra con facilidad y le ocasiona ligero dolor. De entre las siguientes opciones ¿cuál es la más probable?:', 'Carcinoma de células escamosas cutáneo invasivo.', 'Carcinoma basocelular esclerodermiforme.', 'Sarcoma de Kaposi.', 'Lupus vulgar. 1 -', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 6, 'Sin clasificar', 'Pregunta asociada a la imagen 6. Mujer de 70 años que consulta por lesiones cutáneas de 1 año de evolución, sin otra sintomatología asociada. Niega antecedentes personales de interés. En la exploración presenta 20 placas eritematosas finamente descamativas y discretamente atróficas, de tamaños de 4 a 10 cm en glúteos, ambas axilas y mamas, sin otros hallazgos. La anatomía patológica muestra un infiltrado en dermis superficial de linfocitos atípicos en banda, con marcado epidermotropismo y formación de microabscesos intraepidérmicos. La analítica sanguínea completa fue normal. De los siguientes ¿cuál es el diagnóstico más probable?:', 'Linfoma de Hodgkin cutáneo.', 'Síndrome de Sézary.', 'Linfoma no Hodgkin cutáneo tipo T.', 'Psoriasis pustulosa.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 7, 'Sin clasificar', 'Pregunta asociada a la imagen 7. Niño de 23 meses de edad que ingresa por rectorragias de repetición y anemización (hemoglobina 10,0 g/dl, hematocrito 27,9 %. Se realiza estudio ecográfico abdominal sin hallazgos. Se muestra en la imagen la gammagrafía con pertecnetato-99mTc. De los siguientes, el diagnóstico más probable es:', 'Punto de sangrado de origen gástrico.', 'Divertículo de Meckel revestido de mucosa gástrica ectópica.', 'Punto de sangrado de origen genitourinario.', 'Gammagrafía normal.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 8, 'Sin clasificar', 'Pregunta asociada a la imagen 8. Varón de 86 años con antecedentes de adenocarcinoma de próstata tratado con braquiterapia e HTA bien controlada que acude a urgencias por la aparición de edemas en MMII en las dos últimas semanas y disnea progresiva hasta hacerse de reposo. Se realiza ecocardiograma transtorácico observando una hipertrofia leve concéntrica del VI con función sistólica conservada. Se muestra la gammagrafía con pirofosfatos-99mTc. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Infarto agudo de miocardio.', 'Gammagrafía cardiaca normal.', 'Amiloidosis cardiaca mediada por transtiretina.', 'Derrame pericárdico. - 2', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 9, 'Sin clasificar', 'Pregunta asociada a la imagen 9. Mujer de 85 años, en tratamiento con rosuvastatina por dislipemia, que en las últimas 4 semanas presenta fiebre diaria (38-38,5ºC), bien tolerada, sin escalofríos y sin sudoración nocturna, y pérdida de 3 kg de peso. En la exploración física destaca engrosamiento de la arteria temporal izquierda. Análisis: PCR 12 mg/dl, hemoglobina 9,5 g/dl. Radiografía de tórax normal. El resultado de la PET/TC se muestra en la figura. En este contexto ¿cuál es la respuesta correcta?:', 'La fiebre o febrícula es un síntoma presente en menos del 10 % de los pacientes.', 'Cuando se diagnostica la enfermedad, los hallazgos radiológicos (como los observados en esta PET/TC) están presentes en un 50-70 % de los pacientes.', 'Atendiendo a los hallazgos de la PET/TC en esta paciente tiene indicación de tratamiento inmediato con glucocorticoides (20 mg/día) y tocilizumab.', 'La PET/TC es la técnica más específica para establecer el diagnóstico.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 10, 'Sin clasificar', 'Pregunta asociada a la imagen 10. Mujer de 30 años sin cirugías previas en estudio de esterilidad primaria de 18 meses de evolución. No existen hallazgos patológicos en su pareja masculina. La ecografía ginecológica es normal. La histerosalpingografía se muestra en la imagen. Con estos datos ¿cuál sería el siguiente procedimiento a realizar?:', 'Fecundación in vitro.', 'Inseminación artificial.', 'Salpinguectomía bilateral laparoscópica.', 'Cromopertubación laparoscópica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 11, 'Sin clasificar', 'Pregunta asociada a la imagen 11. Varón de 52 años, obeso, que acude a urgencias por pérdida de visión brusca en el ojo derecho. En la exploración del fondo de ojo encontramos la imagen representada. El resto de la exploración se encuentra dentro de la normalidad. ¿Cuál de las siguientes patologías presenta?:', 'Retinopatía hipertensiva aguda con estrella macular.', 'Retinopatía diabética proliferativa con afectación de cuatro cuadrantes.', 'Retinitis por citomegalovirus.', 'Trombosis de vena central de la retina. 2 -', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 12, 'Sin clasificar', 'Pregunta asociada a la imagen 12. Varón de 62 años que consulta por una masa laterocervical derecha de crecimiento progresivo que se acompaña de odinofagia. Fumador de 1 paquete de cigarrillos al día desde hace 30 años. Las exploraciones de cavidad oral, orofaringoscópica, rinoscópica y otoscópica son normales. En la palpación cervical se identifica una adenopatía a nivel III de 4 cm, dura y adherida a planos profundos. ¿Cuál es el diagnóstico clínico más probable según la imagen de laringoscopia?:', 'Carcinoma transglótico derecho con adenopatía metastásica.', 'Carcinoma de seno piriforme derecho con adenopatía metastásica.', 'Carcinoma de supraglotis derecha con adenopatía metastásica.', 'Carcinoma de amígdala palatina derecha con adenopatía metastásica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 13, 'Sin clasificar', 'Pregunta asociada a la imagen 13. Mujer de 64 años que consulta por dolor centrotorácico de 24 horas de evolución sin otras manifestaciones clínicas. En la radiografía de tórax ¿qué hallazgo se encuentra?:', 'Aneurisma aórtico.', 'Pericarditis aguda.', 'Neumonía.', 'Hernia hiatal.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 14, 'Sin clasificar', 'Pregunta asociada a la imagen 14. Varón de 74 años que consulta por dolor en hemitórax derecho de características pleuríticas de 1 semana de evolución, disnea de moderados esfuerzos, tos productiva y febrícula, sin síndrome general. En la analítica destaca PCR 92,9 mg/L y dímero D 1.630 ng/ml (normal <500). Se muestra la radiografía de tórax póstero-anterior. ¿Cuál es el diagnóstico de sospecha y la actitud a seguir?:', 'Solicitar angioTC de arterias pulmonares por sospecha de tromboembolismo pulmonar.', 'Iniciar tratamiento antibiótico por sospecha de neumonía sin signos de complicación y control radiológico en 4-6 semanas.', 'Derivarle a consulta especializada por sospecha radiológica de carcinoma de pulmón.', 'Solicitar radiografía en decúbito lateral derecho por sospecha de derrame pleural encapsulado previo a toracocentesis. - 3', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 15, 'Sin clasificar', 'Pregunta asociada a la imagen 15. En un paciente anticoagulado y antiagregado que presenta lenguaje incoherente sin otras manifestaciones clínicas asociadas, con una imagen en la TC craneal como la que se muestra, ¿cuál es el diagnóstico más probable?:', 'Hemorragia subaracnoidea.', 'Hematoma intraparenquimatoso.', 'Hematoma epidural.', 'Hematoma subdural.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 16, 'Sin clasificar', 'Pregunta asociada a la imagen 16. Varón de 47 años sin antecedentes de interés que acude a urgencias por fiebre de hasta 39ºC con escalofríos y sudoración, de una semana de evolución, acompañada de dolor epigástrico y malestar general. Se realiza TC abdominopélvica con contraste endovenoso que se muestra en la imagen. ¿Cuál de los siguientes diagnósticos es más probable?:', 'Absceso hepático.', 'Hemangioma hepático.', 'Hepatocarcinoma.', 'Hiperplasia nodular focal con necrosis en su interior.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 17, 'Sin clasificar', 'Pregunta asociada a la imagen 17. Varón de 74 años sin antecedentes de interés que consulta por presentar desde hace 15 días sensación continua de distensión abdominal e intolerancia oral con vómitos ocasionales de contenido maloliente. En la analítica únicamente destaca glucemia 110 mg/dl, PCR 6,3 mg/L (normal 0-5) y 13.140 leucocitos/microL. Se realiza TC abdominal con contraste intravenoso, que se muestra. Considerando los datos clínicos y la prueba de imagen ¿qué diagnóstico es más probable?:', 'Obstrucción gástrica por neoplasia antropilórica.', 'Gastritis enfisematosa.', 'Gastroparesia diabética.', 'Úlcera péptica con signos de perforación contenida. 3 -', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 18, 'Sin clasificar', 'Pregunta asociada a la imagen 18. Varón de 43 años alérgico a la penicilina que presenta boca séptica, síndrome febril, disfagia, edema, eritema y dolor submaxilar de una semana de evolución, sin mejoría con tratamiento antiinflamatorio y antibiótico. Se aporta imagen de la TC cervicofacial realizada tras la administración de contraste intravenoso ¿Qué diagnóstico le sugiere?:', 'Angina de Ludwig.', 'Absceso lingual.', 'Faringitis abscesificada.', 'Quiste dermoide lingual abscesificado.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 19, 'Sin clasificar', 'Pregunta asociada a la imagen 19. Varón de 56 años con antecedentes de infección por VIH diagnosticada hace unos meses, que es encontrado confuso, desorientado y con hemiparesia derecha. La familia refiere que presenta una pérdida significativa de peso en los últimos 6 meses, así como diarrea frecuente. No ha comenzado tratamiento antirretroviral por deseo personal. Los análisis muestran una carga viral de VIH-1 de 600.000 copias/mL, 130 linfocitos CD4, 900 linfocitos totales y un cociente CD4/CD8 de 0,1. La serología a toxoplasma, la carga viral de CMV y el antígeno criptocócico en sangre son negativos. La RM cerebral se muestra en la figura. ¿Cuál es el diagnóstico más probable?:', 'Toxoplasmosis cerebral.', 'Linfoma primario del sistema nervioso central.', 'Leucoencefalopatía multifocal progresiva.', 'Encefalitis por CMV.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 20, 'Sin clasificar', 'Pregunta asociada a la imagen 20. Paciente de 75 años diagnosticado de endocarditis bacteriana por Staphylococcus aureus resistente a la meticilina tras presentar fiebre de 10 días de evolución, soplo sistólico en foco mitral 1-2/6, ecocardiografía transtorácica compatible y hemocultivos positivos. Se le está administrando vancomicina. A los 4 días de antibioterapia presenta disnea intensa, ortopnea y TA 110/55 mmHg. Se aprecia un soplo en foco mitral irradiado a axila 3/6. Se muestra la radiografía de tórax. Indique la actitud más apropiada:', 'Añadir al tratamiento voriconazol.', 'Sustituir la vancomicina por daptomicina y administrar furosemida.', 'Añadir gentamicina, rifampicina, furosemida y nitritos.', 'Indicar cirugía de recambio valvular urgente y tratamiento deplectivo. - 4', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 21, 'Sin clasificar', 'Pregunta asociada a la imagen 21. La presencia de lesiones cutáneas en forma de pápulas violáceas en dorso de articulaciones interfalángicas, como las que se aprecian en la figura, son muy características de:', 'Lupus cutáneo subagudo.', 'Porfiria cutánea tarda.', 'Dermatomiositis.', 'Artropatía psoriásica.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 22, 'Sin clasificar', 'Pregunta asociada a la imagen 22. Mujer de 64 años con antecedentes de diabetes mellitus, hipertensión arterial y obesidad (índice de masa corporal 34) que es atendida en su domicilio por el servicio de emergencias tras presentar durante el descanso nocturno dolor torácico, sudoración intensa, mareos y vómitos de dos horas de evolución. Se realiza electrocardiograma urgente (imagen). En la exploración física se aprecia una ligera disminución del nivel de conciencia, frialdad acra y tensión arterial de 75/30 mmHg, además de un aumento de la presión venosa yugular durante la inspiración y la aparición de pulso paradójico, sin evidencia de edema pulmonar en la auscultación. Con los datos clínicos, exploratorios y electrocardiográficos expuestos, ¿qué complicación del infarto sospecha en esta paciente?:', 'Afectación de ventrículo derecho.', 'Rotura del septo interventricular basal.', 'Rotura del músculo papilar posteromedial mitral.', 'Pseudoaneurisma ventricular inferobasal.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 23, 'Sin clasificar', 'Pregunta asociada a la imagen 23. Varón de 19 años con antecedentes familiares de muerte súbita en padre que acude por clínica de ángor y síncopes en esfuerzo, con sensación de palpitaciones rápidas con el esfuerzo. Presenta el ECG que se adjunta. Se realiza un ecocardiograma y es diagnosticado de una miocardiopatía. Considerando su sospecha del tipo de miocardiopatía que presenta, señale la respuesta verdadera:', 'La fracción de eyección del ventrículo izquierdo muy frecuentemente es inferior al 55 %.', 'Esta entidad es debida a una hipertrofia del tabique con obstrucción dinámica en el tracto de salida del ventrículo izquierdo.', 'No se asocia a disfunción diastólica.', 'El grosor de la pared del ventrículo izquierdo es normal o esta disminuido. 4 -', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 24, 'Sin clasificar', 'Pregunta asociada a la imagen 24. En esta genealogía se observa un patrón de herencia autosómica dominante con un salto de generación en II-1 (su padre I-1 y su hijo III-1 están afectados por la enfermedad mientras que II-1 no la manifiesta). ¿Cómo se llama este fenómeno?:', 'Herencia mitocondrial.', 'Expresividad variable.', 'Penetrancia incompleta.', 'Variación en el fenotipo debida al ambiente.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 25, 'Sin clasificar', 'Pregunta asociada a la imagen 25. La imagen corresponde a 5 minutos de estudio de una poligrafía respiratoria en un varón de 62 años. ¿Qué tipo de evento respiratorio se ve en la misma?:', 'Apnea obstructiva.', 'Esfuerzo respiratorio asociado a microdespertar.', 'Apnea central.', 'Hipopnea.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 26, 'Sin clasificar', '¿Cuál de los siguientes estudios de la coagulación se encontraría alterado en un paciente en el que se sospecha un trastorno hemorrágico hereditario por deficiencia del factor VII?:', 'Tiempo de tromboplastina parcial activado.', 'Tiempo de trombina.', 'Tiempo de protrombina.', 'Determinación de factor von Willebrand.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 27, 'Sin clasificar', 'En relación con la toxicidad del etanol, señale la afirmación correcta:', 'El acetato producido en el metabolismo hepático del etanol es oxidado en este tejido para obtener energía.', 'El incremento en la relación NADH/NAD+ en el metabolismo hepático del etanol inhibe la gluconeogénesis.', 'El ácido úrico compite con el lactato en la excreción urinaria, contribuyendo a la hiperlactacidemia.', 'Los principales marcadores bioquímicos de ingesta habitual de etanol son las transaminasas, especialmente la alaninaaminotransferasa sobre la aspartatoaminotransferasa. - 5', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 28, 'Sin clasificar', 'El perfil metabólico a las dos horas de haber ingerido una comida con abundantes proteínas y pocos hidratos de carbono incluye todos los siguientes cambios EXCEPTO:', 'Aumento de la oxidación de aminoácidos de cadena ramificada en el músculo esquelético.', 'Aumento de los niveles de glucagón.', 'Aumento de la gluconeogénesis hepática.', 'Aumento de la utilización de citrulina por los enterocitos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 29, 'Sin clasificar', 'En relación con el control fisiológico hormonal y por autacoides de la filtración glomerular y del flujo sanguíneo renal, indique la afirmación FALSA:', 'El óxido nítrico derivado del endotelio aumenta la resistencia vascular y disminuye la filtración glomerular.', 'Las prostaglandinas y la bradicinina reducen la resistencia vascular renal y tienden a aumentar la filtración glomerular.', 'La noradrenalina y la adrenalina contraen los vasos sanguíneos y reducen la filtración glomerular.', 'La angiotensina II contrae preferentemente las arteriolas eferentes en la mayoría de los estados fisiológicos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 30, 'Sin clasificar', 'Con respecto a la actividad eléctrica del músculo liso gastrointestinal en una situación fisiológica, indique la afirmación FALSA:', 'El ritmo de casi todas las contracciones gastrointestinales viene determinado por la frecuencia de las ondas lentas.', 'La despolarización de las ondas lentas viene determinada por la entrada de iones sodio y calcio.', 'Los potenciales en espiga son potenciales de acción y tienen una duración mayor que el de las grandes fibras nerviosas.', 'En la generación y características de los potenciales en espiga es determinante la participación de iones calcio.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 31, 'Sin clasificar', 'En relación con el volumen y flujo sanguíneo en los pulmones, en un sujeto sano y en bipedestación, señale la afirmación FALSA:', 'En la espiración forzada se puede generar trasvase de sangre de la circulación pulmonar a la circulación sistémica.', 'Cuando disminuye la concentración de oxígeno en los alvéolos, los vasos adyacentes se dilatan.', 'El ejercicio aumenta el flujo sanguíneo en todas las zonas pulmonares.', 'El aumento del gasto cardiaco durante el ejercicio intenso es asumido normalmente sin grandes aumentos en la presión arterial pulmonar. 5 -', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 32, 'Sin clasificar', 'En cuanto a las características de los potenciales de acción que presentan las fibras musculares esqueléticas, en relación con los potenciales de acción de las fibras de las motoneuronas A alfa que las inervan, señale la respuesta INCO- RRECTA:', 'El potencial de membrana de reposo tiene un valor similar.', 'La duración del potencial de acción de la fibra muscular es mayor.', 'La velocidad de conducción del potencial de acción de la fibra muscular es menor.', 'El flujo de corriente en la profundidad de la fibra muscular es similar al de la motoneurona.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 33, 'Sin clasificar', 'Las diferentes clases (isotipos) de inmunoglobulinas (Ig) tienen diferentes funciones que dependen de los fragmentos Fc de sus cadenas pesadas. ¿Cuál de las siguientes afirmaciones es FALSA?:', 'La IgA se une al receptor poli-Ig (pIgR) para atravesar la placenta y participar en la defensa del neonato.', 'La IgG se une al receptor III para Fc-gamma (Fc-gamma-RIII) de los fagocitos activando el proceso de opsonización.', 'La IgM se une a C1q y activa la vía clásica del complemento contribuyendo a la eliminación de bacterias extracelulares.', 'La IgE se une al receptor para Fc-épsilon (Fcépsilon-R) y activa a eosinófilos y mastocitos participando en la defensa frente a los helmintos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 34, 'Sin clasificar', 'En la inmunoterapia antitumoral basada en el uso de anticuerpos monoclonales contra puntos de control inmunológico (checkpoints) destaca el uso de los anticuerpos monoclonales que bloquean la interacción entre PD-1 y sus ligandos. ¿Cuál de las siguientes afirmaciones es cierta?:', 'La molécula PD-1 es un receptor inhibidor de los linfocitos T que se expresa mayoritariamente en linfocitos T naive.', 'La interacción de PD-1 y sus ligandos inhibe la activación de los linfocitos T en los ganglios linfáticos.', 'El bloqueo de PD-1 o de sus ligandos potencia la capacidad antitumoral de los linfocitos T CD8+.', 'El uso de este tipo de inmunoterapia no se debe combinar con tratamientos de quimioterapia. - 6', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 35, 'Sin clasificar', 'Diferentes mutaciones en el gen AIRE (Autoimmune Regulator) causan una enfermedad rara denominada síndrome poliglandular autoinmune tipo 1 (APS-1). Respecto al gen ¿cuál de las siguientes afirmaciones es cierta?:', 'Está ligado al cromosoma X, por lo que el síndrome APS-1 también se conoce como IPEX (Inmunodesregulación, Poliendocrinopatía y Enteropatía ligada al cromosoma X).', 'Se expresa en los timocitos que no expresan CD4 ni CD8 (doble negativos) promoviendo su expansión y participando en el proceso de selección positiva en el timo.', 'Se expresa en las células T reguladoras controlando su función y siendo responsable del proceso de tolerancia periférica.', 'Se expresa en células epiteliales de la médula tímica regulando la expresión antígenos específicos de otros tejidos y participando en el proceso de selección negativa en el timo.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 36, 'Sin clasificar', 'Un estudio reciente indica que aproximadamente el 10-20 % de los pacientes muy graves o fallecidos por COVID-19 poseen autoanticuerpos neutralizantes de los interferones de tipo I. Los interferones de tipo I:', 'Inhiben la actividad citotóxica de los linfocitos T CD8+ contra las células infectadas.', 'Son producidos por linfocitos CD4+ Th1 tras el reconocimiento de péptidos víricos mediante el receptor T para el antígeno.', 'Activan la expresión de genes que confieren a la célula huésped una resistencia mayor a la infección viral.', 'Inhiben la expresión de los antígenos de histocompatibilidad (HLA) de clase I en las células infectadas.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 37, 'Sin clasificar', 'Respecto a las células T reguladoras (Treg) es cierto que:', 'Colaboran en la eliminación de células tumorales.', 'Expresan el correceptor inhibidor CTLA-4.', 'Coexpresan tanto CD4 como CD8.', 'Liberan citoquinas como IL-17 o IL-22. 6 -', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 38, 'Sin clasificar', 'Mujer de 25 años con antecedentes de asma bronquial alérgica por sensibilización a pólenes de gramíneas y dermatitis atópica. Presenta de forma brusca hipotensión, taquicardia, urticaria y broncoespasmo tras ingerir cacahuetes y es trasladada a urgencias. ¿Cuál sería el orden de los fármacos a administrar y qué prueba de laboratorio podría solicitarse para ser evaluada posteriormente?:', 'Adrenalina intramuscular, seguida de un broncodilatador inhalado tipo SABA y dexclorfeniramina intramuscular. A continuación solicitar triptasa sérica.', 'Un broncodilatador inhalado tipo SABA, seguido de dexclorfeniramina intramuscular y adrenalina intramuscular. A continuación solicitar triptasa sérica.', 'Dexclorfeniramina intramuscular, seguida de un broncodilatador inhalado tipo SABA y adrenalina intramuscular. A continuación solicitar proteína catiónica del eosinófilo.', 'Adrenalina intramuscular, seguida de un broncodilatador inhalado tipo SABA y dexclorfeniramina intramuscular. A continuación solicitar proteína catiónica del eosinófilo.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 39, 'Sin clasificar', 'Paciente de 35 años de edad que consulta para confirmar una sospecha de alergia a Anisakis simplex. Ha sufrido previamente un cuadro clínico de anisaquiasis gastrointestinal tras ingerir pescado. En las pruebas efectuadas se evidencian niveles de IgE específica de 10 KU/l frente a Anisakis simplex. De las siguientes ¿cuál sería la recomendación dietética para este paciente?:', 'No puede comer ningún pescado, crustáceo, molusco ni cefalópodo.', 'Puede comer pescado fresco cocinado a la plancha.', 'Puede comer pescado ultracongelado comercialmente.', 'Puede comer pescado fresco marinado o ahumado en frío. - 7', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 40, 'Sin clasificar', 'Mujer de 16 años diagnosticada de rinoconjuntivitis alérgica por sensibilización a pólenes de gramíneas desde los 10 años, que no controla totalmente la sintomatología en época de polinización con antihistamínicos orales y corticoides tópicos nasales. ¿Qué opción terapéutica etiológica estaría indicada?:', 'Inmunoterapia específica vía sublingual o vía subcutánea durante un periodo mínimo de 3 años.', 'Inmunoterapia específica vía sublingual o vía subcutánea durante un periodo máximo de 1 año.', 'Omalizumab vía subcutánea cada 4 semanas durante un período máximo de 1 año.', 'Omalizumab vía subcutánea cada 4 semanas durante un período mínimo de 6 meses.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 41, 'Sin clasificar', 'Se realiza un estudio para determinar la posible relación entre la contaminación ambiental por SO2 en diversas zonas geográficas y el número de visitas a urgencias por asma. Sobre el diseño del estudio, señale la respuesta correcta:', 'Estudio de correlación ecológica.', 'Estudio de incidencia.', 'Estudio de prevalencia.', 'Estudio de cohortes.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 42, 'Sin clasificar', '¿Qué tipo de medidas de precaución deben adoptarse ante un paciente con neumonía y antigenuria positiva a Legionella pneumophila?:', 'Precauciones de transmisión por gotas.', 'Precauciones de transmisión por contacto.', 'Precauciones de transmisión por aire.', 'Precauciones estándar.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 43, 'Sin clasificar', 'En un meta-análisis, el estimador combinado de los resultados de los estudios revisados es:', 'La suma de los resultados de todos los estudios.', 'La media aritmética de los resultados de todos los estudios.', 'La media ponderada de los resultados de todos los estudios.', 'El porcentaje de resultados favorables a la hipótesis estudiada en todos los estudios.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 44, 'Sin clasificar', 'La especificidad de una prueba diagnóstica es del 94 %. ¿Cuál es la interpretación correcta?:', 'De cada 100 resultados negativos, 94 corresponden a pacientes sanos.', 'De cada 100 pacientes sanos, en 94 el resultado de la prueba será negativo.', 'De cada 100 pacientes enfermos, en 6 el resultado de la prueba será negativo.', 'De cada 100 resultados positivos, 6 corresponden a pacientes enfermos. 7 -', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 45, 'Sin clasificar', 'En la valoración del riesgo de sesgo en los ensayos clínicos ¿cuál de los siguientes criterios se considera?:', 'Pérdidas en el seguimiento.', 'Falta de representatividad de la muestra.', 'Insuficiente tamaño muestral.', 'Escasa comparabilidad de los casos y controles.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 46, 'Sin clasificar', 'Un ensayo clínico controlado ha evaluado la eficacia de un nuevo antiagregante en pacientes graves con síndrome coronario agudo. En el grupo de tratamiento convencional (control) la mortalidad fue del 10 % en mujeres y del 8 % en hombres. En el grupo de intervención con el nuevo antiagregante, la mortalidad se redujo a la mitad del observado en el control tanto en mujeres como en hombres. En relación con la eficacia del nuevo antiagregante para mejorar la supervivencia según el género, señale la respuesta correcta:', 'Es más eficaz en mujeres, porque el valor de NNT estimado en mujeres es inferior al de los hombres.', 'Es más eficaz en hombres, porque el valor de NNT estimado en hombres es superior al de las mujeres.', 'El nuevo antiagregante es igual de eficaz en mujeres y hombres, porque en ambos casos reduce la mortalidad a la mitad.', 'Es más eficaz en hombres, porque el valor de NNT estimado en hombres es inferior al de mujeres.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 47, 'Sin clasificar', '¿En cuál de las siguientes infecciones se precisan medidas de aislamiento de contacto y gotas?:', 'Varicela.', 'Fiebres hemorrágicas virales.', 'Norovirus.', 'Clostridioides difficile.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 48, 'Sin clasificar', 'Para conocer si el uso habitual de ácido acetil salicílico (AAS) se asocia a un mayor riesgo de hipertensión se selecciona un grupo de sujetos, se averigua cuántos están tomando AAS y se les sigue durante 5 años para identificar los casos nuevos de hipertensión. ¿Cuál es el diseño de este estudio?:', 'Es un ensayo clínico, porque se realiza con fármacos.', 'Es un estudio ecológico, porque se sigue a muchos sujetos.', 'Es un estudio de casos y controles, en el que los casos toman AAS y los controles no.', 'Es un estudio de cohortes, porque se sigue a sujetos clasificados según su exposición para identificar el riesgo de una enfermedad. - 8', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 49, 'Sin clasificar', '¿Cuál es la mejor forma de medir la carga global de enfermedad en una población?:', 'Los años vividos con discapacidad.', 'Los años de vida perdidos por muerte prematura.', 'La mortalidad general y por las principales enfermedades.', 'Los años de vida ajustados por discapacidad.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 50, 'Sin clasificar', 'Varón de 58 años que acude a control programado de una diabetes mellitus tipo 2 diagnosticada hace 6 años. Tiene antecedentes personales de HTA, dislipidemia, cardiopatía isquémica y pancreatitis de origen biliar. Su medicación incluye lisinopril, metoprolol, metformina, AAS y atorvastatina. En la exploración física presenta tensión arterial 151/93 mmHg, IMC 27,1 kg/m2. La hemoglobina glicada es de 8,3 %. ¿Cuál de los siguientes es el tratamiento más adecuado para este paciente?:', 'Empaglifozina.', 'Glipizida.', 'Acarbosa.', 'Sitagliptina.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 51, 'Sin clasificar', 'Mujer de 55 años con diabetes tipo 1 diagnosticada a los 15 años que refiere náuseas y distensión abdominal, especialmente después de las comidas. La evaluación es compatible con una gastroparesia diabética. ¿Cuál de los siguientes medicamentos sería el tratamiento más adecuado para mejorar sus síntomas?:', 'Lansoprazol.', 'Ondansetrón.', 'Loperamida.', 'Metoclopramida.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 52, 'Sin clasificar', 'Mujer de 35 años diagnosticada de esquizofrenia refractaria que ha iniciado tratamiento con clozapina. ¿Qué valor de laboratorio se debería monitorizar de forma periódica?:', 'El aclaramiento de creatinina.', 'El recuento sanguíneo de leucocitos.', 'El nivel sérico de colesterol.', 'El nivel sérico de transaminasas.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 53, 'Sin clasificar', 'Varón de 28 años que es trasladado a urgencias con signos de intoxicación aguda. Está consciente y presenta un cuadro caracterizado por vómitos, diarrea, sudoración, sialorrea, lagrimeo y miosis. Considerando la causa más probable de este síndrome, ¿qué fármaco indicaría para su tratamiento de entre los siguientes?:', 'Naloxona.', 'Flumazenilo.', 'Ciproheptadina.', 'Atropina. 8 -', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 54, 'Sin clasificar', '¿Qué afirmación es correcta en relación con el omeprazol?:', 'Es un potente antiácido.', 'Bloquea reversiblemente la bomba de hidrogeniones en el estómago.', 'Es un profármaco.', 'Tras disolverse su cubierta entérica en el estómago se une directamente a la bomba de protones de la célula parietal.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 55, 'Sin clasificar', 'Paciente diabético de 63 años a quien su médico de familia ha solicitado una analítica para determinar los niveles de vitamina B12. ¿Cuál es el fármaco antidiabético que toma que justifica dicha solicitud?:', 'Gliclazida.', 'Metformina.', 'Repaglinida.', 'Pioglitazona.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 56, 'Sin clasificar', 'Para tratar una infección en un niño alérgico a la penicilina, de los siguientes antibióticos a los que el germen es sensible según el antibiograma ¿cuál utilizaría?:', 'Claritromicina.', 'Imipenem.', 'Ceftriaxona.', 'Norfloxacino.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 57, 'Sin clasificar', 'Uno de las siguientes signos clínicos impide realizar el diagnóstico de muerte cerebral:', 'Presencia de reflejos medulares.', 'Anisocoria.', 'Ausencia de hipotensión.', 'Ausencia de ventilación espontánea.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 58, 'Sin clasificar', 'Indique cuál de los siguientes NO se considera un factor de riesgo de delirium postoperatorio en el paciente mayor:', 'Caídas previas.', 'Demencia o deterioro cognitivo.', 'Institucionalizado en una residencia.', 'Alteración visual y auditiva.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 59, 'Sin clasificar', 'En la valoración preoperatoria de un paciente ¿cuál de los siguientes NO consideraría un factor predisponente a desarrollar complicaciones pulmonares?:', 'Edad > 60 años.', 'Albúmina sérica < 3,5 g/100ml.', 'Consumo de alcohol.', 'ASA = 1. - 9', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 60, 'Sin clasificar', 'Paciente de 20 años que acude a urgencias tras sufrir un accidente de bicicleta con traumatismo facial. Se realiza TC craneal que muestra una fractura del tercio medio facial que afecta a la región órbito-malar. Una de las complicaciones más frecuentes de este tipo de fracturas es:', 'Anquilosis témporo-mandibular.', 'Maloclusión dental.', 'Pseudoartrosis naso-etmoidal.', 'Enoftalmos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 61, 'Sin clasificar', 'El conocimiento de la anatomía de la mama es fundamental a la hora de realizar intervenciones quirúrgicas en cirugía plástica. Señale cuál de los siguientes troncos nerviosos es el encargado en la mayoría de los casos de inervar el complejo areola-pezón:', 'Rama cutánea lateral del nervio intercostobraquial.', 'Ramas cutáneas mediales del plexo cervical.', 'Rama cutánea medial del nervio torácico largo.', 'Rama cutánea lateral de los nervios intercostales.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 62, 'Sin clasificar', 'Mujer de 57 años intervenida de mamoplastia de aumento con prótesis hace 4 años. Refiere que desde hace 2 años su mama izquierda está más rígida que la derecha y que en ocasiones le ha producido molestias al realizar esfuerzos con su brazo izquierdo. En la exploración física presenta asimetría evidente de ambas mamas con aumento de la consistencia y cierta deformidad de la mama izquierda y desplazamiento moderado hacia el hueco axilar. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Seroma crónico con colonización bacteriana.', 'Linfoma anaplásico de células grandes asociado a prótesis mamarias.', 'Contractura capsular.', 'Carcinoma ductal infiltrante de mama.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 63, 'Sin clasificar', 'Varón de 36 años que consulta por hiperemia conjuntival y sensación de cuerpo extraño. En la exploración presenta afectación del ganglio preauricular. ¿Cuál de las siguientes patologías NO se corresponde con dicha exploración?:', 'Conjuntivitis adenovírica.', 'Conjuntivitis alérgica.', 'Síndrome oculoglandular de Parinaud.', 'Conjuntivitis por Chlamydia. 9 -', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 64, 'Sin clasificar', 'Mujer de 68 años que utiliza para visión lejana gafas de +4,00 dioptrías en ambos ojos. Consulta porque desde hace unas semanas tiene dolor ocular con cefalea y visión borrosa por la noche cuando está viendo la televisión en penumbra. ¿Cuál de las siguientes patologías es más probable que presente?:', 'Glaucoma por cierre angular primario.', 'Migraña.', 'Queratitis actínica.', 'Síndrome de ojo seco.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 65, 'Sin clasificar', '¿Cuál de las siguientes entidades es más probable que presente un paciente que acude a consulta por visión borrosa y metamorfopsia?:', 'Maculopatía.', 'Neuritis óptica.', 'Glaucoma agudo.', 'Catarata intumescente.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 66, 'Sin clasificar', 'Mujer de 60 años con crisis de mareo de segundos de duración que se desencadenan con los movimientos de la cabeza a la derecha y cuando se da la vuelta en la cama a la derecha. No se asocia a hipoacusia, sensación de taponamiento ni acúfenos. La exploración otológica, de la bipedestación y la marcha son normales. No se evidencia nistagmo espontáneo, pero con la maniobra de Dix-Hallpike a la derecha se identifica, tras breve latencia, un nistagmo disconjugado (más torsional derecho y más vertical izquierdo) de unos 30 segundos de duración con mareo y náuseas. Indique la afirmación correcta sobre su diagnóstico y manejo:', 'Vértigo de origen central, es preciso hacer una prueba de neuroimagen.', 'Vértigo posicional paroxístico benigno, debe ser tratado con la maniobra de Epley derecha.', 'Neuronitis vestibular derecha, debe ser tratada con sulpirida.', 'Primera crisis de enfermedad de Ménière en oído derecho, se infiltrarán corticoides intratimpánicos. - 1', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 67, 'Sin clasificar', 'Varón de 40 años sin antecedentes relevantes que consulta por hipoacusia izquierda de instauración progresiva y un bulto ipsilateral en el cuello. No refiere catarro de vías altas, rinorrea acuosa, prurito nasal, otalgia, otorrea, vértigo ni acúfenos. En la otoscopia, en el oído izquierdo se observa una membrana timpánica íntegra con una imagen de líquido ambarino con burbujas en oído medio, siendo la exploración del oído derecho normal. Rinne positivo en oído derecho y negativo en oído izquierdo, Weber lateraliza a oído izquierdo. ¿Cuál de las siguientes enfermedades es más probable que tenga en el oído izquierdo?:', 'Otitis media aguda que debe ser tratada con antibióticos vía oral.', 'Otitis media crónica colesteatomatosa que debe ser tratada mediante cirugía.', 'Otitis media serosa que precisa una exploración de la nasofaringe en busca de una neoformación u obstrucción de la trompa de Eustaquio.', 'Hipoacusia neurosensorial que precisa la realización de una audiometría tonal y una logoaudiometría.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 68, 'Sin clasificar', 'Mujer de 52 años de edad, a la que tres semanas antes se había diagnosticado una sinusitis aguda maxilar, etmoidal y frontal derechos. Mejoró inicialmente con tratamiento antibiótico, descongestionante nasal, mucolítico y corticoides tópicos. Acude dos semanas después con un cuadro de fiebre, cefalea intensa, náuseas y malestar general. Para el estudio de posibles complicaciones supuradas intracraneales la prueba complementaria más adecuada es:', 'Tomografía axial computarizada del macizo facial con cortes coronales y axiales.', 'Endoscopia nasal con ópticas rígidas o flexibles.', 'Resonancia magnética nuclear con gadolinio.', 'Punción lumbar.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 69, 'Sin clasificar', '¿Cuál es el marcador ecográfico más importante en el cribado de la preeclampsia del primer trimestre del embarazo?:', 'Longitud cráneo-caudal.', 'Grosor placentario.', 'Índice de pulsatilidad de las arterias uterinas.', 'Índice de pulsatilidad de la arteria central de la retina materna. 10 -', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 70, 'Sin clasificar', 'Mujer de 43 años portadora de dispositivo intrauterino de levonorgestrel que consulta por falta de descanso nocturno con aparición de calor y palpitaciones. En la analítica destaca T4 libre 10,5 pmol/L (9-19), tirotropina 2,1 mUI/L (0,30-5,00), FSH 95,6 UI/L (1,38-16,7), LH 21 UI/L (2,4-9,3), estradiol < 0,07 nmol/L (0,07 - 1,14). ¿Cuál es el tratamiento más adecuado?:', 'Benzodiacepinas.', 'Estrógenos vaginales.', 'Estrógenos y progestágenos orales en pauta continua.', 'Estrógenos transdérmicos en pauta continua.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 71, 'Sin clasificar', 'En relación con el estudio prenatal de aneuploidías mediante el cribado combinado del primer trimestre ¿Cuál es la afirmación correcta?:', 'El valor de la fracción libre de la gonadotropina coriónica se encuentra disminuido en la trisomía 21.', 'Se realiza mediante la combinación de datos analíticos y ecográficos.', 'Está indicada en el primer trimestre en población gestante de riesgo.', 'La transonolucencia nucal debe medirse entre las 11 y 14 semanas, mediante la realización de un corte sagital y con el embrión en posición de hiperflexión.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 72, 'Sin clasificar', '¿Cuál de los siguientes NO constituye un criterio de selección para la elección de la vía del parto en la presentación de nalgas durante el inicio del trabajo de parto?:', 'Tipo de presentación podálica (nalgas puras, completas o incompletas).', 'Medida del diámetro biparietal fetal.', 'Peso fetal.', 'Actitud de la cabeza fetal.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 73, 'Sin clasificar', 'Mujer de 51 años, menopaúsica desde hace un año y medio, que consulta por manchado vaginal de 2 semanas de evolución. Refiere que el manchado es menor que una regla. En la ecografía se objetiva un endometrio de 7 mm. Señale la opción correcta:', 'El endometrio está engrosado y ante la clínica de la paciente, toma una biopsia endometrial con cánula de Cornier.', 'El endometrio no está engrosado por lo que le pauta ácido tranexámico y seguimiento ambulatorio.', 'Tiene indicación de histeroscopia diagnóstica sin necesidad de toma de biopsia endometrial.', 'El endometrio no está engrosado, pero como tiene clínica de metrorragia está indicada la realización de una biopsia endometrial. - 1', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 74, 'Sin clasificar', 'Primigesta de 34 semanas que presenta cifras tensionales de 165/95 y cefalea de dos días de evolución. Analítica: hemoglobina 10,5 g/dL, plaquetas 98.000/mm3, AST 356 UI/L (0-31), ALT 234 UI/L (0-31), LDH 878 UI/L (125-243). Llaman del laboratorio por presencia de esquistocitos en el frotis de sangre periférica. Ha recibido la segunda dosis de corticoides para maduración fetal hace 24 h. En la ecografía obstétrica el peso fetal estimado está en el percentil 1 para la edad gestacional y el Doppler de arteria umbilical presenta ausencia del flujo telediastólico. ¿Cuál de las siguientes es la actitud clínica más indicada?:', 'Actitud expectante con antihipertensivos y sulfato de magnesio hasta la mejora de las plaquetas maternas.', 'Actitud expectante con tratamiento antihipertensivo a domicilio y controles cada 48 h.', 'Finalización de la gestación cuando complete la maduración pulmonar fetal.', 'Finalización inmediata de la gestación.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 75, 'Sin clasificar', 'Mujer de 30 años que solicita un método anticonceptivo. Como antecedentes tiene una cesárea urgente hace 7 meses, naciendo una niña de 3.550 g. Está dando lactancia materna exclusiva. Señale la afirmación correcta:', 'Le explica que, si está en amenorrea, no requiere de otro método anticonceptivo puesto que la lactancia materna es suficiente como método anticonceptivo.', 'Le informa que el DIU de levonogestrel está contraindicado por haber tenido una cesárea hace menos de un año.', 'Le explica que podría usar un método hormonal de sólo gestágenos.', 'Le ofrece anticoncepción hormonal combinada.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 76, 'Sin clasificar', 'Mujer de 40 años que consulta porque desde hace un mes se nota un bulto en el cuadrante superoexterno de la mama derecha. Aporta un informe de una mamografía que describe una lesión BIRADS 3. ¿Cuál es la actitud a seguir?:', 'Tranquilizarle, puesto que ya se ha hecho una prueba de imagen y se ha descartado malignidad.', 'Esa clasificación implica probablemente cirugía dado que la probabilidad de cáncer es mayor del 10 %. Se lo explica y le deriva de forma preferente a la Unidad de Mama.', 'Se trata de un hallazgo probablemente benigno, dado que hay menos de un 2 % de probabilidad de cáncer. Le explica que requiere de un seguimiento cada 6-12 meses hasta los 24 meses o una biopsia.', 'Los hallazgos son de baja sospecha de cáncer (entre un 2 y un 10 %) pero es necesario hacer una biopsia. 11 -', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 77, 'Sin clasificar', 'Siguiendo las indicaciones del cribado del cáncer de cérvix ¿a qué mujer realizaría una citología entre las siguientes candidatas?:', 'Mujer de 26 años sin citologías previas.', 'Mujer de 40 años con citología y virus del papiloma humano negativos hace 3 años.', 'Mujer de 67 años con incontinencia urinaria de esfuerzo.', 'Mujer de 22 años vacunada para el virus del papiloma humano e inicio de relaciones sexuales hace 1 año.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 78, 'Sin clasificar', 'En una enfermedad genética con un patrón de herencia autosómico dominante el riesgo de recurrencia de la enfermedad en una futura descendencia es de:', '25 % en cada embarazo.', '50 % en cada embarazo en caso de que el hijo sea un varón.', '50 % en cada embarazo siempre que la pareja sea también portadora.', '50 % en cada embarazo independiente del sexo de la descendencia.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 79, 'Sin clasificar', 'En caso de que haya manifestaciones clínicas ¿cuál es la forma clínica más frecuente de primoinfección por el virus del herpes simple tipo 1 en lactantes y niños pequeños?:', 'Meningitis.', 'Genital.', 'Neumonía.', 'Gingivoestomatitis y faringitis.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 80, 'Sin clasificar', 'Lactante de 2 meses de edad con catarro de vías altas de 3 días de evolución, que comienza con dificultad respiratoria moderada y auscultación pulmonar con sibilancias espiratorias. La saturación de oxígeno es de 89 %. Se aísla virus respiratorio sincitial en el exudado nasofaríngeo. ¿Cuál de los siguientes tratamientos considera más indicado para este cuadro?:', 'Rivabirina oral.', 'Salbutamol nebulizado.', 'Oxígeno suplementario.', 'Corticoides intravenosos. - 1', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 81, 'Sin clasificar', 'Con respecto a las comunicaciones interventriculares (CIV) en la infancia, señale la respuesta INCORRECTA:', 'Exceptuando la válvula aórtica bicúspide, la CIV es la cardiopatía congénita más frecuente.', 'Las CIV localizadas en la porción media y apical del tabique interventricular son de tipo muscular.', 'La repercusión clínica y la necesidad de tratamiento dependen del tamaño de la comunicación.', 'Las CIV membranosas son las más frecuentes y la que tienen más probabilidad de cierre espontáneo.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 82, 'Sin clasificar', 'Con respecto al síndrome de dificultad respiratoria neonatal (enfermedad de la membrana hialina), señale la respuesta FALSA:', 'Los corticoides antenatales reducen el riesgo de su aparición.', 'Sus manifestaciones clínicas aparecen a partir de las 24 horas de vida.', 'El riesgo de aparición disminuye ante una rotura prematura de membranas.', 'Su causa principal es el déficit de surfactante pulmonar.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 83, 'Sin clasificar', 'La fenilcetonuria es una enfermedad metabólica congénita. En relación con la misma, indique la contestación FALSA:', 'La fenilalanina debe suprimirse en la dieta completamente.', 'La discapacidad intelectual es constante y progresiva en caso de no realizar bien la dieta.', 'Puede deberse a un déficit de tetrahidrobiopterina BH4.', 'Se recomienda su estudio a las 24-48 horas del inicio de la ingesta del recién nacido.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 84, 'Sin clasificar', 'En una enfermedad genética neurológica, el fenómeno de anticipación implica la aparición de las manifestaciones más precozmente y en general de forma más grave en la siguiente generación. Dado que la anticipación ocurre por la expansión de trinucleótidos, indique en cuál de estas enfermedades es posible esperar este fenómeno:', 'Atrofia muscular espinal.', 'Distrofia muscular de Duchenne.', 'Enfermedad de Parkinson.', 'Distrofia miotónica de Steinert. 12 -', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 85, 'Sin clasificar', 'El neuroblastoma es el tumor sólido extracraneal más común en niños. En relación con su diagnóstico, señale la respuesta FALSA:', 'Debemos sospecharlo ante la aparición de un síndrome opsoclono-mioclono-ataxia.', 'Existe casi siempre un aumento en la excreción urinaria de metabolitos de catecolaminas.', 'La mayoría se diagnostica en menores de 6 años de edad.', 'La gammagrafía con tecnecio es muy específica y está indicada para definir mejor su extensión.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 86, 'Sin clasificar', '¿Cuál de los siguientes NO es indicación de realizar inmunoprofilaxis con palivizumab en un lactante?:', 'Lactante nacido antes de las 29 semanas de gestación en el primer año de vida.', 'Lactante nacido antes de las 32 semanas de gestación con enfermedad pulmonar crónica de la prematuridad en el primer año de vida.', 'Lactante diagnosticado de fibrosis quística de páncreas en el cribado neonatal durante el primer año de vida.', 'Lactante de 12 meses afecto de inmunodeficiencia severa combinada.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 87, 'Sin clasificar', 'Con respecto al síndrome de muerte súbita del lactante, señale la afirmación correcta:', 'La presencia de antecedentes de muertes similares en hermanos/familiares es criterio diagnóstico de este síndrome.', 'Ante un episodio de muerte súbita infantil se debe firmar el certificado ordinario de defunción por el facultativo del servicio de urgencias.', 'La edad del niño superior a 1 año excluye el diagnóstico, independientemente de que se trate o no de lactantes.', 'La existencia de una patología grave diagnosticada en la autopsia es criterio diagnóstico de este síndrome.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 88, 'Sin clasificar', 'Niño de 23 meses que presenta fiebre, hipotensión, vómitos repetidos, signos meníngeos, petequias y equimosis. El hemograma muestra 25.000 leucocitos (75 % neutrófilos, 10 % cayados) y 12.000 plaquetas/microL y el estudio de coagulación una actividad de protrombina de 35 %. ¿Qué opción NO es adecuada en su manejo?:', 'Administración de cefotaxima intravenosa.', 'Realización de punción lumbar.', 'Recogida de hemocultivo.', 'Fluidos intravenosos. - 1', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 89, 'Sin clasificar', 'Niña de 4 años que presenta fiebre alta de 6 días de evolución. En la exploración clínica presenta un exantema eritematoso maculopapular en tronco y zona genital, con tendencia a la confluencia, sin llegar a ser escarlatiniforme; inyección conjuntival sin secreciones y labios rojos con lengua aframbuesada. Presenta también eritema con edema en manos y pies y una adenopatía cervical unilateral de 2 cm de diámetro. El diagnóstico clínico de sospecha más probable es:', 'Enfermedad de Kawasaki.', 'Sarampión.', 'Rubeola.', 'Escarlatina.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 90, 'Sin clasificar', 'Dentro de las cardiopatías cianóticas destaca la tetralogía de Fallot. En relación con este cuadro, señale la respuesta INCORRECTA:', 'En la prueba de hiperoxia con O2 al 100 % no se eleva significativamente la saturación de O2.', 'Es típica la presencia de hiperaflujo sanguíneo pulmonar.', 'Ante toda sospecha debe administrarse precozmente una perfusión de prostaglandina E1.', 'La silueta cardiaca presenta la típica imagen de corazón en bota.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 91, 'Sin clasificar', '¿Cuál de las siguientes NO es una indicación para la realización de pruebas de neuroimagen en psiquiatría?:', 'Trastorno mental de inicio después de los 50 años.', 'Crisis convulsivas con síntomas psiquiátricos.', 'Recaída psicótica al suspender el tratamiento tras un primer episodio psicótico.', 'Presencia de síntomas psiquiátricos atípicos.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 92, 'Sin clasificar', 'Mujer de 75 años traída a consulta por su familia porque le encuentran desde hace meses deprimida y con fallos de memoria. Les preocupa que pueda tener una enfermedad de Alzheimer. La paciente refiere que no cree que le pase nada y que está como siempre. ¿En qué orden se presentan generalmente los siguientes síntomas en la progresión de la enfermedad de Alzheimer?:', 'Cambios de humor, síntomas conductuales, déficit cognitivo.', 'Síntomas conductuales, síntomas motores, declive de la independencia funcional.', 'Cambios de humor, déficit cognitivo, declive de la independencia funcional.', 'Síntomas conductuales, cambios de humor, síntomas motores. 13 -', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 93, 'Sin clasificar', 'Varón de 35 años de edad, casado y padre de tres hijos, que ingresa en el hospital por una fractura de tobillo complicada. Al segundo día se le notó nervioso y comenzó a temblar. Se le interroga acerca de posibles hábitos tóxicos y los niega, explicando que ocasionalmente bebe una cerveza. La esposa señala que desde hace tres años consume cantidades importantes de cerveza diariamente y ocasionalmente se muestra violento. Al día siguiente las enfermeras informan de que ha dormido mal, está muy ansioso y dice incoherencias, estando desorientado en el tiempo. De las siguientes pautas terapéuticas ¿cuál es la más adecuada?:', 'Benzodiacepinas de vida media larga y clometiazol.', 'Benzodiacepinas de vida media corta y betabloqueantes.', 'Benzodiacepinas de vida media larga y carbamacepina.', 'Benzodiacepinas de vida media corta y clozapina.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 94, 'Sin clasificar', 'Varón que consulta porque hace 1 mes falleció su madre, tras un largo periodo de enfermedad neurodegenerativa. A pesar del tiempo transcurrido sigue presentando dificultades del sueño ocasionales y problemas para aceptar su muerte, sintiendo gran añoranza y elevada emocionabilidad cuando la recuerda o le hablan de ella. Por otra parte, si está distraído es capaz de disfrutar algo y en el trabajo su desempeño es prácticamente normal. ¿Cuál de las siguientes respuestas es FALSA?:', 'El diagnóstico es duelo (Z63.4, según la 10ª edición de la Clasificación Internacional de Enfermedades -CIE-10-).', 'Si las dificultades del sueño tienen consecuencias sobre la vigilia del día siguiente podría prescribirle temporalmente un fármaco hipnótico.', 'Dado el tiempo transcurrido se debería instaurar un antidepresivo a dosis bajas.', 'Es conveniente darle una nueva cita al cabo de 1-2 meses para ver su evolución.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 95, 'Sin clasificar', 'Mujer de 23 años que consulta por presentar desde hace 2 meses crisis repentinas y recurrentes de ansiedad con palpitaciones, sudoración, temblor, sensación de ahogo y dolor torácico. Señale cuál de la siguientes afirmaciones NO es correcta:', 'En la evolución es frecuente encontrar agorafobia y conductas de evitación.', 'En el diagnóstico diferencial se deben considerar feocromocitoma, tirotoxicosis e hipoglucemia.', 'Es preciso descartar una taquicardia auricular paroxística.', 'El diagnóstico más probable es un trastorno por ansiedad generalizada. - 1', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 96, 'Sin clasificar', 'Sobre los factores de riesgo de suicidio, indique de entre los siguientes el factor con MENOS riesgo:', 'Abuso de sustancias.', 'Evento estresante de larga duración.', 'Trastorno de pánico coexistente.', 'Edad avanzada.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 97, 'Sin clasificar', 'Señale la afirmación correcta en relación con el tratamiento de la manía:', 'El tratamiento habitual en las primeras 48 horas se basa en benzodiacepinas en monoterapia por vía parenteral.', 'La clozapina es el fármaco de elección para el tratamiento agudo.', 'La combinación de litio y antipsicóticos está contraindicada en las fases iniciales del tratamiento.', 'En casos graves o resistentes puede utilizarse la terapia electroconvulsiva.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 98, 'Sin clasificar', 'Respecto a la utilización de estimulación magnética transcraneal repetitiva en los trastornos psiquiátricos, señale la respuesta correcta:', 'Es especialmente útil en trastornos psiquiátricos secundarios a la epilepsia.', 'Tiene una eficacia superior a la terapia electroconvulsiva.', 'Está indicada en la depresión resistente al tratamiento farmacológico.', 'Por su seguridad, es el tratamiento de elección en la esquizofrenia de inicio tardío.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 99, 'Sin clasificar', 'Ante un síndrome depresivo en un varón de 68 años sin antecedentes psiquiátricos, señalar cuál de las siguientes afirmaciones es INCORREC- TA:', 'La presencia de desorientación, apatía y pérdida de memoria orienta hacia el diagnóstico de demencia.', 'La presencia de temblor de reposo, marcha sin balanceo y amimia facial orienta el diagnóstico hacia enfermedad de Parkinson.', 'La presencia de hipercolesterolemia, bradipsiquia, bradicardia y estreñimiento orienta hacia el diagnóstico de hipotiroidismo.', 'El inicio reciente de tratamiento con betabloqueantes y antiinflamatorios no esteroideos puede justificar la aparición de un síndrome depresivo. 14 -', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 100, 'Sin clasificar', 'Mujer de 80 años con antecedentes de hipertensión arterial y diabetes mellitus que presenta de forma brusca una alteración del lenguaje. A su llegada al hospital se objetiva una fibrilación auricular no conocida y en la exploración presenta habla fluente con tendencia a la jergafasia, mala compresión del lenguaje, incapacidad para la repetición y disnomia. Semiológicamente presenta un cuadro compatible con:', 'Afasia de Broca.', 'Afasia de conducción.', 'Afasia transcortical sensitiva.', 'Afasia de Wernicke.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 101, 'Sin clasificar', 'Todas las siguientes enfermedades neurodegenerativas están relacionadas con una alteración en la proteína Tau, EXCEPTO:', 'Enfermedad de Alzheimer.', 'Demencia frontotemporal.', 'Enfermedad de Parkinson.', 'Parálisis supranuclear progresiva.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 102, 'Sin clasificar', 'Mujer de 29 años con antecedentes de crisis febriles y fumadora importante. Consulta por presentar desde hace unos 2 años episodios frecuentes, estereotipados, que comienzan con una sensación epigástrica ascendente y un olor desagradable, seguidos de desconexión del medio. Los familiares que están con ella observan que hace movimientos de chupeteo y de apertura y cierre repetidos de la mano izquierda. Pasados dos minutos los movimientos ceden, pero le cuesta responder adecuadamente y solo recuerda parcialmente lo ocurrido. De los siguientes ¿cuál es el diagnóstico más probable?:', 'Crisis focales complejas del lóbulo temporal.', 'Accidentes isquémicos transitorios en territorio carotídeo derecho.', 'Crisis focales simples motoras.', 'Episodios de amnesia global transitoria.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 103, 'Sin clasificar', 'Varón de 30 años que consulta por cefaleas perioculares unilaterales que progresan rápidamente hasta hacerse muy intensas. Las crisis de dolor duran entre 30-60 minutos, ocurren 2- 3 veces al día y se acompañan de lagrimeo en el ojo que le duele y rinorrea unilateral. ¿Cuál es el tratamiento preventivo más adecuado?:', 'Prednisona oral con retirada en 2-3 meses.', 'Prednisona oral con retirada en un mes, asociada a verapamilo oral a dosis de 80-180 mg cada 8 horas.', 'Carbamazepina a dosis de 600-1200 mg al día.', 'Indometacina a dosis de 50 mg cada 8 horas durante un mes. - 1', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 104, 'Sin clasificar', 'En un paciente con una parálisis facial periférica (parálisis de Bell) izquierda ¿cuál de los siguientes signos o síntomas NO esperaría encontrar?:', 'Hiperacusia izquierda.', 'Hipoestesia de la hemicara izquierda.', 'Hipogeusia.', 'Falta de lagrimeo en el ojo izquierdo.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 105, 'Sin clasificar', 'Varón de 45 años traído a la consulta por sus familiares por un cuadro de un año de evolución de pérdida de memoria, que ha ido progresando hasta necesitar ayuda para algunas actividades de su vida cotidiana. Tiene antecedentes de migrañas y algún episodio de focalidad neurológica autolimitada por los que no ha consultado nunca. La exploración neuropsicológica es compatible con una demencia inicial y la RM cerebral muestra una leucoencefalopatía grave. ¿Qué prueba habría que solicitar?:', 'Punción lumbar para analizar amiloide y proteína tau en LCR.', 'Estudio genético para presenilina 1 (PSEN1).', 'Estudio genético para NOTCH3.', 'Estudio genético para progranulina.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 106, 'Sin clasificar', 'Con respecto al tratamiento de la hipertensión intracraneal NO es una medida aceptada:', 'Elevar la cabeza del enfermo y mantener la cabeza centrada.', 'El drenaje de LCR a través de un drenaje lumbar.', 'La hiperventilación moderada.', 'Los glucocorticoides en algunas circunstancias.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 107, 'Sin clasificar', 'Varón de 55 años que sufre una hemorragia subaracnoidea por rotura de un aneurisma de arteria cerebral media. Es tratado de forma quirúrgica. Tras una buena evolución en la que recupera la capacidad de caminar, un mes después de sufrir la hemorragia presenta un deterioro progresivo, llegando a encontrarse obnubilado y con dificultad para obedecer órdenes. Señale la afirmación correcta:', 'Se encuentra en el momento de la evolución en el que es más frecuente el vasoespasmo.', 'Probablemente este deterioro progresivo sea secundario al resangrado del aneurisma.', 'El deterioro subagudo que presenta con mayor probabilidad se debe a hidrocefalia.', 'La técnica diagnóstica de elección es la angiografía cerebral. 15 -', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 108, 'Sin clasificar', 'Varón de 49 años que ingresa en UCI por un traumatismo craneoencefálico tras un accidente laboral. En la exploración física no abre ojos, no emite sonidos antes de ser intubado y presenta extensión de extremidades al estímulo nociceptivo. Se coloca un sensor de presión intracraneal y debe realizarse una craneotomía descompresiva por una hemorragia intraparenquimatosa. ¿Cuál de las siguientes afirmaciones es correcta?:', 'A su llegada se encuentra en un coma de la escala de Glasgow de 7.', 'La presión de perfusión cerebral es la presión arterial media más la presión intracraneal.', 'El edema cerebral vasogénico se produce por edema celular, rotura de la membrana y muerte celular.', 'El flujo vascular cerebral aumenta con la hipercapnia y la acidosis.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 109, 'Sin clasificar', 'Respecto a la sedación del paciente crítico en ventilación mecánica en la UCI ¿cuál de las siguientes afirmaciones es cierta?:', 'Los bloqueantes neuromusculares están indicados cuando el paciente presenta asincronías, independientemente del grado de analgesia y sedación.', 'Se prefieren los sedantes no benzodiazepínicos debido a que las benzodiacepinas se relacionan con peor resultado clínico.', 'La interrupción diaria de la sedación no acorta el tiempo de ventilación mecánica ni la estancia en UCI.', 'El paracetamol es el principal agente farmacológico para lograr una adecuada analgesia en los pacientes intubados y ventilados mecánicamente.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 110, 'Sin clasificar', 'El osteosarcoma es un tumor óseo maligno que:', 'Es más frecuente en la primera década de la vida.', 'Su tratamiento con quimioterapia y radioterapia suele evitar la cirugía.', 'Afecta más frecuentemente a huesos en la proximidad de la articulación de la rodilla.', 'Si presenta enfermedad de Paget previa tiene un mejor pronóstico.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 111, 'Sin clasificar', 'El síndrome del túnel carpiano:', 'Es más frecuente en varones.', 'Cursa con hipoestesia en el pulpejo de los dedos segundo a quinto.', 'Los síntomas se exacerban durante la noche.', 'Se acompaña de atrofia de la musculatura de la eminencia hipotenar. - 1', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 112, 'Sin clasificar', 'Mujer de 61 años, administrativa, con antecedentes de sobrepeso, hipertensión, dislipemia y síndrome metabólico, que consulta por dolor en ambas nalgas, región trocantérea izquierda, cara lateral del muslo izquierdo hasta la rodilla y pierna izquierda hasta el tercio medio. El dolor aparece cuando levantamos el miembro inferior con la rodilla extendida, pero se alivia al flexionar la rodilla. ¿Cuál es la primera sospecha clínica?:', 'Artritis gotosa de cadera izquierda.', 'Artrosis coxo-femoral izquierda.', 'Lumbalgia irradiada / lumbociatalgia.', 'Claudicación por estenosis de canal.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 113, 'Sin clasificar', 'Varón de 35 años, cartero, sin antecedentes de interés, que acude a urgencias por un dolor agudo cervical de 24 horas de evolución, sin traumatismo previo, que irradia a brazo izquierdo hasta la mano y se acompaña de parestesias en el borde radial del antebrazo. No presenta pérdida de fuerza objetivable, conserva la movilidad del cuello aunque es dolorosa y se aprecia contractura de la musculatura paravertebral. La primera actitud será:', 'Tratamiento conservador con antiinflamatorios no esteroideos, calor local y reposo relativo.', 'Llamada urgente al neurocirujano para valoración quirúrgica.', 'Solicitud preferente de resonancia magnética y electromiograma.', 'Derivación preferente a consultas externas de traumatología.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 114, 'Sin clasificar', 'Respecto a la rotura del ligamento cruzado anterior de la rodilla, señale la respuesta correcta:', 'Es frecuente que se produzca por un traumatismo sobre la cara anterior de la tibia con la rodilla en flexión.', 'Raramente cursa con hemartros.', 'La maniobra de Lachman es negativa.', 'El tratamiento con fisioterapia con potenciación del cuádriceps y los isquiotibiales puede evitar la cirugía. 16 -', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 115, 'Sin clasificar', 'Varón de 27 años, deportista habitual, que refiere dolor en la pierna derecha tras la práctica de carrera continua. Ha acudido en varias ocasiones a un fisioterapeuta, siendo diagnosticado de una sobrecarga en gemelos. Han transcurrido varios meses, no ha mejorado y refiere dolor intenso tras la actividad física que cede con el reposo en las siguientes horas del ejercicio. ¿Qué prueba puede ayudar en el diagnóstico?:', 'Tomografía de emisión de positrones con 18 FDG.', 'Determinación de la presión del compartimento posterior inmediatamente tras actividad.', 'Ecografía-Doppler para descartar un trastorno circulatorio de la extremidad inferior.', 'Espectrometría por resonancia magnética.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 116, 'Sin clasificar', 'Mujer de 95 años que vive en una residencia, independiente para sus actividades básicas de la vida diaria, sale al jardín a pasear. Tiene antecedentes de HTA, dislipidemia, osteoporosis y deterioro cognitivo leve. Sufre una caída al levantarse por la noche al baño. La radiografía muestra una fractura subcapital desplazada de cadera derecha. ¿Cuál es el tratamiento recomendado?:', 'Hemiartroplastia de cadera.', 'Fijación con clavo trocantérico.', 'Fijación con tornillos canulados.', 'Conservador: vida cama-sillón.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 117, 'Sin clasificar', '¿En relación con las fracturas de la epitróclea en los niños señale la afirmación INCORREC- TA?:', 'Se desencadenan por un mecanismo de valgo forzado del codo en la caída.', 'Están asociadas hasta en un 50 % de los casos con una luxación postero-lateral del codo.', 'Pueden presentar asociada una neurapraxia del nervio cubital.', 'Es más frecuente en niños de edades entre 4 y 6 años.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 118, 'Sin clasificar', 'Varón de 41 años que consulta por gonalgia de varios días de evolución. En la exploración se realiza el test de Thessaly (dolor con los movimientos de rotación interna y externa con la rodilla flexionada) que resulta positivo. ¿Cuál de las siguientes lesiones es más probable?:', 'Lesión meniscal.', 'Lesión por rotura del ligamento cruzado anterior.', 'Lesión por rotura del ligamento cruzado posterior.', 'Lesión por artropatía degenerativa. - 1', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 119, 'Sin clasificar', 'Mujer de 13 años, sin antecedentes relevantes, con menarquia hace 3 meses, seguida desde los 10 años por escoliosis idiopática que ha empeorado. En la exploración física presenta una giba de 7 grados en el test de Adams y en el escoliograma una curva toracolumbar T4-L1 de 35 grados de Cobb y un Risser 0. La actitud correcta a tomar será:', 'Recomendar natación y revisión en tres meses.', 'Prescribir una ortesis tipo corsé.', 'Derivar a fisioterapia para elastificación del raquis.', 'Revisar en 6 meses con una nueva radiografía.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 120, 'Sin clasificar', 'Sobre la fascitis plantar, señale la respuesta correcta:', 'El dolor mejora al andar de puntillas.', 'Se asocia a la presencia de espolón calcáneo.', 'El tratamiento de elección es quirúrgico.', 'Provoca dolor en la zona del talón, más intenso al empezar a caminar.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 121, 'Sin clasificar', 'Mujer de 79 años que ingresa por una fractura osteoporótica de cadera. Respecto a la prevención secundaria de las fracturas por fragilidad, señale la respuesta INCORRECTA:', 'La baja adherencia al tratamiento se asocia a un incremento del riesgo de fractura.', 'Los marcadores de remodelado óseo pueden ser útiles para monitorizar de forma precoz la respuesta al tratamiento.', 'La vitamina D en monoterapia es eficaz en la reducción de dichas fracturas en personas mayores no institucionalizadas.', 'El aumento de calcio dietético o tomar suplementos de calcio de forma aislada no protegen frente a la aparición de fracturas.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 122, 'Sin clasificar', 'Paciente de 78 años sin antecedentes que consulta por astenia y disnea de 3 meses de evolución, que ha progresado hasta hacerse de reposo en los últimos días. En los días previos refiere también dolor torácico de características anginosas con pequeños esfuerzos. En la exploración destaca presión arterial de 110/80 mmHg, frecuencia cardíaca de 85 lpm y auscultación con un soplo sistólico áspero en segundo espacio intercostal derecho y crepitantes en ambas bases pulmonares. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Insuficiencia mitral.', 'Estenosis aórtica.', 'Insuficiencia aórtica.', 'Miocardiopatía dilatada de origen isquémico. 17 -', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 123, 'Sin clasificar', '¿Cuál de las siguientes afirmaciones es FALSA con relación al síndrome del QT largo?:', 'Los betabloqueantes están contraindicados en el QT largo congénito.', 'Los antidepresivos tricíclicos pueden dar lugar a un QT largo adquirido.', 'Predispone a la taquicardia ventricular polimórfica.', 'Su fisiopatología se basa en una alteración de los canales iónicos responsables del potencial de acción transmembrana de la célula miocárdica.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 124, 'Sin clasificar', 'Mujer de 82 años con fibrilación auricular crónica de 10 años de evolución y función sistólica biventricular conservada que presenta episodios de bloqueo aurículo-ventricular completo sintomáticos, por lo que se decide implantar un sistema de estimulación cardiaco definitivo. ¿Cuál de los siguientes está indicado?:', 'Marcapasos DDD (bicameral).', 'Marcapasos VVI (unicameral ventricular).', 'Marcapasos AAI (unicameral auricular).', 'Terapia de resincronización ventricular (TRC).', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 125, 'Sin clasificar', 'Varón de 23 años diagnosticado de síndrome de Wolff-Parkinson-White que acude a urgencias por palpitaciones. El ECG muestra una taquicardia irregular de QRS ancho, con una frecuencia cardiaca de 205 lpm, compatible con fibrilación auricular preexcitada. ¿Cuál de los siguientes fármacos considera adecuado administrar para detener la taquicardia?:', 'Verapamilo.', 'Digoxina.', 'Adenosina.', 'Procainamida. - 1', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 126, 'Sin clasificar', 'Varón de 58 años con antecedentes de hipertensión arterial de 6 años de evolución, que consulta por mal control de las cifras de presión arterial a pesar de recibir tratamiento con un inhibidor de la enzima convertidora de angiotensina, un diurético y un calcioantagonista. En consulta presenta cifras de 149/100 mmHg. Analítica: creatinina 1,2 mg/dl, potasio 2,2 mEq/l y alcalosis metabólica compensada; resto del estudio bioquímico, hemograma, coagulación y sedimento urinario normal. Señale la afirmación correcta:', 'El origen de la hipertensión en este caso es la secreción excesiva de aldosterona causada por una hiperfunción autónoma de la médula suprarrenal.', 'En la mayoría de los casos el sustrato anatómico es una hiperplasia bilateral de la corteza suprarrenal.', 'La TC forma parte del estudio diagnóstico en caso de haber una confirmación bioquímica.', 'La espironolactona está contraindicada en el manejo de esta patología.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 127, 'Sin clasificar', 'Entre las intervenciones sobre los factores de riesgo cardiovascular mostrados ¿cuál es la más rentable para reducir eventos coronarios en prevención secundaria?:', 'Abandono del tabaco.', 'Aumento de los niveles de lipoproteínas de alta densidad (colesterol HDL).', 'Control adecuado de la glucemia en pacientes diabéticos.', 'Aumento de la actividad física.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 128, 'Sin clasificar', 'Mujer de 75 años con antecedentes de insuficiencia cardiaca con fracción de eyección del 25 % que acude a revisión, encontrándose estable en clase funcional III de la NYHA. Tiene un desfibrilador cardioversor implantado. La medicación actual consiste en lisinopril, carvedilol y espironolactona en las dosis máximas toleradas. En la exploración física tiene TA 118/74 mmHg, FC 78 lpm. En la auscultación cardiaca se detecta un tercer tono, la auscultación pulmonar es normal y no presenta edemas. ¿Cuál de los siguientes es el paso más apropiado en su manejo?:', 'Añadir sacubitrilo/valsartan.', 'Añadir ivabradina.', 'Suspender el lisinopril e iniciar sacubitrilo/valsartan.', 'Suspender el carvedilol e iniciar ivabradina. 18 -', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 129, 'Sin clasificar', 'Varón de 65 años que acude a urgencias por aparición de lesiones moteadas cianóticas en los dedos de ambos pies. Antecedentes personales: tabaquismo, hipertensión arterial y dislipemia. Rx tórax: ensanchamiento mediastínico. Angio- TC tóraco-abdómino-pélvica: aneurisma de aorta torácica descendente de 7 cm de diámetro, distal a arteria subclavia izquierda y con trombo mural. De las siguientes, señale la opción correcta:', 'Está indicado el tratamiento con estatinas para estabilizar el trombo.', 'Es necesaria la realización de una aortografía diagnóstica urgente.', 'En la cirugía se sustituye el segmento aneurismático por una prótesis tubular con reimplante de los troncos supraaórticos.', 'Está indicado el implante de una endoprótesis torácica.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 130, 'Sin clasificar', 'Varón de 85 años en fibrilación auricular permanente que consulta por sufrir un dolor brusco y frialdad en el pie derecho desde hace 6 horas. En la exploración presenta cianosis plantar con déficit parcial de sensibilidad y movilidad. El pulso femoral es palpable, estando ausentes los pulsos poplíteo y distales de dicha extremidad. De las siguientes ¿cuál es la actitud terapéutica idónea?:', 'Desestimar la cirugía de revascularización, por el tiempo prolongado de isquemia.', 'Aplicar calor y avisar al cirujano vascular de guardia.', 'Tratamiento quirúrgico urgente mediante tromboembolectomía.', 'Tratamiento médico urgente con prostaglandinas intravenosas.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 131, 'Sin clasificar', 'Varón de 30 años, de complexión delgada, que durante un partido de baloncesto sufre un episodio de dolor torácico derecho agudo, acompañado de disnea de aparición brusca y respiración superficial por el que acude a urgencias. ¿Cuál de los siguientes signos exploratorios le parecería más probable encontrar en la auscultación pulmonar?:', 'Soplo tubárico y crepitantes en base derecha.', 'Disminución del murmullo vesicular en la base derecha, disminución de las vibraciones vocales y matidez a la percusión.', 'Disminución/abolición de las vibraciones vocales y timpanismo en la percusión en hemitorax derecho.', 'Roncus y sibilancias dispersas. - 1', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 132, 'Sin clasificar', 'Varón de 75 años con antecedentes de EPOC que acude a urgencias por disnea progresiva de varios días de evolución y disminución del nivel de conciencia. En la gasometría arterial respirando aire ambiente (FiO2 21%) se informan los siguientes valores: pH 7,25; pO2 45 mmHg; pCO2 70 mmHg; H2CO3 26 mmol/L; EB -0,1 mmol/L. Desde un punto de vista gasométrico presenta:', 'Insuficiencia respiratoria global con acidosis respiratoria.', 'Insuficiencia respiratoria global con acidosis metabólica.', 'Insuficiencia respiratoria parcial con acidosis metabólica.', 'Insuficiencia respiratoria parcial con alcalosis respiratoria.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 133, 'Sin clasificar', 'Mujer de 78 años que consulta por disnea, diagnosticándosele una exacerbación de su EPOC. Tras ser evaluada se decide administrar prednisona. ¿Cuál de las siguientes afirmaciones es correcta?:', 'En este caso es preferible administrar prednisona vía intravenosa ya que es más efectiva que la administración oral.', 'Una buena opción sería administrar prednisona 40 mg/día vía oral durante 5 días', 'La dosis de prednisona debe ser cómo mínimo 1 mg/kg de peso al día.', 'La prednisona debe pautarse de tal forma que la disminución de la dosis se realice de forma paulatina durante 10 días.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 134, 'Sin clasificar', 'Paciente de 71 años sin antecedentes cardiovasculares que consulta por ronquido crónico y apneas presenciadas durante el sueño. En la exploración destaca un índice de masa corporal de 31 kg/m2. El grado de somnolencia diurna evaluado con la escala de Epworth es de 5. Se realiza una poligrafía respiratoria que evidencia un índice de apnea/hipopnea de 15 por hora de registro, con una saturación media de oxígeno del 94 %. La primera intervención terapéutica indicada es:', 'Presión positiva continua en la vía aérea (CPAP).', 'Oxigenoterapia nocturna domiciliaria.', 'Presión positiva de doble nivel en la vía aérea.', 'Medidas higiénico-dietéticas generales. 19 -', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 135, 'Sin clasificar', 'Mujer de 66 años, no fumadora, con tos y disnea de un año de evolución. Se realiza TC torácica de alta resolución por sospecha de fibrosis pulmonar idiopática. ¿Cuál de los siguientes hallazgos radiológicos son típicos de esta entidad?:', 'Quistes de panal y patrón reticular con predominio basal.', 'Opacidades en vidrio deslustrado parcheadas o difusas, bilaterales y simétricas.', 'Consolidaciones múltiples, con distribución periférica en campos pulmonares inferiores.', 'Bronquiectasias por tracción y patrón nodulillar subpleural en bases pulmonares.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 136, 'Sin clasificar', 'Paciente de 65 años, no fumador, que refiere que trabajó en su juventud en industria relacionada con la uralita. Consulta por un cuadro de disnea progresiva, sin fiebre. En la radiografía de tórax se observan calcificaciones pleurales izquierdas y un engrosamiento pleural derecho de características nodulares, que se confirma en la TC de tórax, sin adenopatías mediastínicas, nódulos, ni masas pulmonares o mediastínicas. Con respecto a la actitud a seguir con este paciente, señale la afirmación correcta:', 'La tomografía por emisión de positrones permite llegar al diagnóstico específico si se observa un gran hipermetabolismo a nivel pleural.', 'El diagnóstico más probable es el de carcinoma broncogénico, por lo que deberá realizarse, en primer lugar, una fibrobroncoscopia diagnóstica.', 'La primera maniobra diagnóstica debe ser una toracocentesis. En caso de que no se consiga un diagnóstico etiológico, debe plantearse una toracoscopia diagnóstica para toma de una biopsia pleural.', 'Al tratarse de un derrame pleural atípico, debe descartarse una causa infecciosa, por lo que deberá realizase una toracocentesis con análisis bioquímico y cultivo para indicar un posible drenaje pleural. - 2', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 137, 'Sin clasificar', 'Paciente de 55 años con cirrosis hepática alcohólica, abstinente, sin datos de hipertensión portal. Análisis: AST 34 U/L (normal < 37 U/L); ALT 19 U/L (normal < 41 U/L); bilirrubina total 0,78 mg/dl (normal < 1 mg/dl); alfafetoproteína 7 ng/ml (normal < 10 ng/ml). Se realiza una ecografía hepática que detecta una lesión ocupante de espacio hipoecogénica de 1,5 cm de diámetro. La resonancia magnética muestra una lesión con captación en fase arterial y lavado en fase venosa. ¿Qué actitud de las siguientes es más correcta?:', 'Realizar biopsia del nódulo, ya que el tamaño es inferior a 2 cm.', 'Repetir la ecografía a los 3 meses.', 'Indicar un trasplante hepático.', 'Solicitar estudio de extensión.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 138, 'Sin clasificar', 'Mujer de 27 años que consulta por disfagia y odinofagia. En los últimos meses nota sensación de dificultad al tragar, más con líquidos que con sólidos, dolor centrotorácico, algún vómito aislado, sin esfuerzo y más parecido a una regurgitación. No refiere pérdida de peso ni de apetito. Exploración física normal. Analítica completa dentro de la normalidad. Endoscopia oral sin alteraciones estructurales ni lesiones mucosas. Manometría esofágica de alta resolución: actividad vigorosa y ausencia de peristalsis en el cuerpo esofágico con relajación normal del esfínter esofágico inferior. El diagnóstico más probable es:', 'Espasmo esofágico distal.', 'Esófago hipercontráctil.', 'Acalasia tipo I.', 'Peristalsis fragmentada.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 139, 'Sin clasificar', 'Mujer de 69 años que acude a urgencias por un cuadro de vómitos, estreñimiento, retortijones y distensión abdominal. En la exploración se observa abdomen distendido, sin dolor a la palpación, con ruidos intestinales metálicos. En la radiografía simple de abdomen en bipedestación se observan múltiples niveles hidroaéreos y aerobilia. De los siguientes, el diagnóstico más probable es:', 'Colecistitis enfisematosa.', 'Fitobezoar.', 'Íleo biliar.', 'Colitis isquémica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 140, 'Sin clasificar', 'Con relación a la clasificación de las heridas quirúrgicas en función de la magnitud de la carga bacteriana estimada, una enterotomía durante una obstrucción intestinal se clasifica como:', 'Herida sucia (clase IV).', 'Herida contaminada (clase III).', 'Herida limpia/contaminada (clase II).', 'Herida limpia (clase I). 20 -', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 141, 'Sin clasificar', 'Varón de 18 años que fue intervenido hace 10 días de una apendicitis gangrenosa por laparoscopia con peritonitis localizada pélvica. Acude a urgencias por un síndrome febril en agujas, distensión abdominal y deposiciones diarreicas de 48 h de evolución. ¿Cuál de los siguientes diagnósticos es más probable?:', 'Absceso en fondo de saco de Douglas.', 'Infección de la herida quirúrgica.', 'Infección urinaria complicada.', 'Absceso hepático.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 142, 'Sin clasificar', 'Un paciente con bocio tóxico difuso (enfermedad de Graves) que rechace tratamiento con yodo radioactivo y que presente oftalmopatía grave debe someterse a:', 'Lobectomía tiroidea.', 'Tiroidectomía total.', 'Tiroidectomía subtotal.', 'Enucleación del nódulo principal.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 143, 'Sin clasificar', 'Mujer de 51 años que consulta, tras varios episodios de diverticulitis sigmoidea leve tratados de forma conservadora, por presentar ahora estreñimiento pertinaz que mejora con el uso de laxantes. En ocasiones presenta dolor abdominal tipo retortijón que mejora con la expulsión de heces y gases. Se practica colonoscopia encontrándose una estenosis sigmoidea que impide el paso del colonoscopio. Se toma muestra para estudio anatomopatológico que no es concluyente. En el enema opaco se encuentra una estenosis sigmoidea de unos 5 cm de longitud. La actitud terapéutica más adecuada sería:', 'Sigmoidectomía laparoscópica.', 'Tratamiento conservador con fibra dietética y rifaximina.', 'Dilatación endoscópica.', 'Stent en zona de estenosis.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 144, 'Sin clasificar', '¿Cuál es el objetivo principal del tratamiento adyuvante del cáncer de mama?:', 'Incremento de la supervivencia global.', 'Transformar tumores no resecables en resecables para la cirugía.', 'Aumentar la supervivencia libre de progresión.', 'Mejorar el control de síntomas.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 145, 'Sin clasificar', '¿Cuál de las siguientes vacunas NO está recomendada previamente a una esplenectomía electiva en un adulto?:', 'Vacuna antineumococo PPV 23.', 'Vacuna antihaemophilus influenza B.', 'Vacuna antimeningocócica C.', 'Vacuna antitetánica. - 2', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 146, 'Sin clasificar', 'Mujer de 40 años, sin antecedentes personales ni familiares de interés, que presenta diarrea de varios días de evolución de carácter acuoso, muy abundante, acompañada de pérdida de 10 kg de peso, rubor y enrojecimiento facial, junto a lipotimias y dolor abdominal cólico y que en los datos de laboratorio presenta hipopotasemia. En ecografía abdominal se encuentra masa de 1,5 cm de diámetro en cola pancreática. De entre las siguientes, su sospecha diagnóstica primaria es:', 'Insulinoma.', 'PPoma.', 'VIPoma.', 'Glucagonoma.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 148, 'Sin clasificar', 'Paciente de 48 años remitido a consulta de nefrología por un filtrado glomerular estimado (FGe) de 32 ml/min/1,72 m2. ¿Cuál de los siguientes datos NO orientaría a pensar en una enfermedad renal crónica?:', 'Riñones de pequeño tamaño.', 'Antecedentes familiares de nefropatía.', 'Niveles elevados de fósforo en sangre.', 'Buena diferenciación ecográfica de corteza y médula renales.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 149, 'Sin clasificar', 'Mujer de 67 años con enfermedad renal crónica secundaria a nefropatía diabética. En la actualidad presenta una creatinina de 3,2 mg/dl con filtrado glomerular estimado (CKD-EPI) 14 ml/min. ¿Cuál de las siguientes afirmaciones es cierta?:', 'Presenta una enfermedad renal crónica estadio 3 y debe iniciar quelantes del fósforo.', 'Presenta una enfermedad renal crónica estadio 5 y debe considerarse el tratamiento renal sustitutivo.', 'Un buen control glucémico puede revertir la insuficiencia renal.', 'Es poco probable que presente una proteinuria superior a 500 mg/24h. 21 -', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 150, 'Sin clasificar', 'Mujer de 47 años que consulta por síndrome miccional. Se le diagnostica de infección urinaria no complicada y se le trata con ciprofloxacino durante 5 días. A la semana vuelve a consultar por mal estado general, artralgias y aparición de un rash cutáneo. En la analítica destaca un filtrado glomerular de 45 ml/min (CKD- EPI), siendo el de hace 6 meses de 100 ml/min. En el sedimento se identifican leucocitos, siendo negativo para nitritos. ¿De las siguientes, cuál es la causa más probable de su insuficiencia renal?:', 'Glomerulonefritis postinfecciosa.', 'Nefrotoxicidad por ciprofloxacino.', 'Pielonefritis aguda.', 'Nefritis intersticial aguda.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 151, 'Sin clasificar', 'Varón de 22 años que acude a urgencias por presentar orina "casi negra" desde hace 12 horas. No tiene antecedentes de interés ni toma medicamentos. Refiere un cuadro catarral de vías altas desde hace 4-5 días para el que ha tomado paracetamol. Exploración: temperatura 37,3 ºC, PA 150/95, FC 85 lpm, ligero eritema faríngeo, resto normal. En analítica destaca: Hb 12,8 g/dl, Hcto 39 %, leucocitos 10.500 /mm3 con fórmula normal, plaquetas 250.000 /mm3, coagulación normal, urea 25 mg/dl, creatinina 0,8 mg/dl, iones, perfil hepático, lipídico, albúmina y proteínas totales normales. Estudio de autoinmunidad normal y serología vírica negativa. Orina de 24 h con proteinuria de 0,75 g/24h, sedimento con 10 eritrocitos por campo (90 % dismórficos), no leucocituria. Ecografía renal normal. ¿Qué diagnóstico le parece más probable?:', 'Nefropatía por cambios mínimos.', 'Glomerulonefritis post-infecciosa.', 'Nefropatía IgA.', 'Nefritis intersticial aguda.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 152, 'Sin clasificar', 'Varón de 24 años que presenta microhematuria dismórfica, proteinuria de 3 g/24 h, FGe (CKD- EPI) 85 ml/min e hipoacusia neurosensorial. Refiere que su abuela materna precisó diálisis a los 70 años y tanto su madre como su hermana pequeña presentan microhematuria aislada. ¿Cuál de las siguientes enfermedades es más probable?:', 'Síndrome de Alport.', 'Nefropatía IgA.', 'Enfermedad de Fabry.', 'Poliquistosis renal autosómica dominante. - 2', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 153, 'Sin clasificar', 'Varón de 19 años sin antecedentes de interés que acude a urgencias porque después de una infección respiratoria presenta astenia, malestar general, oliguria y cefalea. Exploración física: TA 210/120 mmHg, fondo de ojo con retinopatía hipertensiva grado III. Analítica: Hb 7,4 g/dl, plaquetas 85.000/mm3, 2-3 esquistocitos en la extensión de sangre periférica, LDH 950 UI/ml, creatinina sérica 8,75 mg/dl. Sistemático de orina: proteinuria 300 mg/dl, sedimento 15 hematíes por campo. Niveles de ADAMTS-13 normales. Ante estos hallazgos ¿cuál sería su principal sospecha diagnóstica?:', 'Púrpura trombótica trombocitopénica.', 'Síndrome hemolítico urémico atípico.', 'Coagulación intravascular diseminada.', 'Síndrome hemolítico urémico típico.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 154, 'Sin clasificar', 'En cuanto a la obstrucción del flujo urinario, señale la respuesta FALSA:', 'La intensidad del dolor es independiente de la velocidad con la que ocurre la distensión.', 'Son sitios frecuentes de obstrucción las uniones pieloureteral y ureterovesical, el cuello vesical y el meato uretral.', 'Los recursos diagnósticos para identificar la obstrucción anatómica incluyen la flujometría.', 'La obstrucción del flujo urinario aumenta la presión hidrostática proximal al sitio de oclusión, causando dolor, distensión del sistema colector renal y aumento de la presión intratubular.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 155, 'Sin clasificar', '¿Cuál de las siguientes es la complicación metabólica más frecuente en el cáncer?:', 'Hiponatremia.', 'Hiperuricemia.', 'Hiperfosfatemia.', 'Hipercalcemia.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 156, 'Sin clasificar', 'En relación con la compresión medular secundaria a infiltración neoplásica de la médula espinal en pacientes con cáncer, señale la respuesta INCORRECTA:', 'La laminectomía quirúrgica y la radioterapia, sola o complementaria a la cirugía, consiguen una recuperación neurológica inferior al 20 %.', 'El tratamiento precoz con corticoides reduce el edema vasogénico y limita la progresión de la lesión medular.', 'Los síntomas más frecuentes son la paraparesia y la reducción de la sensibilidad distal al segmento medular comprimido.', 'La resonancia magnética es la prueba diagnóstica de elección para la confirmación diagnóstica y la identificación del nivel de compresión. 22 -', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 157, 'Sin clasificar', '¿Cuál es la mejor combinación de tratamientos oncológicos en un paciente con el diagnóstico de carcinoma adenoide quístico de paladar duro T4N0M0?:', 'Radioquimioterapia concomitante como primera opción terapéutica.', 'Cirugía de la lesión seguida de radioterapia adyuvante sobre el lecho quirúrgico.', 'Radioterapia y posterior cirugía en ausencia de respuesta completa.', 'Es un tumor benigno y por tanto no precisa de tratamientos oncológicos complementarios.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 158, 'Sin clasificar', 'Señale el tumor en el que la braquiterapia NO es una alternativa efectiva de tratamiento:', 'Adenocarcinoma de endometrio estadio I-B grado 2.', 'Carcinoma ductal infiltrante de mama tras intervención quirúrgica del lecho tumoral con margen cercano.', 'Glioblastoma multiforme resecado parcialmente.', 'Adenocarcinoma de próstata T1N0M0 Gleason 6.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 159, 'Sin clasificar', 'Además de las posibles complicaciones hemorrágicas ¿qué otro efecto adverso del tratamiento parenteral con heparina puede ser grave y comprometer la vida del paciente?:', 'Hipopotasemia extrema.', 'Trastornos gastrointestinales con diarrea abundante y deshidratación.', 'Alcalosis metabólica por toxicidad tubular renal.', 'Trombopenia grave acompañada de fenómenos trombóticos venosos o arteriales.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 160, 'Sin clasificar', 'Mujer de 35 años, que toma anticonceptivos, acude a urgencias con síndrome febril y parestesias en hemicuerpo izquierdo. En la analítica de sangre se observa Hb 7,5 g/dl, plaquetas 7.000/microl, leucocitos normales con recuento diferencial normal, LDH 1.200 UI/l, reticulocitos 10 % (normal 0,5-2 %), haptoglobina en suero indetectable, test de Coombs directo negativo y frotis de sangre periférica con esquistocitos. Coagulación (tiempo de protrombina y APTT) normal. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Anemia hemolítica autoinmune.', 'Púrpura trombótica trombocitopénica.', 'Síndrome de Evans (anemia hemolítica y trombopenia inmunes).', 'Trombocitopenia inmune idiopática. - 2', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 161, 'Sin clasificar', 'En el diagnóstico de un proceso linfoproliferativo es fundamental el estudio molecular y del inmunofenotipo. La detección de la translocación 11:14 con afectación de la ciclina D1 es característica de un:', 'Linfoma folicular.', 'Linfoma de la zona marginal.', 'Linfoma linfoblástico.', 'Linfoma del manto.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 162, 'Sin clasificar', '¿Cuál de las siguientes escalas o instrumentos utilizados para valorar la condición de fragilidad en un paciente mayor se basa en el juicio clínico del observador y es, por tanto, la más subjetiva?:', 'El fenotipo de Fried.', 'La escala clínica de fragilidad (Clinical Frailty Scale).', 'SPPB (Short Physical Performance Battery).', 'Timed Up & Go.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 163, 'Sin clasificar', 'Referente a la sarcopenia, es cierto que:', 'Es un síndrome geriátrico que aparece exclusivamente en pacientes de edad avanzada.', 'Se caracteriza por pérdida de la masa y la fuerza de la musculatura esquelética.', 'Es sinónimo de fragilidad.', 'Se trata con medicamentos que aumentan la masa muscular.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 164, 'Sin clasificar', 'Varón de 78 años con hiperplasia benigna de próstata en tratamiento con finasterida y tamsulosina, independiente para las actividades básicas e instrumentales de la vida diaria y sin deterioro cognitivo. Presenta un creciente número de episodios de escapes de orina involuntarios con sensación de urgencia miccional (actualmente presenta 4-5 escapes durante el día). El sedimento de orina es normal. Tiene un residuo de orina post-miccional de 60 cc. ¿Cuál de las siguientes medidas es la más adecuada?:', 'Iniciar tratamiento con oxibutinina.', 'Colocar una sonda urinaria.', 'Retirar el tratamiento con finasterida.', 'Iniciar medidas higiénicas miccionales con terapia conductual vesical. 23 -', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 165, 'Sin clasificar', 'Mujer de 88 años que presenta episodio de desorientación en espacio y tiempo, inquietud y alteración del nivel de conciencia fluctuante al regresar a casa tras ser dada alta del hospital, tras un ingreso por fractura de cadera. Entre sus antecedentes destacan HTA, hipoacusia leve, deterioro cognitivo leve y osteoporosis. Antes de la fractura era independiente para todas las actividades básicas de la vida diaria, y tras la cirugía ha iniciado la deambulación con andador y las transferencias las realiza con ayuda de una persona. ¿Cuál es el manejo inicial más adecuado del cuadro que presenta?:', 'Valoración del dolor y descartar una impactación fecal.', 'Iniciar haloperidol.', 'Iniciar diazepam.', 'Recomendar reposo en cama y sujeción mecánica para que no se autolesione.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 166, 'Sin clasificar', 'Mujer de 88 años de edad que consulta por caídas frecuentes, deterioro del estado general, hiporexia e insomnio. Como antecedentes presenta deterioro cognitivo moderado, diabetes mellitus tipo 2 con última hemoglobina glicosilada de 8 %, hipertensión arterial, hipercolesterolemia con LDL de 121 mg/dl y enfermedad renal crónica con un filtrado glomerular de 42 mL/m. En tratamiento con sulfonilureas, simvastatina, benzodiacepinas y valsartan/amlodipino. Indique la actuación más correcta:', 'Habría que intensificar el tratamiento de la diabetes para reducir la hemoglobina glicada.', 'La hipercolesterolemia está mal controlada, por lo que añadiría ezetimiba.', 'Revisaría el tratamiento farmacológico para realizar una desprescripción priorizando fármacos imprescindibles.', 'Aumentaría la dosis de benzodiacepinas para control del insomnio.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 167, 'Sin clasificar', 'Uno de los siguientes componentes NO se considera clave para conseguir la eficacia de los programas de valoración geriátrica integral:', 'Liderazgo clínico.', 'Uso de escalas e instrumentos estandarizados.', 'Plan por objetivos con trabajo en equipo interdisciplinar.', 'Intervención intensa de forma temporal. - 2', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 168, 'Sin clasificar', 'Varón de 58 años, obeso, asintomático, bebedor moderado, que presenta una primera glucemia basal de 153 mg/d con glucosuria negativa. En las semanas siguientes ha tenido otras dos cifras de glucemias basales de 118 y 136 mg/dl. ¿Cuál de las siguientes es la actitud más apropiada para confirmar el diagnóstico de diabetes mellitus?:', 'Practicar una curva de glucemia con 75 g de glucosa.', 'Reúne ya criterios diagnósticos de diabetes mellitus.', 'Solicitar una determinación de insulinemia basal o péptido C.', 'Solicitar una determinación de hemoglobina glicosilada.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 169, 'Sin clasificar', '¿Cuál de las siguientes neoplasias NO suele asociarse con un síndrome de neoplasia endocrina múltiple tipo MEN-1?:', 'Adenoma de hipófisis.', 'Feocromocitoma.', 'Insulinoma.', 'Glucagonoma.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 170, 'Sin clasificar', 'Mujer de 75 años en tratamiento con sertralina que acude a urgencias por un cuadro confusional. No se evidencian edemas y la tensión arterial es de 130/70 mmHg. En la analítica destaca Na 126 mEq/l y K 4 mEq/l, la natriuria es de 45 mEq/l y se ha descartado la ingesta de diuréticos. ¿De las siguientes cuál es la actitud más correcta?:', 'Se trata de una enfermedad de Addison y deben administrarse corticoides de inmediato.', 'Administrar suero salino hipertónico a fin de restablecer cuanto antes la natremia.', 'Indicar restricción hídrica y si no se eleva la natremia pasar a infusión lenta de suero salino.', 'Solicitar resonancia magnética cerebral, ya que seguramente se trata de una diabetes insípida.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 171, 'Sin clasificar', 'Mujer de 38 años que consulta por astenia e hipotensión de seis meses de evolución. Después de una evaluación extensa, en la analítica únicamente destaca cortisol 8 microg/dl (5-25 microg/dl) y ACTH de 240 pg/ml (10-60 pg/ml). ¿Cuál de las siguientes afirmaciones es cierta?:', 'Debe solicitarse test de estimulación con ACTH con la sospecha de insuficiencia suprarrenal primaria.', 'Se trata de un síndrome de resistencia a la ACTH y debe solicitarse consejo genético.', 'Debe descartarse tumor hipofisario secretor de ACTH.', 'Se trata de una secreción ectópica de ACTH y debe buscarse una neoplasia. 24 -', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 172, 'Sin clasificar', 'En el síndrome de Klinefelter, ¿cuál de las siguientes afirmaciones es correcta?:', 'El tratamiento con testosterona potencia la fertilidad.', 'Los niveles de gonadotrofinas están disminuidos en la mayoría de los pacientes.', 'El cariotipo X0 subyace en la mayoría de los casos.', 'La incidencia de lupus eritematoso es mayor que en los varones de la población general.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 173, 'Sin clasificar', 'Mujer de 37 años, diagnosticada hace tres meses de enfermedad de Graves, en tratamiento con metimazol y propranolol, que consulta por fiebre y deglución dolorosa. En la exploración física tiene temperatura 38,7ºC y la orofaringe está eritematosa, sin exudados. ¿Cuál de los siguientes es el manejo más adecuado?:', 'Iniciar un tratamiento empírico con penicilina V oral.', 'Obtener una prueba rápida de detección de antígenos para el estreptococo del grupo A.', 'Interrumpir el propranolol y obtener un cultivo de orofaringe.', 'Interrumpir el metimazol y obtener un hemograma con recuento diferencial.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 174, 'Sin clasificar', '¿Cuál de los siguientes hallazgos semiológicos en un paciente con herpes zóster NO indica una especial gravedad?:', 'Presencia de vesículas en el conducto auditivo externo.', 'Afectación multimetamérica.', 'Afectación del ala nasal.', 'Lesiones cutáneas en distintas fases evolutivas.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 175, 'Sin clasificar', 'Paciente de 62 años que consulta por haber estado en contacto cercano en las últimas semanas con una persona con una tuberculosis activa. El Mantoux es positivo (12 mm). Entre sus antecedentes destaca estar en tratamiento con anticoagulantes orales (acenocumarol) por una trombosis venosa profunda hace unos meses. No refiere fiebre ni tos y se encuentra asintomático. La Rx de tórax es normal. ¿Cuál de los siguientes tratamientos es el más recomendable?:', 'Isoniacida, durante nueve meses.', 'Rifampicina, durante cuatro meses.', 'Isoniacida y rifampicina, durante tres meses.', 'Isoniacida y rifapentina, durante tres meses. - 2', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 177, 'Sin clasificar', 'Paciente de 33 años, residente en Valencia, que consulta por presentar en la mejilla derecha una placa eritemato-anaranjada tras picadura de insecto que ha ido creciendo lentamente hasta alcanzar 1,5 cm y que en las últimas semanas se ha ulcerado y cubierto de una escamocostra. La lesión solo le origina discretas molestias si se rasca. Entre sus antecedentes destaca psoriasis en placas en tratamiento con adalimumab subcutáneo. Tiene buen estado general y no toma otros fármacos ni refiere alergias a medicamentos. Indique el tratamiento que emplearía:', 'Isotretinoina oral.', 'Antimoniato de meglumina intralesional.', 'Corticoesteroides sistémicos.', 'Amoxicilina oral.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 178, 'Sin clasificar', 'Varón de 48 años que acude a su consulta por estreñimiento crónico resistente a medidas habituales. Además, refiere palpitaciones y en las últimas semanas disnea de medianos esfuerzos. Señale, de las posibilidades que se ofrecen, cual le orientaría más para sospechar un diagnóstico etiológico específico:', 'Realizar un ECG.', 'Realizar un enema opaco.', 'Realizar un ecocardiograma.', 'Preguntar por el país de procedencia. 25 -', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 179, 'Sin clasificar', 'Paciente de 54 años con antecedentes de alcoholismo crónico y deficientes condiciones de vivienda e higiene. Refiere un cuadro clínico de dos semanas de duración de astenia, febrícula y sudoración nocturna. En la Rx y la TC de tórax se observa una lesión única, cavitada, en el segmento superior del lóbulo inferior derecho, de 4 cm de diámetro, con un nivel hidroaéreo. El estudio microbiológico del esputo es negativo. Decide comenzar con un tratamiento antibiótico empírico. Indique cuál de los siguientes sería el tratamiento MENOS eficaz:', 'Metronidazol IV.', 'Clindamicina IV.', 'La asociación de un betalactámico y betalactamasa IV.', 'Moxifloxacino oral.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 180, 'Sin clasificar', 'Mujer de 26 años diagnosticada de lupus eritematoso sistémico, en tratamiento con hidroxicloroquina, que consulta por sensación de debilidad generalizada que se ha instaurado progresivamente en los últimos 15 días. En la exploración física se aprecia palidez cutánea y en la analítica destaca Hb 7,4 gr/dL, Hcto 31 %, VCM 108. ¿Cuál de las siguientes determinaciones será más útil para decidir la actuación?:', 'Haptoglobina.', 'Test de Coombs.', 'Vitamina B12.', 'Anticuerpos antinucleares.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 181, 'Sin clasificar', 'Varón de 67 años que presenta un cuadro de 3 meses de duración de astenia y febrícula, a la que se añade en el último mes obstrucción nasal con emisión de moco con algunos coágulos. En los últimos días nota dolor en el ojo derecho y asimetría respecto al contralateral. En la exploración física se objetiva proptosis del globo ocular derecho y la inspección de las fosas nasales constata una mucosa eritematosa con costras serohemáticas. El resto de la exploración es normal. Los análisis de sangre (hemograma, función renal y hepática) son normales, a excepción de una VSG de 65 mm/h; en el análisis de orina se detecta microhematuria y proteinuria de 520 mg/24h. ¿Cuál es el diagnóstico inicial más probable?:', 'Granulomatosis eosinofílica con poliangitis.', 'Poliangitis microscópica.', 'Granulomatosis con poliangitis.', 'Poliarteritis nudosa.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 182, 'Sin clasificar', 'En el síndrome de Sjögren, uno de los factores pronósticos asociados a una peor evolución es:', 'Poliartritis de grandes y pequeñas articulaciones.', 'Fenómeno de Raynaud.', 'Hepatoesplenomegalia.', 'Crioglobulinemia. - 2', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 183, 'Sin clasificar', 'Mujer de 45 años sin antecedentes de interés que consulta por presentar sensación disneica de unos 4 días de evolución. La exploración muestra taquicardia rítmica, sin soplos y la auscultación pulmonar es normal. La gasometría arterial muestra una pO2 de 70 mmHg y una pCO2 32 mmHg. El hemograma, la función renal y hepática son normales. Tiempo de protrombina 90 %, tiempo de tromboplastina parcial activada (TTPA) con ratio de 2 respecto al control (N <1,2). ¿De los siguientes diagnósticos cuál es el más probable?:', 'Síndrome antifosfolípido.', 'Factor V de Leiden.', 'Hemofilia.', 'Pericarditis aguda.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 184, 'Sin clasificar', 'Mujer de 70 años que refiere desde hace 1 mes dolor y rigidez en cinturas escapular y pelviana, que predomina al levantarse y mejora con la movilización, sin fiebre, cefalea ni afectación del estado general. En la exploración física se observa rigidez y dolor a la movilización de hombros y caderas. La analítica muestra una elevación de la VSG y la proteína C reactiva. ¿Qué diagnóstico es más probable y qué tratamiento prescribiría?:', 'Artritis reumatoide, iniciaría tratamiento con metotrexato.', 'Fibromialgia, iniciaría tratamiento con duloxetina.', 'Polimialgia reumática, iniciaría tratamiento con corticoides.', 'Espondilitis anquilosante, iniciaría tratamiento con antiinflamatorios no esteroideos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2021, 185, 'Sin clasificar', 'La interconsulta médica en pacientes hospitalizados constituye una actividad habitual entre los especialistas de medicina interna/geriatría, en especial en los servicios quirúrgicos. Indique cuál de las siguientes características NO corresponde al modelo asistencial de interconsulta denominado asistencia compartida:', 'Responsabilidad compartida.', 'Atención a demanda.', 'Atención integral y global.', 'Comunicación fluida entre médicos.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 1, 'Sin clasificar', 'Pregunta asociada a la imagen 1. Varón de 45 años que, tras un cuadro de dos días de hiporexia, astenia leve, sensación distérmica y cefalea holocraneal, sin nauseas ni vómitos, acude a urgencias por inestabilidad en la marcha. Refiere otorrea fluctuante en oído izquierdo desde la infancia. Exploración neurológica: pares craneales normales, marcha con lateropulsión izquierda, ligera dismetría dedo-nariz con mano izquierda, Glasgow 15. En la otoscopia se observa otorrea purulenta y perforación timpánica con epitelio a nivel atical. En la analítica destaca leucocitos 12,8 x10^9/L; 81 % neutrófilos. Se muestra imagen de TC craneal. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Vértigo periférico por laberintitis difusa purulenta.', 'Meningitis otógena izquierda.', 'Síndrome cerebeloso por absceso intraparenquimatoso otógeno izquierdo.', 'Trombosis de seno lateral por otitis media crónica colesteatomatosa izquierda.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 2, 'Sin clasificar', 'Pregunta asociada a la imagen 2. Paciente de 80 años, con dislipemia, sin otros factores de riesgo vascular conocidos, con un cuadro de deterioro cognitivo de un año de evolución quien de manera brusca el día del ingreso presenta una hemiparesia derecha. Se activa código ictus y se traslada a su hospital de referencia, donde a su llegada se objetiva exploración neurológica con debilidad faciobraquiocrural derecha (escala NIHSS 8) y se realiza TC craneal que se muestra en la imagen. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Infarto cerebral secundario a consumo de drogas tipo cocaína.', 'Hemorragia intraparenquimatosa profunda asociada a hipertensión no diagnosticada.', 'Hemorragia parietal lobar izquierda asociada a una posible angiopatia amiloide.', 'Hemorragia intraparenquimatosa asociada a una hemorragia subaracnoidea, por un posible traumatismo craneoencefálico.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 3, 'Sin clasificar', 'Pregunta asociada a la imagen 3. Mujer de 78 años, sin antecedentes médicos de interés, que presenta la fractura-luxación de húmero proximal mostrada en la imagen. ¿Cuál es el tratamiento más recomendable?:', 'Clavo trocantérico largo acerrojado proximal y distal.', 'Rehabilitación intensiva inmediata sin inmovilización.', 'Inmovilización con yeso braquial colgante de Caldwell.', 'Artroplastia glenohumeral.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 4, 'Sin clasificar', 'Pregunta asociada a la imagen 4. Mujer de 51 años con antecedentes de diabetes mellitus tipo I e hipertensión arterial de larga evolución. En tratamiento sustitutivo renal mediante hemodiálisis desde hace 14 años como consecuencia de una enfermedad renal crónica estadio 5. Durante una de las sesiones de diálisis refiere dolor centrotorácico y disnea de aparición súbita. Las constantes hemodinámicas son normales. Se pauta nitroglicerina intravenosa para la corrección del dolor torácico, que cede en unos quince minutos. Se muestran los electrocardiogramas realizados con y sin dolor torácico. No hubo elevación posterior de enzimas de necrosis miocárdica. ¿Cuál es el diagnóstico de sospecha y la actitud a seguir?:', 'Síndrome coronario agudo sin elevación del segmento ST, de alto riesgo. Debe ingresar en una unidad con vigilancia electrocardiográfica continua con recomendación de coronariografía temprana (≤48 h).', 'Síndrome coronario agudo sin elevación del segmento ST, de riesgo moderado. Debe ingresar en una unidad con vigilancia electrocardiográfica continua, con recomendación inicial de coronariografía diferida (>48 h).', 'Síndrome coronario agudo sin elevación del segmento ST, de bajo riesgo. Debe ingresar en planta de hospitalización convencional con recomendación de prueba de inducción de isquemia antes del alta hospitalaria y coronariografía diferida según resultado.', 'Los cambios electrocardiográficos no son diagnósticos de síndrome coronario agudo y se consideran secundarios a la hemodiálisis. No precisa ingreso hospitalario.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 5, 'Sin clasificar', 'Pregunta asociada a la imagen 5. Varón de 57 años, sin factores de riesgo cardiovascular conocidos, que acude a su consulta aquejando disnea de esfuerzo estable de varios meses de evolución. Aporta electrocardiograma de 12 derivaciones (imagen) y en la exploración física se ausculta un soplo sistólico en borde paraesternal izquierdo, cuya intensidad y duración aumentan durante la maniobra de Valsalva. De entre las siguientes patologías cardiacas ¿cuál es el diagnóstico más probable?:', 'Insuficiencia tricuspídea.', 'Estenosis aórtica.', 'Miocardiopatía hipertrófica.', 'Insuficiencia mitral.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 6, 'Sin clasificar', 'Pregunta asociada a la imagen 6. Varón de 39 años, fumador de 20 cigarrillos al día, con antecedentes de un infarto agudo de miocardio inferior a los 38 años. En el cateterismo se observó una lesión en la coronaria derecha proximal y se implantó un stent fármacoactivo. La FEVI era normal. Está en tratamiento con atorvastatina 80 mg/día, ácido acetilsalicílico 100 mg/día y bisoprolol 2,5 mg/día. Realiza dieta adecuada y ejercicio y está asintomático desde el punto de vista cardiovascular. Aporta analítica con lipoproteína (a) 380 nmol/L (valor normal hasta 125 nmol/L), colesterol total 238 mg/dL, HDL 45 mg/dL, LDL 132 mg/dL y TG 142 mg/dL. En la exploración física se observa el siguiente hallazgo (ver imagen). Además de insistirle en que deje de fumar ¿cuál de las siguientes recomendaciones es más adecuada?:', 'Para llegar a los objetivos de tratamiento de la dislipemia, añadir ezetimiba.', 'Añadir un inhibidor de la PCSK9 y solicitar un test genético de hipercolesterolemia familiar.', 'Enviarle al oftalmólogo para descartar una enfermedad de Wilson.', 'Añadir niacina para disminuir la lipoproteína (a).', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 7, 'Sin clasificar', 'Pregunta asociada a la imagen 7. Varón de 60 años, fumador activo, que presenta tos y expectoración diaria de años de evolución, ocasionalmente hemoptoica. En los últimos meses se añade disnea progresiva. Presenta acropaquia y en la auscultación pulmonar destacan roncus y sibilantes teleinspiratorios en pulmón izquierdo. La TC pulmonar de alta resolución se muestra en la imagen adjunta. ¿Cuál es el diagnóstico más probable?:', 'Carcinoma quístico.', 'Enfisema pulmonar.', 'Tuberculosis cavitada.', 'Bronquiectasias.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 8, 'Sin clasificar', 'Pregunta asociada a la imagen 8. Mujer de 82 años que acude a urgencias por un cuadro de dolor abdominal localizado en flanco derecho, irradiado a espalda y febrícula de 37,3 ºC. Se realiza ecografía abdominal que en hipocondrio derecho muestra los resultados de la imagen. ¿Cuál es el diagnóstico más probable?:', 'Colecistitis aguda.', 'Enfermedad de Caroli.', 'Vesícula en porcelana.', 'Cólico biliar.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 9, 'Sin clasificar', 'Pregunta asociada a la imagen 9. En relación con la patología que se observa en la imagen, es correcto que:', 'Su forma de debut más frecuente es un sangrado menstrual.', 'La citología no es útil en el diagnóstico pero sí en el seguimiento.', 'Es más frecuente en mujeres jóvenes.', 'Uno de los factores de riesgo más importantes es el tabaco.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 10, 'Sin clasificar', 'Pregunta asociada a la imagen 10. Varón de 38 años de origen centroafricano que presenta el siguiente frotis. Respecto a la enfermedad que sospecha, señale la respuesta correcta:', 'La esplenomegalia es un hallazgo frecuente en los cuadros de larga evolución.', 'Puede producir episodios dolorosos por crisis oclusivas vasculares.', 'Es debida a un defecto congénito en las proteínas de la membrana eritrocitaria.', 'En el examen del frotis sanguíneo se observa trombopenia y numerosos esquistocitos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 11, 'Sin clasificar', 'Pregunta asociada a la imagen 11. Varón de 32 años que está recibiendo profilaxis pre-exposición al VIH. Consulta por presentar desde hace dos días proctalgia intensa, afectación del estado general y fiebre. En la exploración se palpan adenopatías inguinales y se observan las lesiones cutáneas perianales que se muestran en la imagen. ¿Cuál es el diagnóstico más probable?:', 'Viruela del mono.', 'Herpes genital.', 'Sífilis primaria.', 'Lesiones por primoinfección por VIH.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 12, 'Sin clasificar', 'Pregunta asociada a la imagen 12. Varón de 54 años con antecedentes de asma bronquial. En una TC torácica de control se observan lesiones hepáticas calcificadas. Se completa el estudio con una TC abdominal donde se identifican 3 lesiones quísticas hepáticas. Se realiza enucleación de las 3 lesiones, que miden 8, 3 y 3 cm. En el estudio microscópico se observan membranas acelulares. Se muestra la macroscopia de una de las lesiones. ¿Cuál es el diagnóstico más probable?:', 'Hemangioma complicado.', 'Hepatocarcinoma calcificado.', 'Quiste hidatídico.', 'Metástasis hepática necrótica.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 13, 'Sin clasificar', 'Pregunta asociada a la imagen 13. Niña recién nacida pretérmino de 25 semanas con insuficiencia respiratoria grave en el postparto inmediato. Se inicia la reanimación, pero a los 30 minutos empeora y fallece. ¿Cuál es el diagnóstico histopatológico de la imagen?:', 'Aspiración de meconio.', 'Neumonía intraútero.', 'Malformación pulmonar.', 'Enfermedad de la membrana hialina.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 14, 'Sin clasificar', 'Pregunta asociada a la imagen 14. Ante estas imágenes del colon, con la mucosa desflecada y formaciones polipoides en la macroscopia y el estudio histopatológico que se muestra, el diagnóstico más probable es:', 'Enfermedad crónica inflamatoria intestinal tipo colitis ulcerosa.', 'Colitis infecciosa parasitaria.', 'Poliposis intestinal.', 'Linfoma intestinal.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 15, 'Sin clasificar', 'Pregunta asociada a la imagen 15. Mujer de 70 años con antecedente de oclusión intestinal por bezoar en 2019 y dilatación del colédoco y de la vía biliar intrahepática de causa desconocida. En una TC reciente se evidencia una lesión quística con áreas sólidas de 28 cm, localizada en la cabeza del páncreas, en conexión con el conducto de Wirsung sin condicionar dilatación del mismo. No hay signos de infiltración local ni metástasis a distancia. Se decide realizar una duodenopancreatectomía cefálica. Se muestra una imagen macroscópica y una imagen microscópica de la lesión. ¿Cuál es el diagnóstico más probable?:', 'Neoplasia mucinosa quística.', 'Neoplasia mucinosa papilar intraductal de rama secundaria.', 'Neoplasia sólida-pseudopapilar.', 'Neoplasia mucinosa papilar intraductal con componente invasivo de rama principal.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 16, 'Sin clasificar', 'Pregunta asociada a la imagen 16. Varón de 40 años diabético e hipertenso que acude por presentar desde hace 3 meses lesiones eritematosas descamativas en las palmas y las plantas de entre 0,5 y 2 cm, asintomáticas. No tiene otras lesiones en el momento actual. ¿Ante este cuadro clínico, cuál de estas entidades sería la MENOS PROBABLE?:', 'Psoriasis.', 'Liquen plano.', 'Sífilis.', 'Gonorrea.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 17, 'Sin clasificar', 'Pregunta asociada a la imagen 17. Mujer de 65 años que consulta porque en los últimos dos años ha ido notando pérdida del cabello en la línea anterior de implantación del cuero cabelludo (temporal y frontal), junto a la pérdida completa de las cejas. En la exploración de las mejillas y el mentón se aprecian pequeñas pápulas del color de la piel. Ante este cuadro clínico y la imagen que se muestra señale la respuesta correcta:', 'Se trata de una alopecia reversible.', 'Es más frecuente en hombres.', 'La histopatología es similar a la del liquen plano pilaris.', 'Es un tipo poco frecuente de alopecia androgénica.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 18, 'Sin clasificar', 'Pregunta asociada a la imagen 18. Varón de 66 años, fumador, que es diagnosticado de carcinoma epidermoide de pulmón por biopsia de un nódulo pulmonar de 1 cm. Se realiza estudio de extensión con PET-TC tras la administración de 18F-FDG cuyas imágenes se muestran en proyección de intensidad máxima (MIP), corte axial y corte coronal a nivel del nódulo. ¿Cuál es la estadificación más probable?:', 'T1N1M0.', 'T1N0M0.', 'T1N0M1.', 'T2N0M0.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 19, 'Sin clasificar', 'Pregunta asociada a la imagen 19. Varón de 13 años en estudio por tumoración dolorosa en costado izquierdo. En la TC de tórax se confirma una lesión en el arco anterior de la 5ª costilla izquierda con masa de partes blandas y datos radiológicos de agresividad. La analítica no muestra alteraciones significativas. Se realiza biopsia ecoguiada, compatible con un tumor costal maligno con perfil inmunohistoquímico congruente con sarcoma de Ewing. Se realiza una gammagrafía ósea para estudio de extensión cuya imagen se muestra. Señale la afirmación correcta:', 'Es una gammagrafía ósea normal.', 'No está indicada la gammagrafía ósea en el estudio de extensión, ya que el sarcoma de Ewing no desarrolla metástasis óseas.', 'Existe afectación ósea metastásica diseminada.', 'El único hallazgo anormal es el acúmulo patológico del radiotrazador en el tumor costal conocido.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 20, 'Sin clasificar', 'Pregunta asociada a la imagen 20. Mujer de 50 años con antecedentes de cáncer de mama libre de enfermedad, que refiere cefalea y alteraciones visuales de instauración progresiva, sin respuesta al tratamiento analgésico. Se le realiza la resonancia magnética que se muestra. ¿Cuál es el diagnóstico más probable?:', 'Glioblastoma multiforme.', 'Macroadenoma hipofisario.', 'Quiste aracnoideo.', 'Metástasis.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 21, 'Sin clasificar', 'Pregunta asociada a la imagen 21. Mujer de 26 años que desde hace 6 días presenta dolor en fosa iliaca derecha. La palpación es dolorosa en esa zona. La analítica muestra 17.000 leucocitos, con neutrófilos 88 %. Se muestra la TC de abdomen. ¿De los siguientes cuál es el diagnóstico más probable?:', 'Ooforitis.', 'Apendicitis.', 'Diverticulitis.', 'Absceso de ciego.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 22, 'Sin clasificar', 'Pregunta asociada a la imagen 22. Varón de 75 años con dolor abdominal intermitente, dispepsia y pérdida de peso. Se realiza TC abdominal con contraste de la que se muestra una imagen. Además de la observación casual de un quiste renal izquierdo ¿cuál de los siguientes hallazgo se encuentra?:', 'Tumoración en cola pancreática con calcificaciones e invasión tumoral de arteria esplénica.', 'Calcificaciones pancreáticas difusas en cuerpo y cola pancreática, indicativas de pancreatitis aguda.', 'Tumoración en cabeza pancreática con calcificaciones e invasión tumoral de arteria esplénica.', 'Calcificaciones pancreáticas difusas en cuerpo y cola pancreática, indicativas de pancreatitis crónica.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 23, 'Sin clasificar', 'Pregunta asociada a la imagen 23. Varón de 80 años, sin antecedentes de interés, que refiere dolor cervical progresivo e incapacitante que no cede con tratamiento analgésico. En la imagen de TC ¿cuál es el diagnóstico más probable y su posible origen?:', 'Espondilosis de origen degenerativo.', 'Espondilodiscitis de origen infeccioso.', 'Metástasis blásticas por un cáncer de próstata.', 'Metástasis líticas por un cáncer de pulmón.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 24, 'Sin clasificar', 'Pregunta asociada a la imagen 24. Mujer de 36 años sin antecedentes de interés que acude a urgencias por molestias retroesternales con la deglución, sin fiebre ni clínica infecciosa. Refiere un cuadro de años de evolución de episodios intermitentes de detención alimentaria a nivel retroesternal tras la ingesta de sólidos y líquidos. Se acompaña de pérdida de peso progresiva. La analítica sanguínea es normal. En la radiografía de tórax se observa ensanchamiento mediastínico, por lo que se realiza la TC torácica con contraste intravenoso que se muestra en la imagen. ¿Cuál es el diagnóstico más probable?:', 'Acalasia.', 'Gran divertículo esofágico de Zenker.', 'Espasmo esofágico difuso.', 'Retención alimentaria por tumor submucoso (leiomioma) obstructivo en tercio distal esofágico.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 25, 'Sin clasificar', 'Pregunta asociada a la imagen 25. Mujer de 58 años con un cuadro de meses de evolución de tos, odinofagia y carraspeo, que consulta por presentar esputos hemoptoicos. No refiere fiebre ni disnea. Exfumadora hace más de 30 años (fumó durante 10 años 1 paq/día). La analítica es normal. Se muestra la radiografía de tórax póstero-anterior. ¿Qué hallazgo se encuentra?:', 'Atelectasia de lóbulo inferior izquierdo.', 'Derrame pleural subpulmonar izquierdo.', 'Hernia de Bochdalek o defecto diafragmático posterior izquierdo.', 'Hiperinsuflación pulmonar derecha por bronquiectasias e impactos mucosos basales.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 26, 'Sin clasificar', 'En un paciente con síndrome nefrótico es posible encontrar una de las siguientes alteraciones plasmáticas en el perfil lipoproteico:', 'Disminución de las lipoproteínas de muy baja densidad (VLDL).', 'Aumento de la apolipoproteína B-100.', 'Aumento de la apolipoproteína A-I.', 'Aumento de la actividad lipoproteínlipasa (LPL).', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 27, 'Sin clasificar', 'En relación con el metabolismo de compuestos nitrogenados, el músculo esquelético es capaz de:', 'Sintetizar de forma limitada urea en situaciones de disfunción hepática para paliar la toxicidad del amoníaco.', 'Utilizar los alfa-cetoácidos derivados de los aminoácidos ramificados como fuente energética.', 'Producir alanina por transaminación a partir de piruvato y ácido aspártico, particularmente en determinadas situaciones de ayuno.', 'Elaborar creatina utilizando glicina, ATP y amoníaco para obtener creatin-fosfato como reserva energética y posibilitar su uso durante el ejercicio.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 28, 'Sin clasificar', 'En la glucogenosis de tipo Ia (enfermedad de von Gierke) por déficit de glucosa-6-fosfatasa es característico:', 'El aumento de glucógeno muscular.', 'La hipouricemia por reducción en la reabsorción renal de ácido úrico.', 'El aumento del lactato plasmático.', 'La disminución de la síntesis hepática de triglicéridos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 29, 'Sin clasificar', 'En relación con las presiones que originan el movimiento de entrada y salida de aire en los pulmones en una persona sana, señale la afirmación INCORRECTA:', 'La aspiración continua del exceso de líquidos hacia los conductos linfáticos mantiene una ligera presión negativa entre la superficie visceral del pulmón y la superficie pleural parietal de la cavidad torácica.', 'Durante la inspiración normal, la presión pleural se hace más negativa.', 'Durante la espiración normal, la presión alveolar disminuye con respecto al valor de la presión atmosférica.', 'La presión transpulmonar (presión alveolar menos presión pleural) tiende a colapsar los pulmones durante el ciclo respiratorio completo.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 30, 'Sin clasificar', 'El flujo sanguíneo turbulento tiende a aumentar en proporción directa a todos los siguientes factores EXCEPTO UNO. Señale cuál:', 'Viscosidad de la sangre.', 'Velocidad del flujo sanguíneo.', 'Diámetro del vaso sanguíneo.', 'Densidad de la sangre.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 31, 'Sin clasificar', 'En relación con la regulación del intercambio de líquido y del equilibrio osmótico entre los líquidos intracelular y extracelular en una situación fisiológica, señale la afirmación INCORRECTA:', 'La distribución del líquido entre los compartimentos intracelular y extracelular está determinada sobre todo por el efecto osmótico de los iones más pequeños.', 'Alrededor del 80 % de la osmolaridad total del líquido intersticial y del plasma se debe a los iones sodio y cloro.', 'Alrededor del 50 % de la osmolaridad en el líquido intracelular se debe a los iones calcio.', 'Cambios relativamente pequeños en la concentración de solutos no difusibles en el líquido extracelular pueden causar grandes cambios en el volumen celular.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 32, 'Sin clasificar', 'Señala la respuesta correcta respecto a la reabsorción renal de sodio:', 'En el asa ascendente de Henle se reabsorbe sodio, sin reabsorber agua.', 'En el túbulo colector se reabsorbe un 20 % del sodio.', 'La mayor reabsorción de sodio se produce en el túbulo distal.', 'La reabsorción de sodio en el túbulo proximal está mediada por la aldosterona.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 33, 'Sin clasificar', '¿Cómo se denomina el inicio progresivamente más precoz y el incremento de la gravedad de las manifestaciones clínicas de una enfermedad a lo largo de las sucesivas generaciones?:', 'Penetrancia variable.', 'Anticipación genética.', 'Anticipación alélica.', 'Penetrancia completa.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 34, 'Sin clasificar', 'En relación con el papel de la inmunoglobulina A (IgA) en la defensa frente a patógenos, señale la respuesta INCORRECTA:', 'La IgA activa la vía clásica del complemento contribuyendo a la eliminación de bacterias extracelulares.', 'La IgA pasa de la madre al recién nacido durante la lactancia contribuyendo a la protección de las mucosas del neonato.', 'La IgA puede atravesar la barrera epitelial de las mucosas uniéndose al receptor poli-Ig (pIgR) siendo la inmunoglobulina más abundante en las mucosas.', 'El déficit selectivo de IgA es la inmunodeficiencia más frecuente (aproximadamente 1:400) y la mayoría de los casos son asintomáticos.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 35, 'Sin clasificar', 'Entre las nuevas medidas de protección contra el COVID-19 se incluye el uso de terapias basadas en anticuerpos monoclonales frente la proteína S (spike) del SARS-CoV-2 (tixagevimab y cilgavimab). Este tratamiento:', 'Es una forma de inmunización activa cuyo resultado depende de la activación de linfocitos memoria.', 'Está indicado en pacientes inmunodeprimidos, como los pacientes con trasplante de órganos.', 'Confiere protección durante un período de tiempo aproximado de dos años.', 'Induce memoria inmunológica basada en la activación de linfocitos B.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 36, 'Sin clasificar', 'Las células T reguladoras (CD4+, CD25+, FoxP3+) se encuentran con frecuencia en el infiltrado de tumores sólidos. Estas células:', 'Se consideran marcadores de buen pronóstico en el desarrollo del tumor.', 'Contribuyen a la defensa inmune antitumoral.', 'Producen interferón gamma que contribuye a la activación de linfocitos citotóxicos.', 'Producen interleucina-10 que contribuye a un microambiente tumoral inmunosupresor.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 37, 'Sin clasificar', 'El síndrome de hiper-IgM, una inmunodeficiencia primaria asociada a diferentes mutaciones en las moléculas CD40 o su ligando CD40L, se caracteriza porque:', 'Los pacientes presentan niveles elevados de IgM mientras que mantienen niveles normales de IgG e IgA en suero.', 'Presentan un defecto de la diferenciación de los linfocitos B en la médula ósea con aumento de linfocitos B inmaduros que expresan la cadena mu intracitoplasmática.', 'Existe un defecto en el proceso de colaboración entre linfocitos T y B necesario para el cambio de isotipo de las inmunoglobulinas.', 'Existe un defecto en el proceso de reordenamiento de los genes V de las inmunoglobulinas.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 38, 'Sin clasificar', 'Entre los avances en inmunoterapia antitumoral se incluye el uso de linfocitos T modificados para que expresen un receptor CAR (chimeric antigen receptor, receptor quimérico para el antígeno), denominados CAR-T. En relación con las células CAR-T para el tratamiento de linfomas y leucemias que expresan CD19, señale la respuesta INCORRECTA:', 'El elemento de reconocimiento del receptor CAR está basado en fragmentos variables de anticuerpos anti-CD19 (single-chain variable fragments, scFvs).', 'El receptor CAR posee un dominio intracelular responsable de la transmisión de señales.', 'Entre los efectos secundarios graves de este tratamiento se encuentra el síndrome de liberación de citocinas.', 'El reconocimiento del antígeno por el receptor CAR depende de las moléculas de histocompatibilidad (HLA) clase I en la célula tumoral.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 39, 'Sin clasificar', 'Apicultor de 50 años que presenta reacciones sistémicas graves (anafilaxia) tras picaduras de abejas y en quien se demuestra positividad al veneno de Apis mellifera mediante pruebas cutáneas en intradermorreacción e IgE específica en suero. ¿Qué tratamiento etiológico está indicado?:', 'Entrenamiento del paciente en el empleo de autoinyectores de adrenalina.', 'Educación del paciente en el uso de antihistamínicos bucodispersables, broncodilatadores en aerosol presurizado y corticoides orales.', 'Inmunoterapia específica subcutánea con extracto de Apis mellifera al 100%.', 'Empleo de fármacos inmunomodulares tipo ciclosporina oral.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 40, 'Sin clasificar', 'En relación con la esofagitis eosinofílica, señale la afirmación INCORRECTA:', 'El diagnóstico de certeza se realiza mediante endoscopia digestiva alta y biopsia.', 'El tratamiento inicial es recomendar dieta de eliminación de aquellos alimentos en los que se demuestran reacciones positivas in vivo o in vitro.', 'La inflamación subyacente indica un mecanismo patogénico de hipersensibilidad Th1.', 'La inmunoterapia específica frente a los alérgenos respiratorios y alimentarios a los que se ha demostrado sensibilización es una práctica habitual.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 41, 'Sin clasificar', 'En una enfermedad genética con un patrón de herencia autosómico recesivo el riesgo de la enfermedad en una futura descendencia cuando ambos padres son portadores es:', '25 % en cada embarazo independiente del sexo de la descendencia.', '50 % en cada embarazo de un hijo varón.', '50 % en cada embarazo de una hija mujer.', '50 % en cada embarazo independiente del sexo de la descendencia.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 42, 'Sin clasificar', 'En un determinado gen la secuencia de ADN se transcribe para formar el ARN maduro y este ARN maduro se traduce para formar la proteína. ¿A qué región (secuencia) de la estructura de un gen se denomina intrón?:', 'A la que inicia la transcripción para formar el ARN', 'A la que no está presente en el ARN maduro.', 'A la que se transcribe para estar presente en el ARN maduro y dar lugar a la proteína.', 'A la que regula la expresión del gen.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 43, 'Sin clasificar', 'Para establecer si el consumo habitual de alimentos ultraprocesados (e.g. embutidos) se asocia a mayor riesgo del síndrome de fragilidad en adultos mayores, se selecciona a 5.000 personas mayores de 70 años que viven en sus domicilios, se les pregunta por su dieta habitual y se identifica el consumo de ultraprocesados en cada uno de ellos. Se realiza un seguimiento durante 3 años para identificar quiénes desarrollan el síndrome de fragilidad por primera vez. Señale la respuesta correcta sobre el diseño de este estudio:', 'Es un estudio de cohortes, porque se sigue a sujetos clasificados según su exposición para identificar el riesgo de un problema de salud.', 'Es un ensayo de campo, porque se realiza con personas que no son pacientes.', 'Es un estudio ecológico, porque incluye a un grupo muy amplio de población.', 'Es un estudio de casos y controles, en el que los casos toman muchos alimentos ultraprocesados y los controles toman muy pocos.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 44, 'Sin clasificar', 'Sobre los errores sistemáticos en los estudios observacionales, señale la afirmación INCO- RRECTA:', 'Se clasifican en sesgos de selección, de información y de análisis.', 'Se pueden evitar aumentando el tamaño muestral.', 'Pueden modificar la magnitud del efecto investigado.', 'Pueden afectar a la validez interna del estudio.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 45, 'Sin clasificar', 'El valor predictivo negativo de una prueba diagnóstica es del 92 %. ¿Cómo debe interpretarse dicho resultado?:', 'De cada 100 resultados negativos, 92 corresponderán a personas sanas.', 'De cada 100 personas sanas, en 92 de ellos el resultado de la prueba será negativo.', 'De cada 100 enfermos, en 8 de ellos el resultado de la prueba será negativo.', 'De cada 100 resultados positivos, 8 de ellos corresponderán a enfermos.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 46, 'Sin clasificar', 'El motivo por el que una intervención tiene un grado de recomendación "fuerte" en una guía de práctica clínica es que:', 'Tiene más beneficios que riesgos.', 'Está basada en un alto nivel de evidencia.', 'Tiene un bajo coste.', 'Es la preferida por los pacientes.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 47, 'Sin clasificar', '¿En cuál de las siguientes enfermedades debemos aplicar precauciones de aislamiento por contacto y aire (aerosoles)?:', 'Sarampión.', 'Tuberculosis.', 'Norovirus.', 'Varicela.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 48, 'Sin clasificar', 'En el diagrama de bosque (forest plot) que muestra los resultados de una revisión sistemática de estudios, el cuadrado que aparece al lado de cada estudio es:', 'El tamaño de cada estudio.', 'El estimador de interés (como el riesgo relativo) de cada estudio.', 'El intervalo de confianza del estimador de interés en cada estudio.', 'El peso de cada estudio cuando se realiza un metaanálisis de dichos estudios.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 49, 'Sin clasificar', 'En la valoración del riesgo de sesgo de un estudio epidemiológico se considera uno de los siguientes criterios:', 'Insuficiente tamaño muestral.', 'La excesiva amplitud del intervalo de confianza del 95 % del principal resultado del estudio.', 'La falta de significación estadística de los resultados.', 'Errores de medida en alguna de las principales variables.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 50, 'Sin clasificar', 'La mejor estrategia preventiva para ralentizar la progresión de la enfermedad en un fumador diagnosticado de EPOC es lograr el objetivo de cesación tabáquica. La siguiente medida NO se incluye en los protocolos actuales de primera elección para el tratamiento de refuerzo de la abstención tabáquica, porque faltan estudios demostrativos sobre su eficacia clínica y seguridad:', 'Parche cutáneo de nicotina.', 'Bupropión.', 'Vareniclina.', 'Cigarrillo electrónico.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 51, 'Sin clasificar', 'Las vacunas conjugadas:', 'Son vacunas de virus y bacterias combinadas para hacerlas menos inmunógenas y que provoquen menos efectos secundarios.', 'Son vacunas de virus enteros conjugadas con un polisacárido para poder combinarlas y hacer la trivalente o tetravalente vírica.', 'Son vacunas bacterianas conjugadas con un polisacárido para poder combinarlas y hacer vacunas penta o hexavalentes.', 'Son vacunas polisacáridas conjugadas con una proteína para hacerla dependiente de linfocitos T y lograr memoria inmunológica a largo plazo.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 52, 'Sin clasificar', 'Un ensayo clínico en el cual los participantes se asignan por azar a una de varias intervenciones clínicas se conoce como:', 'Ensayo doble ciego.', 'Ensayo controlado no aleatorizado.', 'Ensayo controlado aleatorizado.', 'Ensayo de superioridad.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 53, 'Sin clasificar', 'En el manejo de una mujer embarazada diagnosticada de trastorno bipolar. ¿Cuál de los siguientes fármacos es efectivo en esta enfermedad y se ha establecido como más seguro en el embarazo?:', 'Flufenazina.', 'Olanzapina.', 'Litio.', 'Carbamazepina.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 54, 'Sin clasificar', 'Paciente de 69 años diagnosticado de linfoma a quien se pauta un tratamiento intravenoso con metotrexato. Al tercer día de tratamiento presenta nefrotoxicidad y retraso en la eliminación renal del fármaco con pH urinario menor de 7. Teniendo en cuenta la naturaleza química del metotrexato (pKa entre 4 y 5,5). ¿Cuál de las siguientes actuaciones sería la más correcta para manejar la toxicidad?:', 'Administración intravenosa de suero fisiológico con cloruro amónico para facilitar la eliminación renal del metotrexato.', 'Administración intravenosa de solución de bicarbonato sódico para acelerar la diuresis del metotrexato.', 'Administración enteral de solución de bicarbonato sódico para reducir la absorción digestiva del metotrexato.', 'Administración intravenosa de furosemida en suero con pH neutro para provocar una diuresis forzada.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 55, 'Sin clasificar', '¿Cuál es el mecanismo por el que la ivabradina, actuando en las células del nodo sinoauricular, produce una disminución de la frecuencia cardíaca?:', 'Potencia la repolarización al activar corrientes de salida de potasio.', 'Modula los receptores beta-1 adrenérgicos.', 'Bloquea la corriente de marcapaso If.', 'Activa los receptores muscarínicos M2.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 56, 'Sin clasificar', 'En un paciente con una úlcera duodenal y alto riesgo cardiovascular por cardiopatía isquémica, en caso de requerir tratamiento con un AINE, ¿cuál de los siguientes le recomendaría como más seguro?:', 'Naproxeno.', 'Celecoxib.', 'Ketorolaco.', 'Ibuprofeno.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 57, 'Sin clasificar', 'Varón de 68 años con antecedentes de obesidad y diabetes mellitus tipo 2, en tratamiento con metformina. Ingresa por un primer episodio de insuficiencia cardiaca. Tiene una hemoglobina glicada de 8,5 %. Para optimizar el tratamiento de la diabetes al alta, ¿cuál de los siguientes fármacos está contraindicado?:', 'Linagliptina.', 'Canagliflozina.', 'Dulaglutide.', 'Pioglitazona.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 58, 'Sin clasificar', 'Niño de 5 años que sufrió un accidente de bicicleta con traumatismo facial sin pérdida de conciencia, objetivándose en urgencias únicamente una herida en el mentón, realizándose sutura de la misma. Es remitido a consulta 5 días después del traumatismo por presentar limitación y desviación de la apertura bucal. ¿Cuál es el diagnóstico más probable?:', 'Fractura tipo LeFort.', 'Fractura combinada de mandíbula y maxilar superior.', 'Fractura de cóndilo mandibular.', 'Fractura de sínfisis y rama horizontal de la mandíbula.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 59, 'Sin clasificar', 'De los siguientes tumores malignos que pueden afectar a la lengua, ¿cuál es el tipo más frecuente y dónde metastatiza habitualmente?:', 'El sarcoma y metastatiza en los ganglios linfáticos cervicales.', 'El carcinoma epidermoide y metastatiza en los ganglios linfáticos cervicales.', 'El sarcoma y metastatiza en tejido óseo a distancia.', 'El carcinoma epidermoide y metastatiza en tejido hepático.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 60, 'Sin clasificar', '¿Cuál de las siguientes descripciones define el estadio II de una úlcera por presión según el sistema de estadiaje del National Pressure Injury Advisory Panel?:', 'Eritema no blanqueable.', 'Pérdida de espesor total de la piel con exposición del tejido celular subcutáneo.', 'Pérdida de epidermis con exposición de la dermis.', 'Aparición de tejido de granulación en el lecho del defecto.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 61, 'Sin clasificar', 'Con respecto a los injertos cutáneos, señale la respuesta INCORRECTA:', 'Unos de los lechos considerados injertables por su rica vascularización es el tejido de granulación.', 'Podemos clasificarlos en injertos de piel parcial (si presentan sólo la epidermis) o injertos de piel total (si presentan la epidermis y la dermis subyacente).', 'Suelen presentar un proceso de contracción, que aparece tanto a la hora de ser extraídos como después de haber sido injertados.', 'Dentro de las comorbilidades médicas asociadas a la pérdida del injerto podemos destacar la diabetes, el tabaquismo y la vasculopatía periférica.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 62, 'Sin clasificar', 'Mujer de 38 años que desde hace unas semanas nota en ambos ojos sensación de arenilla y quemazón, que empeora a lo largo del día, cuando hace viento y con el aire acondicionado. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Conjuntivitis alérgica.', 'Epiescleritis.', 'Pinguécula.', 'Queratoconjuntivitis seca.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 63, 'Sin clasificar', 'Respecto del desprendimiento de vítreo posterior, señale la afirmación INCORRECTA:', 'Los síntomas por los que generalmente consultan los pacientes son los fosfenos y las miodesopsias.', 'El anillo de Weiss es un signo característico en la exploración oftalmoscópica.', 'El signo de Shaffer o polvo de tabaco es un signo de buen pronóstico.', 'Se produce por la licuefacción del gel vítreo por la edad.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 64, 'Sin clasificar', 'Varón de 25 años que refiere en los últimos meses una importante disminución de la visión nocturna y mala adaptación a la oscuridad. Está notando dificultad en la conducción, al bajar las escaleras y últimamente tropieza con los bordillos. Sin embargo, puede leer y ver la televisión. ¿Con cuál de las siguientes entidades relacionaría los síntomas de este paciente?:', 'Enfermedad de Stargardt.', 'Distrofia macular viteliforme de Best.', 'Retinosis pigmentaria.', 'Desprendimiento de retina.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 65, 'Sin clasificar', 'Un niño de 22 meses fue atendido por presentar una otitis media aguda bilateral que cursó con dolor, fiebre, otorrea e hipoacusia. Se instauró tratamiento antibiótico por vía oral y con gotas tópicas con lo que mejoró la sintomatología. A los doce días acude de nuevo a urgencias porque reaparece la fiebre y los padres han observado que el pabellón auditivo se ha desplazado hacia fuera y abajo y que la piel retroauricular está roja y edematosa. ¿Cuál es el diagnóstico más probable?:', 'Otitis externa.', 'Mastoiditis.', 'Condritis.', 'Celulitis.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 66, 'Sin clasificar', 'Mujer de 40 años que presenta un cuadro de mareo acompañado de náuseas y vómitos, de unos veinte minutos de duración. No ha perdido el conocimiento y ha podido sujetarse a una pared para no perder el equilibrio. Ya le había ocurrido en ocasiones anteriores. Refiere haber presentado sensación de plenitud ótica, acúfeno e hipoacusia de oído derecho. En la exploración física se evidencia otoscopia normal, nistagmo horizonte-rotario a la izquierda grado II, Romberg positivo a la derecha y Untenberger con laterodesviación a la derecha. ¿Cuál es el diagnóstico más probable?:', 'Vértigo posicional paroxístico benigno.', 'Neuronitis vestibular.', 'Enfermedad de Ménière.', 'Síndrome de Ramsay-Hunt.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 67, 'Sin clasificar', 'La disfagia orofaríngea es la dificultad de trasladar el alimento desde la cavidad oral hasta el esófago proximal. Entre las causas de disfagia orofaríngea motora están las siguientes EXCEP- TO:', 'Miastenia gravis.', 'Reflujo gastroesofágico.', 'Tétanos.', 'Dermatopolimiositis.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 68, 'Sin clasificar', 'En relación con las infecciones vulvovaginales, señale la afirmación INCORRECTA:', 'La vaginosis bacteriana es habitualmente una infección monomicrobiana.', 'La vulvovaginitis candidiásica es la infección vulvovaginal más prevalente en Europa.', 'Se define como vulvovaginitis candidiásica recidivante cuando aparecen 4 o más episodios en un año.', 'La vaginosis bacteriana únicamente debe tratarse farmacológicamente cuando es sintomática.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 69, 'Sin clasificar', 'Referido al síndrome de ovario poliquístico, señale la afirmación INCORRECTA:', 'Se presenta en mujeres jóvenes.', 'Clínicamente se caracteriza por la presencia de hirsutismo, acné y amenorrea u oligomenorrea.', 'Se asocia a obesidad y resistencia a la insulina.', 'Aumenta el riesgo de cáncer de ovario.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 70, 'Sin clasificar', 'Mujer primigesta de 35 años que se encuentra en la segunda etapa del parto. Lleva analgesia epidural. ¿Cuándo estará indicada la aplicación de la ventosa para abreviar el periodo expulsivo?:', 'Cuando, tras 2 horas en completa, la presentación se queda en un II plano de Hodge con los pujos maternos.', 'Cuando presencia un inicio de sangrado vaginal abundante con repercusión fetal y la presentación se encuentra sobre el estrecho superior de la pelvis materna.', 'Cuando la presentación se queda en un IV plano y el punto guía es el mentón.', 'Cuando se produzca una bradicardia fetal que no se recupera tras el cese de la contracción y la fontanela menor se encuentra pasado el III plano de Hodge.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 71, 'Sin clasificar', 'Mujer de 41 años gestante de 13+2 semanas que tras realizarse la ecografía de la semana 12, presenta un riesgo combinado de cromosomopatías para la trisomía 21 de 1/30. ¿Cuál sería el consejo más adecuado?:', 'Adelantar la ecografía de la semana 20.', 'Realizar una prueba invasiva.', 'Tranquilizarle porque se trata de un riesgo combinado de bajo riesgo en todo caso.', 'Tranquilizarle porque se trata de un riesgo intermedio y está justificado por la edad materna.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 72, 'Sin clasificar', 'Primigesta de 26 semanas de gestación, con seguimiento dentro de la normalidad hasta la fecha. Acude a su centro de salud con un resultado en el test de O´Sullivan de 175 mg/dL. Ante esta situación, ¿cómo deberíamos proceder?:', 'Debe ser informada del riesgo de diabetes gestacional con riesgo fetal y remitida al servicio de urgencias hospitalarias.', 'Se indicará una sobrecarga oral de glucosa de 100 g solamente si tiene factores de riesgo para alteraciones del metabolismo de la glucosa.', 'Al ser un valor superior a 165 mg/dL se confirma el diagnóstico de diabetes gestacional.', 'Debe solicitarse una confirmación diagnóstica de diabetes gestacional mediante la realización de una sobrecarga oral de glucosa de 100 g.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 73, 'Sin clasificar', 'Mujer de 36 años con antecedentes de 2 abortos de primer trimestre y preeclampsia grave que requirió cesárea por pérdida de bienestar fetal a las 33 semanas de gestación. El estudio analítico postparto es normal salvo por la presencia de anticuerpos antifosfolípido IgM e IgG, siendo el resto del estudio de trombofilia normal. La presencia de anticuerpos antifosfolípido fue confirmada a los 4 meses de la primera analítica. ¿Qué recomendación haríamos a esta paciente en caso de nueva gestación?:', 'Aspirina y heparina de bajo peso molecular a dosis profilácticas.', 'Vitaminas antioxidantes a dosis altas.', 'Intentar la gestación mediante diagnóstico genético preimplantacional.', 'Tratamiento según cribado de preeclampsia de primer trimestre con aspirina a dosis bajas si alto riesgo.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 74, 'Sin clasificar', 'Mujer de 54 años nuligesta que consulta por pérdidas de orina tras la percepción de urgencia miccional y por sensación de necesidad de orinar en la noche 3-4 veces. En la exploración ginecológica se evidencia un cistocele de primer grado y una atrofia vaginal moderada. ¿Cuáles serían las medidas iniciales a realizar?:', 'Corrección quirúrgica del cistocele.', 'Realización de diario miccional y reeducación vesical.', 'Indicación de flujometría y evaluación de la función uretral.', 'Prescripción de tratamiento oral con fármacos colinérgicos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 75, 'Sin clasificar', 'Primigesta de 29 años sin antecedentes de interés remitida a las 36,5 semanas de gestación por sospecha ecográfica de restricción de crecimiento. En la consulta presenta tensión arterial 125/75 mmHg y en la ecografía obstétrica se objetiva un peso fetal estimado compatible con un percentil 6 para la edad gestacional y un índice de pulsatilidad Doppler de arteria umbilical por encima del percentil 95. ¿Qué recomendación haría en esta situación?:', 'Finalización de la gestación de forma inmediata mediante una cesárea.', 'Controles semanales con monitorización fetal y ecografía obstétrica cada dos semanas hasta el inicio espontáneo del parto.', 'Controles semanales con monitorización fetal y ecografía obstétrica cada dos semanas hasta las 40 semanas de gestación.', 'Inducción del parto a partir de las 37 semanas de gestación.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 76, 'Sin clasificar', 'Mujer de 35 años que consulta por amenorrea de 6 meses de evolución. En la anamnesis le dice que últimamente le cuesta dormir y se despierta por la noche con mucho calor. Menarquia a los 12 años. Tiene 2 hijas (partos eutócicos) y deseo genésico cumplido. Su madre tuvo la menopausia a los 41 años. La analítica de sangre muestra FSH 65,1 U/L (2-13,8), LH 12 U/L (2-13,8), estradiol < 0,05 pg/mL (fase folicular: 30-100; fase lútea: 50-150; pico ovulatorio: 100-400). Dos meses más tarde le repite la analítica con valores similares. ¿Cuál es el diagnóstico de sospecha y la actitud a seguir?:', 'Probablemente está menopáusica, pero hasta que no se cumplan los 12 meses de amenorrea no podrá iniciar ningún tratamiento.', 'Insuficiencia ovárica prematura. Inicia estudio con cariotipo e indica terapia hormonal sustitutiva.', 'Insuficiencia ovárica prematura. Le explica que son esenciales los hábitos de vida saludables: no fumar, ejercicio y adecuada ingesta de vitamina D. La terapia hormonal la deja como tratamiento de segunda línea.', 'Amenorrea hipotalámica. Precisa estudio con una RM craneal.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 77, 'Sin clasificar', '¿Cuál de las siguientes vacunas NO debe administrarse a un lactante de 9 meses que tiene una inmunodeficiencia primaria combinada?:', 'Vacuna antineumocócica conjugada 13- valente.', 'Vacuna antigripal.', 'Vacuna frente al rotavirus.', 'Vacuna antimeningocócica tipo B.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 78, 'Sin clasificar', 'Varón de 19 meses, correctamente vacunado para su edad. Previamente bien, inicia de forma brusca un cuadro clínico con fiebre alta de hasta 40 ºC sin otra sintomatología, salvo irritabilidad. La exploración al día siguiente es normal, salvo por ligera hiperemia de mucosa oral y membrana timpánica, y microadenopatías laterocervicales. Al cuarto día desaparece totalmente la fiebre y aparece un exantema eritematoso morbiliforme, maculopapuloso de distribución en cara, tronco y extremidades. De los siguientes, ¿cuál es el diagnóstico más probable?:', 'Eritema infeccioso o quinta enfermedad.', 'Sarampión o primera enfermedad.', 'Roséola, exantema súbito o sexta enfermedad.', 'Escarlatina o segunda enfermedad.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 79, 'Sin clasificar', 'Lactante de 14 meses que acude a urgencias por un cuadro de irritabilidad en las últimas 12 horas y heces sanguinolentas con moco. En la exploración destacan episodios de llanto, con flexión de las extremidades inferiores. En la palpación abdominal se objetiva una masa cilíndrica mal definida, incrementándose el llanto del niño cuando se presiona en la parte derecha del abdomen. ¿Cuál es su diagnóstico de sospecha y que prueba realizaría para confirmarlo?:', 'Apendicitis aguda. Ecografía abdominal.', 'Invaginación intestinal. Ecografía abdominal.', 'Apendicitis aguda. TC abdominal.', 'Invaginación intestinal. TC abdominal.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 80, 'Sin clasificar', 'Respecto a la gastroenteritis aguda (GEA) en pediatría, señale la afirmación INCORRECTA:', 'Los rotavirus son una causa infrecuente de GEA en los niños a nivel mundial.', 'Los principales patógenos bacterianos que causan GEA son Salmonella no tifoidea, Shigella, Campylobacter y Yersinia.', 'La enfermedad por Clostridioides difficile puede ser tanto nosocomial como adquirida en la comunidad en los niños.', 'Entre los patógenos bacterianos que causan enfermedades vehiculadas por alimentos se incluyen Bacillus cereus, Clostridium perfringens y Staphylococcus aureus.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 81, 'Sin clasificar', 'Entre las características clínicas siguientes relativas a la anorexia nerviosa, señale la afirmación correcta:', 'Una forma clínica se asocia a atracones y conductas purgativas.', 'Se distribuye por igual entre ambos sexos.', 'La amenorrea es un criterio diagnóstico necesario de enfermedad en mujeres.', 'Hay deseo de perder peso, pero con una percepción normal de la propia constitución.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 82, 'Sin clasificar', 'En relación con la estenosis hipertrófica de píloro, señale la afirmación INCORRECTA:', 'Afecta predominantemente a primogénitos varones.', 'Se ha encontrado mayor incidencia en hijas de madres tratadas con macrólidos durante el embarazo.', 'La alteración hidroelectrolítica típica es una acidosis metabólica hipoclorémica.', 'El tratamiento de elección es la piloromiotomía extramucosa de Ramstedt.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 83, 'Sin clasificar', 'Para el diagnóstico de enfermedad de Kawasaki clásica es necesaria la presencia de fiebre al menos cinco días y 4 de los principales signos de la enfermedad. De los siguientes, señale cuál NO SE CONSIDERA un signo principal:', 'Eritema de las mucosas faríngea y oral con lengua en fresa y/o labios agrietados.', 'Exantema polimorfo.', 'Linfadenopatía cervical (> 1,5 cm de diámetro) generalmente unilateral.', 'Inyección conjuntival exudativa bilateral.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 84, 'Sin clasificar', 'En relación con las vacunas y los calendarios de vacunación en las comunidades autónomas españolas, señale la afirmación INCORRECTA:', 'Las vacunas sistemáticas son aquellas que se administran de forma obligatoria a todos los niños según el calendario vacunal vigente en su comunidad autónoma.', 'Las vacunas no sistemáticas son aquellas que no se administran de forma universal en todas las comunidades autónomas.', 'El calendario vacunal se define como la secuencia cronológica de vacunas que se administra sistemáticamente en un país o área geográfica determinada.', 'Los calendarios vacunales deben actualizarse de forma permanente según el desarrollo de nuevas vacunas o el cambio de incidencia de enfermedades en un área geográfica determinada.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 85, 'Sin clasificar', 'Paciente de 7 años ingresado desde hace varios días con diagnóstico de neumonía, tratado con antibióticos. Mantiene picos febriles por lo que se realiza una ecografía torácica en donde se observa derrame pleural con múltiples tabiques. Se hace una toracocentesis diagnóstica extrayéndose material purulento. ¿Qué se debe hacer a continuación?:', 'Drenaje cerrado con un tubo de tórax con instilación de fibrinolíticos.', 'Toracocentesis repetidas para extraer todo el derrame posible.', 'Decorticación quirúrgica.', 'Ampliación de la cobertura antibiótica.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 86, 'Sin clasificar', 'Mujer de 13 años que acude a consulta por fiebre alta de 5 días de evolución, odinofagia, cefalea, dolor abdominal y astenia intensa que interfiere en su vida cotidiana. En la exploración se aprecian amígdalas rojas con membrana exudativa, maloliente. Se palpan adenopatías cervicales anteriores, posteriores, occipitales y epitrocleares. En el abdomen se palpa hígado a 1 cm y bazo a 3 cm del reborde costal. Ante esta clínica y exploración ¿qué estudio serológico pediría?:', 'Sarampión.', 'Rubeola.', 'Epstein-Barr.', 'Parvovirus B 19.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 87, 'Sin clasificar', 'Indique que fármaco NO está indicado en el tratamiento de mantenimiento del trastorno bipolar:', 'Litio.', 'Valproato.', 'Carbamazepina.', 'Clorazepato.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 88, 'Sin clasificar', 'Varón de 26 años que ha presentado un primer episodio depresivo con remisión completa de la sintomatología con un primer antidepresivo en monoterapia. ¿Cuánto tiempo se recomienda mantener el tratamiento?:', 'En un primer episodio en pacientes jóvenes con buena respuesta se puede suspender el tratamiento al cabo de un mes.', 'Se recomienda mantener el tratamiento durante un mínimo de tres meses tras la remisión.', 'Se recomienda mantener el tratamiento durante un mínimo de seis meses tras la remisión.', 'Se recomienda mantener el tratamiento durante un mínimo de dos años para prevenir recaídas.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 89, 'Sin clasificar', 'Varón de 71 años sin antecedentes psiquiátricos que presenta un cuadro de tres semanas de evolución caracterizado por déficit de memoria, inatención, insomnio, pérdida de peso, inquietud, angustia de predominio matutino e ideas delirantes de culpa y perjuicio. De los siguientes, el diagnóstico más probable es:', 'Catalepsia.', 'Esquizofrenia de inicio tardío.', 'Enfermedad de Alzheimer.', 'Episodio depresivo grave con síntomas psicóticos.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 90, 'Sin clasificar', 'La depresión mayor, especialmente si tiene carácter endógeno/melancólico, se caracteriza por una de las siguientes alteraciones:', 'Incremento del apetito.', 'Disminución de la secreción de cortisol.', 'Dificultad para despertarse por la mañana.', 'Empeoramiento matutino.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 91, 'Sin clasificar', 'Indique cuál de los siguientes trastornos NO es un trastorno de ansiedad según el DSM-5:', 'Trastorno obsesivo-compulsivo.', 'Mutismo selectivo.', 'Fobia situacional.', 'Trastorno de pánico.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 92, 'Sin clasificar', 'En psicogeriatría, cuando es preciso el uso de benzodiacepinas ¿cuál es de elección?:', 'Clorazepato.', 'Lorazepam.', 'Diazepam.', 'Las benzodiacepinas están contraindicadas.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 93, 'Sin clasificar', 'En relación con los efectos secundarios de los antipsicóticos, señale la afirmación INCO- RRECTA:', 'La aparición de síndrome metabólico es más frecuente con el uso de antipsicóticos típicos.', 'La sedación es un efecto secundario frecuente con la mayoría de los antipsicóticos, más pronunciado al inicio del tratamiento.', 'La discinesia tardía es un trastorno del movimiento involuntario que afecta con mayor frecuencia a la región orofacial, aparece tras la administración prolongada de antipsicóticos y puede ser irreversible.', 'La acatisia es un efecto extrapiramidal para cuyo tratamiento puede estar indicada la adición de benzodiazepinas o el uso de betabloqueantes.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 94, 'Sin clasificar', 'Acerca de la terapia combinada con psicofármacos y psicoterapia de los trastornos mentales, es cierto que:', 'Está indicada únicamente cuando han fracasado ambas formas de tratamiento por separado.', 'El alivio rápido de los síntomas de ansiedad gracias a la medicación disminuye la motivación para la psicoterapia.', 'Exige que un mismo profesional lleve a cabo las dos modalidades de tratamiento.', 'Los resultados de la terapia combinada son superiores a los de cada una utilizada por separado.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 95, 'Sin clasificar', 'Dentro de los síndromes parkinsonianos primarios, la enfermedad de Parkinson se produce por:', 'Una degeneración neuronal que afecta especialmente al globo pálido, sustancia reticular y oliva inferior y produce un déficit de dopamina.', 'Una degeneración de los núcleos de la protuberancia, oliva inferior y el cerebelo.', 'Una degeneración celular en la sustancia negra que disminuye la tasa de dopamina a nivel del estriado, lo que provoca una actividad subtalámica y palidal excesiva.', 'Una degeneración neuronal progresiva a nivel cortical y de los ganglios basales.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 96, 'Sin clasificar', 'Respecto a la exploración neurológica de una lesión en la vía córtico-espinal, señale la afirmación INCORRECTA:', 'Se encuentra debilidad global en todos los grupos musculares de los miembros afectados.', 'El reflejo de Babinski está presente.', 'Presenta hipertonía tipo rigidez.', 'Existe hiperreflexia en los reflejos osteotendinosos rotulianos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 97, 'Sin clasificar', 'Varón de 52 años, diabético, que consulta por pie caído derecho indoloro. En la exploración hay debilidad del músculo tibial anterior y peroneos derechos, con reflejo rotuliano y aquíleos preservados. ¿Cuál es el diagnóstico más probable?:', 'Radiculopatía S1 derecha.', 'Mononeuropatía del ciático poplíteo externo derecho.', 'Radiculopatía L5 derecha.', 'Amiotrofia diabética.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 98, 'Sin clasificar', 'En un paciente con un síndrome parkinsoniano de dos años de evolución, señale cuál de las siguientes manifestaciones clínicas le harían dudar de un diagnóstico de enfermedad de Parkinson:', 'Disartria grave.', 'Ausencia de temblor.', 'Presencia de un trastorno de conducta del sueño REM.', 'Estreñimiento.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 99, 'Sin clasificar', 'Un estudiante de 19 años sufre una primera crisis tónico-clónica generalizada mientras estaba tumbado en el sofá. La exploración neurológica es normal. En la anamnesis dirigida nos dice que esos días había dormido menos horas porque estaba de exámenes y que a veces, por las mañanas, tiene sacudidas en los brazos al coger la taza del desayuno. Su electroencefalograma muestra descargas de puntas y polipunta-onda generalizadas. Señale la respuesta INCORRECTA:', 'Probablemente la RM craneal sea normal.', 'No iniciaría tratamiento por ser una primera crisis.', 'El diagnóstico más probable es una epilepsia mioclónica juvenil.', 'Iniciaría tratamiento con valproato.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 100, 'Sin clasificar', 'Un varón de 21 años comienza con un cuadro psiquiátrico consistente en alucinaciones, alteraciones conductuales y episodios de catatonía. En unos días se añade al cuadro un déficit de memoria y discinesias orales y al décimo día comienza con crisis convulsivas. ¿Cuál de las siguientes pruebas daría más información para el diagnóstico?:', 'RM cerebral con espectroscopia.', 'EEG de larga duración con vídeo-EEG.', 'Realizar un ciclo de tratamiento con metilprednisolona a dosis altas para valorar respuesta.', 'Estudio en LCR y suero de autoanticuerpos autoinmunes específicos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 101, 'Sin clasificar', 'Mujer de 53 años sin antecedentes de interés que acude a urgencias por alteración del habla iniciada bruscamente una hora antes. En la exploración solo se objetiva una afasia motora. La TC craneal basal es normal. En la TC de perfusión hay un defecto de flujo en la región cortical frontal izquierda sin afectación en los mapas de volumen. En la angio-TC se objetiva un trombo en el segmento distal (M3-M4) de la arteria cerebral media izquierda. Señale cuál de los siguientes es el tratamiento más correcto:', 'Trombectomía mecánica.', 'Fibrinolisis endovenosa con rTPA.', 'Fibrinolisis endovenosa y, si no se consigue recanalización, trombectomía mecánica.', 'Anticoagulación con heparina sódica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 102, 'Sin clasificar', 'En los pacientes con esclerosis tuberosa (enfermedad de Bourneville) señale la respuesta IN- CORRECTA:', 'Con frecuencia presentan crisis epilépticas.', 'Suelen presentar angiofibromas faciales.', 'El tumor cerebral más frecuente es el astrocitoma gigantocelular subependimario.', 'Con frecuencia presentan neurinomas.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 103, 'Sin clasificar', 'Mujer de 64 años que presenta dolor en la cara en el territorio de la tercera rama del V par. Respecto al diagnóstico de la neuralgia del trigémino, señale la afirmación INCORRECTA:', 'Dolor lancinante de muy corta duración.', 'El dolor tiene un punto gatillo, asociándose a la estimulación táctil de la zona afecta.', 'El dolor puede desaparecer espontáneamente después de persistir semanas o meses.', 'Se asocia a hipoestesia de la cara.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 104, 'Sin clasificar', 'Con respecto a las crisis epilépticas postraumáticas es cierto que:', 'Son comunes inmediatamente después del impacto.', 'Las lesiones penetrantes y la gravedad de la lesión son factores favorecedores.', 'Está indicado el tratamiento anticomicial profiláctico.', 'Tras un par de años de mayor riesgo los pacientes con lesiones graves tienen el mismo riesgo que la población general.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 105, 'Sin clasificar', 'Varón de 25 años que ingresa en UCI tras una intoxicación farmacológica indeterminada. Por disminución progresiva del nivel de conciencia, sin mejoría con naloxona ni con flumazenilo, se decide intubación orotraqueal y ventilación mecánica invasiva. ¿Cuál de los siguientes fármacos NO utilizaría para realizar la intubación orotraqueal?:', 'Quetiapina.', 'Rocuronio.', 'Etomidato.', 'Fentanilo.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 106, 'Sin clasificar', 'Varón de 50 años con neumonía por Legionella que precisa ingreso en la UCI por insuficiencia respiratoria aguda. Debe ser intubado orotraquealmente y conectado a ventilación mecánica invasiva. Se diagnostica un síndrome de distrés respiratorio agudo y se le coloca en decúbito prono. Respecto a esta técnica posicional, señale la afirmación INCORRECTA:', 'Se realiza para intentar aumentar la relación entre la presión parcial de oxígeno y la fracción inspirada de oxígeno.', 'Se realiza por personal entrenado para evitar complicaciones.', 'La relación entre la presión parcial de oxígeno y la fracción inspirada de oxígeno por debajo de la cual se recomienda es de 300 mmHg.', 'La posición en decúbito prono durante la ventilación mecánica invasiva precisa una sedación profunda.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 107, 'Sin clasificar', 'Paciente de 58 años que sufre una neumonía por COVID 19 que precisa intubación con ventilación mecánica en UCI. A la semana se realiza una traqueostomía y sigue precisando ventilación mecánica. Se detecta un déficit motor en las cuatro extremidades con hiporreflexia generalizada. La orientación diagnóstica inicial y la actitud terapéutica a seguir serán:', 'Síndrome de Guillain-Barré. Confirmar el diagnóstico con pruebas complementarias.', 'Síndrome postCOVID. Rehabilitación respiratoria.', 'Miopatía del enfermo crítico. Corticoides y pruebas complementarias.', 'Miopatía del enfermo crítico. Rehabilitación respiratoria y motora intensivas.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 108, 'Sin clasificar', 'Varón de 55 años sin antecedentes de interés que tras realizar un esfuerzo nota dolor lumbar irradiado hacia el miembro inferior derecho por la parte anterolateral del muslo y cara anterior de la rodilla. Exploración: maniobra de Lasègue positiva a 40 º, reflejo rotuliano disminuido y dificultad para la marcha de talones. ¿Cuál es el diagnóstico más probable?:', 'Hernia discal L2-L3 derecha.', 'Hernia discal L3-L4 derecha.', 'Hernia discal L4-L5 derecha.', 'Hernia discal L5-S1 derecha.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 109, 'Sin clasificar', 'Acude a urgencias un paciente de 5 años con fiebre de 48 horas de evolución, con mala respuesta a los antitérmicos y rechazo al apoyo del miembro inferior izquierdo. En la exploración física se observa limitación de la movilidad de la cadera. En la analítica aumento de la PCR y leucocitosis. ¿Qué prueba complementaria se debe solicitar en primer lugar?:', 'Radiografía de cadera.', 'Ecografía de cadera.', 'RM de ambas caderas.', 'Artrografía de cadera.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 110, 'Sin clasificar', 'Mujer de 82 años con antecedentes de insuficiencia cardíaca congestiva y cáncer de mama que consulta por una fractura de muñeca izquierda. La fractura es estable, no es conminuta ni presenta trazos intraarticulares. ¿Cuál de los siguientes tratamientos es el más adecuado?:', 'Reducción cerrada y yeso antebraquial.', 'Artroplastia total de muñeca.', 'Osteosíntesis con placas dorsal y volar.', 'No inmovilizar, rehabilitación inmediata.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 111, 'Sin clasificar', 'Empleada de hogar de 35 años, sin antecedentes de interés, diestra, que refiere dolor en 5º dedo de mano izquierda y en cara interna de antebrazo izquierdo acompañado de acorchamiento y pérdida parcial de sensibilidad. ¿Cuál sería la primera sospecha diagnóstica?:', 'Síndrome del túnel carpiano.', 'Hernia discal cervical C3-C4.', 'Compresión cubital epitroclear.', 'Tendinitis de De Quervain.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 112, 'Sin clasificar', 'Respecto a la pseudoartrosis del escafoides, señale la afirmación INCORRECTA:', 'Suele cursar con una necrosis del fragmento distal de la fractura.', 'Puede cursar de manera asintomática.', 'A largo plazo suele provocar una artrosis radiocarpiana.', 'En estadios iniciales el tratamiento de elección es la fijación de la fractura y aporte de injerto óseo.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 113, 'Sin clasificar', 'Varón de 69 años, con índice de masa corporal 37 y gran obesidad central (abdominal) que aqueja dolor lumbar incapacitante que se extiende hasta ambas regiones glúteas, pero no irradia a miembros inferiores. Le impide permanecer de pie quieto y caminar más de 10 minutos, pero desaparece sentado y en la cama. La maniobra de Lasègue es negativa. ¿Cuál es el diagnóstico más probable?:', 'Hernia discal a nivel L5-S1.', 'Estenosis de canal lumbar.', 'Hernia discal a nivel L4-L5.', 'Espondilodiscitis bacteriana.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 114, 'Sin clasificar', 'Ante una lesión diafisaria de húmero de carácter lítico que afecta a la totalidad del diámetro del hueso en un varón de 67 años con el antecedente de un cáncer de pulmón (supervivencia estimada superior a 2 años) y que le provoca dolor continuo mal controlado. ¿Cuál de las siguientes es la mejor actitud terapéutica?:', 'Actitud expectante, ya que se trata de un hueso sin carga, lo que reduce el riesgo de fractura.', 'Aplicación de mórficos a dosis altas para controlar el dolor que le permitan realizar fisioterapia para recuperar la función.', 'Ajustar un yeso de forma correcta para disminuir el riesgo de fractura.', 'Colocación de un clavo endomedular acerrojado.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 115, 'Sin clasificar', 'Varón de 29 años que acude por dolor lumbar y edema de las manos de varias semanas de evolución, junto a visión borrosa y ojos rojos. Ha tenido varias relaciones sexuales sin protección y en su familia hay casos de psoriasis. En la exploración física presenta temperatura 37,5 ºC, inyección conjuntival bilateral e hinchazón de la parte distal de los dedos y de la muñeca de lado izquierdo, con maniobras sacroilíacas positivas. ¿Cuál es el diagnóstico más probable?:', 'Artritis reactiva.', 'Artritis psoriásica.', 'Artritis enteropática.', 'Espondilitis anquilosante.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 116, 'Sin clasificar', 'Varón de 55 años con antecedentes de hiperuricemia que acude a urgencias por presentar un primer episodio de dolor agudo muy intenso e invalidante en rodilla derecha acompañado de enrojecimiento, tumefacción e hinchazón. Febrícula de 37,5 ºC. ¿Cuál de las siguientes es la actitud más recomendable a seguir?:', 'Realizar artrocentesis y enviar el líquido sinovial al laboratorio para evaluar presencia de cristales y gérmenes.', 'Empezar tratamiento con colchicina porque está sufriendo un episodio de gota.', 'Empezar tratamiento con un AINE y alopurinol para tratar el episodio de gota y la hiperuricemia.', 'Empezar tratamiento con un AINE, alopurinol y un antibiótico para tratar el episodio de gota, la hiperuricemia y la probable infección.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 117, 'Sin clasificar', 'Mujer de 81 años asmática que utiliza los corticoides de forma frecuente para controlar los brotes de broncoespasmo y que consulta porque tiene un dolor agudo intenso en la región dorsolumbar después de caer en casa desde una silla. ¿Cuál de las siguientes es la actitud más recomendable a seguir?:', 'Solicitar de forma urgente radiografías de columna dorsal y lumbar y pautar tratamiento analgésico para el dolor.', 'Solicitar una RM de columna dorsal y lumbar y pautar tratamiento analgésico y reposo para el dolor.', 'Pautar tratamiento analgésico y empezar tratamiento antirreabsortivo.', 'Solicitar una densitometria, pautar tratamiento analgésico y empezar con tratamiento antireabsortivo, calcio y vitamina D.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 118, 'Sin clasificar', '¿Cuál de los siguientes NO es un criterio para el diagnóstico de endocarditis infecciosa?:', 'Presencia de fenómenos embólicos arteriales mayores.', 'Un único hemocultivo positivo para Coxiella burnetii.', 'Al menos dos hemocultivos positivos extraídos con un intervalo > 12 horas de microorganismos compatibles con una endocarditis infecciosa.', 'Presencia de anemia hemolítica.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 119, 'Sin clasificar', '¿Cuál de los siguientes criterios se considera de alto riesgo en la estratificación de un síncope?:', 'Síncope producido al rotar la cabeza o presionar el seno carotídeo.', 'Síncope durante el esfuerzo o en decúbito supino.', 'Síncope después de una visión, sonido u olor desagradable.', 'Bloqueo aurículoventricular de segundo grado Mobitz I.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 121, 'Sin clasificar', 'Varón de 68 años portador de una válvula mecánica mitral, anticoagulado con acenocumarol, que presenta un INR de 9 en un control rutinario en su centro de salud. No tiene síntomas de sangrado en el momento actual. ¿Cuál de las siguientes es la actitud más correcta?:', 'Suspender el tratamiento con acenocumarol y administrar 10 mg de vitamina K en infusión intravenosa lenta, que se repetirá cada 12 horas si fuera necesario.', 'Suspender el acenocumarol y remitir al paciente a un centro hospitalario para vigilar la aparición de sangrado.', 'Suspender temporalmente el acenocumarol y reanudar la anticoagulación cuando se haya alcanzado el intervalo terapéutico, calculando de nuevo la dosis.', 'Iniciar la administración de concentrado de complejo de protrombina o plasma fresco congelado según el peso.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 122, 'Sin clasificar', 'En relación con el taponamiento cardíaco, ¿cuál de las siguientes afirmaciones es cierta?:', 'Las manifestaciones ecocardiográficas y los cambios hemodinámicos se producen con anterioridad a la aparición de las manifestaciones clínicas.', 'Es típica la hipotensión, la taquicardia, la disminución de la presión venosa yugular y unos ruidos cardíacos atenuados.', 'El volumen de líquido pericárdico necesario para producir taponamiento es similar en una pericarditis aguda que en una pericarditis crónica.', 'El pulso paradójico es un dato de la exploración física característico que se define como un descenso de 5-10 mmHg en la tensión arterial sistólica durante la inspiración.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 123, 'Sin clasificar', 'Paciente de 71 años de edad, diabético, sin otras comorbilidades, diagnosticado previamente de estenosis aórtica grave. Ingresa por un síndrome coronario agudo sin elevación del ST, Killip I con un pico de troponinas ligeramente elevado. El cateterismo muestra enfermedad coronaria con lesiones proximales significativas de los tres vasos coronarios. Su función ventricular es normal. ¿Cuál de las siguientes estrategias terapéuticas es la más correcta?:', 'Tratamiento intervencionista con la implantación de stents coronarios en los 3 vasos e implantación simultanea de una bioprótesis aórtica transcatéter (TAVI).', 'Prótesis valvular aórtica mecánica quirúrgica, seguida de un tratamiento intervencionista percutáneo coronario en un segundo tiempo.', 'Prótesis aórtica biológica transcatéter (TAVI) y luego, de manera ambulatoria, tratar percutáneamente las arterias coronarias con stents.', 'Tratamiento quirúrgico simultáneo con recambio valvular y revascularización quirúrgica coronaria con bypass.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 124, 'Sin clasificar', 'Varón de 75 años que refiere disnea progresiva, con una tolerancia al esfuerzo cada vez menor. Refiere síncope en dos ocasiones en los últimos meses, coincidiendo con un esfuerzo moderado y refiere dolor torácico ocasional que aumenta con el esfuerzo. En la exploración destaca la presencia de pulso arterial de características parvus et tardus y un soplo mesosistólico. La analítica es normal excepto por una creatinina de 2,2 mg/dL. El cálculo de riesgo quirúrgico establece un riesgo intermedio. Señale cuál de las siguientes opciones terapéuticas es la más indicada:', 'Reemplazo quirúrgico de la válvula mitral.', 'Implante percutáneo de la válvula aórtica (TAVI).', 'Reemplazo quirúrgico de la válvula aórtica.', 'Valvulotomía mitral percutánea.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 125, 'Sin clasificar', 'Mujer de 43 años, nadadora profesional, sin antecedentes de interés, que refiere hinchazón y pesadez de brazo derecho de 72 horas de evolución. En la exploración destaca edema de miembro superior derecho con presencia de venas dilatadas en región pectoral. En relación con el enfoque diagnóstico, señale la respuesta INCO- RRECTA:', 'El eco-Doppler color es de gran valor como primera prueba diagnóstica.', 'Debe realizarse una radiografía simple de tórax para detectar anomalías óseas.', 'La angio-TC permite el diagnóstico de confirmación.', 'Debe realizarse una flebografía para confirmar la presencia de trombosis venosa axilosubclavia.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 127, 'Sin clasificar', 'Varón de 67 años diagnosticado de EPOC con una categoría GOLD 1, fumador, que refiere disnea con esfuerzos intensos, sin exacerbaciones. ¿Cuál de las siguientes sería la recomendación terapéutica más correcta?:', 'Tratamiento regular con broncodilatadores muscarínicos de acción prolongada (LAMA).', 'Tratamiento regular con broncodilatadores betaadrenérgicos de acción prolongada (LA- BA).', 'Tratamiento con LABA más glucocorticoides inhalados.', 'Tratamiento no farmacológico.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 128, 'Sin clasificar', 'Acude al servicio de urgencias un varón de 38 años diagnosticado de asma bronquial, sin otras comorbilidades. Refiere aumento de su disnea que le imposibilita para hablar y ortopnea. En la exploración se observa taquicardia de 125 lpm, sudoración y utilización de los músculos accesorios para respirar. Indique cuál de los siguientes es un signo de gravedad, de mala evolución y probablemente de indicación de ventilación mecánica:', 'Pulso paradójico.', 'Frecuencia respiratoria >25 respiraciones/minuto.', 'Silencio pulmonar en la auscultación.', 'Cianosis.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 129, 'Sin clasificar', 'Mujer de 70 años ingresada por traumatismo craneoencefálico grave con hemorragia subaracnoidea secundaria. El segundo día de ingreso presenta episodio de disnea y dolor torácico. Se realiza angioTC de tórax que confirma el diagnóstico de tromboembolismo de pulmón. El tratamiento de elección es:', 'Heparina de bajo peso molecular.', 'Rivaroxaban.', 'Acenocumarol.', 'Filtro de vena cava inferior.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 130, 'Sin clasificar', 'Paciente de 71 años que consulta por ictericia con bilirrubina total 6 mg/dL (bilirrubina directa 4 mg/dL), transaminasas normales y elevación de GGT 349 U/L y fosfatasa alcalina 260 U/L. En la ecografía de abdomen se aprecia dilatación de la vía biliar intra y extrahepática. No tiene dolor y refiere pérdida de peso de unos 5 kg en el último mes. Se le realiza una colangiopancreatografía retrógrada endoscópica apreciándose una estenosis abrupta del colédoco distal. ¿Cuál es su primera sospecha diagnóstica?:', 'Colangitis esclerosante primaria.', 'Coledocolitiasis.', 'Cáncer de páncreas.', 'Hepatitis aguda.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 131, 'Sin clasificar', 'Varón de 58 años con cirrosis compensada Child A-5 secundaria a hígado graso no alcohólico, sin otros antecedentes. Refiere astenia sin anorexia ni pérdida de peso. En una ecografía abdominal de cribado y posteriormente en una TC toracoabdominal trifásica se detectan cuatro lesiones hepáticas (una de ellas de 6 cm), hipervasculares en fase arterial y con lavado en fase venosa, con invasión de vena porta y sin metástasis extrahepáticas. No se observa ascitis. ¿Cuál de los siguientes es el mejor tratamiento?:', 'Quimioembolización transarterial.', 'Sorafenib.', 'Trasplante hepático.', 'Ablación con radiofrecuencia.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 132, 'Sin clasificar', '¿Cuál de los siguientes tipos de apendicitis aguda cursa más frecuentemente con signo del psoas positivo?:', 'Apendicitis pélvica.', 'Apendicitis mesoceliaca.', 'Apendicitis retrocecal.', 'Apendicitis medioinguinal.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 133, 'Sin clasificar', 'Paciente de 45 años con un episodio de colecistitis hace tres meses en el que se encontró colelitiasis por ecografía. Ahora presenta fosfatasa alcalina alta y en una nueva ecografía litiasis vesiculares de pequeño tamaño con vía biliar de 1 cm de diámetro. ¿Qué exploración de las siguientes realizaría antes de la intervención quirúrgica?:', 'Colangiografía retrógrada endoscópica.', 'Ecoendoscopia.', 'Colangiografía transparietohepática.', 'Colangiorresonancia.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 134, 'Sin clasificar', 'Respecto a la fisura anal, señale la afirmación INCORRECTA:', 'Consiste en un desgarro longitudinal de la piel que recubre la porción del canal anal distal a la línea dentada y origina un dolor intenso con la defecación.', 'Tiene dos formas típicas: la primaria o idiopática aparece en individuos sanos y no se asocia a ningún tipo de enfermedad; la secundaria se detecta en pacientes que sufren otro proceso.', 'La mayoría de las fisuras primarias se localizan en la comisura anterior, al ser ésta una zona del canal anal más susceptible al traumatismo y a la isquemia de la mucosa.', 'Las fisuras secundarias a otras enfermedades aparecen con frecuencia en posiciones más laterales.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 135, 'Sin clasificar', 'Mujer de 24 años intervenida hace un año de endometriosis tras presentar episodios de dolor abdominal intensos especialmente relacionados con el ciclo menstrual, acompañados ocasionalmente de náuseas y vómitos. A pesar de la intervención no ha apreciado ninguna mejoría, con progresivo empeoramiento y extensión del dolor a todo el cuerpo, junto con debilidad de extremidades. Los análisis rutinarios son normales, los anticuerpos antinucleares y el factor reumatoide son negativos, solo existe alguna analítica aislada con un Na de 132 mEq/L y alguna ALT (GOT) discretamente elevada. Ecografía abdominal y TC abdominopélvica recientes normales. Hace dos meses le diagnosticaron de depresión y fibromialgia. El tratamiento antidepresivo y analgésico con derivados opiáceos no parece tener ningún efecto. Lleva meses sin apenas levantarse de la cama. Nos piden una segunda opinión. Indica cuál de las siguientes pruebas diagnósticas deberíamos comprobar que ha sido realizada:', 'Estudio del gen MEFV.', 'Porfobilinógeno y ácido aminolevulínico en orina.', 'Anticuerpos antimitocondriales en sangre.', 'Calprotectina en heces.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 136, 'Sin clasificar', 'Varón de 34 años, que acude a urgencias por disnea de tres semanas de evolución, junto a la presencia de orina roja intermitente en los últimos diez días. En la exploración física presenta: temperatura 36,6 ºC, TA 132/72 mmHg, frecuencia respiratoria 16 rpm y cardiaca 88 lpm, junto a crepitantes finos diseminados en la auscultación pulmonar. Analítica de sangre: BUN 56 mg/dL, creatinina 5,8 mg/dL. Análisis de orina: hematíes 4+, proteínas 2+. Se realiza una biopsia renal que revela una glomerulonefritis difusa con semilunas. ¿Cuál de las siguientes pruebas confirmaría el diagnóstico?:', 'Concentración de complemento C3.', 'Títulos de anticuerpos antimembrana basal glomerular.', 'Títulos de antiestreptolisina O.', 'Cultivo de heces para Escherichia coli O157:H7.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 137, 'Sin clasificar', 'Paciente de 36 años que acude a urgencias por mal estado general. No tiene analíticas previas. Se detecta creatinina 10 mg/dL, Hb 6,5 g/L, ausencia de microalbuminuria, PTH 500 pg/ml, diuresis total conservada. Ecografía: riñones reducidos de tamaño. ¿Cuál de los siguientes diagnósticos es más probable?:', 'Poliquistosis renal autosómica dominante.', 'Glomerulonefritis rápidamente evolutiva.', 'Nefropatía tubulointersticial crónica.', 'Nefropatía diabética.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 138, 'Sin clasificar', 'Mujer de 32 años, embarazada de 10 semanas, que presenta en control rutinario bacteriuria asintomática. ¿Cuál de las siguientes medidas le parece más apropiada?:', 'Vigilancia estrecha y si aparecen síntomas iniciar tratamiento antibiótico empírico con amoxicilina 7-10 días.', 'Tratamiento empírico con fosfomicina a dosis única de 3 g y, si persiste la bacteriuria, urocultivo para valorar la sensibilidad.', 'Tomar muestra para urocultivo y comenzar de inmediato tratamiento empírico con betalactámicos durante 4-7 días.', 'Ecografía para descartar complicaciones, urocultivo e iniciar tratamiento empírico con nitrofurantoína 5-7 días.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 139, 'Sin clasificar', 'Varón de 73 años que acude a urgencias por dolor en zona lumbosacra que irradia hacia ambos flancos e hipogastrio de dos semanas de evolución que no cede con ibuprofeno a dosis altas. Tiene antecedentes de hipertensión, aneurisma de aorta infrarrenal y hernia discal L5-S1. Refiere pérdida de 6 kg de peso en el último mes. Exploración: Regular estado general, palidez mucocutánea y puñopercusión renal dudosa bilateral, sin otros hallazgos. Analítica: Hb 8,2 g/dL, VCM 81 fL, leucocitos 6.330 (fórmula normal), glucosa 89 mg/dL, urea 228 mg/dL, creatinina 5,4 mg/dL, Na 134 mEq/L, K 5,1mEq/L, Ca 11,3 mg/dL, proteínas totales 8,2 g/dL, albúmina 3,0 g/dL, PCR 0,54 mg/dL. Orina: proteínas 30 mg/dL con proteinuria estimada 1,5 g/24h. Sedimento de orina: leucocitos 20-30/campo, eritrocitos >50/campo. ¿Qué diagnóstico le parece más probable como causa del fracaso renal?:', 'Nefropatía intersticial aguda por analgésicos.', 'Mieloma múltiple.', 'Pielonefritis aguda.', 'Progresión del aneurisma aórtico con afectación bilateral de las arterias renales.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 140, 'Sin clasificar', 'Varón de 45 años que es traído a urgencias por presentar crisis tónico-clónicas en la vía pública. Se encuentra confundido y con respuestas poco coherentes e imprecisas. Revisando su historia, vemos que está diagnosticado de esquizofrenia y cuadro depresivo, pero parece que lleva unas semanas sin tomar el tratamiento. Exploración: estuporoso, sin otros hallazgos. Analítica con hemograma normal, glucosa 98 mg/dL, urea 37 mg/dL, creatinina 0,8 mg/dL, Na 118 mEq/L, K 3,4 mEq/L, Ca 9,7 mg/dL, osmolaridad sérica 252 mOsm/kg, osmolaridad urinaria 78 mOsm/kg, densidad de orina 1002, sedimento normal. ¿Cuál es la causa más probable de sus alteraciones electrolíticas?:', 'Insuficiencia suprarrenal.', 'Polidipsia primaria.', 'Diabetes insípida.', 'Síndrome de secreción inadecuada de ADH.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 141, 'Sin clasificar', 'En relación con la prostatectomía radical para el tratamiento del cáncer de próstata, señale la respuesta INCORRECTA:', 'Los factores relacionados con la continencia después de una prostatectomía radical incluyen edad avanzada, longitud de la uretra y experiencia del cirujano.', 'La recuperación de la función eréctil tras la prostatectomía radical se asocia con individuos más jóvenes, calidad de las erecciones antes de la operación y ausencia de daño a los haces neurovasculares.', 'El alprostadilo puede ayudar a recuperar una función sexual satisfactoria.', 'Un PSA >0,01 tras una prostatectomía radical es indicativo de recidiva bioquímica.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 142, 'Sin clasificar', 'En el cáncer de próstata es cierto que:', 'Los pacientes con enfermedad clínicamente localizada se tratan con prostatectomía radical, radioterapia o vigilancia activa.', 'Para su diagnóstico, los esquemas contemporáneos aconsejan biopsias con 10 cilindros.', 'Después de la prostatectomía radical, el PSA se vuelve indetectable en sangre en dos semanas.', 'En su tratamiento se utilizan antiandrógenos no esteroideos de primera generación, como bicalutamida y abiraterona.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 143, 'Sin clasificar', 'La realización de la biopsia selectiva del ganglio centinela y el mapa linfático en el cáncer de mama:', 'Está indicada en el cáncer de mama diseminado.', 'Está indicada si hay afectación clínica de los ganglios axilares.', 'Si es negativa no necesita ampliar la cirugía axilar.', 'No está indicada en varones con cáncer de mama.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 144, 'Sin clasificar', 'En relación con el tratamiento con radioterapia, señale la respuesta INCORRECTA:', 'Puede ser una alternativa de tratamiento curativo en diversas situaciones en oncología.', 'Se emplea también para determinadas patologías benignas.', 'Está contraindicada para el tratamiento de tumores pediátricos.', 'Tiene una demostrada utilidad en el control del dolor por metástasis óseas.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 145, 'Sin clasificar', 'Paciente con diagnóstico de glioblastoma multiforme. El informe de anatomía patológica refiere la presencia de metilación del promotor del gen MGMT (metil guanina metil transferasa). Con respecto al tratamiento de este paciente:', 'Esta información no es relevante.', 'La presencia de la metilación aumenta la supervivencia en pacientes tratados con temozolamida.', 'La presencia de la metilación contraindicaría el tratamiento con temozolamida.', 'La presencia de la metilación nos apoyaría la decisión de tratamiento con cisplatino frente al uso de un agente alquilante.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 146, 'Sin clasificar', 'La radioterapia en el tratamiento del cáncer de mama localmente avanzado y pronóstico molecular adverso:', 'Debe incluir las regiones ganglionares locorregionales.', 'Está contraindicada después de la mastectomía.', 'Está contraindicada después de la quimioterapia neoadyuvante.', 'Su mejor alternativa estética es la irradiación parcial de la mama.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 147, 'Sin clasificar', 'Varón de 19 años, asintomático, que presenta en una analítica preoperatoria una trombopenia (plaquetas 43 x 109/L) con niveles de hemoglobina y leucocitos normales. ¿Cuál de las siguientes actuaciones hay que realizar en primer lugar?:', 'Iniciar tratamiento con prednisona vía oral.', 'Realizar una biopsia de medula ósea para ver si la trombopenia es de origen central o periférico.', 'Realizar un examen morfológico del frotis sanguíneo para descartar la presencia de agregados plaquetarios inducidos por el anticoagulante.', 'Transfundir un concentrado de plaquetas para evitar un problema hemorrágico.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 148, 'Sin clasificar', 'Varón de 35 años, diagnosticado de hemofilia A desde la infancia, que recibe un trasplante hepático por hepatopatía crónica por virus de hepatitis C. Seis meses después del procedimiento presenta un estudio de coagulación normal con actividad de factor VIII del 100 %. ¿Cuál de las siguientes afirmaciones es cierta?:', 'La hemofilia se ha curado ya que el factor VIII se sintetiza en el hígado.', 'El tratamiento inmunosupresor ha solucionado el problema ya que estamos ante un cuadro autoinmune.', 'La larga vida media de los factores antihemofílicos usados en el trasplante hace que su efecto perdure varios meses.', 'Solo puede tratarse de un error o artefacto de laboratorio, ya que la hemofilia A es una enfermedad genética incurable hoy en día.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 149, 'Sin clasificar', 'Varón de 65 años que consulta por astenia progresiva y sensación de hormigueo en manos y pies. En la exploración física presenta tez amarillenta y disminución de la sensibilidad vibratoria y posicional en zonas distales. En el hemograma se observa VCM 120 fl con anisocitosis. Lo más probable es que padezca:', 'Mielopatía cervicoartrósica.', 'Mielitis necrosante subaguda.', 'Mielosis funicular.', 'Mielopatía crónica de la esclerosis múltiple.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 150, 'Sin clasificar', 'Varón de 41 años ingresado en la UCI por neumonía grave que precisa intubación y administración de catecolaminas. A la exploración se observa sangrado alrededor de los lugares de venopunción. Sus resultados de laboratorio son: 15.500 leucocitos; Hb 10,4 g/dL; Hcto 32 %; 52.000 plaquetas; LDH 820 U (normal 110-210); recuento de reticulocitos 4 %. ¿Cuál de los siguientes resultados NO es de esperar en este paciente?:', 'Fibrinógeno bajo.', 'Concentración elevada de antitrombina y proteína C.', 'Tiempo de protrombina y tiempo parcial de tromboplastina activada alargados.', 'Presencia de productos de degradación de la fibrina (dímero D).', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 151, 'Sin clasificar', '¿Cuál de los siguientes factores NO se ha asociado específicamente a un mayor riesgo de caídas en personas mayores?:', 'Osteoporosis.', 'Déficit visual.', 'Artrosis.', 'Polifarmacia.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 152, 'Sin clasificar', 'El Short Physical Performance Battery (SPPB) es una prueba de rendimiento físico empleada para la valoración de la función física, de la fragilidad y del riesgo de caídas en los mayores. ¿Qué aspectos se evalúan en este test?:', 'El equilibrio, la velocidad de la marcha y la capacidad para subir y bajar escaleras.', 'El equilibrio, la velocidad de la marcha y la capacidad para levantarse y sentarse de una silla.', 'El equilibrio, la velocidad de la marcha y la resistencia de los miembros superiores.', 'El equilibrio, la capacidad para subir y bajar escaleras y la capacidad para levantarse y sentarse de una silla.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 153, 'Sin clasificar', 'Uno de los siguientes mecanismos NO se ha propuesto en la patogenia básica del delirium en el paciente mayor:', 'La neuroinflamación.', 'El estrés oxidativo.', 'La excesiva actividad colinérgica.', 'El exceso de dopamina.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 154, 'Sin clasificar', 'Respecto a las prescripciones potencialmente inadecuadas en la persona mayor, es cierto que:', 'Las benzodiacepinas no aumentan el riesgo de caídas.', 'No existen criterios que faciliten la correcta prescripción de fármacos en este grupo de población.', 'Se recomienda la utilización de metformina en diabéticos con filtrados glomerulares menores de 30 ml/min.', 'Los estrógenos tópicos vaginales o el pesario con estrógenos están indicados para la vaginitis atrófica sintomática.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 155, 'Sin clasificar', 'En relación con la valoración funcional del paciente mayor, señale la respuesta INCORREC- TA:', 'Debe interpretarse como una medida global de la repercusión general de los problemas de salud en el paciente mayor.', 'Existe una jerarquía progresiva obligada tanto para la adquisición como para la pérdida de las actividades de la vida diaria (AVD), desde las instrumentales hasta las avanzadas.', 'En los pacientes mayores hospitalizados, se debe usar el estado funcional previo al ingreso hospitalario, para establecer así el plan de tratamiento y poner en marcha los objetivos realistas de la intervención.', 'Se suele medir con informes autorreferidos o notificados por una tercera persona, aunque en ocasiones, algunos miembros del equipo realizan una evaluación estructurada para medir la capacidad funcional real.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 156, 'Sin clasificar', 'Mujer de 79 años con antecedentes de HTA y gonartrosis bilateral, independiente para las actividades de la vida diaria, vive sola. Durante una visita al médico de familia se valora la sarcopenia. Realiza el test de levantarse de la silla para 5 elevaciones en 20 segundos, y el test Timed Up and Go en 26 segundos. Señale la respuesta correcta:', 'No presenta riego de caídas.', 'Tiene el diagnóstico de sarcopenia confirmada.', 'Si tuviera sarcopenia, ésta sería grave', 'No se sospecha sarcopenia.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 157, 'Sin clasificar', 'Varón de 24 años con ginecomastia bilateral, vello corporal escaso, testes de 3 cc, firmes, testosterona total 257 ng/dL (N>350), LH 11 mUI/mL (N<10), FSH 24 mUI/mL (N<10). El siguiente paso en el diagnóstico es:', 'Cariotipo.', 'Biopsia testicular.', 'RM de hipófisis.', 'Estudio del receptor de FSH.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 158, 'Sin clasificar', 'En relación con la hiperprolactinemia, señale la afirmación INCORRECTA:', 'La hiperprolactinemia puede estar ocasionada por fármacos.', 'El hipertiroidismo provoca elevación de prolactina.', 'El tratamiento médico de elección son los agonistas dopaminérgicos.', 'Causa amenorrea hipogonadotropa.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 159, 'Sin clasificar', 'Mujer de 63 años con diabetes mellitus tipo 2 de siete años de evolución, en tratamiento con metformina. HbA1c 7,6 %, índice de masa corporal 41,3 kg/m2. Para el tratamiento de la obesidad en esta paciente ¿cuál es la mejor opción de las siguientes?:', 'Pioglitazona.', 'Empagliflozina.', 'Semaglutida.', 'Alogliptina.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 160, 'Sin clasificar', 'Mujer de 24 años que consulta por odinofagia intensa de dos días de duración. Indica que tuvo mialgias y tos seca unos diez días antes, que se alivió la semana pasada. Se siente temblorosa y con sudoración. La exploración no muestra eritema o exudado faríngeo, pero sí dolor a la palpación en región anterior cervical baja, sin nódulos, masas ni adenopatías. En la exploración física tiene pulso 110 lpm, temperatura 38,2 ºC y un ligero temblor en reposo. ¿Cuál es el diagnóstico más probable?:', 'Tiroiditis subaguda.', 'Tiroiditis linfocitaria focal.', 'Tiroiditis aguda o infecciosa.', 'Enfermedad de Graves-Basedow.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 161, 'Sin clasificar', 'Mujer de 83 años ingresada desde hace 20 días por diverticulitis aguda complicada. Como parte de su tratamiento ha precisado una sigmoidectomía y recibe antibioterapia intravenosa con ertapenem desde hace 8 días. Presenta en los últimos días diarrea sin productos patológicos, ingestas del 25 % de lo recomendado y pérdida de 9 kg desde el momento del ingreso; actualmente pesa 75 kg y mide 1,55 m, IMC 31,2 kg/m2. Respecto a su estado nutricional ¿cuál es el diagnóstico más probable?:', 'No presenta alteración del estado nutricional.', 'Desnutrición grave relacionada con la enfermedad aguda.', 'Fallo intestinal por síndrome de intestino corto.', 'Obesidad grado II.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 162, 'Sin clasificar', 'Varón de 37 años con diagnóstico de carcinoma medular de tiroides de 2,6 cm, sin datos de afectación ganglionar en el estudio preoperatorio, tratado mediante tiroidectomía total y linfadenectomía del compartimento central; estadiaje T2N0M0, estadio I. Para el abordaje correcto de la enfermedad, hay que tener en cuenta múltiples aspectos. Seleccione la respuesta correcta:', 'El carcinoma medular de tiroides es el segundo tipo histológico de cáncer de tiroides más frecuente y se puede encontrar en el contexto de un síndrome de neoplasia endocrina múltiple tipo 2.', 'En la mayoría de los casos es esporádico y para el seguimiento bioquímico de la enfermedad se pueden usar tanto la calcitonina, como el CEA o la tiroglobulina.', 'El tratamiento sustitutivo con levotiroxina debe ajustarse para conseguir una TSH suprimida.', 'Siempre está indicado el estudio genético del protooncogen RET, ya que se puede encontrar mutado tanto en los carcinomas medulares hereditarios como en los esporádicos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 163, 'Sin clasificar', 'En el manejo perioperatorio del control glucémico en un paciente diabético sometido a una artroplastia de cadera señale la afirmación INCO- RRECTA:', 'El control glucémico intensivo en el periodo perioperatorio por lo común se acompaña de mejoría en los resultados.', 'Las cifras de glucemia deseadas se situarán entre 100 y 180 mg/100mL en el periodo perioperatorio.', 'Si el control glucémico es muy deficiente (HbA1c >9 %) debería intentarse su optimización antes de la cirugía.', 'La optimización del control glucémico perioperatorio reduce las infecciones y, en pacientes quirúrgicos críticos, puede reducir la mortalidad.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 164, 'Sin clasificar', 'Varón de 80 años procedente de una residencia que presenta una sepsis de origen urinario que no ha respondido al tratamiento empírico con ceftriaxona. En los hemocultivos y urocultivos crece E. coli resistente a cefalosporinas. El laboratorio nos informa que es una cepa productora de betalactamasas de espectro extendido. ¿Qué antibiótico, entre los siguientes, debe utilizarse?:', 'Ertapenem.', 'Amoxicilina/clavulánico.', 'Tigeciclina.', 'Ceftazidima.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 165, 'Sin clasificar', 'Varón que consulta por haber tenido, hace 48 horas, una relación sexual de riesgo sin protección, con eyaculación, con una persona con VIH que está en tratamiento antirretroviral y mantiene una carga viral indetectable desde hace años. La prueba de VIH hecha al paciente en ese momento en urgencias es negativa. ¿Cuál es la mejor recomendación que debemos darle?:', 'No debe hacer nada, ya que el riesgo de transmisión del VIH es insignificante.', 'Debe recomendarse gammaglobulina IV en las primeras 72 horas.', 'Debe hacer profilaxis postexposición frente al VIH durante 28 días.', 'Podría haber realizado profilaxis postexposición, pero ya es tarde para iniciarla.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 166, 'Sin clasificar', 'Un paciente de 22 años presenta síntomas de proctitis, con moco, tenesmo rectal y fiebre. En la exploración se encuentra febril y presenta adenopatías inguinales bilaterales. La PCR del exudado rectal muestra Chlamydia trachomatis serovar linfogranuloma venéreo. ¿Cuál de los siguientes es el mejor tratamiento?:', 'Doxiciclina 100 mg cada 12 horas durante 21 días.', 'Cloxacilina 500 mg cada 6 horas durante 7 días.', 'Ceftriaxona 0,5 g IM (una única dosis) y azitromicina 1 g VO (una única dosis).', 'Moxifloxacino 400 mg una vez al día durante 7 días.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 167, 'Sin clasificar', 'Varón de 34 años diagnosticado de otitis media 5 días antes, sin otros antecedentes, que comienza con fiebre de 39 ºC, cefalea y rigidez de nuca. Se realiza una punción lumbar que es sugerente de meningitis bacteriana. Decide iniciar tratamiento empírico hasta recibir el cultivo y los resultados del antibiograma. ¿Cuál de los siguientes sería el mejor tratamiento?:', 'Ceftriaxona más vancomicina.', 'Cefotaxima más ampicilina.', 'Moxifloxacino más vancomicina.', 'Meropenem más ampicilina.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 168, 'Sin clasificar', 'En las faringitis causadas por Streptococcus pyogenes del grupo A es cierto que:', 'El cuadro clínico es diagnóstico: fiebre elevada, malestar general, dolor de garganta y en ocasiones, adenopatías.', 'Los test de diagnóstico rápido presentan una elevada sensibilidad, por lo que si el resultado es positivo podemos establecer un diagnóstico definitivo.', 'La pauta de tratamiento de elección es amoxicilina-clavulánico 875 mg cada 8 horas durante 10 días.', 'El tratamiento antibiótico ha demostrado reducir la posibilidad de fiebre reumática pero no de glomerulonefritis postestreptocócica.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 169, 'Sin clasificar', 'Paciente de 72 años, con antecedentes de diabetes mellitus e hipertensión arterial, que presenta fiebre de tres semanas de evolución con malestar general, sin foco aparente aunque se intuía un soplo cardiaco por lo que es ingresado. Los hemocultivos fueron positivos para Staphylococcus aureus resistente a la meticilina con sensibilidad intermedia a vancomicina. Un ecocardiograma mostró una imagen compatible con vegetación sobre la válvula mitral. Se inició tratamiento con daptomicina 10 mg/kg IV una vez al día. Tras siete días de tratamiento sigue con fiebre y presenta ortopnea. En la exploración aparece un soplo sistólico 3/6 en ápex, irradiado a axila izquierda. La Rx de tórax muestra un infiltrado pulmonar bilateral hiliofugal alvéolo-intersticial. ¿Cuál de las siguientes es la actitud más adecuada?:', 'Indicar cirugía de recambio valvular urgente.', 'Añadir ceftarolina IV, diuréticos y control en cuidados intensivos.', 'Retirar daptomicina y pautar vancomicina a dosis altas y gentamicina, junto con diuréticos y control en cuidados intensivos.', 'Solicitar un nuevo ecocardiograma, administrar tratamiento diurético y control en cuidados intensivos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 170, 'Sin clasificar', 'Mujer de 67 años que sufrió dos meses antes de la consulta una infección por Clostridioides difficile. Acude por un nuevo cuadro compatible con una infección recurrente por el mismo germen. ¿Cuál es el tratamiento más eficaz para evitar recurrencias adicionales de la infección?:', 'Metronidazol.', 'Fidaxomicina.', 'Vancomicina.', 'Rifaximina.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 171, 'Sin clasificar', 'Mujer de 52 años con hipertensión arterial de difícil control que consulta por la aparición de lesiones eritematosas en las mejillas, el tórax y los brazos, junto a poliartralgias, tras iniciar tratamiento con hidralazina. Los análisis de autoinmunidad básica detectan positividad de los anticuerpos antinucleares de 1:160 (N <1:80). Ante la sospecha de lupus inducido por fármacos, ¿cuál de los siguientes autoanticuerpos debe investigarse?:', 'Anticuerpos antihistona.', 'Anticuerpos anticitoplasma de neutrófilo.', 'Anticuerpos anticromatina.', 'Anticuerpos antifosfolipidos.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 172, 'Sin clasificar', 'En una paciente diagnosticada recientemente de esclerodermia difusa, ¿cuáles son los controles que deben realizarse periódicamente durante los primeros meses de evolución?:', 'Ecocardiografía Doppler y electrocardiograma.', 'Índice de Rodnan (prueba del grosor de la piel) y capilaroscopia.', 'Función renal y presión arterial.', 'Pruebas funcionales respiratorias y TC de tórax.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 173, 'Sin clasificar', 'Varón de 23 años, de raza caucásica y natural de Zaragoza, sin antecedentes patológicos ni familiares destacables. Desde los cinco años presenta episodios autolimitados de fiebre hasta 39 ºC, dolor abdominal difuso, mialgias generalizadas y lesiones eritematosas en la parte inferior de las piernas. A la edad de 10 años fue apendicectomizado, aunque en el apéndice no se evidenciaron signos inflamatorios. Los episodios duran unos 2- 3 días, mejoran con AINE y se repiten cada 1 o 2 meses. Durante los brotes febriles, en la exploración física destaca un dolor abdominal difuso con defensa a la palpación superficial y lesiones erisipeloides en la cara antero-lateral y distal de las piernas, y en los análisis una elevación de la proteína C reactiva de hasta 6 mg/dL (N <1 mg/dL), que se normalizan en periodos sin fiebre. ¿Cuál es el diagnóstico inicial más probable?:', 'Síndrome de Muckle-Wells (síndrome periódico asociado a criopirina).', 'Fiebre mediterránea familiar.', 'Síndrome de Blau (granulomatosis artrocutaneouveal).', 'Síndrome periódico asociado al receptor del factor de necrosis tumoral.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 174, 'Sin clasificar', 'Mujer de 41 años con antecedentes de retraso del crecimiento durante la infancia sin alteración en los estadios del desarrollo. Refiere intolerancia al ejercicio desde la juventud que describe como falta de habilidad para los deportes. En los últimos 4 años refiere aumento del perímetro abdominal; una ecografía evidenció hepatomegalia leve, uniforme, sin datos ecográficos de cirrosis. Tras una infección leve por COVID-19 hace 8 meses desarrolla inestabilidad y debilidad simétrica generalizada y progresiva que le impide realizar las actividades de la vida diaria, con episodios de sudoración. Exploración física: fuerza muscular globalmente disminuida de forma simétrica. Discreta hepatomegalia no dolorosa. Análisis: pH arterial 7,38, PaO2 99 mmHg, PaCO2 39 mmHg, glucemia 49 mg/dL, ASAT/ALAT 63/71 U/L, lactato 14 mg/dL (N: 5- 20), amonio 25 µmol/L (N: 9-33), TSH: 4,6 mUI/L (N: 0,37-4,7), creatincinasa 500 U/L (N: <300), cetonuria ++. Un ecocardiograma evidenció ligera hipertrofia y dilatación del ventrículo izquierdo. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Glucogenosis tipo III.', 'Síndrome post COVID-19.', 'Hipertiroidismo primario.', 'Alteración en la beta-oxidación de los ácidos grasos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 175, 'Sin clasificar', 'Mujer de 42 años que desde hace 4 años, con el frío, presenta cambio de coloración de los dedos de las manos con intensa palidez. Desde hace unos meses precisa tratamiento con omeprazol por sensación de ardor retroesternal ocasional y en la exploración se observa dificultad para pinzar la piel en el dorso de las manos. ¿Cuál de los siguientes autoanticuerpos consideramos esencial para su correcto seguimiento, por las consecuencias pronósticas que comportaría su positividad?:', 'Anti-ADN', 'Anti-proteinasa 3.', 'Anti-membrana basal glomerular.', 'Anti-ARN polimerasa III.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 176, 'Sin clasificar', 'En el momento del diagnóstico de un síndrome de Sjögren, ¿qué factores se asocian a la posibilidad de desarrollar un linfoma B?:', 'Fiebre y adenopatías.', 'Anticuerpos anti-La y anti-Ro.', 'Esplenomegalia y pancitopenia.', 'Hipocomplementemia y crioglobulinemia.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 177, 'Sin clasificar', 'Varón de 45 años, no fumador y no consume alcohol, que consulta por disnea progresiva de dos meses de evolución. Exploración física: afebril, frecuencia respiratoria 19 rpm, frecuencia cardiaca 120 lpm, SatO2 93 %. Lesiones cutáneas de aspecto ulceroso en palmas y dedos de las manos; estertores crepitantes en ambas bases pulmonares; fuerza muscular normal. Análisis: CK 300 UI/L (N: <150) y aldolasa 12 UI/L (N: <6 ). Radiografía de tórax: patrón intersticial bibasal. Una biopsia muscular evidenció necrosis de células musculares, atrofia perifascicular e infiltrados inflamatorios perivasculares. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Dermatomiositis asociada al autoanticuerpo anti-TIF1-gamma (transcription intermediary factor 1-gamma).', 'Miopatía inflamatoria idiopática asociada al autoanticuerpo anti-FHL-1 (Four and a half LIM domains 1).', 'Dermatomiositis asociada al autoanticuerpo anti-MDA-5 (melanoma differentiationassociated gen 5).', 'Miopatía miofibrilar asociada al anticuerpo anti-desmina.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 178, 'Sin clasificar', 'Varón de 56 años, que acude para control de su diabetes mellitus tipo 2. En tratamiento con metformina 850 mg dos veces al día desde hace ocho semanas. Refiere encontrarse bien, sin poliuria ni polidipsia, con controles glucémicos entre 140- 180 mg/dL. Su última HbA1c fue 7,7 %. Exploración física: tensión arterial 137/86 mmHg y pulso 74 lpm. El fondo de ojo revela retinopatía proliferativa leve. En el sedimento urinario se observa microalbuminuria de 180 mg/g creatinina. ¿Cuál es el siguiente paso más adecuado?:', 'Estudio de orina de 24 horas para determinación de proteínas y creatinina.', 'Indicar una ecografía renal.', 'Iniciar tratamiento con antagonistas del calcio.', 'Iniciar tratamiento con IECAs.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 179, 'Sin clasificar', 'Mujer de 65 años que consulta por hipercolesterolemia. Niega antecedentes personales o familiares de dislipemia. En la analítica destaca: colesterol total 500 mg/dL, colesterol LDL 350 mg/dL, HDL 38 mg/dL y triglicéridos 206 mg/dL. Resto de análisis y hormonas tiroideas normales, salvo proteínas totales 5,9 g/dL (N: 6,4-8,3) y albúmina 3 g/dL (N: 3,5-5). Orina elemental con relación albúmina/creatinina de 2.000 mg/g y proteinuria +++. En el examen físico no hay xantomas ni arco corneal, sí discretos edemas maleolares. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Dislipemia secundaria a un síndrome nefrótico.', 'Hipercolesterolemia familiar heterocigota.', 'Hipercolesterolemia familiar homocigota.', 'Hipercolesterolemia familiar recesiva por afectación del gen LDLRAP1.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 180, 'Sin clasificar', '¿Qué tipo de deseos del paciente NO pueden atenderse en una planificación anticipada de decisiones (o planificación compartida de la atención)?:', 'Rechazo de intervenciones con riesgo vital.', 'Donación de órganos.', 'Rechazo de intervenciones sin riesgo vital.', 'Instauración de intervenciones fútiles, sin indicación clínica.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 181, 'Sin clasificar', 'Mujer de 89 años, institucionalizada en residencia desde hace 5 años por demencia tipo Alzheimer de 8 años de evolución. Es dependiente para todas las actividades básicas de la vida diaria y presenta deterioro cognitivo grave. No reconoce a sus familiares ni es capaz de emitir lenguaje. Ingresa por un cuadro de infección respiratoria de mecanismo aspirativo. Tras completar un ciclo antibiótico evoluciona favorablemente pero al intentar reintroducir la ingesta oral persiste disfagia con riesgo alto de aspiración. El médico responsable propone a los hijos no iniciar estrategias de alimentación enteral por sondas, sino dejar la enfermedad a su evolución natural, realizando un tratamiento sintomático de eventuales complicaciones. ¿Qué concepto ético subyace a esta decisión clínica?:', 'Rechazo al tratamiento.', 'Eutanasia activa.', 'Limitación de esfuerzo terapéutico.', 'Obstinación terapéutica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 182, 'Sin clasificar', 'Paciente de 48 años, diagnosticado de esclerosis lateral amiotrófica hace 3 años. Precisa ayuda para todas las actividades básicas de la vida diaria y sonda para mantener su alimentación. En el último año, ha tenido varios ingresos por infecciones respiratorias. Actualmente ingresa por una nueva infección respiratoria con insuficiencia respiratoria global asociada. El paciente requiere ventilación mecánica no invasiva como parte del tratamiento. Tras 5 días de ingreso, sin presentar mejoría clínica, el paciente manifiesta que está viviendo un sufrimiento intolerable , que no encuentra sentido a continuar viviendo en una situación así y solicita que se le retire la ventilación mecánica, aunque le provoque la muerte. Después de varias conversaciones, Vd. confirma con el paciente que este es su deseo y que su familia apoya la decisión. Esta se trata de una decisión de:', 'Rechazo de tratamiento.', 'Limitación del esfuerzo terapéutico.', 'Obstinación terapéutica.', 'Eutanasia.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 183, 'Sin clasificar', 'Varón de 65 años traído al servicio de Urgencias intubado y sedado por un politraumatismo tras un accidente de tráfico. Tras la valoración inicial se objetiva una laceración esplénica que requiere intervención quirúrgica urgente. ¿Cómo se debería proceder con el proceso de consentimiento y la firma del formulario de consentimiento a la cirugía?:', 'No es posible realizar una intervención quirúrgica urgente cuando sólo se obtiene un consentimiento verbal de un representante del paciente.', 'Si no se pudiera contactar con ningún familiar o allegado del paciente no podría realizarse la intervención quirúrgica.', 'El médico responsable debe intentar contactar con los familiares del paciente y, tras explicar la situación, obtener de ellos el consentimiento para realizar la intervención.', 'Sin un documento de consentimiento informado firmado por los familiares del paciente no es posible realizar la intervención.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 184, 'Sin clasificar', 'En relación con el tratamiento de la depresión mediante fármacos antidepresivos en pacientes con enfermedades terminales. ¿Cuál de las siguientes es la mejor opción?:', 'La dosis inicial de los inhibidores selectivos de la recaptación de serotonina debe ser la misma que la utilizada en adultos sin enfermedad terminal.', 'Se recomienda evitar los antidepresivos tricíclicos, a menos que se utilicen como complementos en el tratamiento del dolor.', 'En pacientes en los que predominan síntomas como ansiedad o insomnio es preferible el uso de fluoxetina.', 'La trazodona, incluso cuando se emplea a dosis bajas, está contraindicada por sus frecuentes efectos adversos.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 185, 'Sin clasificar', 'En relación con el tratamiento del estreñimiento en los pacientes con enfermedades terminales, señale la respuesta INCORRECTA:', 'En presencia de tratamiento con opioides son recomendables los suplementos de fibra vegetal.', 'Los elementos fundamentales del tratamiento son los laxantes estimulantes y osmóticos, reblandecedores de heces, líquidos y enemas.', 'Para evitar el estreñimiento causado por los opioides se debe recurrir a la combinación de un laxante y un reblandecedor de heces.', 'Si no hay defecación tras varios días de tratamiento, se necesita el tacto rectal para extraer el material impactado.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 186, 'Sin clasificar', 'Varón de 95 años que ingresa en el servicio de urgencias del hospital con el antecedente de traumatismo craneal por caída casual en el domicilio y en una TC craneal se observa hematoma epidural agudo. Fallece poco tiempo después del ingreso en el propio servicio de urgencias. Desde el punto de vista legal, el facultativo responsable tiene la obligación de cumplimentar solo uno de los siguientes documentos:', 'Certificado ordinario de defunción.', 'Boletín estadístico de defunción con intervención judicial (muerte violenta).', 'Boletín estadístico de defunción.', 'Parte de lesiones.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 187, 'Sin clasificar', 'Si una persona que es menor de 18 años desea ser donante de órgano de vivo. ¿Cuál de las siguientes afirmaciones es cierta?:', 'Si la persona tiene entre 16 y 18 años, la decisión corresponde a la persona menor si demuestra que es capaz de comprender el alcance del procedimiento. pero los padres o tutores deben ser consultados obligatoriamente.', 'Si la persona tiene entre 16 y 18 años, la decisión corresponde a los padres o tutores legales, pero la persona menor debe ser consultada si demuestra que es capaz de comprender el alcance del procedimiento.', 'En caso de conflicto entre el criterio del menor y el de sus padres o tutores legales, debe resolver un juez mediante la aplicación del principio del interés superior del menor.', 'Los menores de 18 años no pueden ser donantes de órganos de vivo, según la Ley. No hay excepciones.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 188, 'Sin clasificar', 'especto de la escabiosis o sarna, señale la afirmación INCORRECTA:', 'Es una infestación cutánea muy contagiosa causada por el Sarcoptes scabiei.', 'Se trata de una erupción polimorfa en la que confluyen lesiones producidas por el propio ácaro que se localizan en los pliegues interdigitales y las muñecas, y en menor medida en las axilas, en las mamas y en el pene.', 'En los casos muy persistentes del adulto las lesiones suelen generalizarse por el tronco y la cara.', 'El análisis mediante dermatoscopia del final del trayecto de un surco puede poner en evidencia el ácaro, que se ve en forma de ala delta.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 190, 'Sin clasificar', 'Varón de 50 años, sin antecedentes de interés salvo que es fumador de 20 cigarrillos al día. Realiza vida sedentaria y no toma medicación de forma crónica. A la exploración se observa: circunferencia abdominal 104 cm, presión arterial 136/89 mmHg. En la analítica destaca: triglicéridos 160 mg/dL, colesterol HDL 30 mg/dL y glucemia basal 88 mg/dL. Según los criterios diagnósticos de síndrome metabólico del ATPIII, 2001 (Adult Treatment Panel III. The National Cholesterol Education Program). ¿Cuántos criterios presenta?:', 'Dos criterios.', 'Tres criterios.', 'Cuatro criterios.', 'Cinco criterios.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 191, 'Sin clasificar', 'Paciente de 50 años que consulta por presentar una adenopatía localizada. ¿Qué localización de las siguientes debe hacer sospechar un mayor riesgo de malignidad?:', 'Retroauricular.', 'Supraclavicular.', 'Axilar.', 'Inguinal.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 192, 'Sin clasificar', 'Varón de 70 años, con antecedentes de hipertensión arterial y dislipemia, que consulta a su médico de familia tras ingreso reciente por insuficiencia cardiaca. Actualmente se encuentra asintomático, en tratamiento con enalapril, furosemida, atorvastatina y ácido acetilsalicílico. En la exploración física se observa frecuencia cardíaca 78 lpm, sin signos de insuficiencia cardiaca. En el ecocardiograma realizado durante el ingreso se observa hipertrofia ventricular izquierda y fracción de eyección del 30 %. ¿Cuál es la actitud terapéutica más adecuada?:', 'Añadir bisoprolol.', 'Añadir diltiazem.', 'Suspender enalapril e iniciar losartán.', 'Ningún cambio en la medicación.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 193, 'Sin clasificar', 'Paciente de 50 años con diabetes mellitus en tratamiento con insulina. ¿Cuál es el objetivo recomendado para la concentración de glucosa plasmática capilar postprandial?:', '< 126 mg/dL.', '< 140 mg/dL.', '< 180 mg/dL.', '< 220 mg/dL.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 194, 'Sin clasificar', 'En pacientes con diabetes mellitus tipo 2 en tratamiento a largo plazo con el mismo fármaco, ¿cuál de los siguientes NO se asocia con una disminución de la probabilidad de complicaciones cardiovasculares?:', 'Inhibidores del cotransportador sodio-glucosa tipo 2 (iSGLT2).', 'Agonistas de los receptores de glucagón tipo 1 (arGLP1).', 'Insulina.', 'Metformina.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 195, 'Sin clasificar', 'Mujer de 14 años que es llevada a urgencias por sus padres tras haber ingerido 12 horas antes múltiples comprimidos de paracetamol (no saben concretar la cantidad). Está nauseosa, pálida y sudorosa. Se solicitan niveles de paracetamol en sangre que se encuentran en rango de probable toxicidad hepática. Las pruebas de función hepática y coagulación son normales. ¿Cuál será la actitud a seguir?:', 'Observación y repetición de niveles de paracetamol en 4 horas.', 'Iniciar tratamiento con N-acetilcisteína y mantenerlo durante 12 horas.', 'Observación y repetición de niveles de paracetamol, pruebas hepáticas y coagulación en 4 horas.', 'Iniciar tratamiento con N-acetilcisteína y mantenerlo en función de la evolución de los niveles de paracetamol, pruebas hepáticas y renales.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 196, 'Sin clasificar', 'En el manejo inicial de un paciente con un shock séptico en urgencias, señale la afirmación IN- CORRECTA:', 'Se debe determinar el lactato sérico como un marcador de hipoperfusión tisular.', 'Se debe realizar una toma precoz (1ª hora) de muestra para cultivos e inicio de antibioterapia de amplio espectro.', 'La reposición del volumen se debe realizar con cristaloides dentro de las 3 primeras horas.', 'Se recomienda la dopamina como el vasopresor de primera elección.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 197, 'Sin clasificar', 'Varón de 70 años, sin hogar, expuesto durante horas a temperaturas elevadas, trasladado a urgencias por sospecha de golpe de calor. Presenta temperatura 40,5 ºC, desorientación y disminución del nivel de conciencia. ¿Cuál de las siguientes es la actuación inicial más correcta?:', 'Medidas generales de soporte y baño por inmersión para reducir la temperatura corporal.', 'Medidas de soporte, enfriamiento con esponjas húmedas (a 15-20 ºC) sobre la superficie corporal y asegurar una hidratación adecuada por vía intravenosa.', 'El uso de mantas de enfriamiento es la medida más eficaz para la rápida reducción de la temperatura corporal.', 'Medidas de soporte, enfriamiento con esponjas empapadas en alcohol aplicadas sobre la superficie corporal y antipiréticos.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 198, 'Sin clasificar', 'El SOFA rápido o qSOFA (Quick Sequential Organ Failure Assessment), es un índice pronóstico en pacientes con infección. Si un paciente acude a urgencias de un centro de salud por un cuadro infeccioso y en la exploración presenta 15 puntos en la escala de Glasgow, frecuencia cardiaca 110 lpm, frecuencia respiratoria 18 rpm, temperatura 38 ºC y presión arterial sistólica de 92 mmHg. ¿Qué puntuación presenta si se utiliza el qSOFA?:', 'Un punto.', 'Dos puntos.', 'Tres puntos.', 'Cuatro puntos.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 199, 'Sin clasificar', 'Mujer de 65 años rescatada de un incendio de un almacén de envases de plástico y trasladada a urgencias con cuadro de cefalea, náuseas, vómitos y somnolencia tras inhalación de humo. De los siguientes, ¿cuál es el diagnóstico de sospecha y el tratamiento inicial más correcto?:', 'Intoxicación por cloro. Nebulización bicarbonatada (4 ml de suero salino 0,9% + 6 mL de bicarbonato sódico 1M) en las primeras 3 horas tras la exposición.', 'Inhalación de vapores nitrosos. Tratamiento sintomático y de soporte.', 'Intoxicación por monóxido de carbono y cianuro. Medidas de soporte junto con oxigenoterapia al 100 % e hidroxicobalamina con una dosis de 5 g IV en 10 min.', 'Intoxicación por absorción cutánea de tóxicos. Medidas de soporte, oxigenoterapia, limpieza cutánea y atropina (1 mg IV) que se puede repetir cada 2-3 minutos hasta mejoría clínica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 200, 'Sin clasificar', 'Varón de 59 años, sin antecedentes personales, que consulta por astenia y disnea de esfuerzo de varios meses de evolución. En su historia clínica previa se observa que no acude a consulta desde hace más de diez años. En la exploración física se detecta palidez conjuntival, siendo el resto normal. El electrocardiograma es normal y en el hemograma destaca: Hb 10,6 g/dL, Hcto 31 %, VCM 75 fl, ancho de distribución eritrocitaria 22 %. ¿Cuál de los siguientes sería el paso inicial apropiado?:', 'Tacto rectal y programar colonoscopia.', 'Espirometría y programar broncoscopia.', 'Medir haptoglobina y realizar test de Coombs.', 'Medir vitamina B12 y programar biopsia de médula ósea.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 201, 'Sin clasificar', 'Los pacientes oncológicos pueden presentar complicaciones cardiovasculares como el síndrome de vena cava superior. Señale en cuál de las siguientes neoplasias es más frecuente dicha complicación:', 'Linfoma.', 'Cáncer de mama.', 'Cáncer de pulmón.', 'Metástasis ganglionares mediastínicas de otros orígenes.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 202, 'Sin clasificar', 'Varón de 75 años que acude al hospital por insuficiencia renal rápidamente progresiva, anuria, mal estado general y fiebre. Los datos de laboratorio muestran ANCAs positivos y Ac anti-MBG negativos. Se realiza biopsia renal. En la tinción de hematoxilina-eosina se observa glomerulonefritis necrotizante con reacción epitelial extracapilar y formación de semilunas en el 80 % de los glomérulos. Las técnicas de inmunofluorescencia directa para IgA, IgG, IgM, C3, C1q, kappa y lambda son negativas. ¿Cuál es el diagnóstico anatomopatológico?:', 'Glomerulonefritis postinfecciosa.', 'Vasculitis pauciinmunitaria.', 'Nefropatía IgA.', 'Síndrome de Goodpasture.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 203, 'Sin clasificar', 'Varón de 30 años con antecedente de hemorragia digestiva alta hace 1 año. En la gastroscopia se observaron varias úlceras pépticas. Consulta por un episodio de cólico renal. En la analítica se objetiva calcio 11,1 mg/dL (N: 8,6-10,3 mg/dL), hormona paratiroidea 150 ng/L (N: 8-51 ng/L) con niveles normales de albúmina y 25-OH vitamina D. ¿Con qué síndrome se relacionan estos datos clínicos y analíticos?:', 'Complejo de Carney.', 'Síndrome poliglandular tipo 1.', 'Neoplasia endocrina múltiple tipo 2A.', 'Neoplasia endocrina múltiple tipo 1.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 204, 'Sin clasificar', 'El síndrome de lisis tumoral, frecuente en neoplasias hematológicas, se caracteriza por las siguientes complicaciones, EXCEPTO:', 'Hipercalcemia.', 'Hiperuricemia.', 'Hiperfosfatemia.', 'Uremia.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 205, 'Sin clasificar', 'Varón de 35 años que presenta desde hace 3 meses dolor e inflamación en la 2ª y 3ª articulaciones metacarpofalángicas derecha y en la 3ª y 4ª interfalángicas de la mano izquierda. En la exploración física se observan lesiones cutáneas descamativas en las zonas extensoras de los codos y en la rodilla derecha. Los primeros análisis muestran VSG 34 mm , PCR 1,8 mg/dL (N: 0- 0,5), factor reumatoide y anticuerpos anti péptidos cíclicos citrulinados negativos. Radiografías de manos: aumento de partes blandas sin erosiones. ¿Cuál de los siguientes diagnósticos es el más probable?:', 'Artritis reumatoide.', 'Lupus eritematoso sistémico.', 'Artritis psoriásica.', 'Artrosis.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 206, 'Sin clasificar', 'Mujer de 20 años que presenta en los meses de invierno lesiones violáceas sobreelevadas en la zona distal de los dedos de los pies. Refiere picor y aparición ocasional de heridas en los dedos que cicatrizan en pocos días. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Fenómeno de Raynaud.', 'Eritema pernio.', 'Acrocianosis.', 'Eritromelalgia.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 207, 'Sin clasificar', 'Con respecto a las enfermedades torácicas relacionadas con la exposición al asbesto, señale la respuesta INCORRECTA:', 'La presencia de derrame pleural en paciente con exposición conocida a asbesto indica mesotelioma maligno.', 'Las opacidades lineales irregulares en bases pulmonares son los signos radiográficos característicos de asbestosis.', 'El cáncer pulmonar es la tumoración más frecuente relacionada con la exposición al asbesto.', 'Las placas pleurales indican que hubo tan sólo exposición, pero no afectación pulmonar.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 208, 'Sin clasificar', 'Varón de 68 años que presenta afectación del estado general de 4 días de evolución con fiebre y tos con expectoración. Exploración física: crepitantes bibasales. Radiografía de tórax: infiltrados con patrón alveolo intersticial periférico. PCR para SARS-CoV 2 positiva. Relación entre presión parcial de oxígeno en sangre arterial y fracción inspiratoria de oxígeno es 250. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Hemorragia pulmonar secundaria a infección por SARS-CoV 2.', 'Neumonía bacteriana en paciente positivo a SARS-CoV2.', 'Neumonía por SARS-CoV 2 con síndrome de distrés respiratorio agudo.', 'Infección grave por SARS-CoV 2 con hipoventilación alveolar.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 209, 'Sin clasificar', 'Varón de 56 años con hernia de hiato y rinitis persistente por sensibilización a arizónicas que consulta por empeoramiento en las últimas semanas, con aparición de bloqueo nasal, lagrimeo, tos, disnea de esfuerzo y sibilancias inspiratorias, que no mejora con su broncodilatador y corticoide inhalado habituales. Convive con un perro desde hace 5 años. Utiliza un humidificador desde hace 3 meses durante la noche por sequedad de garganta. Auscultación pulmonar: crepitantes finos en bases. Espirometría: FVC 2740 (68 %), FEV1 2530 (79 %), FEV1/FVC 0,92. TC tórax: infiltrados de localización subpleural con fino patrón reticular en ambos lóbulos inferiores y algunos de forma parcheada en lóbulos superiores. ¿Cuál sería el diagnóstico más probable y la actitud a tomar?:', 'Neumonitis por hipersensibilidad. Se recomienda retirar humidificador y control evolutivo.', 'Tos relacionada con reflujo gastroesofágico. Se recomienda comenzar con inhibidores de la bomba de protones.', 'Crisis asmática en paciente con sensibilización al polen. Se recomienda añadir corticoides sistémicos.', 'Alergia al pelo de animales. Se recomienda realizar pruebas de sensibilización.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2022, 210, 'Sin clasificar', 'Paciente de 62 años que consulta seis meses después de sufrir un infarto agudo de miocardio. Actualmente fuma 15 cigarrillos al día, tiene sobrepeso y hace vida sedentaria. Está en tratamiento con atorvastatina 80 mg/día y ramipril 5 mg/día. Aporta análisis con colesterol LDL 68 mg/dL, glucemia 115 mg/dL, Hb1Ac 5,7 %, ausencia de microalbuminuria, presión arterial en consulta de 140/85 mmHg. Señale la medida más eficaz, de las siguientes, para evitar un nuevo evento cardiovascular:', 'Optimizar el tratamiento de la hipertensión arterial, ya que está mal controlado.', 'Optimizar el tratamiento hipolipemiante, ya que está mal controlado.', 'Añadir un fármaco para la diabetes.', 'Abandonar el hábito tabáquico, caminar a diario y perder peso.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 1, 'Sin clasificar', 'Pregunta asociada a la imagen 1. Hombre de 56 años con un tumor palpable en el lado izquierdo del cuello móvil a la deglución. Se acompaña d e disfagia y d isfonía. Tiene historia familiar de tumo res endocrinos. ¿Cuál de l os siguientes es el diagnóstico anatomopatológico más probable de la lesión que aparece en la imagen?:', 'Carcinoma papilar de tiroides.', 'Carcinoma medular de tiroides.', 'Linfoma difuso de célula grande.', 'Sarcoma sinovial.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 2, 'Sin clasificar', 'Pregunta asociada a la imagen 2. Paciente que ha sufrido un accide nte de bicicleta con traumatismo facial di recto s obre l a región anterior de la mandíbula. Se realiza la tomo grafía computarizada (TC) de la imagen que confirma una:', 'Fractura panfacial tipo Lefort I.', 'Fractura panfacial tipo Lefort II.', 'Fractura mandibular bicondílea inestable.', 'Fractura ma ndibular bilateral en ramas horizontales inestable.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 3, 'Sin clasificar', 'Pregunta asociada a la imagen 3. Hombre de 75 años, sin antecedentes personales de interés, a gricultor jubilado, que a cude a la consulta refiriendo que en los últimos 10 años ha notado la aparición progresiva en cuero cabelludo (es c alvo des de h ace años) de pequeñas pl acas eritematosas, muchas de ellas con descamación y rasposas al tacto, siendo la mayoría asintomáticas, si bien alguna le molesta al tacto. Ante este cuadro clínico y la imagen ¿cuál de los siguientes sería el diagnóstico?:', 'Dermatitis seborreica.', 'Queratosis actínica.', 'Liquen nitidus.', 'Psoriasis.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 4, 'Sin clasificar', 'Pregunta asociada a la imagen 4. Hombre de 25 años sin antecedentes personales de interés que acude a la c onsulta de dermatología porque desde hace 4 semanas nota la aparición de unas pápulas aterciopeladas en l a zona perianal (imagen), asintomáticas , que van aume ntado e n número poc o a poc o. ¿Cuál de los siguientes diagnósticos es más probable?:', 'Condiloma lata.', 'Molluscum contagiosum.', 'Condiloma acuminado.', 'Liquen plano.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 5, 'Sin clasificar', 'Pregunta asociada a la imagen 5. Mujer de 32 añ os co n dia gnóstico re ciente de carcinoma ductal infiltr ante G3 de mama izquierda, fenotipo triple negativo. Se muestran las imágenes de la PET-T C con 18F-FDG c on proyección de intensidad máxima (MIP) y cortes axiales a nivel de mama y axila. De las siguientes afirmaciones, señale la correcta:', 'El tratamiento electivo de inicio es tumorectomía y biopsia selectiva de ganglio centinela.', 'El tratamiento electivo de inicio es mastectomía y biopsia selectiva del ganglio centinela.', 'Se vis ualiza afectación en mama izquie rda y axilar ipsilateral.', 'Se visualiza afectación en mama izquierda, axila izquierda y metástasis a distancia.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 6, 'Sin clasificar', 'Pregunta asociada a la imagen 6. Mujer de 27 años, sin antecedentes de interés, que acude a ur gencias p or e pisodios tr ansitorios de pérdida de visió n bilateral de 15 segundos de duración, cefalea al despertarse y acúfenos de unas semanas de evolución. Tiene un IMC de 29. La RM craneal descarta lesiones ocupantes de esp acio. Con la clínica referida y la imagen de fondo de ojo ¿cuál de las siguientes afirmaciones es correcta?:', 'La pérdida de peso no es eficaz en esta situación.', 'La acetazolamida y la furosemida son fármacos empleados habitualmente.', 'Se debe realizar una punción lumbar antes de la prueba de imagen.', 'Los corticoides orales se usan ampliamente en el manejo de esta entidad.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 7, 'Sin clasificar', 'Pregunta asociada a la imagen 7. Mujer de 57 añ os que c onsulta p or hipoacusi a derecha neurosensorial progresiva y acúfenos. En relación con la imagen mostrada, indique de qué exploración se trata y el diagnóstico más probable:', 'RM sin contraste. Meningioma.', 'TC con contraste. Tumor epidermoide.', 'RM con contraste. Tumor glial.', 'RM con contraste. Schwannoma vestibular.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 8, 'Sin clasificar', 'Pregunta asociada a la imagen 8. Hombre de 84 años con antec edentes de hipertensión arterial, dislipemia e infarto agudo de miocardio. Acude a ur gencias por deterioro cognitivo r ápidamente progresivo, a mnesia, inestabilidad para la ma rcha y h emianopsia homónima izquierda. Se le realiza la siguiente TC craneal. Señale cuál es el diagnóstico más probable ante el hallazgo mostrado:', 'Absceso cerebral secundario a otitis media aguda derecha.', 'Trombosis venosa del seno sigmoide derecho.', 'Infarto isquémico agudo en territorio de a rteria cerebral posterior derecha.', 'Neoplasia cerebral de origen glial con edema perilesional asociado.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 9, 'Sin clasificar', 'Pregunta asociada a la imagen 9. Hombre de 72 años c on diagnóstico de carcinoma de cavidad oral inter venido hace tre s meses con resección c ompleta, e n tratamiento c on quimioterapia, po rtador de g astrostomía endoscópica percutánea profiláctica, que acude a urgencias por dolor y distensión abdominal de tres días de evolución, intolerancia oral y ausencia de deposiciones. Se realiza l a TC abdominopélvica con contraste intravenoso que se muestra en la imagen. ¿Cuál de lo s siguientes es el diagnóstico más probable?:', 'Obstrucción intestinal secunda ria a neoplasia estenosante de colon descendente.', 'Obstrucción intestinal de causa extrínseca por carcinomatosis peritoneal.', 'Obstrucción intestinal por mi gración e impactación de la sonda de gastrostomía.', 'Obstrucción funcional o íleo pseudoobstructivo por fármacos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 10, 'Sin clasificar', 'Pregunta asociada a la imagen 10. Hombre de 61 años, que recibió un trasplante alogénico haploidéntico hace 20 meses por linfoma no Hodgkin T, en respuesta completa, que consulta por un síndrome febril desde hace 72 horas con tos y expectoración blanquecina y disnea progresiva a moderados esfuerzos. Refiere astenia desde hace un mes y medio. Se realiza la TC torácica que se muestra en la imagen. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Neumonía por Mycobacterium tuberculosis.', 'Neumonía por Aspergillus.', 'Neumonía por Streptococcus pneumoniae.', 'Neumonía por Pneumocystis jirovecii.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 11, 'Sin clasificar', 'Pregunta asociada a la imagen 11. Hombre de 52 años que consul ta por dolor centrotorácico des garrador de 30 mi nutos de duración. A la explor ación es tá inquieto y sudoroso. La tensión arterial es de 190/110 mmHg en ambos brazos. A la auscultación no hay soplos cardiacos ni estertor es crepitantes. El electrocardiograma está en rit mo sinusa l a 90 latidos por minuto sin al teraciones de l a repolarización. En la angioTC torácica se observa la imagen que se adjunta. ¿Cuál es el diagnóstico más probable?:', 'Hematoma intramural.', 'Úlcera penetrante arteriosclerótica.', 'Pseudoaneurisma de aorta.', 'Disección de aorta tipo A de Stanford.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 12, 'Sin clasificar', 'Pregunta asociada a la imagen 12. Hombre de 75 años sin factores de ries go cardiovascular. Acude a su centro de salud por disnea de m oderados esfuerzos de un año de evolución, que en las últimas semanas aparece ante pequeños es fuerzos. En la explor ación física se ausculta en e l 2º espacio intercostal derecho un soplo sis tólico r udo, irradiado a car ótidas c on borramiento del 2º ton o cardiaco. Se practica un ecocardiograma que muestr a una funci ón biventricular normal y un en grosamiento de una de las válvulas cardiacas que presenta un área de 0,95 cm2 (imagen). ¿Cuál es el diagnóstico más probable y la actitud terapéutica a seguir?:', 'Estenosis valvular aórtica grave con indicación de recambio valvular.', 'Estenosis valvular aórtica m oderada co n indicación de seguimiento clínico ambulatorio.', 'Estenosis mitral gra ve c on i ndicación de recambio valvular.', 'Estenosis mitral modera da con indicación de seguimiento clínico ambulatorio.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 13, 'Sin clasificar', 'Pregunta asociada a la imagen 13. En relaci ón con el electrocardiograma de 12 derivaciones que se muestra, señale la descripción INCORRECTA:', 'Ritmo auricul ar de sorganizado con frecuencia ventricular irregular muy sugestiva de fibrilación auricular.', 'Alteración del sistema de conducción cardiaca con bloqueo bifascicular (bloqueo completo de rama derecha y hemibloqueo anterosuperior izquierdo del haz de His).', 'Alteración del sistema de conducción cardiaca con episodios de bloqueo aurículo-ventricular de alto grado o completo.', 'Elevación significativa del segme nto ST en derivaciones inferiores muy sugestiva de isquemia miocárdica aguda.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 14, 'Sin clasificar', 'Pregunta asociada a la imagen 14. Paciente de 54 años que acude a realizarse una ecografía abdominal c omo c ontrol de una enfermedad de Crohn. Nunca ha presentado cólicos biliares y no tiene otra co morbilidad relevante. En la ima gen se muestran los hallazgos de la ec ografía (izquierda modo B y derecha con contraste I V). De las siguientes, s eñale la afirmación correcta:', 'A pesar de que nunca ha tenido síntomas de origen biliar está ind icada la co lecistectomía como prevención del cáncer de vesícula biliar.', 'Dado que está asintomático y no tiene riesgo aumentado de cáncer de v esícula biliar no se recomienda la colecistectomía y no es preciso seguimiento por este motivo.', 'La image n no es s uficientemente c oncluyente como para tomar una decisión terapéutica. Sería necesario ampliar el estudio con R M y/o PET/TC.', 'No está indicada la colecis tectomía por estar asintomático, pero sí el seguimiento periódico.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 16, 'Sin clasificar', 'Pregunta asociada a la imagen 16. En la mielofi brosis prim aria se obs ervan en el frotis sanguíneo (ver imagen) unos hematíes con una forma característica denominados:', 'Dacriocitos.', 'Piropoiquilocitos.', 'Esquistocitos.', 'Acantocitos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 17, 'Sin clasificar', 'Pregunta asociada a la imagen 17. Hombre de 63 años, fumador de 15 cigarrillos al día como único antecedente de interés, que consulta por cefalea. Se detecta presión arterial de 180/110 mm Hg, iniciá ndose tratamiento con enalapril 10 mg. Se realiza analítica donde no hay ningún parámetro fuera de rango. A la semana se objetiva un buen control de la presi ón arterial y una creatinina de 3 m g/dL correspondiente a un FGe (filtrado glomerular estimado) de 22 ml/min. En la exploración física se detec ta un s oplo abdominal. Se realiza una an gioTC abdomin al (figura). ¿Cuál de las si guientes afirmaciones es más probable?:', 'Tiene una estenosis unilateral de la arteria renal y la administración de enalapril ha provocado una caída del FGe por la pérdida de vasoconstricción de la arteriola eferente.', 'Tiene una nefritis intersticial por enalapril.', 'Tiene una esten osis b ilateral d e las arterias renales y la administración de e nalapril ha provocado una caída del FGe por la pérdida de vasoconstricción de la arteriola eferente.', 'Tiene una insuficiencia renal aguda debida a la crisis hipertensiva.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 18, 'Sin clasificar', 'Pregunta asociada a la imagen 18. Mujer de 45 años con proctalgia en relación con la deposición de 12 sem anas de e volución. En la exploración en posición genupectoral se observa la siguiente ima gen. ¿Cuál e s el di agnóstico má s probable?', 'Fisura anal anterior crónica.', 'Fisura anal aguda.', 'Fístula ano-vaginal.', 'Úlcera anal por enfermedad de Crohn.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 19, 'Sin clasificar', 'Pregunta asociada a la imagen 19. Hombre de 57 años que refiere que hace 7 días comenzó de forma s úbita con dolor en fl anco izquierdo con irradiaci ón anteri or, náuse as y vómitos, que ha acudido cuatro veces a urgencias por este motivo. Hoy acude nuevamente, ya que el dolor no se controla con la analgesia pautada. Se objetiva te nsión arterial media de 63 mmH g, temperatura 38,5 ºC y o bnubilación. En l a analítica sanguínea destacan 3.300 leucocitos/mm3 con 80 % segmentados, creatinina 1,4 m g/dl y proteína C reactiva 7,5 m g/dl (<0 ,5 mg/dl). Sedimento urinario con pH 5, nitritos, leucocituria, microhematuria y ba cteriuria. Se so licitan radiografía simple de abdomen y eco grafía abdominal (imágenes). Ante estos hallaz gos ¿cuál de las siguientes es la actitud más adecuada?:', 'Antibioticoterapia, su eroterapia, an algesia y alcalinización intravenosas y un alfa-bloqueante vía oral y observación en urgencias hasta control sintomático.', 'Antibioticoterapia y su eroterapia intravenosas y derivación urgente de l a vía urinaria mediante catéter doble jota o nefrostomía percutánea, con tratamiento diferido del agente causal.', 'Antibioticoterapia, su eroterapia, analgesia intravenosas y un alfa -bloqueante vía oral e ingreso en la Unidad de Cuidados Intensivos.', 'Antibioticoterapia y su eroterapia intravenosas y litotricia extracorpórea por ondas de choque o ureterorrenoscopia.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 20, 'Sin clasificar', 'Pregunta asociada a la imagen 20. Ante esta imagen en un paciente con un trastorno motor en miembros inferiores, señale la respuesta INCORRECTA:', 'Debemos buscar una malformación de Chiari.', 'En algunos casos se asocia a hidrocefalia.', 'Se caracteriza por una pérdida de la sensibilidad táctil y vibratoria con preservación de la sensación térmica y dolorosa.', 'Puede producirse tr as trau matismos o infecciones.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 21, 'Sin clasificar', 'Pregunta asociada a la imagen 21. Un paciente de 27 años, tras sufrir una caída de un caballo, presenta un traumatismo en el miembro inferior izquierdo con una ac titud del mismo en flexión, aducción y r otación i nterna. T ras realizarle la radiografía anteroposterior de pelvis que se muestra, señale cuál es el diagnóstico:', 'Fractura pertrocantérea de fémur izquierdo.', 'Fractura subcapital de fémur izquierdo.', 'Luxación a nterior de cade ra, c on fract ura de pared anterior de acetábulo.', 'Luxación posterior de cadera, con fractura de pared posterior de acetábulo.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 22, 'Sin clasificar', 'Pregunta asociada a la imagen 22. Mujer de 75 años, autónoma y activa, que sufre una caída en su domicilio y acude a urgencias con dolor, impotencia funcio nal y de formidad alrededor de la ro dilla izquierda. Había sido intervenida quirúrgicamente de esta rodilla hacía 2 años p or gonartrosis mediante una a rtroplastia total de r odilla cementada postero-estabilizada. Los pulsos distales están conservados. Existe una movilidad patológica de la rodilla izquierda sin apreciarse déficit neurológico en la pierna afecta. Se realizan la radiografía y la TC que se muestran en las imágenes. ¿Cuál de las siguientes sería la actitud terapéutica en esta situación?:', 'Placa condílea de ángulo fijo a 95 gra dos con tornillos de compresión interfragmentaria.', 'Placa condílea de fémur bloqueada de fijación angular.', 'Clavo de fémur retrógrado acerrojado largo.', 'Clavo anterógrado cérvico-cefálico de f émur para proteger todo el fémur.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 23, 'Sin clasificar', 'Pregunta asociada a la imagen 23. Mujer de 84 años que consulta a su médico de familia por la lesión en el párpado inferior de 2 meses de e volución que aparece en la ima gen. ¿Cuál de lo s si guientes di agnósticos es el m ás probable?:', 'Carcinoma basocelular ulcerado.', 'Blefaritis.', 'Orzuelo externo.', 'Dermatitis eccematosa.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 24, 'Sin clasificar', 'Pregunta asociada a la imagen 24. Paciente que con sulta p orque se ha notad o "bultos" cerv icales bilaterales y mo lestias faríngeas de meses de e volución, incluso con leve dificultad para tra gar. No refiere disnea ni disfonía, pero observamos una voz e ngolada. Ha perdido 3 K g de peso recientemente. No es fumador per o sí ha sid o bebedor impor tante. Después de e xplorar la c avidad oral y orofaringe sin ha llar a lteraciones, se rea liza la videofibroscopia de vía aerodigestiva superior, una de cuy as imágenes se m uestra. ¿Cuál de las siguientes descripciones es correcta?:', 'Lesión que respeta las cuerdas vocales sugestiva de carcinoma de supraglotis.', 'Lesión transglótica sugestiva de carcinoma de laringe T2.', 'Lesión en seno piriforme sugestiva de carcinoma de hipofaringe.', 'Lesión en amígdala palatina derecha sugestiva de carcinoma de orofaringe T2.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 25, 'Sin clasificar', 'Pregunta asociada a la imagen 25. Mujer de 57 años sin antecedentes de interés que consulta por presentar desde hace 2 meses sensación disneica, que en la última semana se ha hecho de mínimos es fuerzos. No presenta fenómeno de Raynaud, fiebre ni ortopnea. A la exploración física destacan las lesiones cutáneas que se observan en la imagen. No presenta edemas, la auscultación ca rdíaca es no rmal y la auscultación respiratoria muestra crepitantes secos en ambas bases pulmonar es. La r adiografía de tórax muestra un índice cardiotorácico normal y un discreto patrón intersticial basal derecho. En la analítica destaca únicamente una VSG de 75 mm, hemograma normal, AST, ALT, CK, creatinina y ionograma con valores normales. ¿Cuál de la s siguientes actitude s diagnósticas es la má s apropiada?:', 'Determinar la presencia de anticuerpos anti-PL7, anti-PL12 y anti-Jo1.', 'Determinar la presencia de anticuerpos anticentrómero.', 'Determinar la presencia de anticuerpos anti- MDA5.', 'Solicitar una TC torácica de alta resolución.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 26, 'Sin clasificar', 'En relación con el metabolismo del hi erro y su control mediado por hepcidina, es cierto que:', 'La caí da en la presión parcial de oxígeno promueve la activ ación del factor inducible por hipoxia (HIF), que a umenta la expresión de hepcidina.', 'El aumento de hierro sérico o la inflamación estimulan la síntesis de hepcidina en el hígado, que regula negativamente la función de la ferroportina.', 'La hepcidina disminuye la absorción intestinal de hierro a través de la inactivación del transportador de metales bivalentes 1 (DMT1).', 'En la hemocromatosis hereditaria de tipo 1, las mutaciones en la proteína de la hemocromatosis humana ( HFE) ca usan un a umento de l a producción de hepcidina.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 27, 'Sin clasificar', '¿Cuál de las siguientes alteraciones bioquímicas se observa en e l reordenamiento met abólico de l a diabetes mellitus?:', 'La disminuci ón de la traslocación de los transportadores de gl ucosa GLU T2 y GL UT4 desde las vesículas de almacenamiento intracelular a la membrana plasmática.', 'El aumento de la producción de urea por una mayor degradación nucleotídica.', 'El incre mento de la síntesis he pática de triglicéridos.', 'El aumento de la síntesis hepática de glicerol como sustrato gluconeogénico.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 28, 'Sin clasificar', 'Una persona sana s ufre una deshidratación tras realizar e jercicio fí sico intenso a al tas temperaturas sin in gerir líquidos. Respecto a la activación del sist ema reninaangiotensinaaldosterona en esas c ondiciones, s eñale la respuesta INCORRECTA:', 'Los cambios de presión arterial se acompañan de cambios p roporcionales en la filtració n glomerular.', 'Se produce vasoconstricción de las arte riolas eferentes.', 'Aumenta la activ idad d e los núcleos hipotalámicos supraóptico y paraventricular.', 'Aumenta la secreción renal de potasio.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 29, 'Sin clasificar', 'De las siguientes afirmaciones relacionadas con las estructuras anatómicas que forman el manguito de los rotadores, señale la correcta:', 'Los músculos que forman el manguito de los rotadores son el subescapular, el supraespinoso, el infraespinoso y el redondo mayor.', 'Los t endones de l os músculos del manguito refuerzan la cáps ula fibrosa de la articulación escápulo-humeral.', 'El músculo infraespinoso rota el braz o en dirección interna.', 'El músculo supraespinoso ayuda a la aducción (aproximación) del brazo.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 30, 'Sin clasificar', '¿Cuál de l as si guientes características de la anatomía del esófago es la que facilita la realización de la ecocardiografía transesofágica?:', 'El cayado aórtico c ontacta con el esófago a la altura de la 4ª vértebra dorsal y lo proyecta hacia delante.', 'El segmento torácico del esófago discurre por la cara posterior de aurícula y ventrículo derechos.', 'El esófago recorre la cara posterior de la aurícula izquierda.', 'La existencia de un segmento del esófago más dilatado entre la estrechez aórtica y la estrechez diafragmática.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 31, 'Sin clasificar', 'Una persona joven y sana se encuentra en posición anatómica erguida. En relación c on el flu jo sanguíneo a tr avés de los pulm ones y su distribución, señale la respuesta INCORRECTA:', 'En situación de r eposo, el flujo en los vértices pulmonares es habitualmente intermitente.', 'El ejercicio aumenta el flujo sanguíneo en todas las regiones pulmonares.', 'El aumento del gasto cardiaco durante el ejercicio intenso es asumido por la circulación pulmonar sin grandes aumentos en la presión arterial pulmonar.', 'Una di sminución significativa de la concentración de O2 en los alveolos provoca una vasodilatación de los vasos adyacentes.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 32, 'Sin clasificar', 'En relación c on el pote ncial de acción cardiac o, señale la afirmación correcta:', 'Las células automáticas tienen un po tencial de acción lento y calciodependiente.', 'El potencial de reposo de las células automáticas es más negativo que el de las cél ulas del miocardio ventricular.', 'Las células automáticas tienen canales rápidos de sodio.', 'Los canales If se sitú an predominantemente en las células del miocardio ventricular.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 33, 'Sin clasificar', 'Una de las siguientes enfermedades se produce por hipermetilación de una expansión de tripletes CGG en la región promotora:', 'Enfermedad de Hungtinton.', 'Ataxia de Friedreich.', 'Síndrome del cromosoma X frágil.', 'Distrofia miotónica tipo 1.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 34, 'Sin clasificar', 'Un rasgo que aparece en todas las generaciones, tanto e n varones como en m ujeres, per o los varones no lo transmiten a sus hijos varones, se corresponde con uno de los siguientes patrones de herencia:', 'Autosómica dominante.', 'Ligada al sexo dominante.', 'Ligada al sexo recesiva.', 'Mitocondrial.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 35, 'Sin clasificar', 'Las células tumorales desarrollan diferentes mecanismos dirigidos a evitar la a ctivación de la respuesta inmunitaria antitum oral. Entre las inmunoterapias an titumorales diri gidas a contrarrestar estos mec anismos de evasión destaca:', 'La i noculación intratumoral de cél ulas T reguladoras específicas frente a antígenos tumorales.', 'La inoculación de células de la inmunidad innata con cap acidad antitumoral como las célu las reguladoras de origen mieloide (myeloid-derived suppressor cells, MDSC).', 'El uso de citocinas como el TGF-beta o la IL-10 que frenan el crecimiento tumoral.', 'El uso de anticuerpos monoclonales inmunomoduladores frente a PD-1 o los ligandos de PD-1.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 36, 'Sin clasificar', 'En relación con el m ecanismo inmunol ógico implicado e l rechazo de ór ganos só lidos trasplantados, señale la respuesta INCORRECTA:', 'El rechazo agudo mediado por linfocitos T puede ser controlado mediante el uso de fármacos como la ciclosporina A o los corticoides.', 'La prese ncia en el receptor de a nticuerpos específicos contra el donante (DSA) previa al trasplante es una contraindicación para el mismo.', 'El rechazo crónico o lesión crónica del injerto se asocia al da ño del endotelio mediado por anticuerpos anti-HLA.', 'El rechazo hiperagudo es mediado por linfocitos T ci totóxicos cont ra antígenos del donante presentes en el receptor.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 37, 'Sin clasificar', 'La vacunación utilizando ARN mensajero de la proteína S (Spike) del SARS-CoV-2 va dirigida a la protección de la población frente a la COVID-19. En relación con la respuesta a esta vacuna señale la afirmación INCORRECTA:', 'La respuesta no requiere la colaboración de los linfocitos T, al ser un antígeno timo - independiente.', 'Un ele vado porce ntaje de pacientes inmunodeprimidos, como aquellos con trasplante de órganos o con inmunodeficiencia, tienen un defecto en la respuesta a esta vacuna.', 'Es una forma de inmuniz ación activa cuyo resultado se aso cia al camb io de isotipo de lo s anticuerpos.', 'Induce memoria inmuno lógica b asada en la activación de linfocitos B.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 38, 'Sin clasificar', 'En relación con las enfer medades as ociadas al mecanismo de hipersensibi lidad tipo II , señale l a respuesta INCORRECTA:', 'La presencia de anticuerpos frente al receptor de las hormonas tiroideas T3 y T4 se asocia a la enfermedad de Graves.', 'La prese ncia de autoanticuerpos antidesmogleína se asocia al pénfigo vulgar.', 'La miastenia gravis se asocia a la presencia de anticuerpos frente al receptor de la acetilcolina.', 'El síndrome de G oodpasture se asoci a a l a presencia de anticuerpos frente a la membrana basal glomerular renal y pulmonar.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 39, 'Sin clasificar', 'En el asma bronquial son numerosas las células que participan en la inflamación de la vía aérea. En relación con las diferentes poblaci ones linfocitarias y las citocinas que liberan ¿cuál de las siguientes afirmaciones es correcta?:', 'Los lin focitos B so n los responsables de la coordinación de la respuesta inflamatoria.', 'En el asma bronquial hay un predominio de fenotipo linfocitario TH1.', 'Las citocinas IL4 e IL13 son las fa vorecedoras de la síntesis de IgE.', 'La población de linfocitos T reguladores (CD4+ y CD25+) está aumentada.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 41, 'Sin clasificar', 'Mujer de 63 años en tratamiento con sulfamidas (trimetoprim-sulfametoxazol) vía or al por una infección de ví as urinarias bajas. Acude a urgencias por presentar le siones cutáneas y en mucosas (oral, conjuntival y genital). Las lesiones cutáneas tienen for ma de máculas irre gulares oscuras, con desprendimiento cutáneo y afectan a más del 30 % de la superficie corpo ral. Se interpreta como una posible reacción farmacológica grave. ¿Cuál d e lo s si guientes diagnósticos es más probable?:', 'Eritema multiforme.', 'Síndrome de Stevens-Johnson.', 'Necrólisis epidérmica tóxica.', 'Síndrome de hipersensibilidad inducido p or fármacos.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 42, 'Sin clasificar', 'Un paciente acude a c onsulta recie ntemente diagnosticado de esofa gitis eo sinofílica y tr as exponerle las opciones de tratamiento prefiere hacer tratamiento dietético con dieta de exclusión de dos alimentos. ¿Cuáles son los alimentos que tendría que retirar de la dieta?:', 'Huevo y trigo.', 'Leche de vaca y pescado.', 'Legumbres y leche de vaca.', 'Leche de vaca y trigo.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 43, 'Sin clasificar', 'En relación con las condiciones necesarias para la implementación de un programa de cribado poblacional de c áncer, señale la respue sta INCORRECTA:', 'Debe e xistir una prueba adecu ada para l a detección, independientemente de la aceptabilidad de la prueba en la población.', 'La enfermeda d que se detecta mediant e el cribado debe ser relevante desde el punto de vista de salud pública.', 'La enfermeda d que se detecta mediant e el cribado de be ser tratabl e en la e tapa presintomática y el daño po tencial de la intervención debe ser inferior al del tratamiento en la etapa sintomática.', 'Se debe disponer de recursos suficientes para la implementación de la estrategia a medio / largo plazo.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 44, 'Sin clasificar', '¿Qué ti po de est udio epi demiológico NO PERMITE calcular un riesgo relativo?:', 'Un ensayo clínico aleatorizado.', 'Un estudio de cohortes retrospectivo.', 'Un estudio de cohortes prospectivo.', 'Un estudio de casos y controles.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 45, 'Sin clasificar', 'Al aumentar el tam año muestral de un estudio transversal (o de prevalencia) aumenta:', 'La representatividad de la muestra.', 'La validez del estudio.', 'La reproducibilidad del estudio.', 'La precisión del estudio.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 46, 'Sin clasificar', 'En un estudio s obre la validez de un a pr ueba diagnóstica, para resumir la relación entre la sensibilidad y la especi ficidad de la p rueba se puede usar:', 'El índice de Kappa.', 'La curv a ROC (receiver operating characteristics).', 'El coeficiente de correlación intraclase.', 'El gráfico de Altman y Bland.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 47, 'Sin clasificar', 'Para establecer si la exposición a r adiaciones ionizantes de los trabajadores de una mina influye en la aparición de muertes por cáncer de pulmón se decide en el año 2010 r ealizar un estudio. L os investigadores recopilan información del registro de exposición a radiaciones en la empresa minera, con datos sobre las radiaciones acumuladas por cada trabajador desde el año 1980 al 2000, año en que se cier ra la mina. Y también reco gen información sobre las m uertes por c áncer de pulmón en esos trabajadores desde el año 1980 al año 2008, a partir de los registros de mortalidad existentes. Fi nalmente, c omparan la mortalidad por cáncer de pulmón e ntre los tr abajadores con mayor y m enor exposición a las r adiaciones ionizantes. ¿Qué tipo de diseño epidemiológico es éste?:', 'Estudio de casos y controles retrospectivo.', 'Estudio de casos y controles prospectivo.', 'Estudio de cohortes retrospectivo.', 'Estudio de cohortes prospectivo.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 48, 'Sin clasificar', 'Un hombre de 52 años se está recuperando de una dependencia al alcoh ol y solicita apoyo farmacológico pa ra prevenir la reca ída y mantenerse abstinente. ¿Cuál de lo s si guientes medicamentos está indicado com o tratamiento complementario para mantener la abstinencia en el marc o de un pr ograma de tr atamiento de pacientes d esintoxicados que ha n sido dependientes de alcohol?:', 'Vareniclina.', 'Nalmefeno.', 'Acamprosato.', 'Tiamina.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 49, 'Sin clasificar', 'Un artículo describe un ensayo clínico aleatorizado en fase IV en una muestra de adultos obtenida de 42 centros sanitarios de 16 países dis tintos que recibieron un fár maco en estudio y un placebo durante 12 semanas. ¿Cuál de las siguientes afirmaciones describe mejor el contexto de esta investigacion atendiendo a estas características?:', 'Al ser una investigación aleatorizada, el número de hombres en ca da uno de l os grupos experimentales (fármaco o placebo) debe ser el mismo que el de mujeres.', 'El fármaco que se investiga en este ensayo ya se encuentra aprobado para su prescripción en otras indicaciones o situaciones clínicas.', 'Este ensayo clínico trata de analizar en personas sanas y enfermas las dosis terapéuticas de u n fármaco e xperimental en c omparación con un placebo.', 'Este tipo de ensayo se denomina metaanálisis al incluir pacientes de distintos centros sanitarios y países.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 50, 'Sin clasificar', 'Un ensayo clínico cuyo objetivo fundamental es obtener datos preliminares de eficacia terapéutica y establecer la relación entre las dosis y la eficacia para determinar un intervalo de dosis adecuadas, es un:', 'Estudio preclínico.', 'Ensayo clínico fase I.', 'Ensayo clínico fase II.', 'Ensayo clínico fase III.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 51, 'Sin clasificar', 'Para la detección de r eacciones adversas a medicamentos poco fre cuentes ( <1/10.000) el método de fármacovigilancia más adecuado es:', 'Notificaciones espontáneas.', 'Monitorización intensiva hospitalaria.', 'Estudios de cohorte.', 'Metaanálisis.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 52, 'Sin clasificar', 'Uno de los si guientes fár macos, a demás de su efecto analgésico, posee un efecto relajante de fibra muscular lisa:', 'Diclofenaco.', 'Paracetamol.', 'Ketorolaco.', 'Metamizol.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 53, 'Sin clasificar', 'La hipertermia maligna NO se relaciona con:', 'Succinilcolina.', 'Desflurano.', 'Propofol.', 'Sevoflurano.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 54, 'Sin clasificar', 'Se gún la cla sificación del esta do físico preoperatorio del paciente establecida por la ASA (Sociedad Americana de Anestesiología), un paciente con hipertensión arterial mal controlada correspondería a un grado:', 'IV', 'III', 'II', 'I', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 55, 'Sin clasificar', 'El carcinoma adenoide quístico:', 'Es el t umor malign o más frecu ente de las glándulas salivares.', 'Nunca afecta las glándulas s alivares menores a nivel del paladar.', 'Puede asociarse con parálisis facial debido a su neurotropismo.', 'Se debe tratar con radioterapia como primera opción terapéutica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 56, 'Sin clasificar', 'Respecto al cáncer de lengua:', 'El tipo histológico más frecuente es el carcinoma basocelular y su tratami ento primario es habitualmente radioterápico.', 'Se relaciona c on factores etiopatogénicos como la irradiación solar y el virus del papiloma humano.', 'Rara vez provoca metástasis por vía linfática.', 'El tipo histológico más frecuente es el carcinoma epidermoide y su tratamiento quirúrgico asocia habitualmente disección ganglionar cervical.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 57, 'Sin clasificar', '¿Cuál de los siguientes colgajos NO PODRÍA ser utilizado par a realizar la reconstr ucción de un defecto en la región cervical posterior?:', 'Colgajo an terolateral fasciocu táneo d e muslo, pediculado.', 'Colgajo libre de músculo dorsal ancho con isla cutánea.', 'Colgajo pediculado de t rapecio (musculocutáneo).', 'Colgajo lib re SCIP (d erivado d el sistema circunflejo ilíaco superficial).', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 58, 'Sin clasificar', 'Hombre de 45 años con antecedentes de queratitis herpética de repetición e n ojo izquie rdo (OI). Consulta por dolor, hiperemia y visión borrosa en OI de un d ía de e volución. A l a exploración presenta una agudeza visual con s u corrección de 1,0 en OD y 0,6 en OI, la presión intraocular es de 18 mmH g en OD y 35 mmH g en OI. L a exploración con lámpara de hendidura en OD es normal y en el OI presenta hiperem ia ciliar, turbidez en cám ara anterior, li gero leucoma corneal y un test de fluoresceína negativo. ¿Con cuál de las siguientes patologías relacionaría este cuadro clínico?:', 'Uveítis hipertensiva.', 'Glaucoma maligno.', 'Glaucoma neovascular.', 'Queratitis epitelial herpética.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 59, 'Sin clasificar', 'Mu jer de 57 años que consulta para una revisión rutinaria. En la exploración oftalmológica presenta una agudeza visual (AV) sin corrección de 1,0 en OD y 0,5 en OI, la AV con agujero estenopeico es de 1,0 en ambos ojos y la presión intraocular es de 16 mmHg en ambos o jos. ¿Cuál de las si guientes sería la actitud a seguir más correcta?:', 'Realizar un e studio refractivo para valorar un defecto de refracción.', 'Realizar un campo visual pa ra desca rtar un déficit visual periférico en OI.', 'Realizar un estudio de fondo de ojo para valorar una patología macular en el OI.', 'Hacer un seguimiento en un año para valorar la evolución de la AV.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 60, 'Sin clasificar', 'El defecto campimétrico asociado a una lesión en la cintilla óptica derecha es:', 'Hemianopsia homónima izquierda.', 'Hemianopsia heterónima bitemporal.', 'Cuadrantanopsia homónima izquierda.', 'Cuadrantanopsia homónima derecha.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 61, 'Sin clasificar', 'Hombre de 40 años que presenta un cuadr o vertiginoso d e varias h oras de e volución. No presenta hipoacusia, acúfenos ni sens ación de taponamiento ótico. En la exploración se observa un nistagmo espontáneo. ¿Qué características del nistagmo orientarán hacia un vértigo periférico?:', 'Nistagmo horiz ontal, unidirecci onal, que aumenta de i ntensidad cuando se dirige al lado de la fase rápida.', 'Nistagmo vertical, uni direccional, que n o se suprime con la fijación de la mirada.', 'Nistagmo horizontal, con componente rotatorio, que cambia de dirección cuando se dirige al lado de la fase lenta.', 'Nistamo horizo ntal, con compo nente rotatorio que no se suprime con la fijación de la mirada.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 62, 'Sin clasificar', 'Las siguientes enfer medades sisté micas puede n cursar con síntomas otorrinolaringológicos. Señale aquella que puede afec tar con mayor frecuencia (aproximadamente 70-80 % de los c asos) a la cavidad nasal, la cavidad bucal y la orofaringe, y que en la mitad de los casos puede existir también afectación laríngea:', 'Penfigoide.', 'Policondritis recidivante.', 'Sarcoidosis.', 'Pénfigo.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 63, 'Sin clasificar', 'Hombre de 48 años, profesor universitario, que refiere sufrir problem as c on la voz de sde hace varios años, que han empeorado progresivamente y que consis ten e n voz áspera y f orzada, co n posibles c ambios de ton o, cansancio y fa tiga al hablar. En la expl oración fibrovideoendoscópica faringolaríngea no se observan lesiones orgánicas en las cuerdas vocales, pero sí una disminución del diámetro anteroposterior del v estíbulo la ríngeo durante la fonación. El diagnóstico más probable del trastorno vocal que padece este paciente es:', 'Parálisis abductora laríngea.', 'Disfonía espasmódica.', 'Distonía de la musculatura extrínseca laríngea.', 'Disfonía por tensión muscular.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 64, 'Sin clasificar', '¿En cuál de las siguientes pacientes NO estaría indicada la rea lización d e un a his teroscopia diagnóstica como primera línea de estudio?:', 'Mujer de 32 años con estudio ecográfico normal, episodios d e d ismenorrea grav e y esterilidad primaria.', 'Mujer de 70 a ños con metrorragia postmenopáusica de 1 mes de evolución.', 'Mujer de 4 5 años c on hemorragia uterina anormal cíclica de 6 meses de evolución.', 'Mujer de 4 3 años c on hemorragia uterina anormal acíclica y sospecha ecográfica de mioma tipo 2 de la FIGO.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 65, 'Sin clasificar', 'Mu jer de 17 años que consulta porque no tiene la menstruación desde hace 7 meses . No re fiere antecedentes de interés ni otra sintomatología. No ha acudido antes porque estaba entrenando en un centro de portivo de alto rendimien to. Tuvo la menarquia a los 13 años, ciclos muy irregulares, sin dismenor rea y una interrupción l egal del embarazo a l os 16 añ os. La an alítica muestr a hemograma normal, FSH <0,1 U/L, LH <0,1 U/L, estradiol <5,0 pg/mL, TSH 1,56 mU/L. ¿Cuál de los siguientes es el di agnóstico más probable y la actitud a seguir?:', 'Fallo ovárico prematuro, po r lo que le p auta terapia hormon al su stitutiva y control en 3 meses.', 'Síndrome de Asherman, por lo que indica una histeroscopia.', 'Amenorrea c entral hipofisaria (sí ndrome de Sheehan), por l o que s olicita resonancia magnética cerebral para confirmar el diagnóstico y pautar tratamiento sustitutivo.', 'Amenorrea central hipotalámica funcional, por lo que solicita resonancia magnética para descartar otras patologías.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 66, 'Sin clasificar', 'A una de s us pacien tes, primi gesta, s e le ha practicado un a eco grafía de rut ina a las 20 semanas de gestación que ha detectado un mioma en su úter o que parece haber crecido bas tante respecto a l as previas. Está mu y preocupada por las posibles secuelas que este tumor pueda tener en el resultado de su embarazo. Usted le informa de que todas l as si guientes complicaci ones pueden ocurrir en el embarazo como consecuencia de los miomas uterinos, EXCEPTO:', 'Necrosis y degeneración de los miomas.', 'Malposición fetal.', 'Progresión a leiomiosarcoma.', 'Parto pretérmino.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 67, 'Sin clasificar', 'Mujer de 35 años sin antecedentes de interés , nuligesta, que acude a ur gencias por sangrado entre reglas en cantidad moderada que afecta a su calidad de vida. Además refiere que últimamente tiene re glas mucho más abundantes. El hemograma y la coagulación son normales. En la ecografía ginecológica se observa útero en ante, regular, de 58x35 m m, c on end ometrio en fase proliferativa, nódulo hipoecoico en c ara anterior uterina con Doppler periférico de alta resistencia (sin Doppler central) de 28x29 mm compatible con un l eiomioma ti po 1 (clasificación de l a FIGO 2011), a nejos norm ales, no líquido libre e n Douglas. Señale la actitud más correcta:', 'Le explica los hallazgos y descarta que el leiomioma, dada la localización, sea la causa de sus sangrados.', 'Le explica que el leiomioma es probablemente la causa de los sangrados y la deriva a la consulta de histeroscopias.', 'Le explica que el leiomioma es probablemente la causa de los sangrados y la deriva a la consulta de ginecología para programar una miomectomía por laparoscopia.', 'Dados los hallazgos eco gráficos, solicit a resonancia magnética preferente, pa uta u n análogo de la GnRH y revisión en consulta.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 68, 'Sin clasificar', 'Gestante de 16 semanas con antecedente de parto prematuro a las 33 sem anas en una gestación anterior, que actualmente presenta una lon gitud cervical de 28 mm. ¿Cúal es la inter vención más eficaz para la prevención de la recur rencia del parto prematuro?:', 'Reposo relativo, antibioticoterapia y nifedipino via oral.', 'Progesterona natural micronizada vía vaginal.', 'Cerclaje profiláctico.', 'Pesario cervical.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 69, 'Sin clasificar', 'Mu jer de 29 años sin antecedentes de interés que acude por deseo gestacional de más de dos años. Refiere reglas regulares de 4 días de duración con dismenorrea que le impide su actividad habitual, dolor a la de fecación y dispareunia. ¿Cúal de las siguientes es la sospecha diagnóstica?:', 'Endometriosis.', 'Insuficiencia ovárica prematura.', 'Síndrome del ovario poliquístico.', 'Esterilidad de origen tubárico.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 70, 'Sin clasificar', 'Acude al servicio de urgencias una puérpera de 32 años (con un parto eutócico hace 2 meses e instauración adecuada de lactancia materna) que presenta dolor, enrojecimiento y calor en la mama derecha, junto con males tar general y un pico febril único de 38 ºC. ¿Cuál de las siguientes es la actitud más apropiada?:', 'Retirada de la lactancia con cabergolina y administrar probióticos oral es, como el Lactobacillus fermentum, durante 1 mes.', 'Antibioticoterapia oral, jun to con el vaciado adecuado de la mama.', 'Retirada de la lactancia con cabergolina y antibioticoterapia oral.', 'Antibióticos l ocales, j unto con l avados de l a mama con antisépticos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 71, 'Sin clasificar', 'Gestante de 37 semanas, fumadora, que acude a urgencias por sangrado vaginal similar a la regla, sin otros síntomas. No tiene antecedentes de interés salvo una c esárea. No se ha contr olado l a gestación. A la exploración se objetiva un sangrado constante, activo y brilla nte. El re gistro cardiotocográfico muestra un p atrón activo reactivo, línea de base de 140 latidos por minuto, variabilidad a corto plazo normal, sin dinámica. Señale la afirmación correcta:', 'Ante la sospecha de desprendimiento prematuro de placenta normoinserta, indica cesárea urgente.', 'Ante la s ospecha de placenta pre via oclu siva total, indica finalización de la gestación mediante cesárea.', 'Ante la sospecha de desprendimiento prematuro de placenta normoinse rta, indica fi nalización mediante parto vaginal dado que el monitor es tranquilizador.', 'Ante la sospecha de una r otura uterina, indica cesárea urgente.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 72, 'Sin clasificar', 'Gestante de 29 sem anas remitida por sospecha de crecimiento intrauterino restringido (CIR). En la ecografía se observa un pe so fetal estimado en el percentil 1 con Doppler de la arteria umbilical con onda de velocidad de flujo con diástole revertida. ¿En qué momento se aconseja la finalización de la gestación?:', 'Se t rata de un feto pequeño para l a edad gestacional: finalización a las 40 semanas.', 'Se trata de un feto CIR tipo 1: finalización a las 37 semanas.', 'Se trata de un feto CIR tipo 2: finalización a las 34 semanas.', 'Se trata de un feto CIR tipo 3: finalización a las 30 semanas.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 73, 'Sin clasificar', 'En relación con la tos fe rina pr oducida p or la Bordetella pertussis señale la afirmación correcta:', 'En la exp loración clínica de la to s ferina es habitual la presencia de sibilancias en la auscultación pulmonar.', 'La azitromicina es el antibiótico de elección para el tratamiento en todos los grupos de edad.', 'El "g allo" (esfuerzo inspiratorio masivo) se produce fundamentalmente en los niños menores de 2 meses de edad.', 'Los vómitos posteriores al ep isodio paroxístico de tos son extremadamente raros.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 74, 'Sin clasificar', 'Paciente de 3 años que acude a ur gencias de un hospital. En el triángulo de evaluación pediátrica muestra alteración de 2 lados: apariencia y circulatorio. En la exploración destaca una presión arterial de 60/ 30 mmHg y un exante ma eritematoso macular generalizado. Los exámenes complementarios mues tran elevación de ure a y creatinina, alar gamiento del tiempo de protrombina, f ibrinógeno ba jo, plaquetas 50.000/mm3 y elevación de tr ansaminasas. En el hemocultivo s e a ísla estreptococo del grupo A. ¿Cuál de l os siguientes e s el dia gnóstico má s probable?:', 'Fascitis estreptocócica.', 'Glomerulonefritis postestreptocócica.', 'Shock tóxico estreptocócico.', 'Escarlatina.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 75, 'Sin clasificar', 'Acerca de la bronquiolitis aguda en la infa ncia, señale la respuesta correcta:', 'El v irus resp iratorio sincitial (VRS) es la segunda cau sa d e bronquiolitis agu da y neumonía vírica en menores de 1 año.', 'Se recomienda la administración de palivizumab para proteger a niños con riesgo alto contra las complicaciones graves de la enfe rmedad por el VRS.', 'La bronquiolitis se produce por obstrucción y colapso de las vías respiratorias de me diano y gran calibre durante la espiración.', 'El tratamient o se basa e n aeros oles de suero salino hipertónico, a drenalina y/ o beta-2 agonistas según la gravedad.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 76, 'Sin clasificar', 'Niña de 10 años que presenta en un análisis un a importante el evación de transaminasas, que persiste en controles posteriores. Entre los estudios complementarios destaca la presencia en sangre de anticuerpos antimicrosómicos de hígado-riñón tipo 1 (a nti-LKM-1). El cua dro que presenta tiene todas las características siguientes, EXCEPTO una de las siguientes:', 'Hipogammaglobulinemia.', 'En l a biopsia hepática p resentará una típica hepatitis de interfase.', 'Es más frecuente en el sexo femenino.', 'Se trata de una hepatitis autoinmune tipo 2.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 77, 'Sin clasificar', 'Paciente de 2 años con fiebre, c onjuntivitis, rinorrea y tos repetitiva. Su estado vacunal es desconocido. En l a exploración presenta en l a mucosa oral, a la altura de los premolares, puntos de col or blanco azulado rode ados d e un hal o eritematoso. ¿Cuál de los si guientes es el diagnóstico más probable?:', 'Enfermedad de Kawasaki.', 'Escarlatina.', 'Rubeola.', 'Sarampión.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 78, 'Sin clasificar', 'Niña de 18 meses procedente de un país africano que aca ba de ser adoptada y es atendida e n consulta para un examen de salud. En la analítica se observan unos niveles de vitamina D muy bajos. Respecto a este hallaz go ¿cuál es el dato exploratorio menos probable?:', 'Persistencia de fontanela anterior.', 'Ensanchamiento de muñecas y rodillas.', 'Hepatomegalia.', 'Genu valgo.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 79, 'Sin clasificar', 'La puntuación de Apgar es un método práctico en la valoración del recién nacido. Inclu ye todos los siguientes signos EXCEPTO uno. ¿Cuál?:', 'Frecuencia cardiaca.', 'Frecuencia respiratoria.', 'Tono muscular.', 'Color.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 80, 'Sin clasificar', 'Niño de 8 años, atendido por dolor abdominal de 2 días de evolución. La noche anterior presentó una deposición c on s angre. Es ta ma ñana s e ha levantado con dolor en ambos tobillos, no quiere andar y le han visto unas manchas en las piernas. A la explo ración p resenta buen es tado general, auscultación n ormal, abdomen d oloroso a l a palpación sin si gnos irritación peritoneal. En la esfera ORL solo se apre cia una farin ge r oja. Presenta lesiones petequiales y equímosis en ambas piernas con infla mación de a mbos tobillo s. El diagnóstico clínico más probable con los da tos aportados es:', 'Púrpura de Schönlein-Henoch.', 'Sarampión.', 'Enfermedad de Kawasaki.', 'Escarlatina.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 81, 'Sin clasificar', 'El síndrome hemolític o-urémico es una de las causas más frecuentes de insuficiencia renal aguda en niños pequeños. Se caracteriza típicamente por todo lo siguiente, EXCEPTO:', 'Anemia hemolítica microangiopática.', 'Trombocitopenia.', 'Alargamiento de l os t iempos de coa gulación (TPTA y protrombina).', 'Puede desencadenarlo una infección previa por Streptococcus pneumoniae.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 82, 'Sin clasificar', 'Sobre el tratamiento farmacológico de la manía aguda en el trastorno bipolar, señale la respuesta INCORRECTA:', 'El litio es igual o ligeramente más eficaz que el valproato.', 'Los an tipsicóticos son efectivos tanto en monoterapia como e n asociación con eutimizantes.', 'El litio muestra una eficacia similar a lo s antipsicóticos, aunque con un inicio de acción más rápido.', 'No existe un antipsic ótico de elección en el tratamiento.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 83, 'Sin clasificar', 'Con respec to a l a epidemiología de la esquizofrenia, señale la afirmación correcta:', 'Su edad máxima de aparición es a los 40 años.', 'El inicio precoz es más frecuente en varones.', 'Al tratarse de una enfe rmedad del neurodesarrollo, la importancia de los factores psicosociales en su aparición es despreciable.', 'Las personas que la padecen tiene n una probabilidad de 2 a 3 veces men or de morir prematuramente que la población general.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 84, 'Sin clasificar', 'Médico de 50 años que con frecuencia acumula retraso de 2 horas en la consulta, creando algún conflicto, aunque es el que tiene menor cupo de pacientes. Empieza su jornada laboral antes de la hora para planificar y adelantar su trabajo, pero siempre es el último en salir. Explica: “no soporto dejar algo a medias, soy muy perfeccionista, tengo muchas cosas que hacer adem ás de las visitas (burocracia, papele os) y no tengo tie mpo para nada más. No sé c ómo lo hacen mis compañe ros que tienen familia, aficiones... Yo no tengo tiempo ni para ir al gimnasio. Los fines de semana me quedo en casa, descansando. No tengo vida social." A la exploración se aprecia una preocupación por los detalles, el orden y las normas, una incapacidad para discernir lo que es urgente y prioritario de lo que no lo e s, u na c onducta in flexible y un a incapacidad para delegar. ¿Cuál de las si guientes sería la orientación diagnóstica?:', 'Trastorno esquizoide de la personalidad.', 'Trastorno narcisista de la personalidad.', 'Trastorno obs esivo-compulsivo de la personalidad.', 'Trastorno de la personalidad no especificado.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 85, 'Sin clasificar', 'La base neurobiológica fundamental de la bulimia nerviosa, en que se apoya también su tratamiento farmacológico habitual, consiste en una disfunción de la neurotransmisión:', 'Serotoninérgica.', 'Dopaminérgica.', 'Histaminérgica.', 'Colinérgica.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 86, 'Sin clasificar', 'Mujer de 87 años que padece una enfermedad de Alzheimer e n grado m oderado e hi pertensión arterial. Sufre también una incontinencia de orina que se ha ido agravando en las últimas semanas, para la que se le ha pres crito recientemente un fármaco an ticolinérgico ( oxibutinina). ¿Qué problema puede desencadenar con más frecuencia la toma de este fármaco?:', 'La aparición de delirium.', 'La aparición de bloqueo aurículo-ventricular.', 'La aparición de crisis hipertensivas.', 'La aparición de un síndrome de Sjögren.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 87, 'Sin clasificar', 'Valoramos en urgencias a una persona adulta que se encuentra irritable, bostezando, c on quejas de dolor muscular y calambres. Está nauseosa y tiene lagrimeo llamativo. Las pupilas están midriáticas. ¿Cuál de lo s si guientes e s el dia gnóstico má s probable?:', 'Intoxicación por benzodiazepinas.', 'Abstinencia de opiáceos.', 'Intoxicación por cannabis.', 'Abstinencia de alcohol.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 88, 'Sin clasificar', 'Los criterios DSM-5 para el diagnóstico de un trastorno depresivo mayor requieren la presencia de al menos uno de dos de los síntomas principales de la enfermedad. ¿Cuál de los siguientes es uno de esos síntomas principales?:', 'Agitación.', 'Insomnio.', 'Anergia.', 'Anhedonia.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 89, 'Sin clasificar', 'Hombre de 33 años, soltero, vive en pareja desde hace 10 años. Operario de profesión. Muy buena relación co n su fa milia de o rigen, cierta dependencia emocional de la madre. Desde hace un año prese nta un aumento de pre ocupación por cualquier aspecto de su vida y está muy inquieto y en ocasiones irritable. Se siente agotado, tenso y enfermo, por lo que el último año ha acudido un par de veces a urgencias. Además, tiene sensación de falta de contr ol, r umiaciones, ansiedad anticipatoria, tristeza y apatía. El cuadro clínico se inició cuando la empresa en la que trabaja inició un expediente de regulación de empleo. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Trastorno distímico.', 'Trastorno de ansiedad generalizada.', 'Episodio depresivo mayor.', 'Trastorno por somatización.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 90, 'Sin clasificar', 'Dentro de la exploración neurólogica el término astereognosia hace referencia a:', 'La incapacidad de reconocer la forma, el tamaño, el peso y la textura de un objeto por la palpación a cieg as, sien do normales las sen sibilidades básicas.', 'La inca pacidad de localizar en el c uerpo un estímulo táctil superficial.', 'La p érdida de la cap acidad sen sitiva d e discriminación entre dos estímulos simultáneos que ha bitualmente se reconocen c omo independientes.', 'La situación que se da c uando se e stimula de manera simultánea en dos puntos simétricos y solo se percibe uno de los estímulos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 91, 'Sin clasificar', 'Adolescente de 15 años que comienz a con crisis mioclónicas, sobre todo en los br azos, más frecuentes al despertar, que suelen aparecer tras la privación del sueño o la ingesta de alcohol. Tras las mioclonias presenta al gunas veces una crisis convulsiva generalizada. En el EEG se ob jetivan complejos de pu nta-onda y polipunta-onda c on gran fotosensibilidad. De los siguientes ¿cuál sería el fárm aco antiepiléptic o m ás indicado par a comenzar el tratamiento?:', 'Clonazepam.', 'Carbamazepina.', 'Etosuximida.', 'Ácido valproico.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 92, 'Sin clasificar', 'Mu jer de 50 años que r efiere dificultad para conciliar el sueño por intraquilidad y parestesias en las piernas. La exploración física y neurológica es normal. Su tratamiento NO debería incluir:', 'Metilfenidato.', 'Suplementos de hierro, en caso de ferrropenia.', 'Agonistas dopaminérgicos.', 'Pregabalina.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 93, 'Sin clasificar', 'Niño de 7 años q ue acude a ur gencias por un cuadro de 12 horas de evolución de fiebre, cefalea, rigidez de nuca y petequias en tronco y piernas, con impor tante afectación del es tado general. ¿Cuál de las siguientes afirmaciones es correcta?:', 'Es esperable encontrar diplococos grampositivos en el líquido cefalorraquídeo.', 'La etiología mas probable es el neumococo.', 'Será n ecesario hacer qu imioprofilaxis en las personas que hayan estado en contacto íntimo con el paciente.', 'El tratamiento empírico inicial más apropiado es el aciclovir.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 94, 'Sin clasificar', 'Hombre de 67 años con deterioro brusco del nivel de conciencia, encontrándose obnubilado. Presenta alteración visual, con ptosis y midriasis del ojo derecho asociados a pérdida de visión en o jo derecho, sólo cuenta dedos con ojo izquierdo. La TC craneal muestra una lesión hemor rágica que agranda y deforma la si lla turca, c on cierta extensión supraselar. En relación con este cuadro clínico, señale la respuesta INCORRECTA:', 'El tratamiento quirúrgico por vía endoscópica transnasal urgente podría mejorar el pronóstico visual y de afectación de pares.', 'Suele cursar con hiperfunción hormonal.', 'Este cuadro clínico puede aparecer también en mujeres tras el parto.', 'Suele producirse cu ando de b ase h ay una tumoración previa.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 95, 'Sin clasificar', 'Mu jer de 45 años que presenta un dolor de características lancinantes en hemicara derecha. El dolor se despierta al tocarse, lavarse o cepillarse los dientes. No le duele por la noche. Señale la respuesta INCORRECTA:', 'El tratamiento más efectivo es la descompresión quirúrgica si existe contacto neurovascular.', 'La carbamazepina sigue siendo el tratamiento de elección.', 'Tanto la rad iocirugía como los procedimientos ablativos (p.ej. radiofrecuencia) tienen riesgo de recidiva.', 'Es frecuente la pérdida de sensibilidad asociada al dolor.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 96, 'Sin clasificar', '¿Cuál de lo s siguientes fármacos se as ocia a una reducción del delirium en las unidades de cuidados intensivos?:', 'Cisatracurio.', 'Dexmedetomidina.', 'Midazolam.', 'Venlafaxina.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 97, 'Sin clasificar', 'Hombre de 59 años que i ngresa e n UCI por insuficiencia respir atoria aguda hipoxémica secundaria a neum onía c omunitaria grave. P or fracaso respiratorio, precisa sedación y conexión a ventilación mecánica invasiva. Tiene com o antecedente laboral el trabajar en una granja de cerdos, por lo que empíricamente se decide cubrir un esta filococo aureus me ticilin resistente ha sta tener los cultivos de las sec reciones respiratorias. ¿Cuál d e los si guientes a ntibióticos iniciaría empíricamente com o monoterapia antimicrobiana?:', 'Piperacilina-tazobactam.', 'Ceftarolina.', 'Cefazolina.', 'Cefotaxima.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 98, 'Sin clasificar', 'Paciente de 27 años que sufre un accidente de alto impacto con patinete eléctrico en la c alle. A la llegada a urgencias está consciente y orientado, Glasgow 15, con tendencia a la hipotensión. En la exploración inicial presenta impotencia funcional con un balance musc ular segun Daniels de 5 e n todos los grupos de ex tremidades superiores. En extremidades inferi ores psoas 5, cuadriceps 3, tibial anterior, triceps sural y extensores del dedo gordo 0 bilateral. De las siguientes, la sospe cha diagnóstica inicial es:', 'Fractura-luxación de C7-T1', 'Fractura esta llido de L 2 con a fectación neurológica.', 'Isquemia med ular lum bar s ecundaria a l traumatismo.', 'Fractura estallido de T12 con afectación medular completa.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 99, 'Sin clasificar', 'Niña de 12 años sin antecedentes relevantes, con menarquia hace 4 meses, que acude a la consulta de reha bilitación deri vada po r su pediatra tras encontrar una asimetría de hombros en la revisión anual. E n l a exploración fí sica pr esenta una asimetría de la altura de los hombros y de las caderas c on test de Adams positivo. De las siguientes, la actitud correcta a seguir es:', 'Solicitar un escoliograma en bipedestación y en función de l os grados de Cobb de cidir tratamiento con corsé.', 'Proponer u na revisión en 6 meses con un escoliograma en decúbito.', 'Derivar a fi sioterapia para estiramientos y masajes del raquis.', 'Recomendar natación para corregir y revisión en 6 meses.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 100, 'Sin clasificar', 'Mujer de 52 años, c arnicera de pr ofesión, sin antecedentes de interés ni caídas, que presenta dolor en el hombr o de 4 meses de e volución al levantar el brazo. El dolor es de características inflamatorias y las m aniobras de imp ingement positivas. Señale la actitud INCORRECTA:', 'Iniciar t ratamiento con AINE, so licitar un a ecografía y derivar a rehabilitación', 'Derivar a un cirujano especialista para hacer una artroscopia de hombro.', 'Si hay limitación pasiva del balance articular, con la sospecha de capsulitis adhesiva, derivar a rehabilitación urge nte para movilizaciones pasivas.', 'Se sos pecha una l esión del manguito de los rotadores (supraespinoso con bursitis subacromial), por lo que hay que potenciar la musculatura descoaptante del hombro.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 101, 'Sin clasificar', 'Mujer de 56 años que c onsulta porque hace 4 meses se torció el tobillo en la pla ya y de sde entonces no ha de jado de mol estarle. Se ca nsa subiendo escaleras y le cuesta usar calzado plano. En la explor ación presenta dolor e n el seno del tarso, el talón y la cara medial del to billo. Al examen podoscópico presenta el talón en valgo, aunque corrige de puntillas. La estructura más probablemente afecta es:', 'El tendón del músculo tibial posterior.', 'El ligamento peroneo-astragalino anterior.', 'El tend ón d el músculo f lexor larg o del dedo gordo.', 'El ligamento intertalocalcáneo.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 102, 'Sin clasificar', 'Cuidadora de personas mayores de 55 años, sin antecedentes de interés, diestra, que refiere dolor y acorchamiento en cara palmar de ambas manos, peor en la de recha, con predominio nocturno, así como sensación de gran hinchazón al despertarse por las mañanas, siendo algo más intenso en lo s dedos 2º y 3º. No re fiere ningún otro síntoma en miembros s uperiores ni en cuello. ¿De la s siguientes, cuál es l a primera sos pecha diagnóstica?:', 'Espondiloartrosis cervical C5-C6.', 'Compresión cubital epitroclear.', 'Hernia discal cervical C6-C7.', 'Síndrome del túnel carpiano.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 103, 'Sin clasificar', 'Acude de nuevo a urgencias una mujer de 67 años que ayer fue tratada de una fractura del extremo distal del radio izquierdo mediante r educción cerrada bajo anestesia focal y yeso antebraquial. Aqueja dolor insoportable, que aumenta cuando se le mueven los dedos; efectivamente es incapaz de movilizar activamente los dedos y estos están muy hinchados. ¿Qué c omplicación debemos tratar inmediatamente?:', 'Síndrome de dolor regional complejo.', 'Síndrome compartimental local.', 'Rotura tendinosa de extensores.', 'Desplazamiento secundario de la fractura.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 104, 'Sin clasificar', 'Paciente de 73 años activo, que presenta dolor de intensidad EVA 8-9 en el hom bro derecho (miembro dominante) con pérdida de movilidad. Se realiza una radiografía y una RM que muestran una r otura c ompleta del manguito rota dor co n ascenso de la cabeza humer al y erosi ón (acetabulización) del borde inferior del acromion. ¿Cuál de la s siguientes es la ac titud terapéutica más adecuada?:', 'Prótesis anatómica de hombro.', 'Infiltración del resto d e manguito con células mesenquimales.', 'Reparación artroscópica d el manguito rotador mediante anclajes en doble hilera.', 'Prótesis invertida de hombro.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 105, 'Sin clasificar', 'Niña de 6 añ os que estab a celebrando un cumpleaños en un castillo hinchable, ca yendo sobre el br azo extendido. Acude a urgencias con dolor y de formidad a ni vel del húm ero distal derecho e i mpotencia funcional del c odo. A l a exploración no se palpa pulso radial, el relleno capilar de los dedos es de 2 segundos y el color de la mano es sonrosado. L a actitud má s recomendable es:', 'Realizar una arteriografía de la arteria humeral.', 'Reducir y fi jar l a fractura en q uirófano y observar la respuesta vascular.', 'Proceder a la exploración quirúrgica de la arteria humeral.', 'Hacer una ecografía Doppler de la arteria radial a nivel de la muñeca.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 106, 'Sin clasificar', 'Neonato de 3 semanas que presenta un reflejo de Moro asimétrico. P arto va ginal de ma dre primímara, peso a l na cer 4.600 g. Se palpa un bulto en la clavícula derecha y mantiene el hombro derecho e n aducción, c on el codo e xtendido y flacidez de muñeca y dedos de la mano derecha. En la radiografía de t órax realizada al nacer se observa una elevación del hemidiafragma derecho. Es signo de mal pronóstico la existencia de:', 'Ausencia de contracción del bíceps a esta edad.', 'Una fractura de clavícula ipsilateral.', 'Un síndrome de Horner ipsilateral.', 'Una luxación congénita de la cadera ipsilateral.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 107, 'Sin clasificar', 'Hombre de 62 años sin antecedentes de interés y profesión sedentaria, que consulta por dolor muy intenso, incapacitante, en re gión lumbar, de 1 semana de e volución, irr adiado a n alga, cara posterior de muslo izquierdo y cara anterolateral de piern a iz quierda. El signo de Lasègue es negativo y no presenta déficit de fuer za en las extremidades inferiores. La actitud terapéutica más adecuada, de entre las siguientes, es:', 'Remitir de forma urgente a n eurocirugía para pruebas de imagen y valoración quirúrgica.', 'Realizar ra diografía y resonancia magnética urgentes de raquis lumbar.', 'Pautar un antiinflamatorio no esteroideo a dosis alta, evitar el reposo en cama, calor local suave y revisión en 2 semanas.', 'Solicitar un electromiograma prefe rente de extremidades inferiores.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 108, 'Sin clasificar', 'Mujer de 60 años de edad diagnosticada de una enfermedad autoinmune. En la exploración física presenta aumento de ta maño bilateral de parótidas, vasculitis cutánea y test de Schirmer en ojo derecho 2 mm, ojo izquierdo 1 mm (por debajo de l o normal). E n l a analítica des taca f actor reumatoide positivo, VSG 30 mm (1-20), PCR 1,3 (0-0,5), anticuerpos an tinucleares positivos con patrón moteado fino, anti Ro y anti La positivos e hipocomplementemia. ¿Cuál de esta s enfermedades tiene m ás riesgo de desarrollar durante la evolución de la enfermedad?:', 'Leucemia linfoblástica aguda.', 'Linfoma de células B.', 'Leucemia de células NK.', 'Linfoma no Hodgkin de células T.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 109, 'Sin clasificar', 'Hombre de 50 años que consulta por dolor lumbar de 6 mese s de evolución que no mejora con el reposo, incluso le despier ta por l a noche, con rigidez lumbar matutina de má s de una hora de duración. ¿Cuál de las siguientes imágenes es más probable encontrar en una radiografía de columna lumbar?:', 'Osteofitos típicos de la espondiloartrosis.', 'Osteofitos típicos de la espondiloartritis.', 'Sindesmofitos típicos de la espondiloartrosis.', 'Sindesmofitos típicos de la espondiloartritis.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 110, 'Sin clasificar', 'Respecto a las manifestaciones extraarticulares de la artritis reumatoide, señale l a respuesta INCORRECTA:', 'Es la causa más frecue nte de sí ndrome de Sjögren se cundario y cursa con queratoconjuntivitis seca.', 'La manifestación cardiaca más frecuente es la pericarditis.', 'La pleuritis se caracteriza por un derrame pleural con características de exudado y típicamente con glucosa muy baja.', 'La manifestación hematológica más frecuente es la leucopenia.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 111, 'Sin clasificar', 'Hombre de 48 años con a ntecedentes de hipercolesterolemia y tabaquismo activo. Presenta dolor ce ntrotorácico irradiado a cuello acompañado de náuseas y sudoración profusa de una hora de evolución. El dolor se había iniciado durante el ascenso a una montaña, motivo por el que es trasladado a un centro de salud, donde se le practica un electrocardiograma que muestra un infarto de mi ocardio a gudo an teroseptal. El hospital terciario más cercano (con hemodinámica de guardia 24 h) se encuentr a a tres horas de distancia. ¿En cuál de las siguientes circunstancias DESCARTARÍA la reperfusión cor onaria extrahospitalaria mediante fibrinólisis intravenosa y plantearía una angioplastia primaria?:', 'Presencia de signos de insuficiencia cardiaca.', 'Antecedente de hemorragia craneal sin secuelas hace 10 años.', 'Antecedente de ictus isquémico hace 18 meses.', 'Cifras de tensión arterial ≥ 140/90 mmHg.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 112, 'Sin clasificar', 'Todas las situaciones que se enumeran a continuación se refieren a pacientes con alto riesgo de desarrollar endocarditis infecciosa y por ello con i ndicación de pr ofilaxis antibiótica ante procedimientos invasivos, EXCEPTO UNA. Señale cual:', 'Pacientes portadores de válvula aórtica protésica transcatéter.', 'Pacientes con cardiopatía congénita cianótica no tratada.', 'Pacientes con válvula aórtica bicúspide.', 'Pacientes que han sufrido endocarditis infecciosa previa.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 113, 'Sin clasificar', 'En relación con el tratamiento de los pacientes con síncope, señale la respuesta correcta:', 'El tratamiento del sí ncope reflejo es fundamentalmente farmacológico.', 'La estimulación con marcapasos en el síncope recurrente asociado a un mecanismo hipotensor ha demostrado ser eficaz.', 'Los fármacos bet abloqueantes re ducen l a mortalidad de los síncopes reflejos.', 'Las contracci ones muscula res isotónicas son útiles en pacientes jóvenes con síncope reflejo y pródromos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 114, 'Sin clasificar', 'Hombre de 23 años q ue tras un cu adro gripal acude en situación de shoc k cardiogénico refractario a aminas a un hospital de 3º nivel. En el ecocardiograma tr anstorácico se aprecia una fracción de eyección de ventrículo izquierdo del 15 %. Ante la sospecha de miocarditis vírica ¿cuál de las siguientes es la opci ón terapéutica de elección para mejorar su situación hemodinámica?:', 'Aumentar la dosis de aminas e inclusión en lista urgente para trasplante cardiaco.', 'Colocación de un bal ón de c ontrapulsación intraaórtico.', 'Implante de un dispositivo el ectrónico de estimulación biventricular.', 'Colocación de un dispositivo de a sistencia ventricular de corta duración .', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 115, 'Sin clasificar', 'En rela ción con la endocarditis infeccio sa (EI) señale c uál de las si guientes situ aciones tiene indicación de cirugía cardiaca en 24-48 horas:', 'Paciente de 82 años con EI po r S. mitis sobre prótesis aórtica biológica, c on buena evolución clínica, sin dehiscencia valvular, c on un pseudoaneurisma de raíz aórtica a la 4º semana de tratamiento antibiótico.', 'Paciente de 70 años con EI mitral por E. faecalis en el que se evidencia una insuficiencia valvular moderada.', 'Paciente de 75 años con EI aórtica con regurgitación valvular mo derada y si n compromiso hemódinámico, co n ai slamientos repetidos en hemocultivos de Candida albicans sensible a azoles.', 'Paciente de 68 años con EI aórtica por S. aureus con i nsuficiencia val vular aórtica mode radagrave y episodio de fracaso ventricular izquierdo con insuficiencia cardiaca grado III de la NYHA durante la primera se mana de tratamient o antibiótico.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 116, 'Sin clasificar', 'En relación con el prolapso de la válvula mitral, señale la respuesta correcta:', 'La degeneración mixomatosa valvular también puede afectar a las válvulas tricúspide y aórtica.', 'Es más frecuente en hombres.', 'Tiene un curso benigno y raramente o rigina insuficiencia valvular mitral.', 'El soplo c ardiaco q ue pue de originar característicamente disminuye de intensidad con la maniobra de Valsalva.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 117, 'Sin clasificar', 'Mujer de 58 años que, tras un catarro de vías altas, ingresa en e l hospital por disnea de mínimos esfuerzos, as tenia intensa y disnea paroxístic a nocturna en los días p revios. El electrocardiograma muestra un ritmo sinusal a 70 lpm con bloqueo de r ama izquierda. En el ecocardiograma tr anstorácico se aprecia una función ventricular izquierda (FEVI) del 25 %. La coronariografía desc arta enfer medad arterial coronaria. De las si guientes prop uestas de tratamiento ¿cuál sería la combinación de fármacos recomendada que mejore su pronóstico y reduzca los reingresos hospitalarios por descompensación cardiaca?:', 'Betabloqueante, digoxina, AR NI (i nhibidor de neprilisina-receptor an giotensina) e iSGLT2 (inhibidores del cotransportador de sodio-glucosa tipo 2).', 'Betabloqueante, antagonistas de l a aldosterona, ivabradina e i SGLT2 (inhibidores del cotransportador de sodio-glucosa tipo 2).', 'Betabloqueante, antagonistas de l a aldosterona, ARNI (inh ibidor de n eprilisina-receptor angiotensina) y milrinona.', 'Betabloqueante, antagonistas de l a aldosterona, ARNI (inh ibidor de n eprilisina-receptor angiotensina) e i SGLT2 (inhibidores del cotransportador de sodio-glucosa tipo 2).', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 118, 'Sin clasificar', 'Paciente de 65 años con antecedentes de un infarto de miocardio de c ara anterior que presenta una taquicardia con QRS ancho que se acompañ a de hipotensión (TA 70/40 mmHg) y de obnubilación. ¿Cuál de l os si guientes es el tr atamiento de elección?:', 'Lidocaína IV.', 'Amiodarona IV.', 'Procainamida IV.', 'Cardioversión eléctrica urgente.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 119, 'Sin clasificar', 'Ante un recién nacido a término cianótico con pO2 de 30 mmHg, hipertrofia de ventrículo derecho en el electrocardiograma e imagen "de huevo" en la radiografía de tórax ¿cuál de l os siguientes es el diagnóstico más probable?:', 'Dextro-transposición de grandes arterias.', 'Persistencia del ductus arterioso.', 'Tetralogía de Fallot.', 'Enfermedad de Ebstein.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 120, 'Sin clasificar', 'Hombre de 70 años sometido hace 5 días a cirugía de re vascularización cor onaria que ac ude a urgencias por un sínc ope tras el que persiste sensación de mare o. E n la explor ación des taca tensión ar terial 70/40 mmHg, rui dos cardi acos disminuidos y distensi ón ve nosa yugular c on fenómeno de alter nancia eléctric a en el electrocardiograma. ¿Cuál de l os s iguientes diagnósticos es más probable?:', 'Síndrome coronario agudo.', 'Pericarditis.', 'Taponamiento cardiaco.', 'Endocarditis.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 121, 'Sin clasificar', 'Mujer as mática que tras un día de torme nta presenta sensación disneica y autoes cucha de sibilancias. Tras tratamiento inicial co n un agonista beta2 y cor ticoides inhal ados n o se produjo me joría de l os síntomas, requiriendo broncodilatadores cada hora durante varias horas consecutivas, con aparición de u n i mportante aumento del trabajo respiratorio. De las siguientes ¿cúal es la actitud más adecuada?:', 'Se deben administrar de forma urgente agonistas beta2 nebulizados y, e n caso de au sencia de respuesta t emprana, a ñadir corticoides intravenosos.', 'Antes de iniciarse el trata miento debe realizase radiografía d e tórax, gasometría arterial y analítica general para establecer el diagnóstico.', 'Los c orticoides i nhalados est arían contraindicados po r au mentar el r iesgo d e neumonía.', 'Como primera elección se de ben admi nistrar anticolinérgicos ne bulizados, de bido a l a ausencia de respuesta a los agonistas beta2.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 122, 'Sin clasificar', 'Hombre de 75 años con a ntecedentes de insuficiencia cardiaca con fracción de eyección del ventrículo iz quierdo del 30 % . Consulta p or apneas durante el sueño presenci adas por s u pareja. El grado de somnolencia en la escala de Epworth es de 5. El es tudio del sue ño muestra episodios de respiración periódica con un índice de apneas-hipopneas de 22 por hora de sueño, siendo todos los eventos res piratorios centrales. De las siguientes, la actitud terapéutica recomendada es:', 'Iniciar tratamiento con presión positiva continua por vía nasal.', 'Optimizar el tratamie nto de la insuficiencia cardiaca.', 'Ensayo terapéutico con prótesis de avanzamiento mandibular.', 'Iniciar tratamiento con servoventilación.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 123, 'Sin clasificar', 'Paciente de 75 años, fumador (IPA 35), que refiere disnea de esfuerzo progresiva desde hace 3 años. La radiografía de tórax no mues tra alteraciones relevantes. En la espirometría basal presenta FVC 1720 mL (62 %) , FE V1 610 mL (30 %) y FEV1/FEVC 35 %. ¿Cúal es el dia gnóstico d e sospecha y la siguiente acción a tomar?:', 'Se trata de una alteración ventilatoria mixta de predominio restrictivo. Par a el estudio de las causas se debe realizar estudio funcional completo.', 'Se pue de establecer el diagnóstico de enfermedad pu lmonar obstructiva crónica. Se debe solicitar TC torácica para co nfirmar la existencia de enfisema.', 'Se trata de una alteración ventilatoria mixta con un co mponente ob structivo gr ave. Probable EPOC en la que, una vez confirmada la ausencia de rev ersibilidad, se p uede in iciar tratamiento con corticoides inhalados.', 'Presenta un a alteración ventilatoria mix ta con componente obstructivo g rave que sugiere EPOC. Un a vez co nfirmada la au sencia de reversibilidad, se pu ede in iciar tratamiento broncodilatador.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 124, 'Sin clasificar', 'En relación con la fibrosis pulmonar idiopática, señale cual de las siguientes afirmaciones es cierta:', 'La imagen característica de l os hallazgos en la TC torácica e s la aparición de opacida des en vidrio deslustrado.', 'Para establece r el diagnósti co se re quiere la realización de una bi opsia del pa rénquima pulmonar.', 'En ocasiones se asocia a enfermedades del tejido conectivo.', 'La terap ia an tifibrótica (p irfenidona y nintedanib) pued e lentificar el d eterioro de la función pulmonar.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 125, 'Sin clasificar', 'Hombre de 65 años diagnosticado de E POC con dos agudizaciones en el último año, en tratamiento inhalado con tiotropio. Presenta un volumen espiratorio máximo en el primer segundo (VEMS) del 48 %. Tras estar más de dos meses en situación clínica estable, presenta PaO2 58 mmHg y PaCO2 49 mmHg en la gasometría arterial. En la analítica presenta 450 eosinófilos/microL. No presenta hipertensión pulm onar, cor pulmonale, ni poliglobulia. Con estos datos ¿cuál de las siguientes actuaciones es más apropiada?:', 'Iniciar oxigenoterapia crónica domiciliaria.', 'Optimizar el tratamiento broncodilatador.', 'Optimizar el tratamient o broncodilatador e iniciar oxigenoterapia crónica domiciliaria.', 'Iniciar o xigenoterapia crónica d omiciliaria y ventilación mecánica no invasiva domiciliaria.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 126, 'Sin clasificar', 'La causa mas frecuente de hipoxemia es:', 'Hipoventilación alveolar.', 'Trastornos d e l a difusión alveolocapilar de oxígeno.', 'Cortocircuito intrapulmonar de derec ha a izquierda.', 'Desequilibrio en la relació n ventilaciónperfusión.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 127, 'Sin clasificar', 'Mujer de 7 1 años diagnosticada de esclerosis lateral amiotrófica. Es valorada en co nsulta por ortopnea y cefalea m atutina. Presenta una capacidad vital forzada del 40 %, PaCO2 de 53 mmHg. La oximetría nocturna mues tra una saturación de oxígeno media de 91 % y un 16 % del tiempo con saturación de oxigeno inferior al 90 % y alguna desaturación inferior al 70 %. ¿Cuál de las siguientes actitudes es más apropiada?:', 'Iniciar ventilación mecánica no invasiva.', 'Realizar co ntroles clín icos sin iniciar un tratamiento concreto en el momento actual.', 'Iniciar oxigenoterapia por presentar insuficiencia respiratoria nocturna.', 'Iniciar presión positiva continua (CPAP).', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 129, 'Sin clasificar', '¿Cuál de los siguientes genes puede estar afectado en familias que desarrollan tumores malignos de colon en sucesivas generaciones?:', 'RAS.', 'p53.', 'BRCA1.', 'MLH1.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 130, 'Sin clasificar', 'En un paciente con es teatosis hepática metabólica (antes enfermedad hepática por depósito de grasa) el ries go de des arrollo de he patocarcinoma e n comparación con otras etiologías frecuentes como la hepatopatía alcohólica o la hepa titis C, se caracteriza por:', 'Aparecer en personas más jóvenes.', 'Se beneficia de l os programas de diagnóstico precoz.', 'Aparece más fecuentemente en fases previas a la cirrosis.', 'Presenta una incidencia acumulada anual mayor que en la hepatitis C.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 131, 'Sin clasificar', 'Mujer de 24 años que consulta por un cuadro de dolor abdominal, asten ia, diarre a de lar ga evolución con rectorragia ocasional y pérdida de 10 K g de peso en 3 mes es. En l a exploración destacan signos de desnutrición, dolor abdominal difuso con mayor focalidad en fosa ilíaca derecha. En la analítica destacan una hemoglobina baja y una elevación de la PCR. En la colonoscopia se encuentran úlceras aftosas, inflam ación segmentaria y un área de estenosis infranqueable, todo ello en ciego. La enterorresonancia confirma este hallazgo y la existencia de inflamación en íleon distal. E l cuadro es refr actario al tratamiento farmacológico, por lo que se considera la cirugía. De las siguientes, señale la técnica quirúrgica más adecuada:', 'Hemicolectomía derecha ampliada.', 'Panproctocolectomía con reservorio en J.', 'Ileocequectomía.', 'Colostomía terminal.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 132, 'Sin clasificar', 'Mujer de 73 añ os que acude a ur gencias p or prurito, ictericia, astenia y pérdida de peso de un mes de evol ución. Recientemente ha recibido tratamiento con amoxicilina/clavulánico por una infección urinaria. Se realiza una eco grafía que informa de dilatación de la vía biliar intra y extrahepática con vesícula biliar distendida. De las siguientes ¿cuál es la primera sospecha diagnóstica y actitud?:', 'Toxicidad por fármacos. Retirada del antibiótico.', 'Colecistitis aguda. Colecistectomía urgente.', 'Coledocolitiasis d istal. So licitar u na colangiorresonancia magnética.', 'Tumoración maligna obstructiva de colédoco distal. Solicitar una TC abdominal para estudio de extensión local y a distancia.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 133, 'Sin clasificar', 'Hombre de 57 años con cirr osis hepática metabólica que consulta por un cuadro recidivante de c onfusión y desorientaci ón a pe sar del tratamiento con rifaximina y lactulosa. En la angio-CT s e aprecia una c omunicación portosistémica d e gran calibre. L a función hepática está alterada co n MELD 17p y C hild- Pugh B8. ¿Cuál de los siguientes tratamientos es más apropiado?:', 'Trasplante hepático.', 'Oclusión de la comunicación portosistémica.', 'Colocación de TIPS (p rotesis intrahe pática percutánea transyugular).', 'Trasplante de microbiota fecal.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 134, 'Sin clasificar', 'En relación con l a clasificación de l as heridas quirúrgicas de los Centers for Disease Control and Prevention, una incisión e n la que se encuentra inflamación aguda no purulenta es:', 'Grado I: Herida limpia.', 'Grado II: Herida limpia contaminada.', 'Grado III: Herida contaminada.', 'Grado IV: Herida sucia-infectada.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 135, 'Sin clasificar', 'Mujer de 62 años que consul ta por d olor abdominal persistente, pérdida de peso no intencionada de 10 k g en los últimos tres meses, ictericia y acolia. En las últimas horas presenta vómitos de retención gástrica. Las analíticas muestran elevaci ón de bilirrubina y enzimas hepáticas as í como hipopotasemia. La TC abdominal rev ela un a ma sa e n la ca beza d el páncreas y proce so u ncinado que provoca obstrucción de la vía biliar, infiltración inextirpable vascular , distensión y retenci ón gástrica. Tras estabil izarla se efec túa ecoendoscopia con biopsi a que de muestra la existencia de un aden ocarcinoma pancreático con estenosis infranqueable del duodeno. ¿Cuál de las siguientes es la mejor actitud terapéutica?:', 'Doble derivación bilio-digestiva.', 'Intervención de Whipple.', 'Intervención de Puestow.', 'Coledocoduodenostomía.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 136, 'Sin clasificar', 'Hombre de 50 años que consulta por presentar una tumoración reductible en región inguinal que se aprecia tras maniobras de Valsalva y que apareció tras realizar un esfuerzo 1 mes antes. E n relación con la pa tología más probable, indique la opción terapéutica adecuada:', 'Resección de la tumorac ión pa ra análisis anatomopatológico.', 'Colocación de una prótesis mediante un abordaje endovascular.', 'Realización de una derivación o by pass a nivel de la lesión.', 'Reparación del defecto herniario con una prótesis para evitar tensión.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 137, 'Sin clasificar', 'Paciente di abético de 50 años que ac ude a urgencias con fiebre de 39ºC y malestar general que re fiere dolor anal desde hace 5 días. A la exploración destaca una gran tumoración perianal caliente y dolorosa, con necrosis de piel. El tratamiento de elección es:', 'Drenaje-desbridamiento quirúrgico.', 'Antibiótico de amp lio esp ectro y esp erar evolución.', 'Ingreso hospitalario para estudio.', 'Punción-drenaje guiado por radiología.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 139, 'Sin clasificar', 'Hombre de 45 años que presenta un pólipo sesil de aspecto ma croscópicamente b enigno en colon sigmoide. Extraído med iante po lipectomía endoscópica, la biopsia mues tra un adenocarcinoma. ¿Cuál de los siguientes hallazgos anatomopatológicos indica alto ries go de recurrencia y es indicación de c olectomía segmentaria?:', 'Tumor T1 con invasión de la submucosa sm3.', 'Distancia al borde de sección de 2,5 mm.', 'Tumor bien diferenciado.', 'Ausencia de invasión linfovascular.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 140, 'Sin clasificar', 'En relación con la antisepsia del campo quirúrgico en una lapar otomía de piel indemne por ciru gía oncológica, ¿qué s olución de l as si guientes ha demostrado ser más eficaz?:', 'Povidona iodada.', 'Clorhexidina acuosa.', 'Clorhexidina alcohólica.', 'Poli-hexametilen-biguanida.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 141, 'Sin clasificar', '¿Cuál de las si guientes es causa de acidosis metabólica con brecha aniónica (anion gap) normal?:', 'Acidosis láctica por metformina.', 'Diarrea aguda.', 'Cetoacidosis diabética.', 'Intoxicación por metanol.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 142, 'Sin clasificar', 'Acude a consulta un paciente con diabetes mellitus tipo 2 de siete añ os de evolución, c on un filtrado glomerular estimado de 35 ml/min. ¿Cuál de lo s siguientes hallazgos NO apoya el diagnóstico de enfermedad renal diabética?:', 'Aumento lento de las cifras de creatinina sérica.', 'Presencia de retinopatía diabética.', 'Hematuria persistente (micro o macroscópica).', 'Cociente albúmina/crea tinina en ori na > 30 mg/g.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 143, 'Sin clasificar', 'Hombre de 28 años con diagnóstico reciente de linfoma de Hodgkin, que consulta por debilidad y edematización pro gresivas. La exploración e s normal salvo por la presencia de edema con fóvea hasta las ro dillas. Análisis: urea 58 mg/dl, creatinina 0,78 mg/dl, sodio 138 mEq/l, potasio 4,3 mEq/l, albú mina 2 g/dl. Sistemático de orina: proteinuria 4+ (> 600 mg/dl) sin hema turia ni leucocituria. ¿Cuál de las siguientes enfermedades es más probable que tenga?:', 'Glomerulonefritis de cambios mínimos.', 'Glomerulonefritis membranosa.', 'Glomerulonefritis membranoproliferativa.', 'Glomeroesclerosis focal y segmentaria.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 144, 'Sin clasificar', 'Mujer de 52 añ os que c onsulta p or un ras h eritematoso pruri ginoso. Com o antecedentes destacables consta un cólico nefrítico una semana antes, para el que re cibió tr atamiento c on dexketoprofeno y omepra zol. En la ana lítica destaca un filtrado glomerular estim ado de 45 ml/min (previamente normal), sin pr oteinuria ni otras al teraciones. ¿Cuál de los si guientes diagnósticos es más probable y qué actitud terapéutica debe adoptarse?:', 'Toxicidad renal directa del dexketoprofeno y/o omeprazol. Con la s uspensión de los fármacos sería suficiente.', 'Obstrucción de t racto urinario superior por litiasis. Realizar una ecografía para confirmarlo y, de ser así, eliminar la obstrucción.', 'Necrosis tubular aguda. Dar un marg en d e tiempo para la recuperación espontánea de las células tubulares.', 'Nefritis intersticial. Hacer una biopsia renal para confirmarlo y, en cas o afirmativo, administrar corticoides.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 145, 'Sin clasificar', 'Hombre de 5 2 años que acude a urgencias por debilidad y dificultad para la articulación de la palabra. Con stantes: TA 115/60 mmHg, F C 80 lpm, t emperatura 37,8ºC. Exp loración neurológica: bradilalia, bradipsiquia y pérdida de fuerza en mano izquierda. Auscultación y abdomen sin hallazgos. Petequias en cara interna de muslos y dorso de los pies. An gioTC cerebral sin signos de sangrado intracraneal ni patología isquémica aguda. Analítica: Hb 7,2 g/dl, 12 .340 leucocitos (92 % PMN), plaquetas 14.600, urea 183 mg/dl, creati nina 2,3 m g/dl, bilirrubina total 2 mg/dl, tra nsaminasas normales, LDH 2. 125 UI, ferritina 1.582 n g/mL, haptoglobina < 30 mg/dl. Frotis de s angre perifé rica con anis ocitosis y abundantes microesferocitos y esquistocitos (3-4 por campo) s in agregados plaquetarios. ¿Cuál de los siguentes tratamientos es MENOS apropiado?:', 'Iniciar plas maféresis con plasma fresc o congelado de forma precoz.', 'Realizar transfusión de hematíes.', 'Realizar transfusión de plaquetas.', 'Iniciar tratamiento con corticoides.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 146, 'Sin clasificar', 'En relación c on el cáncer de prós tata, señale la respuesta INCORRECTA:', 'El principal factor de riesgo es la edad.', 'Los portadores del gen BRCA-1 tienen mayor predisposición a sufrir la enfermedad.', 'Es más frecuente en varones caucásicos.', 'Las grasas animales, la ob esidad, el háb ito tabáquico y el cad mio tamb ién se h an relacionado con su etiopatogenia.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 147, 'Sin clasificar', 'Varón de 66 años sin antecedentes de interés que acude a urgencias por dolor ti po cólico en fos a renal derecha, sin re percusión analítica. El dolor se controla con el tratamiento analgésico pautado. La ecografía abdominal describe la existencia de un engrosamiento focal de 2,5 cm de diámetro en pelvis renal derecha. ¿Qué prueba se debe solicitar para completar el estudio?:', 'Resonancia magnética.', 'Urografía intravenosa.', 'Tomografía axial sin y con contraste IV.', 'Repetir la ecografía abdominal.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 148, 'Sin clasificar', 'Hombre de 1 7 años que acude a urgencias por dolor testicular izquierdo de 10 horas de evolución de inicio súbito, que le ha despertado mientras dormía, asociado a cortejo vegetativo y náuseas. En las últimas 24 horas refiere haber realizado actividad deportiva (un partido de fútbol en el que no recuerda haber sufrido traumatismo) y actividad sexual (con su pare ja ha bitual y con preservativo). A l a exploración he miescroto izquierdo hipersensible, con testícul o y epidídimo tumefactos y mu y dol orosos, horizontalizados y discretamente aumentados de tamaño respecto al contralateral, si gno P rehn n egativo, transiluminación ne gativa. N o h ay dispo nible urólogo ni radiólogo de presencia física. ¿Cuál es la actitud más apropiada?:', 'Intento de detorsión testicular manual en rotación externa y exploración quirúrgica en las primeras 24 horas.', 'Toma d e constantes, an alítica u rgente (hemograma, bioquímica y sistemático de orina), analgesia y antibioticoterapia intravenosa.', 'Remitir a la co nsulta d e urología d e forma preferente.', 'Hielo local y analgesia intra venosa con reevaluación posterior.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 149, 'Sin clasificar', 'Con respec to a l a PET-TC con 18F- fluorodesoxiglucosa (18F-FDG) en p acientes c on linfoma, señale la respuesta INCORRECTA:', 'Es más exacta para la valoración de la médula ósea en el linfoma de Hodgkin (LH).', 'Realizada a mitad de tratamiento en el LH ayuda a decidir la duración del mismo.', 'Es útil en los lin fomas no Hod gkin de bajo grado.', 'Al final del tratamiento puede diferenciar entre enfermedad residual y enfermedad activa.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 150, 'Sin clasificar', 'En relación con l a indicación de i rradiación parcial del cáncer de mama, señale la respues ta correcta:', 'No está indicada en pacientes postmenopáusicas.', 'Solo la pueden recibir pacientes diagnosticadas de carcinoma in situ.', 'Es de elecci ón e n pacientes c on ganglios positivos.', 'No se debe emplear cuando hay más de un foco tumoral o lesiones multicéntricas.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 151, 'Sin clasificar', '¿Cuál de las si guientes al teraciones es m ás frecuente en el cáncer de pulmón no m icrocítico metastásico?:', 'Mutación de KRAS.', 'Mutación de BRAF.', 'Reordenamiento de ALK.', 'Fusión de NTRK.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 152, 'Sin clasificar', 'Mujer de 21 años sin antecedentes de interés que consulta por palpitaciones, nerviosismo y cambios de comportamiento. Se le diagnostica de crisis de ansiedad. Diez días más tarde consulta de nuevo por ce falea, alucinaciones audi tivas, discurso incoherente y sí ntomas psicóticos. L a analítica general, la radiografía de tórax, la TC craneal y los estudios microbiol ógicos son normales. La resonancia ma gnética cerebral mues tra hiperintensidad en FLAIR e n hipocampo. En sangre se detectan anticuerpos contra receptores de N-me til-d-aspartato. ¿Cuál de l os siguientes diagnósticos es el más probable?:', 'Teratoma ovárico.', 'Sarcoma de Ewing.', 'Cáncer de mama.', 'Linfoma de Hodgkin.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 153, 'Sin clasificar', '¿Cuál de los siguientes datos NO es relevante antes de inicia r un tratamiento a dyuvante con fluorouracilo a un paciente intervenido de cáncer de colon?:', 'El aclaramiento de creatinina.', 'Determinación d e la d ihidropirimidina deshidrogenasa (DPD).', 'Síntomas previos de neurotoxicidad.', 'Antecedentes de cardiopatía isquémica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 154, 'Sin clasificar', 'Paciente de 6 2 años en estudio por un a pancitopenia. Se realiza una punción de la medula ósea objetivando un 15 % de blastos mieloides con estudio citogenético normal. Según la clasificación de enfermedades de la OMS el proceso debería ser catalogado como:', 'Leucemia mieloide aguda.', 'Síndrome mielodisplásico con exceso de blastos.', 'Anemia megaloblástica.', 'Aplasia medular.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 155, 'Sin clasificar', 'En una anemia por deficiencia de hierro en una mujer joven por sangrado menstrual excesivo, sin otras complicaciones añadidas, ¿cuál de los siguientes par ámetros analíticos es tará aumentado?:', 'Concentración de ferritina en suero.', 'Concentración de hemoglobina en reticulocitos.', 'Volumen corpuscular medio de los hematíes.', 'Concentración de transferrina en suero.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 156, 'Sin clasificar', 'Un paciente con grupo sanguíneo A positivo y una leucemia mi eloide a guda es some tido a un trasplante h ematopoyético con un donante B positivo. La médula del don ante prende adecuadamente alcanz ando un quimerismo completo. Sin haber recibido transfusiones en los cuatro mese s previos, a los seis meses del procedimiento, perm aneciendo en quimerismo completo, se realiza un nuevo grupo sanguíneo al receptor. El resultado será:', 'A po sitivo. El grupo san guíneo p ermanece inalterable durante toda la vida.', 'AB positivo. Existe una mezcla de ambos grupos en los hematíes.', 'B positivo. Ha cambiado de grupo adquiriendo el del donante.', 'O positivo. Los anticuerpos anti-transferasa del receptor inhiben la expresión de los grupos sanguíneos, siendo todos lo s p acientes trasplantados del grupo O.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 157, 'Sin clasificar', 'El conjunto de to das las ca pacidades f ísicas y mentales de una persona que permiten hacer frente a l os cambios de l entor no, ori ginando discapacidad cuando fallan, se denomina:', 'Fragilidad.', 'Morbilidad.', 'Capacidad intrínseca.', 'Discapacidad.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 158, 'Sin clasificar', 'Una de las siguientes escalas, usadas para valorar la fragilidad, requiere la realización de pruebas de ejecución:', 'La escala FRAIL.', 'El índice de fragilidad de Rockwood.', 'La Clinical Frailty Scale (CFS).', 'La Short Physical Performance Battery (SPPB).', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 159, 'Sin clasificar', 'Hombre de 84 años que acude a su m édico de familia porque, tras haberse caído tres veces a lo largo del último año, tiene miedo a volver a caerse. Se le hace una prueba cronometrada "Levántese y Ande" (Get Up and Go), que tarda en completar 21 segundos (normal <10 s) . Respecto el ries go de caída que presenta, señale la respuesta correcta:', 'El riesgo es bajo, por lo que se reevaluará dentro de un año.', 'El riesgo es i ntermedio, por lo que se realizará educación general para prevenir futura s caídas sin intervención individualizada.', 'No tiene riesgo de nueva s caídas, no precisa seguimiento.', 'El riesgo es alto, por l o que se realizará una valoración multifactorial del riesgo de caídas con intervención individualizada.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 160, 'Sin clasificar', 'Hombre de 93 años c on antecedentes de HT A, diabetes mellitus, hiperplasia benigna de próstata y demencia mixta leve. Necesita a yuda d e un a persona para bajar las es caleras, es incontinente urinario pero él mismo se cambia el pañal y es independiente para el res to de las actividades básicas de la vida diaria, con dependencia para la mayoría de actividades i nstrumentales. Ha sido intervenido de una fractura subcapital de fémur derecho Garden IV de etiología osteoporótica con colocación de hemiartr oplastia, sin presentar complicaciones médicas ni quirúr gicas. Señale la respuesta correcta:', 'No es candidato a tratamiento osteoprotector por edad y presencia de demencia.', 'No se deben iniciar bi fosfonatos si presenta hipocalcemia.', 'Debe s uplementarse co n calcio au nque su s valores sean normales.', 'Debe permanecer encamado seis semanas tras la intervención qu irúrgica p ara mejorar la consolidación de la fractura.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 161, 'Sin clasificar', 'Hombre de 91 años que consulta por creciente dificultad para hacer su s tareas h abituales y sensación de debilidad. Su IMC es de 22,5 y su masa muscular medida po r bioimpedanciometría es de 14 k g (normal >20 k g) con aumento del porcentaje de grasa, su fuerza de prensión es de 19 kg (>27 kg) y su velocidad de la marcha 0,7 m/s (>1,0 m/s). ¿Cuál de los siguientes diagnósticos es más probable?:', 'Envejecimiento normal.', 'Sarcopenia grave.', 'Malnutrición moderada.', 'Caquexia.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 162, 'Sin clasificar', 'Respecto a los c ambios del sistema in munitario que aparece n con el enve jecimiento, definidos como inmunosenescencia, señale la respues ta correcta:', 'La disminución de interleuquina 6 se relaciona con fragilidad y demencia.', 'Disminuye el número de linfocitos T.', 'Disminuye el factor de necrosis tumoral.', 'Disminuye la producción de autoanticuerpos por los linfocitos B.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 163, 'Sin clasificar', 'Señale l a respuesta c orrecta e n relación con el tratamiento con yodo radiactivo en los pacientes con cáncer diferenciado de tiroides:', 'Se de be a dministrar antes de l a tiroidectomía para disminuir el tamaño tumoral.', 'Administrado con ca rácter a blativo posttiroidectomía facilita el seg uimiento con la determinación de tiroglobulina sérica.', 'Está indica do únicamente cua ndo e xisten metástasis a distancia.', 'En pacientes de baj o riesgo o muy bajo riesgo reduce las recurre ncias y prol onga la supervivencia.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 164, 'Sin clasificar', 'La técnica quirúrgica indicada en los pacientes con adenoma tiroideo tóxico s olitario que precisan intervención quirúrgica es:', 'Nodulectomía.', 'Hemitiroidectomía del lado afecto.', 'Tiroidectomía subtotal.', 'Tiroidectomía total.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 165, 'Sin clasificar', 'Mujer de 25 años, obesa, que consulta por clínica de 2 meses de evoluci ón de pérdida de 5 Kg de peso, pa lpitaciones, dificulta d para el sueño nocturno y n erviosismo. A la exploración fí sica destaca temblor fino distal, frecuencia cardiaca de 110 lpm y no presenta bocio. Se realiza analítica que m uestra TSH suprimida, T4 el evada y tiroglobulina ba ja. L a gammagrafía t iroidea muestra una abs orción disminuida de yodo radiactivo. ¿Cuál de los siguientes le parece el diagnóstico más probable?', 'Tirotoxicosis facticia.', 'Tiroiditis subaguda.', 'Hipertiroidismo por enfermedad de Graves.', 'Teratoma de ovario (estruma ovárico).', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 166, 'Sin clasificar', 'Si usted está de guardia y le avisan por un paciente con malestar general, cefalea y náuseas, en quien encuentra una h iponatremia con función renal normal ¿qué esperaría encontrar si la causa de la misma fuera un SIADH?:', 'Osmolalidad plasmática >270 mosm/Kg.', 'Hipovolemia.', 'Osmolalidad urinaria >100 moms/Kg.', 'Excreción urinaria de socio reducida con ingesta adecuada de sal y agua.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 167, 'Sin clasificar', 'En una paciente joven sin antecedentes de interés que después de un tratamiento antibiótico por otro motivo es diagnosticada de candidiasis vaginal, es cierto que:', 'El tratamient o de elección es un c omprimido vaginal de 500 mg de clotrimazol en dosis única.', 'Si estuviera embar azada, el tratamiento antifúngico debería ser oral.', 'Es preciso tratar a su pareja sexual, aunque esté asintomática.', 'Es nece sario realizar un criba do de otras enfermedades de transmisión sexual.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 168, 'Sin clasificar', 'Sobre el tratamiento con antivíricos orales en un paciente con herpes zóster de menos de 72 horas de evolución, es cierto que:', 'Deja de ser contagioso a las 24 horas de inicio del tratamiento.', 'Deben t ratarse los sí ntomas con a nalgésicos además del tratamiento del herpes.', 'En casos con muy pocas lesiones, su efectividad es similar al tratamiento tópico con antivíricos.', 'Sólo está indicado en pacientes inmunodeprimidos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 169, 'Sin clasificar', 'Ante un c aso de sarna e n u n paci ente inmunocompetente, señale la respuesta INCORRECTA:', 'El tratamiento de elección es permetrina tópica al 5 % desde la línea mandibular hasta los dedos de los pies, dejando actuar entre 8 y 14 horas.', 'Es preciso lavar la ropa usada en l as 48 horas previas y otras ropas del hogar al menos a 50 grados, lavado en seco o en su defecto poner la ropa en bolsas de plástico durante 15 días, para eliminar el parásito correctamente.', 'La medida del efecto terapéutico del tratamiento es a través de la desaparición del picor en las primeras 48 horas.', 'En caso de fracaso del tratamiento tópico o sarna nodular, el tratamiento de elección en nuestro entorno es la ivermectina oral en dosis única.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 170, 'Sin clasificar', 'El tratamiento de la leishmaniasis visceral en personas con infección por VIH con inmunodeficiencia grave se basa en el uso de:', 'Anfotericina B liposomal.', 'Voriconazol y anfotericina B liposomal.', 'Anfotericina B liposomal y miltefosina.', 'Miltefosina y paromomicina.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 171, 'Sin clasificar', 'Hombre que consulta por la aparició n de linfadenopatías generalizadas no dolorosas y lesiones cutáneas ma culosas, papulosas, papuloescamosas y pustulosas. Las máculas son de color r ojo pálido o rosa , no pruri ginosas, distribuidas por tronco, zonas prox imales de extremidades y en palmas y plantas, coexisten en distintas fase s de evoluci ón. Refiere, adem ás, malestar general, febrícula, odinofagia y cefalea. En los antecedentes per sonales fi guran que fue diagnosticado de infección por VIH y abandonó el tratamiento. Reconoce que practica con frecuencia sexo con otros hombres. ¿Cuál de las siguientes respuestas es INCORRECTA en relaci ón con la enfermedad que sospecha que padece?:', 'Puede cursar con uveítis y producir ceguera.', 'Las lesio nes cu táneas in volucionan espontáneamente entre 1 y 6 meses.', 'Una cifra baja d e linfo citos CD4 + (<350 cel/microL) es un riesgo p ara d esarrollar afectación del sistema nervioso central y puede estar indicado practicar una punción lumbar.', 'La azitromici na es una buena opción para el tratamiento de la enfermedad, y a que la resistencia a los macrólidos es escasa.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 172, 'Sin clasificar', 'En la revisión de un hombre de 27 años que ha comenzado tr atamiento con tenofovir/emtricitabina com o profilaxis preexposición al VIH (PrEP) hace tres meses, se identifica un a serología posi tiva a V IH. En el momento del inicio de la PrEP la serología a VIH era negativa y la adherencia al tratamiento ha sido completa. L a explicación más pr obable par a el fracaso de la PrEP en este caso es:', 'Resistencias p rimarias a l os an tirretrovirales usados.', 'Haber iniciado la PrEP en el periodo ventana de la infección por VIH.', 'Se trata de un falso positivo.', 'Mayor susceptibilidad al VIH por las frecuentes infecciones de transmisión sexual asociadas a la PrEP.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 173, 'Sin clasificar', 'En la esclerodermi a, el uso de altas dosis de glucocorticoides se asocia con el desarrollo de:', 'Crisis renal esclerodérmica.', 'Mala evolución de las úlceras digitales.', 'Hipertensión pulmonar precapilar.', 'Sobrecrecimiento bacteriano intestinal.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 174, 'Sin clasificar', 'Mujer de 50 años, con antecedentes de lumbalgia crónica de sde los 30 años, que actualmente presenta gonalgi a bilateral de predominio izquierdo de 5 meses de e volución. A la exploración física se aprecia una mancha marrón en escalera en el ojo derecho y la rodilla izquierda aumentada de tamaño con limitación a l a movilidad activa y pas iva. Se realiza una artrocentesis de esa rodilla donde se extrae líquido articular de color amarillo y ligeramente turbio. Recuento cel ular: 600 leucocitos/mm 3 y 7 800 eritrocitos/mm3. No se observan microcristales bajo luz polarizada ni microor ganismos en la tinción de Gram. Se realiza una artroscopia para toma de biopsia sinovial que informa de presencia de te jido de pi gmentación ocr e. ¿Cuál es el diagnóstico más probable?:', 'Porfiria aguda intermitente.', 'Alcaptonuria.', 'Osteoartritis séptica.', 'Artritis reumatoide.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 175, 'Sin clasificar', 'Mujer de 54 años , fumadora, con s obrepeso e hipercolesterolemia tr atada de forma i rregular, que acude a consulta tres meses después de sufrir un in farto de mioc ardio. Com o parte de su tratamiento se pa utó a l alta hospitalaria atorvastatina 4 0 m g/24 horas . Se encue ntra asintomática, ha dejado de fumar y su a nalítica muestra un colesterol total de 196 mg/dl, HDL 56 mg/dl, LDL 110 mg/dl y triglicéridos 150 mg/dl. Señale la afirmación correcta:', 'Se d ebe intensificar el trat amiento hipolipemiante h asta el ob jetivo terapéutico (LDL < 55 mg/dl).', 'Su perfil lipídico es adecuado dado que tiene un colesterol total inferior a 200 mg/dl.', 'Su perfil lipídico es adecuado porque su HDL es elevado.', 'Al dejar de fumar y ser mujer su riesgo es bajo y no hace falta insistir en optimizar s u perfil lipídico.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 176, 'Sin clasificar', 'Paciente de 39 años que consulta para conocer su riesgo vascul ar. Su padre sufri ó un infarto de miocardio sin aparentes factores de riesgo a edad temprana. En el perfil lip ídico la lipoproteína (a) está muy elevada, 600 nmol/L (valor normal hasta 125 nmol/L). Respecto a esta lipoproteína, señale la respuesta INCORRECTA:', 'Es un f actor d e riesgo independiente p ara la enfermedad vascular aterosclerótica.', 'Las c oncentraciones plasmáticas ele vadas habitualmente son de origen genético.', 'El tratamiento con dieta y ejercicio reduce las concentraciones plasmáticas de la lipoproteína en un 25 %.', 'Dado que es un factor heredable habitualmente sólo se necesita medir una vez en la vida.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 177, 'Sin clasificar', 'Mujer de 75 años con antecedentes de insuficiencia venosa crónica que acude a urgencias por edem a unilateral infrapoplíte o de extremidad inferior derecha, di agnosticándose de trombosis venosa profunda de venas gemelares derechas. Dado que no presenta ninguna otra comorbilidad ni clínica de embolia pulmonar se plantea el alta hospitalaria con tr atamiento y se guimiento e n consul tas externas. ¿Cuál de e stos fármacos es el MENOS indicado para iniciar tratamiento anticoagulante?:', 'Rivaroxaban.', 'Enoxaparina.', 'Acenocumarol.', 'Fondaparinux.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 178, 'Sin clasificar', 'Hombre de 78 años con antecedentes de fibrilación auricular paroxística, hi pertensión arterial y dislipidemia. Sigue tratamiento desde hace años con acen ocumarol, ami odarona, candesartan y pitavastatina. La pita vastatina es la tercer a estatina que toma por elevación persistente de la CK y mal control de l a dislipidemia. Desde hace meses refiere estreñimiento, astenia y adinamia, caída del ca bello y malestar general sin mialgias. Aporta análisis con CK 1200 U/L (normal hasta 171 U/L), función renal normal y cLDL 1 08 mg/dL a pesar del tra tamiento. Seña le la afirmación correcta:', 'Hay qu e añadir ot ro hi polipemiante como u n inhibidor de PCSK9.', 'Probablemente tenga un hipotiroidismo inducido por amiodarona.', 'Hay que añadir un complemento alimenticio.', 'Hay que cambiar la estatina por rosuvastatina a dosis bajas.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 179, 'Sin clasificar', 'Mujer de 23 años que s eis meses antes inició cuadro de astenia y febrícula y en el último mes se añadió dolor en extremi dad superior derecha, sobre todo con la movilización y la elevación mantenida. En la exploración física se detectó un soplo en la zona s upraclavicular derecha, una disminución del puls o radial derecho y un a disminución de presión arterial de 30 mmHg en esta extremidad respecto a la izquierda. La V SG fue de 20 mm y la bioquímica y el hemograma no mostraron alteraciones destacables. Con la sospecha diagnóstica inicial de una va sculitis de grandes vasos, señale la respuesta INCORRECTA:', 'Algunos pacientes presentan estenosis arteriales establecidas que se detectan de forma casual en una fase inactiva.', 'Sus manifestaciones vasculares periféricas son soplos vasculares, di sminución de p ulsos y claudicación de extremidades en más de la mitad de los pacientes.', 'La V SG normal descartaría el diagnóstico de sospecha.', 'Un est udio angiográfico co n re sonancia magnética es de gran utilidad en su diagnóstico, ya q ue p roporciona información de la luz vascular y de la afectaci ón inflamatoria de la pared de la aorta y sus ramas principales.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 180, 'Sin clasificar', 'Mujer de 45 años con antecede ntes de colitis ulcerosa, que consulta por fiebre diari a de hasta 40ºC acompañada de escalofríos, astenia, anorexia y cefa lea intensa . En la exploración está febril, normotensa, a 90 lpm y destaca hepatoesplenomegalia blanda. En l a analítica destaca bicitopenia ( leucocitos 2650 [73 N, 19 L, 3M], Hb 9,7, Hcto 28,6 %, VCM 95, CHCM 34), hipofibrinogenemia, ALT 88 UI/L (N hasta 37), AST 126 UI/L (N hasta 32 ), LDH 431 UI/L (N hasta 190), ferritina 936 μg/L (N 15 a 120), hipergammaglobulinemia (gamma: 27 %) y proteína C reactiva 78 mg/L (N hasta 8). Estudio serológico : IgM anti-ACV (antígeno de la cápside del virus de Epstein-Barr) positivo, IgG anti-ACV positivo. Médula ósea: disminu ción de l a eritropoyesis y granulocitopoyesis con hiperplasia de histiocitos con intensa hemofagocitosis y cultivo negativo. ¿Cuál es la re spuesta I NCORRECTA sobre la enfermedad que sufre esta paciente?:', 'Puede asociarse a un síndrome linfoproliferativo ligado al cromosoma X tipo 2.', 'Si se logra l a remisi ón, el único tratamiento curativo es el trasplante a utólogo de células madre hematopoyéticas.', 'Existe una activ ación in cesante de linfocitos CD8+ y macrófagos.', 'El tratamiento de elección s on los anticuerpos monoclonales ant i-IL6 as ociado a a nticuerpos monoclonales antiTNF.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 181, 'Sin clasificar', 'Un paciente de 45 años ha sido recie ntemente diagnosticado de tubercul osis pulmonar por un cuadro clínico característico, una lesi ón cavitada en la Rx de tórax y una bacilosc opia positiva. Refiere ser s u segundo episodio de tuberculosis pulmonar, habiendo sufrido otro hace 6 años. El curso clínico esta siendo de lenta resolución y en el estudio de resistencias se i dentifica resistencia a isoniacida. E l me jor tr atamiento de entre los siguientes es:', 'Rifampicina, isoniacida, pirazinamida y etambutol durante 18 meses.', 'Rifampicina, pirazinamida, etambutol y levofloxacino durante 6 meses.', 'Rifampicina, b edaquilina y p roteonamida durante 12 meses.', 'Rifampicina, etambutol, pirazinamida y linezolid durante tres meses.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 182, 'Sin clasificar', 'Le avisa el equipo de e nfermería por un paciente ingresado con un adenocarcinoma de pulmón con metástasis óseas. Su tratamiento analgésico incluye morfina de li beración prolongada oral y también contempla la administración, en form a de medicación de rescate, de clorur o m órfico intravenoso cada 4 horas si el paciente lo requiere. La percepción de los enfermeros es que tiene dolor, pero su fami liar s olicita que no se administre cloruro m órfico com o analgésico p orque "n o quiero verle dormido". ¿Cuál de las siguientes opciones serí a la primer a a re alizar en es ta situación?:', 'Aceptar la petición del familiar y prescribir un analgésico no opioide para el control del dolor.', 'Rechazar la solicitud del fa miliar y orde nar la administración de cloruro mórfico, a l as dosis previamente prescritas.', 'Plantear la rotación del tratamiento analgésico por otro opioide con menor riesgo sedante, como oxicodona/naloxona.', 'Preguntar al paciente acerca de la intensidad de su dolor actual y de sus preferencias de analgesia en este momento.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 183, 'Sin clasificar', 'Hombre de 73 años de edad diagnosticado hace 8 meses de un adenoc arcinoma de próstata con metástasis óseas, en tratamiento c on hormonoterapia. Acude a ur gencias por aumento del do lor dorso-lumbar que no cede con la medicación prescrita. Hasta el momento estaba en tratamiento con fentanilo en parche transdérmico 25 mcg/h cada 72 horas y metamizol en caso de dolor, pero desde hace unas 48 horas no le alivia el dolor, que refiere como continuo, sordo, que se exacerba con los movimientos y de características similares al de base pero con mayor intensidad. En este contexto, señale la respuesta INCORRECTA:', 'En el caso de dolor por metástasis óseas está indicado el uso de antiinflamatorios como AINEs o corticoides como tratamiento coadyuvante.', 'En el dolor neuropático están indicados como coadyuvantes fármacos anticonvulsivantes como la gabapentina.', 'Dado que el paciente usa fentanilo como opioide de base, si decidimos pautar un opioide de rescate deberá ser también fentanilo dado que no deben mezcla rse fármacos del te rcer e scalón analgésico.', 'La radioterapia con finalidad analgésica es una opción e n pacientes co n metástasis óse as de neoplasias prostáticas.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 184, 'Sin clasificar', 'En cuidados paliativos se intenta usar el menor número de fármacos posible. En algunos casos esto es factible dado que al guno de l os medicamentos con indicación para un determinado síntoma tiene además efecto benefici oso para otr o. Señale la respuesta INCORRECTA:', 'La buscapina q ue se usa p ara disminuir las secreciones bronquiales al final de la vida se emplea tambi én para evit ar o dis minuir el estreñimiento.', 'La morfina que se pauta para el dolor moderadograve tiene un efecto positivo importante para reducir la sensación de disnea.', 'La de xametasona que s e emplea c omo antiinflamatorio se usa también para mejorar el apetito.', 'El h aloperidol qu e se u tiliza p ara paliar la agitación del d elirium puede ser u sado como antiemético, aunque en dosis menores.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 185, 'Sin clasificar', 'Mujer de 79 años con EPOC avanzada y FEV1 del 20 %, con disnea de mínimos esfuerzos y episodios repetidos de disnea de reposo sin una clara causa desencadenante. Ha perdido 8 kg en los últimos 6 meses. Ha seguido tr atamiento c on antibioticoterapia en ciclos repetidos, intensificación de l a broncodilatación, corticoides inhalados, codeína y oxigenoterapia sin respuesta. Se plantea introducir en el t ratamiento morfina. ¿Cuál sería la respuesta correcta?:', 'No está i ndicada por deprimir el c entro respiratorio y no mejorar la disnea.', 'Está indicada únicamente cuando la saturación de O2, sin oxigenoterapia, se ma ntiene por debajo del 90 %.', 'Está indicada porque existen síntomas y signos claros de empeoramiento grave y mal pronóstico.', 'Estaría i ndicada ú nicamente cuando hay evidencia de ins uficiencia res piratoria grave medida por gasometría arterial.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 186, 'Sin clasificar', 'En la intoxicación por monóxido de carbono (CO) se produce un desplazamiento del oxígeno de l a hemoglobina por parte de la molécula del CO. Con respecto a las circunstancias en que esta intoxicación se presenta en la clínica, solo es cierta una de las siguientes afirmaciones:', 'La etiología suicida de la intoxicación por CO es excepcional.', 'La intoxicación por CO no está incluida en la lista d e enfermed ades profesionales, y a que cuando se presenta lo hace de forma accidental.', 'El CO es un gas incoloro pero dotado de un olor característico a almendras amargas.', 'Una fuente habitual de producción de CO es la mala combustión de gases l icuados ( propano, butano, etc.).', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 187, 'Sin clasificar', 'Hombre de 39 años que consulta por debilidad y alteración de la sensibilidad en ambos miembros inferiores acompañadas de di plopía. E ntre l os posibles diagnósticos está la esclerosis múltiple. En relación con esta enfermedad señale la respues ta INCORRECTA:', 'En la mayoría de l os casos, la pre sentación es entre los 20 y los 40 años y afecta con mayor frecuencia a los hombres que a las mujeres.', 'En su etiopatogenia l os estudios indican que existe una susceptibilidad poligénica.', 'El síntoma más frecuente es la alteración de la sensibilidad, en forma d e parestesias o acorchamiento de uno o más miembros o del tronco.', 'La lesión característica es la placa o lesión focal de desmielinización perivenosa, con inflamación y pérdida axonal variables.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 188, 'Sin clasificar', '¿Cuál de l os si guientes fárm acos d eberíamos EVITAR en un paciente ma yor c on diabetes mellitus?:', 'Sitagliptina.', 'Empagliflozina.', 'Glibenclamida.', 'Semaglutida.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 189, 'Sin clasificar', 'En relación con el índice tobillo-brazo, señale la respuesta correcta:', 'Se obtiene calculando la relación entre la presión diastólica en el tobillo y la presión d iastólica braquial.', 'Se considera normal si se obtienen valores entre 1 y 1,5.', 'Tiene una sen sibilidad del 95 % y una especificidad del 60 % para el diagnóstico de enfermedad arterial periférica.', 'Se c onsidera un indicador por sí mismo de enfermedad arteriosclerótica.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 190, 'Sin clasificar', '¿Cuál de los si guientes fárm acos o grupos terapéuticos son de indic ación preferente en un paciente con diabetes mellitus y obesidad (IMC mayor de 30) en preve nción secundaria cardiovascular?:', 'Inhibidores del enzima di peptidil peptidasa 4 (iDPP4).', 'Glitazonas.', 'Sulfonilureas.', 'Análogos del receptor Glucagon Like Peptid 1 (arGLP1).', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 191, 'Sin clasificar', 'Según el Programa de Ac tividades Preventivas y Promoción de la Salud de la semFyC, así como de la US Preventive Task Force y la American Cancer Society, ¿a partir de qué edad se recomienda, con una recomendación tipo A, iniciar l as pruebas de cribado de cáncer colorrectal, en población general asintomática?:', 'A partir de los 40 años.', 'A partir de los 50 años.', 'A partir de los 60 años.', 'A partir de los 65 años.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 192, 'Sin clasificar', 'En el abordaje del tabaquismo com o factor de riesgo y como primera causa prevenible de muerte, enfermedad e incapacidad en las sociedades industrializadas, es imp ortante tener e n cuenta muchos as pectos. Se ñale la afirmación INCORRECTA:', 'La atención primaria es el entorno más favorable para detectar el consumo de tabaco, proporcionar consejo breve, facilitar la deshabituación tabáquica y promover estrategias de abandono.', 'La detección y el tratamiento de la dependencia del tabac o se considera una intervenci ón con coste-efectividad favorable, sin repercusión en términos de coste por año de vida ganado.', 'En la ayuda para d ejar de fumar, la evidencia avala tant o l as estrate gias no farmac ológicas (intervención breve o apoyo motivacional) como las estrategi as fa rmacológicas, siendo la combinación de ambas lo más efectivo.', 'Los fuma dores que no desea n intentar el abandono d el tabaco pu eden care cer de la información adecuada sobre sus efectos nocivos, tener creencias erróneas o e star desmoralizados por haber tenido recaídas.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 193, 'Sin clasificar', 'Paciente de 82 años, con poliartrosis periférica e incontinencia urinaria de esfuerz o. Cuidadora de su m arido de 84 años con enfer medad de Alzheimer. El marido llama a la vecina porque su mujer está muy adormilada y no le ha preparado el desayuno. Acude a su do micilio su médica de familia y ob jetiva que está des orientada, con sequedad de mucosas y dificultad para la marcha, sin otra foc alidad neurológica. Al re visar la historia clínica consta que fue atendida hace 2 días por el servicio de urgencias nocturno por sensación de mareo con prescripción de sulpiride. Ante esta situación clínica, de las siguientes, cuál sería la causa MENOS PROB ABLE en el dia gnóstico diferencial?:', 'Delirium por infección de orina.', 'Deshidratación y alteración electrolítica.', 'Demencia en fase inicial.', 'Efecto secundario de fármacos.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 194, 'Sin clasificar', 'Varón de 78 años que a cude a u rgencias p or deterioro del estado general, increm ento del perímetro abdominal, micción entrecortada, tenesmo y aumento de frecue ncia miccional asociados a incontinencia urinaria de predo minio nocturno de 5 días de evolución. Como antecedente refiere diabe tes mellitus en tr atamiento con metformina. Se encuentra afebril y normotenso. En la analítica de sangre destaca glucemia 345 mg/dl, creatinina 2,9 mg/dl (0,7-1,3), urea 79 mg/dl (17-49) y en el sistemático de orina nitritos, leucocitos y microhematuria. A l a exploración destaca una masa pa lpable en línea media, infraumbilical. ¿Cuál sería la actitud inicial según su diagnóstico de sospecha?:', 'Urocultivo.', 'Enema de limpieza.', 'Sondaje vesical.', 'TC abdominal urgente.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 195, 'Sin clasificar', 'Indique cúal de las siguientes afirmaciones NO es correcta ante la sos pecha de botulism o en un paciente que acude a urgencias tras consumo de alimentos envasados de una marca responsable de un brote detectado en varios puntos de España:', 'Debe ingresar con me didas de so porte y administración inmediata de a ntitoxina botulínica.', 'El síndrome característico consiste inicialmente en la parálisis simétrica de los pares craneales.', 'Se ac ompaña de pa rálisis espást ica simétrica ascendente e hiperreflexia.', 'El periodo de incubación suele ser de 8-36 h tras la ingesta, pero puede ser de hasta 10 días.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 196, 'Sin clasificar', 'Paciente de 65 años c on leucemia li nfoblástica aguda que acude a ur gencias por presentar tras una sesión de quimioterapia hace 48 h un cuadro de náuseas, vómitos, irritabilidad neuromuscular, alteración del nivel de c onciencia, fracaso renal agudo, hiperuricemia, hiperpotasemia, hiperfosfatemia e hipoc alcemia. El dia gnóstico inicial de sospecha más probable es:', 'Sepsis en paciente inmunodeprimido.', 'Síndrome de lisis tumoral.', 'Hipocalcemia por citostáticos.', 'Alteración metabólica secunda ria a la hiperemesis postquimioterapia.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 197, 'Sin clasificar', 'Los carcinomas serosos de alto grado de ovario tienen su origen en:', 'Epitelio de las fimbrias de la trompa de Falopio.', 'Epitelio de glándulas de quistes de endometriosis del ovario.', 'Epitelio de los folículos ováricos.', 'Restos epiteliales del ovario.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 198, 'Sin clasificar', 'Hombre de 35 años de ed ad con antecedentes de asma y alergia a ant inflamatorios no esteroideos. Refiere que desde la infanc ia presenta lesiones en la piel lo calizadas en la cara y en l os plie gues cutáneos, acompañadas de intenso prurito y que lograba co ntrolar co n emo lientes y corticoides tópicos. Sin embargo, en los últimos 5 años ha ido empeorando con aumento del prurito e importante extensión de sus lesiones. P or ello ha recibido varias tandas de corticoides orales, ciclosporina y metotrexato con respuesta parcial e ins uficiente. Ante esta situación ¿cuál de los siguientes fármacos biológicos está indicado?:', 'Ustekinumab.', 'Dupilumab.', 'Certolizumab.', 'Bimekizumab.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 199, 'Sin clasificar', 'De las siguientes afirmaciones en rel ación con la psoriasis ¿cuál es la correcta?:', 'El fenómeno de Koebner indica que la psoriasis es una e nfermedad asociada a co morbilidades metabólicas y articulares.', 'El principal tratamiento sistémico de la psoriasis palmoplantar se basa e n ciclos cortos de corticoides orales.', 'La ps oriasis es un trastorno cr ónico inmunomediado, c on u na herencia autosómica recesiva y factores desencadenantes ambientales, como traumatismos, infecciones, medicamentos o estrés psicológico.', 'Los hal lazgos histológicos t ípicos i ncluyen acantosis con crestas elongadas, hipogranulosis, hiper y pa raqueratosis, vas os dilatados y agregados de neutrófilos en la epidermis.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 200, 'Sin clasificar', 'Mujer de 71 años con fototipo II e i ntenso daño actínico y antecedentes personales de melanoma in situ en la espalda, tres carcinomas basocelulares en la cara y un carcinoma epidermoide en el br azo. Consulta por una lesión pigmentada en la pierna. Tras la extirpación de la lesión, la histopatología muestra un melanoma de extensión s uperficial Breslow 0,6 milímetros sin ulceración ni regresión. ¿Cuál es la actitud recomendada?:', 'Realizar una cirugía con ampliación de márgenes de 1 cm.', 'Realizar una cirugía con ampliación de márgenes de 1 cm y biopsia de ganglio centinela.', 'Dado qu e es un segun do melanoma requiere tratamiento con la terapia dirigida dabrafenib + trametinib.', 'Dado que tiene múltiples tipos de cáncer cutáneo se podría be neficiar de un tratamient o con inmunoterapia, co mo n ivolumab o pembrolizumab.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 201, 'Sin clasificar', '¿Cuál de las si guientes NO es una respuesta hormonal a la hipoglucemia?:', 'Aumento de l a secreción de h ormona del crecimiento.', 'Reducción de la secreción de glucagón.', 'Aumento de la secreción de cortisol.', 'Aumento de la secreción de adrenalina.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 202, 'Sin clasificar', 'Tras el di agnóstico en urgencias de embolism o pulmonar, es necesario hacer una val oración y estratificación del riesgo para decidir cual es la mejor opción terapéutica. Indique cu al de los siguientes es un factor de alto riesgo de te ner un resultado clínico adverso:', 'Extensión del embolismo pulmonar con función normal del ventrículo derecho y normotensión.', 'Identificación en la TC t orácica de si gnos de crecimiento del ventriculo izquierdo.', 'Valor elevado del dímero D.', 'Signos de disfunción del ventrículo derecho en el ecocardiograma con presión arterial sistólica <90 mmHg mantenida.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 203, 'Sin clasificar', 'En un paciente con cáncer de colon metastásico ¿cuál de las siguientes determinaciones moleculares se deben realizar antes de comenzar el tratamiento sistémico?:', 'EGFR, NR AS, KR AS, p roteínas re paradoras, HER2.', 'NRAS, KRAS, BRAF, proteínas reparadoras.', 'EGFR, NRAS, KR AS, BRAF, proteínas reparadoras.', 'NRAS, KRAS, B RAF, p roteínas re paradoras, PI3K.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 204, 'Sin clasificar', 'Hombre de 45 años que en las últimas 6 semanas presenta astenia, pér dida de 5 kg de peso y artromialgias de predominio en región proximal de ambas extremidades inferiores, junto a hipoestesia asimétrica en manos y pies. Además, en los últimos 3 días desarrolla una livedo reticularis y varios nódulos subcutáneos, eritematosos y dolorosos, en cara anterior de am bas piernas. E n la analítica destaca VSG 90 mm/h (normal <20) y proteína C reactiva 12 m g/dl (normal < 1,0). Radiografía de tórax norm al. Electroneuromio grafía (ENMG): hallazgos compatibles co n mononeuritis múltiple. Teniendo en cuenta el di agnóstico más probable, marque la opción correcta:', 'A diferencia de lo objetivado en el paciente, la alteración de la ENMG más característica es una neuropatía de fibra fina.', 'Una biopsia de músculo no permitiría demostrar histológicamente la enfermedad.', 'A pesar de la sospecha diagnóstica, no cumple criterios clasificatorios de la enfermedad, por lo que no es posible diagnosticarle.', 'Existen p acientes qu e cump len los criterio s clasificatorios de la enfermedad que presentan mutaciones con pérdida de función en el gen CECR1 que codifica la adenosina desaminasa 2.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 205, 'Sin clasificar', 'Paciente de 26 años sin antecedentes de interés que consulta por engrosamiento y cambio de color de la parte distal de la uña del dedo gordo del pie derecho. A la expl oración se observa una mu y probable onicomicosis de la uña, sin otras lesiones o uñas afectadas. Sobre esta situación clínica es cierto que:', 'El tratamiento con amorolfina tópica al 5 % dos veces por se mana por un periodo de 3 meses suele ser efectivo.', 'Si la lesión af ectara la matr iz ungu eal el tratamiento debe p rolongarse hast a l os 6- 9 meses.', 'El tratamiento oral de elección en este caso es la griseofulvina.', 'En casos de resistencia una opción es el tratamiento con itraconazol oral 200 mg cada 24 horas durante 12 semanas.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 206, 'Sin clasificar', 'Mujer de 49 años di agnosticada de dislipemia. Exfumadora hace 3 años y no cons ume alcohol. Exploración física: presión arterial 129/81 mmHg, electrocardiograma, retinografía y exploración de pies normales. Índice de m asa corporal 28 kg/m2. Analítica: glucemia en ayunas 103 mg/dl, colesterol total 1 83 mg/dl, co lesterol L DL 104 m g/dl, colesterol HDL 42 m g/dl, triglicéridos 186 mg/dl. Filtrado glomerular estimado (CKD-EPI) 55 ml/min/1,7 2m2, cociente albúmina/creatinina en orina 4 mg/g. ¿Qué riesgo cardiovascular presenta según las guí as europeas de pre vención cardiovascular?:', 'Riesgo bajo.', 'Riesgo moderado.', 'Riesgo alto.', 'Riesgo muy alto.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 207, 'Sin clasificar', 'Mujer de 67 años exfumadora con antecedentes de hipertensión arterial, diabetes mellitus tipo 2 de 10 años de e volución con microalbuminuria y obesidad es enviada a su co nsulta. Ap orta un análisis con una hemo globlina glicada de 1 0 %, colesterol total de 210 m g/dL, colesterol LDL no calculable, colesterol HDL de 30 mg/dL y unos triglicéridos de 496 mg/dL. Función renal normal. Respecto a la hipertrigliceridemia, s eñale la respuesta correcta:', 'El primer es calón es conseguir un control adecuado de s u diabetes pa ra corre gir la hipertrigliceridemia y añadir una estatina.', 'Aunque el control de la diabetes es necesario, no influye en la h ipertrigliceridemia. El primer escalón es añadir ácidos grasos omega-3.', 'La primera opción de tratamiento es combina r gemfibrozilo con una estatina.', 'La primera opción es i niciar tratamien to co n fibratos.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 208, 'Sin clasificar', 'Con respecto a l a retirada de me dios de soporte vital en casos de futilidad de los tratamientos en un paciente en si tuación terminal ¿cuál de l as siguientes afirmaciones es cierta?:', 'Es acepta ble éticamente, aunque c on ello sobrevenga la muerte del paciente.', 'Se t rata de una medida q ue depende fundamentalmente de la vo luntad del méd ico responsable del paciente.', 'Es una práctica equivocada y obsoleta desde que existen medios so fisticados de sopo rte vital artificial.', 'Según la ley española es eutanasia.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 209, 'Sin clasificar', 'La vía subcutánea es d e gran utilida d en el tratamiento de pacientes en situación de cuidados paliativos y se considera de elección cuando la vía oral no es posible. Sin embargo, hay fármacos cuyo uso por vía subcutánea está desconsejado. Uno de esos fármacos es:', 'Furosemida.', 'Metamizol.', 'Haloperidol.', 'Metoclopramida.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2023, 210, 'Sin clasificar', 'El certificado médic o de defunción (CMD) es un documento de car ácter jurídico-administrativo necesario para obte ner la licencia de enterramiento del cuerpo de una persona fallecida. Si existe una sospecha razonable de que la persona ha fallecido c omo consecuencia de una neumonía provocada por una infección por COVID-19 ¿cuál de las siguientes afirmaciones es cierta?:', 'En el CMD se hará c onstar que el ca dáver pertenece al grupo I, po r presentar enfermedad infecciosa que supone un riesgo relevante para la salud pública.', 'No se puede cumplimentar el CMD por tratarse de muerte sospechosa de criminalidad.', 'No se puede cumplimentar el CMD por que sólo se dispone de criterios de presunción y no de confirmación, au nque la s circunstancias del fallecimiento y la patobiografía sean compatibles.', 'Se hará constar la infección por COVID-19 en el apartado de causa fund amental y no e n el apartado de causa inmediata.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 1, 'Sin clasificar', 'Pregunta asociada a la imagen 1. Mujer de 42 años que acude a la consulta de genética por un diagnóstico reciente de cáncer de endometrio. En base a los antecedentes familiares que constan en la imagen, ¿cuál de los siguientes síndromes es más probable que presente?:', 'Poliposis adenomatosa familiar.', 'Síndrome de Lynch.', 'Síndrome de cáncer de mama y ovario hereditario.', 'Síndrome de Cowden.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 2, 'Sin clasificar', 'Pregunta asociada a la imagen 2. Paciente de 65 años que acude a urgencias por disminución brusca de agudeza visual en ojo derecho. La retinografía de dicho ojo se muestra en la imagen. Uno de los siguientes tratamientos está indicado para una enfermedad que es un factor de riesgo para esta situación. Indique cuál:', 'Latanoprost y timolol.', 'Flecainida.', 'Hidroxicloroquina.', 'Complejos vitamínicos y antioxidantes.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 3, 'Sin clasificar', 'Pregunta asociada a la imagen 3. Hombre de 70 años exfumador de un paquete al día y bebedor de 2 copas de vino al día consulta por una molestia faríngea de 1 mes de evolución. Se observa exudado amigdalar por lo que se inicia tratamiento antibiótico. El resultado del test de estreptococo es negativo. La clínica persiste y se añade odinofagia con otalgia refleja y leve cambio en el timbre de la voz. Nota un bulto duro de unos 2 cm a nivel II cervical ipsilateral no doloroso. La orofaringoscopia se refleja en la imagen asociada (imagen aumentada en el recuadro resaltado en rojo). ¿Cuál es la sospecha diagnóstica y su manejo?:', 'Resistencia bacteriana a antibioterapia recibida, precisa cultivo de exudado faríngeo con antibiograma para indicación adecuada.', 'Sospecha de absceso periamigdalino izquierdo, será remitido a urgencias de Otorrinolaringología para drenaje quirúrgico.', 'Sospecha de neoplasia maligna de amígdala palatina, será remitido preferente-urgente a Otorrinolaringología.', 'Sospecha de angina de Plaut-Vincent, remitido a Otorrinolaringología para realización de biopsia de ganglio para estudio de linfoma. Página:', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 4, 'Sin clasificar', 'Pregunta asociada a la imagen 4. Niña de 7 años que acude por otalgia y otorrea purulenta derecha desde hace 3 semanas, tratada con antibióticos y antinflamatorios. Tras la resolución de las manifestaciones clínicas, vuelve a aparecer la otorrea por lo que se pauta de nuevo tratamiento antibiótico. A los 5 días se objetiva una tumefacción retroauricular. En la otoscopia se pone de manifiesto una leve retracción de la membrana timpánica, escasa secreción blanquecina en el conducto auditivo externo y una tumefacción retroauricular blanda que ocasiona un mínimo desplazamiento anterior del pabellón auricular. Indique el diagnóstico que sugiere la imagen de resonancia magnética mostrada:', 'Absceso subperióstico extracraneal.', 'Trombosis venosa cerebral.', 'Absceso cerebral retromastoideo.', 'Área de cerebritis retromastoidea.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 5, 'Sin clasificar', 'Pregunta asociada a la imagen 5. Una mujer de 18 años acude a urgencias por dolor abdominal intenso, febrícula, test de embarazo positivo y manchado vaginal de 3 días de evolución junto con líquido libre intraabdominal en la ecografía. Se realiza una laparoscopia en la que se encuentra el siguiente hallazgo tras aspirar sangre de la cavidad abdominal. ¿Cuál es el diagnóstico más probable de los siguientes?:', 'Gestación ectópica.', 'Quiste de ovario complicado.', 'Apendicitis aguda.', 'Enfermedad inflamatoria pélvica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 6, 'Sin clasificar', 'Pregunta asociada a la imagen 6. Hombre de 40 años que presenta cefalea brusca con exploración neurológica normal. Se realiza TC craneal que se muestra en la imagen y una angiografía cerebral en la que no se encuentra patología subyacente. El cuadro clínico más probable es:', 'Hemorragia subaracnoidea traumática occipital.', 'Hemorragia causada por una malformación arteriovenosa angiográficamente oculta.', 'Hemorragia subraracnoidea perimesencefálica con un probable origen venoso o capilar.', 'Hemorragia causada por una discrasia sanguínea.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 7, 'Sin clasificar', 'Pregunta asociada a la imagen 7. Hombre de 75 años consulta por un cuadro de dificultad para la marcha de 2 años de evolución de forma progresiva. Presenta reflejos vivos en las cuatro extremidades. Se muestra la RM cervical realizada. Con respecto al cuadro clínico del paciente señale la respuesta INCORRECTA:', 'El cuadro de paraparesia puede ser asimétrico.', 'La progresión de la enfermedad es lenta pero puede acelerarse por movimientos de flexión o extensión cervical forzados.', 'Se trata de una enfermedad primaria de motoneurona.', 'La incontinencia urinaria aparece con la progresión de la enfermedad.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 8, 'Sin clasificar', 'Pregunta asociada a la imagen 8. Mujer de 14 años derivada a Rehabilitación para el manejo de una deformidad de la columna vertebral. Tuvo la menarquia a los 10 años. En la exploración física se aprecia mínima asimetría de escápulas, el eje occipito-sacro está centrado y en el test de Adams se observa una gibosidad torácica derecha de 10 mm. Se aporta telerradiografía de columna en proyección antero-posterior. ¿Cuál de los siguientes considera el manejo más adecuado a seguir?:', 'Observación, con recomendación específica de ejercicios y revisión posterior.', 'Corsé de Milwaukee a tiempo completo.', 'Corsé de Boston a tiempo parcial.', 'Derivación a cirugía para tratamiento quirúrgico.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 9, 'Sin clasificar', 'Pregunta asociada a la imagen 9. Hombre de 60 años de edad que tras dolor brusco y chasquido en hombro presenta la siguiente deformidad en el brazo. ¿Cuál es el diagnóstico más probable?:', 'Rotura de la porción larga del bíceps braquial.', 'Rotura de la porción corta del bíceps braquial.', 'Rotura del tendón distal del bíceps braquial.', 'Rotura del tendón del pectoral mayor. Página:', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 10, 'Sin clasificar', 'Pregunta asociada a la imagen 10. Paciente de 41 años, de talla baja, consulta por dolor en ambas caderas, más intenso en la izquierda. Refiere haber tenido dolor en caderas a edades tempranas aunque nunca consultaron por este motivo. Tras estudio radiográfico de caderas, se decide prótesis total de cadera izquierda, siguiendo buena evolución. Durante el postoperatorio el paciente refiere además dolor en hombros. Ante la sospecha diagnóstica se solicita una telerradiografía (ver imagen). Indique qué proceso es más probable que padezca el paciente desde su infancia:', 'Enfermedad de Perthes.', 'Osteonecrosis multifocal.', 'Epifisiolisis bilateral de cadera.', 'Displasia epifisaria múltiple.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 11, 'Sin clasificar', 'Pregunta asociada a la imagen 11. Hombre de 40 años que consulta por tumoración dolorosa en cara interna de rodilla. En el estudio radiográfico se obtiene esta imagen. ¿Cuál es el diagnóstico más probable?:', 'Osteomielitis.', 'Osificación heterotópica.', 'Encondroma.', 'Osteocondroma.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 12, 'Sin clasificar', 'Pregunta asociada a la imagen 12. Hombre de 80 años, fumador. Refiere en los últimos días episodios de mareos no relacionados con el ejercicio ni el estrés, de unos 3-4 minutos de duración. Solicita atención urgente en su domicilio tras presentar un síncope, con pérdida completa de conciencia, de unos 15-20 segundos de duración. La presión arterial es 110/40 mmHg. Se obtiene el ECG de la imagen. ¿Cuál es su diagnóstico?:', 'Infarto agudo de miocardio con elevación del segmento ST, anterior.', 'Bloqueo aurículo ventricular (AV) de primer grado.', 'Bloqueo AV de segundo grado, tipo II.', 'Bloqueo AV de tercer grado.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 13, 'Sin clasificar', 'Pregunta asociada a la imagen 13. Hombre de 75 años que consulta por palpitaciones de aparición súbita hace 1 hora, sin dolor torácico ni cortejo vegetativo asociado. Tiene antecedentes de hipertensión arterial, dislipemia, hipertrofia benigna prostática y accidente isquémico transitorio hace 12 años. PA 180/109 mmHg, FC 126 lpm, Sat O2 98%. Auscultación cardíaca tonos rítmicos, sin soplos audibles. Miembros inferiores sin edemas ni signos de trombosis venosa profunda. Se realiza ECG que se muestra en la imagen. Indique, de los siguientes, el diagnóstico más probable:', 'Fibrilación auricular.', 'Flutter auricular.', 'Infarto agudo de miocardio.', 'Taquicardia ventricular.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 14, 'Sin clasificar', 'Pregunta asociada a la imagen 14. Mujer de 69 años, obesa, con historia de apnea obstructiva del sueño, insuficiencia respiratoria hipercápnica, polimialgia reumática e hipotiroidismo de larga evolución. Acude a consulta en su centro de salud con los resultados de una tomografía computarizada (TC) solicitada por hallazgo de cardiomegalia en la Rx de tórax. Su frecuencia cardíaca es 68 lpm, y la presión arterial es 145/70 mmHg. Con inspiración profunda, sus cifras tensionales son 139/68 mmHg. Con estos datos clínicos y la imagen de la TC que se muestra, señale qué diagnóstico es más probable:', 'Neumotórax.', 'Taponamiento cardíaco con colapso de cavidades cardíacas.', 'Disección de aorta.', 'Derrame pericárdico crónico. Página:', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 15, 'Sin clasificar', 'Pregunta asociada a la imagen 15. Paciente de 72 años con antecedentes de cardiopatía isquémica que acude a Urgencias por astenia, disnea de esfuerzo y malestar general desde hace dos semanas. En analítica se objetiva hemoglobina 7,1 g/dL, leucocitos 9.330/µL (Neutrófilos 77%), plaquetas 15.6000/µL, creatinina sérica 7,6 mg/dL (previa 1,1 mg/dL), Na+ 139 mmol/L, K+ 5,2 mmol/L. Orina: Na+ 121 mmol/L, K+ 21,3 mmol/L, cociente proteína/creatinina 3,5 g/g, eritrocitos +3, leucocitos +3. Se realiza un TC de tórax que se muestra en la imagen. Indique la actitud más correcta en relación con su diagnóstico y tratamiento inicial:', 'Neumonía atípica con fracaso renal agudo secundario a necrosis tubular aguda y el tratamiento es la administración de antibióticos de amplio espectro y hemodiálisis.', 'Fracaso renal agudo parenquimatoso de probable origen glomerular con hemorragia alveolar asociada y el tratamiento es inmunosupresores y plasmaféresis.', 'Síndrome urémico hemolítico atípico y hay que plantear plasmaféresis y administración de eculizumab.', 'Fracaso renal agudo funcional secundario a insuficiencia cardíaca y hay que iniciar tratamiento con diuréticos a altas dosis y diálisis si no responde.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 16, 'Sin clasificar', 'Pregunta asociada a la imagen 16. Hombre de 68 años, exfumador desde hace 3 meses, con criterios clínicos de bronquitis crónica. Consulta por cuadro de pérdida de peso junto con astenia de un mes y medio de duración. Refiere tos seca ocasional y sensación distérmica sin fiebre termometrada. Tras realizarle la radiografía de tórax se solicita TC torácico que se muestra en la imagen. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Bronquiolitis respiratoria con enfermedad pulmonar intersticial.', 'Neumonía organizada criptogénica.', 'Atelectasia obstructiva de lóbulos inferiores por neoplasia central.', 'Neumonía intersticial inespecífica.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 17, 'Sin clasificar', 'Pregunta asociada a la imagen 17. Paciente de 63 años consulta por dolor en flanco derecho, ictericia y aumento del perímetro abdominal. Se realiza ecografía doppler y TC de hígado como se muestra en la imagen. ¿Cuál de las siguientes es la mejor opción terapéutica?:', 'Colocación de una derivación intrahepática percutánea (TIPS).', 'Anticoagulación oral.', 'Trasplante hepático.', 'Angioplastia percutánea.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 18, 'Sin clasificar', 'Pregunta asociada a la imagen 18. Mujer de 90 años que acude a urgencias por hipotensión, vómitos oscuros y dolor abdominal. Se realiza una TC abdominal que se muestra en la imagen. De las siguientes opciones, ¿cuál es la más probable?:', 'Se observa gas en el sistema portal siendo indicativo de mal pronóstico.', 'Se trata de una aerobilia y por tanto el diagnóstico más probable es el de colangitis.', 'Se observa aerobilia y pneumatosis gástrica.', 'Se trata de un hallazgo no relevante en relación con una CPRE o cirugía previa.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 19, 'Sin clasificar', 'Pregunta asociada a la imagen 19. Hombre de 60 años sin antecedentes de interés que acude a urgencias con un cuadro de 48 horas de fiebre de 38ºC y dolor abdominal en fosa iliaca izquierda. A la exploración abdominal destaca cierta defensa a la palpación sin peritonismo generalizado. La analítica sanguínea sólo destaca una discreta leucocitosis. La TC abdomino-pélvica se muestra en la imagen adjunta. ¿Cuál es el diagnóstico más probable?:', 'Cáncer de colon izquierdo oclusivo.', 'Síndrome de Ogilvie.', 'Diverticulitis aguda.', 'Megacolon tóxico o infeccioso. Página:', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 20, 'Sin clasificar', 'Pregunta asociada a la imagen 20. Hombre de 73 años con antecedentes de hipertensión arterial y diabetes mellitus tipo 2 que acude a urgencias por presentar desde hace una semana hiperglucemia mayor de 500 mg/dL. Refiere que comenzó con dolor en vacío derecho y vómitos autolimitados. Desde entonces, disminución de la ingesta, poliuria y sensación distérmica sin fiebre termometrada. Se realiza ecografía y TC abdominopélvica sin contraste intravenoso que se muestra en la imagen. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Pielonefritis enfisematosa obstructiva.', 'Necrosis papilar renal.', 'Pielonefritis xantogranulomatosa.', 'Absceso retroperitoneal perirrenal por apendicitis aguda evolucionada.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 21, 'Sin clasificar', 'Pregunta asociada a la imagen 21. Mujer de 57 años con enfermedad renal crónica que presenta astenia, hipotensión y cianosis en manos tras una sesión de diálisis. En la analítica se detecta anemia normocítica (Hb 7 g/dL, VCM 96 fL) con discreta reticulocitosis, leucocitos y plaquetas normales; aumento de LDH y hemoglobina libre en plasma elevada. El estudio inmunohematológico muestra un anticuerpo con especificidad anti-P. Se realiza frotis sanguíneo (ver imagen) mediante punción digital. El diagnóstico más probable es:', 'Síndrome hemofagocítico.', 'Hemoglobinuria paroxística a frigore.', 'Hemoglobinuria paroxística nocturna.', 'Crioglobulinemia.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 22, 'Sin clasificar', 'Pregunta asociada a la imagen 22. Mujer de 58 años acude a urgencias por dolor en la punta de los dedos de la mano. No tiene alergias conocidas, ni hábitos tóxicos. Entre los antecedentes explica tres abortos, una apendicetomía, sensación frecuente de reflujo retroesternal y, desde hace unos 5 años aproximadamente, presenta con la exposición al frío episodios de palidez en los dedos de ambas manos que cada vez se han hecho más intensos. A la vista de la imagen, ¿cuál de las siguientes actitudes se plantea realizar en primer lugar?:', 'Solicitar una TC torácica.', 'Valoración de tratamiento quirúrgico por cirugía vascular.', 'Determinación de ANA y anti-centrómero.', 'Tratamiento vasodilatador con prostaglandinas iv.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 23, 'Sin clasificar', 'Pregunta asociada a la imagen 23. En relación con un hombre de 74 años, que muestra alteraciones cognitivas y de la movilidad y en el cerebro neuronas con inclusiones citoplásmicas, como se observa en la imagen histológica, el diagnóstico más probable es:', 'Enfermedad de Alzheimer.', 'Demencia senil.', 'Enfermedad de Parkinson.', 'Encefalitis viral.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 24, 'Sin clasificar', 'Pregunta asociada a la imagen 24. Mujer de 35 años con historia de dolor abdominal recurrente que coincide con la menstruación. Los hallazgos de la intervención quirúrgica requieren una resección intestinal. El estudio anatomopatológico se muestra en la imagen. ¿Cuál es el diagnóstico más probable?:', 'Adenocarcimoma intestinal.', 'Metástasis de adenocarcinoma de endometrio.', 'Colitis ulcerosa.', 'Endometriosis.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 25, 'Sin clasificar', 'Pregunta asociada a la imagen 25. Hombre de 36 años con prácticas sexuales de riesgo. Presenta un cuadro de 4 días de evolución de lesiones cutáneas no pruriginosas (ver imagen). No ha tomado medicación previamente y no tiene antecedente de alergias farmacológicas. Se realiza serología para VIH que es negativa. La serología de sífilis antitreponema pallidum es positiva y RPR 1:32. Señale la respuesta correcta:', 'Se recomienda el análisis del líquido cefalorraquídeo.', 'La azitromicina oral es un tratamiento alternativo eficaz.', 'Se recomienda una valoración clínica y serológica (RPR) a los 6 y 12 meses después del tratamiento.', 'Si los títulos de RPR permanecen positivos después de 12 meses está indicado administrar el tratamiento de nuevo.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 26, 'Sin clasificar', 'Entre los cambios metabólicos que se observan en un paciente con resistencia a insulina existe:', 'Incremento de la expresión hepática de genes gluconeogénicos mediado por FOXO1 (forkhead box other) fosforilado.', 'Descenso en los niveles intracelulares de hexoquinasa 2 dependiente de insulina.', 'Aumento de la glucogenólisis muscular, contribuyendo al incremento de la glucemia.', 'Aumento en los niveles séricos de aminoácidos como leucina e isoleucina. Página:', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 27, 'Sin clasificar', 'La deficiencia de acil-CoA-deshidrogenasa provoca una de las siguientes alteraciones bioquímicas:', 'Disminución de ácidos dicarboxílicos.', 'Aumento de la gluconeogénesis.', 'Disminución de la ureagénesis.', 'Aumento de carnitina libre.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 28, 'Sin clasificar', 'Respecto a la técnica de exploración de la motilidad pupilar y sus reflejos indique la respuesta INCORRECTA:', 'El reflejo de la visión próxima se explora con una linterna que se enfoca sobre las pupilas de forma alternativa.', 'El signo pupilar de Marcus Gunn o defecto pupilar aferente relativo está presente en enfermedades del nervio óptico y enfermedades retinianas no extensas.', 'El reflejo fotomotor consensuado está afectado cuando el daño implica la vía eferente vehiculada por el nervio motor ocular común.', 'La anisocoria que aumenta en condiciones de oscuridad mostrando una pupila más miótica se debe a que hay un trastorno en el sistema simpático.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 29, 'Sin clasificar', 'En relación con el proceso de envejecimiento, respecto a los principales cambios morfológicos de los aparatos y sistemas, indique la respuesta INCORRECTA:', 'En el aparato respiratorio, calcificación de los cartílagos traqueales.', 'En el sistema nervioso, aumento del tamaño de los surcos interhemisféricos y de los ventrículos cerebrales.', 'En el aparato cardiovascular, reducción en el número de células marcapaso.', 'En el sistema nefrourológico, reducción del tejido mesangial.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 30, 'Sin clasificar', 'La utilización baja de energía por el músculo liso es fundamental para el gasto de energía corporal (órganos como los intestinos, la vejiga urinaria o la vesícula biliar mantienen una contracción muscular tónica casi indefinidamente). A este respecto, señale la afirmación correcta:', 'La disposición física de los filamentos de miosina y actina es similar a la del músculo esquelético.', 'En esa contracción, es fundamental la lentitud de la unión y separación de los puentes cruzados entre los filamentos de actina y miosina.', 'La fuerza máxima de contracción es con frecuencia menor que la que se produce en el músculo esquelético.', 'La contracción prolongada exige que la excitación de las fibras musculares se mantenga mientras lo haga esa contracción.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 31, 'Sin clasificar', 'En relación con el control químico de la respiración en condiciones fisiológicas señale la afirmación INCORRECTA:', 'Los quimiorreceptores carotídeos y aórticos detectan especialmente cambios en la presión parcial de O2 en la sangre.', 'Los quimiorreceptores carotídeos y aórticos reciben un flujo arterial muy elevado por lo que se consideran expuestos en todo momento a sangre arterial.', 'Los quimiorreceptores centrales detectan fundamentalmente cambios en la concentración de H+ (procedente sobre todo de la disociación de CO2 y H2O).', 'El efecto estimulador de la ventilación del CO2 se mantiene sin atenuación en los primeros días.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 32, 'Sin clasificar', 'En un paciente diagnosticado de una neoplasia maligna de nasofaringe que presenta dolor y edema orbitario, neuropatía de los pares craneales III, IV y VI, y neuropatía de la rama V1 del V par craneal, indique qué estructura es más probable que se encuentre infiltrada:', 'Seno cavernoso.', 'Hipófisis.', 'Agujero yugular.', 'Fosa pterigopalatina.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 33, 'Sin clasificar', 'Niña de 7 años con una sospecha de anemia de Fanconi. ¿Cuál de las siguientes manifestaciones clínicas NO se ajusta a los rasgos típicos de esta enfermedad?:', 'Anomalías pigmentarias.', 'Anomalías renales.', 'Anomalías esqueléticas.', 'Estatura alta.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 34, 'Sin clasificar', 'La exploración ecográfica de una mujer gestante de 26 semanas muestra hallazgos consistentes con osteogénesis imperfecta tipo II (gen COL1A1/COL1A2). La paciente tuvo un embarazo previo con la misma patología. Ni ella ni su pareja tienen manifestaciones clínicas de osteogénesis imperfecta. ¿Cuál de las siguientes es la explicación más probable para la recurrencia?:', 'Herencia autosómica recesiva.', 'Mutación de novo.', 'Penetrancia incompleta.', 'Mosaicismo germinal. Página:', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 35, 'Sin clasificar', 'Las vacunas contra el neumococo recomendadas para prevenir la enfermedad neumocócica en personas mayores de 65 años y en pacientes inmunocomprometidos pueden estar constituidas por polisacáridos del neumococo purificados (PPV23) o polisacáridos conjugados a proteínas (PCV15 o PCV20). Desde una perspectiva inmunológica las vacunas conjugadas:', 'No generan memoria inmunológica.', 'Activan una respuesta inmunitaria T-dependiente (o timo-dependiente).', 'No activan el proceso de hipermutación somática.', 'No inducen cambio de isotipo.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 36, 'Sin clasificar', 'El paso de autoanticuerpos de la madre al feto a través de la placenta puede asociarse a la aparición de enfermedades autoinmunes en el recién nacido. Señale cuál de las parejas Enfermedad – Autoanticuerpo es INCORRECTA:', 'Pénfigo vulgar – Anticuerpos antidesmogleina 3.', 'Bloqueo cardíaco congénito – Anticuerpos anti Ro y anti-La.', 'Miastenia gravis – Anticuerpos anti receptor de la acetilcolina.', 'Lupus eritematoso neonatal – Anticuerpos anti- Sm.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 37, 'Sin clasificar', 'Mutaciones en el gen Btk pueden causar una inmunodeficiencia primaria que cursa con la disminución drástica o ausencia de inmunoglobulinas en la sangre periférica (agammaglobulinemia). En relación al estudio de los pacientes con esta agammaglobulinemia, ¿cuál de las siguientes afirmaciones es cierta?', 'Es una enfermedad autosómica recesiva.', 'El porcentaje de linfocitos que expresan CD19 o CD20 (linfocitos B) en sangre periférica está dentro de los límites normales.', 'El nivel de IgG en suero disminuye paulatinamente desde el nacimiento hasta resultar indetectable.', 'La expresión de la proteína Btk en monocitos es normal.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 38, 'Sin clasificar', 'Hombre de 20 años que, tras ingesta de gambas, presenta de forma prácticamente inmediata prurito palmoplantar, sensación de nudo en la garganta y ronquera, mareo, sensación de inestabilidad y debilidad intensa. Entre sus antecedentes destaca cuadro de edema laríngeo por alergia a las lentejas al año de edad. No refiere alergia conocida a otros alimentos, tampoco reacciones adversas a fármacos ni picadura de insectos. Entre los antecedentes familiares tiene un hermano con rinitis alérgica leve intermitente por alergia a pólenes. ¿Cuál debe ser el tratamiento inicial de forma urgente?:', 'Hidrocortisona 500 mg IV y dexclorfeniramina 5 mg IV.', 'Adrenalina 0,3-0,5 mL IV.', 'Adrenalina 0,3-05 mL IM.', 'Metilprednisolona 40 mg IM y desclorfeniramina 5 mg IV.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 39, 'Sin clasificar', 'Hombre de 40 años sin antecedentes patológicos de interés, residente en una zona de interior de la península ibérica, que presentó cuadro de urticaria aguda por sensibilización a Anisakis simplex tras haber ingerido larvas vivas en unos boquerones en vinagre. El cuadro descrito le ocurrió hace más de 6 meses. Aporta prueba cutánea e IgE específica positiva frente a dicho parásito. En relación a la ingesta de pescados, ¿qué pauta de las que se indican a continuación debe seguir?:', 'Puede comer pescados y mariscos sin ningún tipo de precaución dado que han transcurrido más de 6 meses de la ingesta.', 'No puede ingerir ningún tipo de pescado.', 'Puede comer pescado cocinado a 45ºC.', 'Puede comer pescado previamente congelado a - 20ºC durante 72 horas en el domicilio o pescado congelado industrial.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 40, 'Sin clasificar', 'La medida adecuada para estimar el riesgo individual de enfermar es:', 'La incidencia acumulada.', 'La densidad de incidencia.', 'La prevalencia puntual.', 'El riesgo relativo. Página:', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 41, 'Sin clasificar', 'Al finalizar el periodo de seguimiento en el estudio PREDIMET (“Primary Prevention of Cardiovascular Disease with a Mediterranean Diet”), el 3,8% de los individuos asignados a dieta mediterránea presentaron algún tipo de evento cardiovascular (infartos de miocardio, ictus o muertes de origen cardiovascular), frente al 4,4% de eventos ocurridos en el grupo control. ¿Cuál es el número necesario de pacientes a tratar (NNT) con dieta mediterránea para evitar un evento cardiovascular?:', '26.', '60.', '80.', '167.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 42, 'Sin clasificar', 'En evaluación económica de intervenciones sanitarias, un estudio que compare los costes alternativos de dos intervenciones frente a sus resultados de salud expresados en años ajustados por calidad o años de vida ajustados por discapacidad se denomina:', 'Análisis coste-beneficio.', 'Análisis coste-efectividad.', 'Análisis coste-utilidad.', 'Análisis de minimización de costes.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 43, 'Sin clasificar', 'Señala la opción INCORRECTA respecto a la enfermedad meningocócica:', 'El mecanismo de transmisión es por gotas.', 'Se dispone de vacunas efectivas únicamente para la prevención de 4 subtipos de meningococo.', 'La vacuna frente a meningococo tipo B está incluida en el calendario sistemático de inmunizaciones del Sistema Nacional de Salud.', 'Ante un contacto de riesgo con un paciente con meningitis meningocócica, la vacunación del contacto no debe ser la primera estrategia de profilaxis postexposición.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 44, 'Sin clasificar', 'Se diagnostica de varicela a un niño de 8 años. Su madre está embarazada de 32 semanas y se le solicita una serología en la que se observan anticuerpos de tipo IgG frente a varicela por debajo de los niveles protectores y niega haber padecido la enfermedad en el pasado. ¿Cuál es la actitud recomendada con la gestante sabiendo que han pasado 3 días desde el inicio de la exposición?', 'Administrar una dosis de la vacuna frente a varicela.', 'Forzar la terminación del embarazo para poder vacunarla.', 'Es tarde para plantear una estrategia de profilaxis post-exposición.', 'Administrar gammaglobulinas polivalentes o hiperinmunes.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 45, 'Sin clasificar', 'En un metaanálisis, el riesgo relativo estimado para la asociación causal entre el uso de mascarilla y la incidencia de SARS-CoV-2 fue de 0,47. ¿Cuál es la interpretación correcta de este resultado?:', 'La incidencia de SARS-CoV-2 se reduce un 47% cuando la población usa mascarilla.', 'No usar mascarilla aumenta un 53% el riesgo de infección por SARS-CoV-2.', 'El uso de mascarilla podría evitar 47 de cada 100 casos de SARS-CoV-2 que se dan en personas que no la usan.', 'La incidencia de SARS-CoV-2 en la población que no usa mascarilla se reduciría un 53% si la utilizara.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 46, 'Sin clasificar', 'Hombre de 79 años de edad con antecedentes de hipertensión arterial, hiperuricemia y artrosis que acude a urgencias por presentar posible reacción adversa farmacológica. No refiere antecedentes alergológicos de interés. Después de una excursión en barco sin protección solar presenta un cuadro cutáneo agudo facial, principalmente en párpados superiores e inferiores, consistentes en eritema y edema intenso bilateral. El paciente estaba realizando tratamiento médico de forma habitual con hidroclorotiazida 25 mg, amlodipino 5 mg, atorvastatina 10 mg y apixaban 5 mg. ¿Cuál de los cuatro fármacos descritos es más probable que sea el responsable de una posible reacción de fotosensibilidad?', 'Hidroclorotiazida.', 'Amlodipino.', 'Atorvastatina.', 'Apixaban.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 47, 'Sin clasificar', '¿Con cuál de estos fármacos administrados en monoterapia es necesario realizar un ecocardiograma antes de su inicio?:', 'Trastuzumab.', 'Tamoxifeno.', 'Paclitaxel.', 'Docetaxel.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 48, 'Sin clasificar', 'La inducción de secuencia rápida en la anestesia general es:', 'Método de inducción anestésica utilizado cuando existe riesgo de regurgitación gástrica y aspiración pulmonar.', 'Método de inducción anestésica realizado exclusivamente con halogenados.', 'Procedimiento anestésico que requiere la ventilación del paciente con presión positiva.', 'Método de inducción anestésica utilizado habitualmente para la realización del procedimiento quirúrgico programado. Página:', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 49, 'Sin clasificar', 'Señale la actitud correcta ante un paciente en edad infantil que refiere antecedente de traumatismo facial no tratado hace 3 años y que presenta limitación progresiva de la apertura oral y desviación del mentón hacia un lado:', 'Debe descartarse la existencia de una fractura antigua tipo Lefort-1.', 'Debe realizarse un estudio mediante tomografía computarizada para descartar una displasia fibrosa.', 'Debe descartarse el diagnóstico de osteocondroma del cóndilo mandibular.', 'Debe descartarse el diagnóstico de anquilosis témporo-mandibular.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 50, 'Sin clasificar', 'Respecto al colgajo DIEP (Deep inferior epigastric perforator), señale la respuesta INCORRECTA:', 'Se trata de un colgajo basado en vasos perforantes que puede ser usado como colgajo libre o como colgajo pediculado.', 'Está irrigado por ramas de la arteria circunfleja femoral lateral.', 'Puede utilizarse para reconstrucción mamaria.', 'Los vasos perforantes musculocutáneos atraviesan el músculo recto del abdomen antes de irrigar la piel del colgajo.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 51, 'Sin clasificar', '¿Cuál de los siguientes escenarios podría suponer una contraindicación para el uso de un injerto de piel parcial como cobertura de un defecto cutáneo?:', 'Cuando el defecto cutáneo abarca una gran superficie corporal.', 'En un paciente con comorbilidades médicas significativas.', 'Cuando hay un tendón sin paratendón en la base de la herida.', 'Cuando hay una infección activa en el lecho de la herida.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 52, 'Sin clasificar', 'Un enfermo diabético de reciente diagnóstico acude a revisión oftalmológica. A las pocas horas vuelve con un cuadro bilateral de edema y eritema palpebral, quemosis, hiperemia conjuntival, lagrimeo y picor. Su actitud debe ser:', 'Solicitar una analítica con glucemia, hemoglobina glicosilada y velocidad de sedimentación globular.', 'Prescribir un colirio antihistamínico o corticoide de baja potencia.', 'Realizar una OCT (tomografía de coherencia óptica) para descartar la existencia de un edema macular diabético.', 'Realizar una gonioscopia para descartar la presencia de neovasos en el ángulo camerular.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 53, 'Sin clasificar', 'En relación al tratamiento quirúrgico de las cataratas, señale cuál de los siguientes enunciados es correcto:', 'El empeoramiento de la visión cercana está inducido por la catarata y se denomina miopía de índice.', 'La cirugía de cristalino disminuye el riesgo de desprendimiento de retina en los pacientes miopes jóvenes.', 'Las cataratas se operan cuando la agudeza visual está muy disminuida sin tener en cuenta otros síntomas o signos.', 'Los fármacos alfa bloqueantes como la tamsulosina asocian complicaciones intraoperatorias.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 54, 'Sin clasificar', 'Hombre de 72 años exfumador, acude a consulta por visión borrosa y dificultad para leer, especialmente en el ojo derecho, situación que ha progresado lentamente en los últimos seis meses. En la exploración del segmento anterior no se encuentran alteraciones clínicamente relevantes. En el ojo derecho se observan múltiples drusas en la región macular (una de tamaño grande) y alteraciones pigmentarias. En la tomografía de coherencia óptica se muestra un adelgazamiento del epitelio pigmentario de la retina y áreas de acumulación de material subretiniano en la mácula del ojo derecho. ¿Cuál es el manejo inicial indicado para este paciente?:', 'Iniciar tratamiento con implante intravítreo de dexametasona.', 'Recomendar el uso de suplementos vitamínicos específicos.', 'Indicar de forma preferente cirugía de catarata con implante de lente intraocular.', 'Iniciar tratamiento con inyecciones intravítreas de anti-VEGF (factor de crecimiento endotelial vascular). Página:', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 55, 'Sin clasificar', 'Hombre de 26 años que presenta otorrea unilateral derecha de una semana de evolución desde su regreso de vacaciones en la playa donde una ola le arrolló provocando inmersión. Refiere haber sido tratado en la infancia con colocación de drenajes transtimpánicos bilaterales y ha evitado la entrada de agua en los oídos desde entonces. No presenta dolor, pero sí molestias y leve hipoacusia. Tampoco tiene vértigo, pero sí sensación de taponamiento ótico. En la otoscopia se evidencia una perforación timpánica central de bordes lisos y otorrea que proviene de oído medio. ¿Cuáles son el diagnóstico y tratamiento del paciente?:', 'Reactivación de una otitis media crónica simple que será tratada con ciprofloxacino en gotas óticas y remitir a Otorrinolaringología.', 'Otitis media aguda que precisa tratamiento con gentamicina en gotas óticas y revisión otoscópica pasada una semana.', 'Otitis media crónica colesteatomatosa que será tratada con gentamicina en gotas óticas y remitir a Otorrinolaringología.', 'Otitis externa aguda complicada que precisa tratamiento con ciprofloxacino en gotas óticas y revisión otoscópica pasada una semana.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 56, 'Sin clasificar', 'Hombre de 40 años que acude a urgencias por presentar un cuadro de mareo con giro de objetos acompañado de náuseas, vómitos, palidez y sudoración de varias horas de evolución. Nunca había presentado un cuadro similar. No refiere hipoacusia ni acúfeno ni sensación de taponamiento. La otoscopia es normal. Se observa un nistagmo horizonto-rotatorio hacia el lado derecho grado III que aumenta la velocidad cuando dirige la mirada a la derecha, maniobra oculocefálica positiva izquierda, test de Skew y el test de Romberg positivo a la izquierda. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Infarto cerebral.', 'Neuritis vestibular.', 'Enfermedad de Meniére.', 'Vértigo posicional paroxístico benigno.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 57, 'Sin clasificar', 'Mujer de 54 años consulta por hipoacusia unilateral derecha de horas de evolución que se ha presentado de manera brusca. Presentó un cuadro viral de vía aerodigestiva superior hace unos días. Sin antecedentes de interés, no presenta vértigo ni sensación de taponamiento ótico ni acúfeno. No refiere dolor ni presenta parálisis facial. La otoscopia es normal. En la acumetría la prueba Rinne es positiva bilateral y la pruebas Weber lateraliza al lado izquierdo. ¿Cuál es la sospecha diagnóstica y el manejo?:', 'Hipoacusia súbita, se solicitará una tomografía computerizada craneal urgente.', 'Hipoacusia de conducción por otitis media serosa, se tratará con lavados nasales y esteroides tópicos nasales.', 'Hipoacusia súbita, precisa audiometría tonal urgente y se tratará con corticoterapia sistémica y/o intratimpánica.', 'Síndrome de Ramsay-Hunt se tratará con corticoterapia más valaciclovir.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 58, 'Sin clasificar', 'Mujer que acude a ecografía de rutina de segundo trimestre a las 22 semanas de gestación. Las biometrías corresponden a un feto de 19 semanas. ¿Cuál es el siguiente paso para orientar el caso?:', 'Valorar estudio genético teniendo en cuenta el riesgo de anomalía cromosómica en primer trimestre.', 'Valorar si la gestación está correctamente datada según la longitud craneocaudal fetal de la ecografía del primer trimestre.', 'Repetir ecografía para nuevas biometrías en 2 semanas.', 'Estudio para descartar preeclampsia.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 59, 'Sin clasificar', '¿Cuál de los siguientes métodos anticonceptivos es el más adecuado para una mujer de 35 años con migraña con aura?:', 'Anticonceptivos orales combinados.', 'Parche anticonceptivo.', 'Anticonceptivo inyectable con estrógeno y progestágeno.', 'Dispositivo intrauterino (DIU) con levonorgestrel. Página: 1', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 60, 'Sin clasificar', 'Mujer con gestación monocorial biamniótica de 22 semanas que acude a urgencias por dinámica uterina ocasional. En la ecografía se observa feto 1 con peso estimado en el percentil 80 y columna máxima vertical de líquido amniótico de 11 cm, vejiga urinaria distendida y aumentada de tamaño y feto 2 con un peso en el percentil 25 con una columna máxima de líquido amniótico de 0,5 cm y vejiga urinaria no visible. Exploración vaginal anodina. La longitud cervical es de 36 mm. ¿Cuál es el diagnóstico más probable?:', 'Trasfusión feto-fetal.', 'Discordancia de crecimiento fetal con crecimiento fetal restringido selectivo del feto 2.', 'Rotura prematura de membranas de feto 2.', 'Malformación renal feto 2.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 61, 'Sin clasificar', 'Puérpera de parto eutócico sin complicaciones hace 4 días que acude a urgencias por cefalea de 12 horas de evolución y edemas maleolares. A la exploración presenta cifras tensionales de 165/100 mmHg en dos ocasiones y en la analítica se observa una cifra de plaquetas de 254.000/µL, AST 172 UI/L, ALT 154 UI/L y LDH 345 UI/L, creatinina 0,9 mg/dL y cociente prot/creat 235 mg/g. ¿Cuál de las siguientes opciones terapéuticas forma parte de la primera línea de tratamiento inmediato?', 'Sulfato de magnesio vía endovenosa.', 'Labetalol vía oral.', 'Corticoides a dosis altas.', 'Diuréticos vía endovenosa.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 62, 'Sin clasificar', '¿Cuál es la vía de diseminación más frecuente y característica del cáncer de ovario en el momento del diagnóstico?:', 'Vía linfática.', 'Vía hematógena.', 'Infiltración por contigüidad.', 'Diseminación peritoneal.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 63, 'Sin clasificar', '¿Cuál de las siguientes es una de las características que condiciona de modo crucial e independiente la elección del tratamiento adyuvante del cáncer de endometrio?:', 'Tamaño tumoral.', 'Perfil molecular del tumor.', 'Presencia de células tumorales aisladas en los ganglios linfáticos.', 'Presencia de metrorragia.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 65, 'Sin clasificar', 'Niña de 10 meses, correctamente vacunada para su edad, tiene fiebre alta, fotofobia y tos. Tras 4 días de fiebre se aprecian unas manchas blancas, como un espolvoreado de harina en mucosa malar a nivel del 2º molar. Al día siguiente de detectarse estas manchas, todavía con fiebre y tos, se detecta un exantema eritematoso, maculo-papuloso morbiliforme, con tendencia a la confluencia en algunas zonas, de aparición craneocaudal. La fiebre persiste hasta 3 días más. Al 5º día de iniciar el exantema el niño se encuentra afebril pero inicia en la piel una fase de descamación fina, furfurácea. El diagnóstico clínico más probable es:', 'Sarampión.', 'Rubeola.', 'Varicela.', 'Escarlatina.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 66, 'Sin clasificar', 'El síndrome de Guillain-Barré es considerado una polineuropatía postinfecciosa que presenta todas las características siguientes, EXCEPTO una:', 'Existe hiperreflexia tendinosa en las extremidades que manifiestan debilidad.', 'Es predominantemente un trastorno motor, aunque puede haber síntomas sensitivos.', 'En el líquido cefalorraquídeo las proteínas están elevadas, sin pleocitosis y con glucorraquia normal.', 'El tratamiento con inmunoglobulina intravenosa acelera la recuperación, pero no modifica la evolución a largo plazo. Página: 1', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 67, 'Sin clasificar', 'Un lactante de 6 meses acude a urgencias por presentar vómitos y diarrea en las últimas 12 horas. Su peso es de 6 kg. Hace 24 horas su peso era de 6,5 kg. Presenta frecuencia cardíaca 140 lpm, frecuencia respiratoria 30 rpm, presión arterial 90/40 mmHg. En la gasometría venosa se observa pH 7,25, pCO2 33 mmHg, pO2 45 mmHg, bicarbonato 17 mmol/L, exceso de bases -7, lactato 2,5 mmol/L. El sodio es 143 mmol/L. ¿Cuál es su situación en el equilibrio ácido base?:', 'Acidosis metabólica sin compensar respiratoriamente.', 'Acidosis metabólica parcialmente compensada respiratoriamente.', 'Acidosis respiratoria parcialmente compensada metabólicamente.', 'Alcalosis respiratoria compensada metabólicamente.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 69, 'Sin clasificar', 'Respecto a las medidas a tomar ante un niño diagnosticado de tos ferina, en relación a sus contactos, indique la respuesta INCORRECTA:', 'Tratar con antibióticos a toda la familia, independientemente de la edad, estado de inmunización y sintomatología.', 'Tratar con antibióticos a todo el personal sanitario que ha atendido al niño independientemente de la edad, estado de inmunización y sintomatología.', 'Vacunar a los adultos convivientes, aunque hayan padecido la enfermedad ya que la inmunidad no dura toda la vida.', 'Aislar al paciente al menos 5 días después de iniciar el tratamiento.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 70, 'Sin clasificar', 'Indique la respuesta FALSA respecto a la invaginación intestinal en pediatría:', 'La mayoría de los casos de invaginación en niños se deben a adherencias congénitas.', 'La incidencia estacional alcanza picos en otoño e invierno.', 'Se ha apreciado una correlación con infección respiratoria previa o concurrente por adenovirus (tipo C).', 'Se ha observado un aumento ligero de la invaginación en las tres semanas posteriores a la vacuna de rotavirus (sobre todo tras la primera dosis).', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 71, 'Sin clasificar', 'Todas las siguientes pueden ser manifestaciones tardías de sífilis congénita, habitualmente no evidentes clínicamente en los 2 primeros años de vida. Indique la manifestación que NO es habitual en esta patología:', 'Dientes de Hutchinson.', 'Nariz en silla de montar.', 'Queratitis intersticial.', 'Cardiopatía congénita.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 72, 'Sin clasificar', 'Mujer de 35 años que hace dos días sufrió un accidente de coche sin apenas consecuencias físicas acude a su médica de atención primaria, por insomnio con pesadillas, expresa también recuerdos vívidos de detalles del accidente y síntomas de hiperactivación. El diagnóstico más probable es:', 'Reacción aguda de estrés.', 'Reacción adaptativa depresiva.', 'Trastorno de estrés postraumático.', 'Trastorno de ansiedad generalizada.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 73, 'Sin clasificar', 'Los mecanismos de defensa que con mayor frecuencia se presentan en el trastorno delirante son los siguientes, EXCEPTO:', 'Proyección.', 'Negación.', 'Formación reactiva.', 'Regresión. Página: 1', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 74, 'Sin clasificar', 'Sobre los factores de mal pronóstico en la esquizofrenia, señale la respuesta INCORRECTA:', 'Inicio en edad temprana.', 'Presencia de síntomas negativos.', 'Presentación clínica aguda.', 'Antecedentes de agresividad.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 75, 'Sin clasificar', 'Adolescente de 16 años que es traída a la consulta por sus padres debido a cambios drásticos en su comportamiento en los últimos seis meses. Ha mostrado síntomas de depresión, irritabilidad y recientemente ha comenzado a autolesionarse realizándose cortes en los brazos. También se ha aislado socialmente y ha tenido dificultades para mantener su rendimiento académico. ¿Cuál de los siguientes factores es el más significativo para indicar desregulación emocional y riesgo de conducta suicida en esta paciente?:', 'Presencia de autolesiones.', 'Aislamiento social.', 'Irritabilidad.', 'Dificultades académicas.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 76, 'Sin clasificar', 'Mujer de 28 años con diagnóstico de trastorno bipolar tipo I embarazada de 12 semanas. Ha tenido episodios maníacos y depresivos en el pasado. Actualmente, está preocupada por el impacto de su tratamiento en el feto. ¿Cuál de los siguientes tratamientos es más seguro y recomendado durante el embarazo, y qué tipo de psicoterapia es apropiada como complemento?:', 'Ácido valproico y terapia interpersonal.', 'Lamotrigina y terapia cognitivo-conductual.', 'Litio y terapia cognitivo-conductual.', 'Carbamazepina y terapia interpersonal.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 77, 'Sin clasificar', 'Respecto a la enfermedad de Alzheimer, señale la respuesta INCORRECTA:', 'El gen de la ApoE (apolipoproteína epsilon ) alelo E4 es factor de riesgo.', 'Hay un descenso de la proteína tau en el LCR.', 'El PET tau y el PET amiloide son útiles en el diagnóstico precoz de la enfermedad.', 'En la RM de estos pacientes esperamos encontrar atrofia en el lóbulo temporal medial.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 78, 'Sin clasificar', 'Un paciente acude a la consulta porque tiene un trastorno de la marcha, tropieza y tiene caídas frecuentes. En la exploración presenta temblor de reposo en el miembro superior derecho, rigidez en rueda dentada al movilizarle las extremidades superiores y marcha alterada desplazando el tronco hacia delante con pasos cortos. ¿Cuál de las siguientes afirmaciones apoyaría el diagnóstico de enfermedad de Parkinson?:', 'Falta de respuesta inicial al tratamiento con Levodopa.', 'SPECT con transportador de dopamina que muestre una hipocaptación en la vía nigroestriada.', 'Gammagrafía miocárdica con MIBG (metayodobencilguanidina) normal.', 'Presencia precoz de síntomas de disautonomía.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 79, 'Sin clasificar', 'Mujer de 35 años consulta por cuadro de diplopia y debilidad proximal progresivas que empeora a lo largo de día. En la exploración neurológica se aprecia voz nasal, ptosis bilateral sin afectación pupilar, limitación para la abducción de ojo derecho y debilidad proximal con reflejos miotáticos conservados. Respecto a esta paciente señale la opción INCORRECTA:', 'El nivel de anticuerpos es independiente de la gravedad de la enfermedad.', 'En ocasiones se asocia a otra enfermedad autoinmune.', 'Es frecuente la agregación familiar.', 'La respuesta a inmunosupresores es mayor en pacientes con anticuerpos antirreceptor de acetilcolina y anticuerpos antiMusk positivos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 80, 'Sin clasificar', 'Con respecto a la parálisis facial, ¿cuál de los siguientes signos y síntomas nos haría pensar en un origen central?', 'La presencia de ageusia asociada a la parálisis facial.', 'La presencia de hipoestesia o dolor en la región del pabellón auricular del mismo lado que la parálisis.', 'Si la debilidad de los músculos faciales sólo afecta a la mitad inferior de la hemicara afectada sin afectación de los músculos palpebrales ni de la frente.', 'Si hay disminución de la secreción lacrimal en el ojo correspondiente al lado de la parálisis facial. Página: 1', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 81, 'Sin clasificar', 'Hombre de 75 años con antecedentes de fibrilación auricular e hipertensión arterial es traído a urgencias por hemiparesia derecha, dificultad para hablar y fiebre de 38,5°C. La tomografía computarizada (TC) de cráneo revela un infarto cerebral en la región parietal izquierda e ingresa en la unidad de ictus. A las 48 h del ingreso se informa de presencia de Streptococcus viridans en hemocultivo. ¿Cuál es el diagnóstico más probable y el enfoque diagnóstico-terapéutico adecuado en este caso?', 'Accidente cerebrovascular isquémico secundario a fibrilación auricular; iniciar anticoagulación y antipiréticos.', 'Meningitis bacteriana con complicación isquémica; realizar punción lumbar e iniciar antibiótico dirigido según antibiograma.', 'Endocarditis infecciosa con embolia séptica; confirmar con ecocardiograma y tratar con antibiótico dirigido según el antibiograma.', 'Neoplasia cerebral con fiebre paraneoplásica; realizar resonancia magnética cerebral y evaluación oncológica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 82, 'Sin clasificar', 'Mujer de 55 años que consulta por una cefalea con sensación de presión bilateral, que no asocia fotofobia, náuseas ni vómitos. La paciente puede realizar sus actividades habituales porque el dolor es de intensidad moderada. El dolor es prácticamente diario en los últimos 6 meses. Desde el punto de vista terapéutico, ¿cuál es la opción más adecuada?', 'Tratamiento analgésico simple con paracetamol diario, los días que tenga dolor.', 'Tratamiento con triptanes en el momento agudo de la cefalea los días que sea más intensa.', 'Tratamiento preventivo de entrada con betabloqueantes tipo propranolol a dosis entre 40- 160 mg/d entre 3-6 meses.', 'Tratamiento preventivo de entrada con amitriptilina a dosis bajas entre 25-50 mg/d y mantenerlo entre 3 y 6 meses.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 83, 'Sin clasificar', 'Mujer de 18 años sin antecedentes de interés ni consumo de tóxicos que ingresa en planta por un cuadro de alteración conductual con ansiedad, agresividad e ilusiones visuales. Durante su ingreso presenta una crisis convulsiva junto con discinesias orolinguales y distonía del pie izquierdo. Dos semanas previas había presentado un cuadro de diarrea, náuseas y vómitos autolimitados. Respecto a este síndrome señale la respuesta INCORRECTA:', 'La encefalitis anti NMDAR es la encefalitis autoinmune más frecuente.', 'La RM con hiperseñal hipocampal es patognomónica de la enfermedad.', 'Existe una fuerte asociación con patología tumoral.', 'El pronóstico habitualmente es favorable.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 84, 'Sin clasificar', 'Hombre de 81 años con antecedentes de HTA, dislipemia y enfermedad de Alzheimer leve. Avisa su familia porque lo han encontrado en su casa caído en el suelo y no es capaz de movilizar extremidades derechas. Llega al hospital trasladado por emergencias como código ictus. A la exploración física destaca paresia facial derecha supranuclear, afasia global, hemianopsia derecha y hemiplejia de miembros derechos. La TC craneal se informa como ASPECTS 8 sin datos de sangrado. En angioTC oclusión de segmento M2 de división anterior de ACM izquierda. ¿Cuál de los siguientes es el mejor tratamiento inicial para este paciente?', 'Fibrinolisis con alteplasa.', 'Doble antiagregación y estatinas.', 'Manejo conservador por los antecedentes del paciente.', 'Trombectomía mecánica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 85, 'Sin clasificar', 'Sobre el tratamiento quirúrgico de la enfermedad de Parkinson señale la opción correcta:', 'Los núcleos diana principales son el núcleo pálido y el núcleo ventral inferomedial del tálamo.', 'La cirugía lesional es la opción utilizada más frecuentemente hoy en día.', 'La presencia de síntomas o signos que no responden a la levodopa desaconsejan el tratamiento.', 'La estimulación eléctrica de los núcleos genera una activación de los mismos, principio fundamental del tratamiento.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 86, 'Sin clasificar', 'El APACHE-II (Acute Physiologic Assessment and Chronic Health Evaluation II) es un índice cuantitativo de gravedad que se calcula en el paciente crítico utilizando las siguientes variables, EXCEPTO:', 'Recuento de leucocitos en sangre.', 'Escala de coma de Glasgow.', 'Lactato en sangre.', 'pH en sangre.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 87, 'Sin clasificar', 'Mujer de 57 años ingresada en la Unidad de Cuidados Intensivos por hipotensión persistente y fracaso multiorgánico. Tras monitorización hemodinámica avanzada, la paciente presenta frecuencia cardíaca de 105 lpm, resistencias vasculares sistémicas de 400 din-seg-m2/cm5, gasto cardíaco de 8 L/min, presión venosa central de 5 mmHg, variación del volumen sistólico del 9% e índice de agua pulmonar extravascular indexado de 5 mL/kg. ¿A qué tipo de shock orienta dicha monitorización hemodinámica avanzada?:', 'Shock distributivo.', 'Shock cardiogénico.', 'Shock hipovolémico.', 'Shock obstructivo. Página: 1', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 88, 'Sin clasificar', 'Mujer de 63 años, diabética en tratamiento con antidiabéticos orales que consulta por dolor en hombro derecho de 3 meses de evolución sin antecedente traumático. El dolor le limita el movimiento completo del hombro y desde hace una semana le impide el descanso nocturno. En la exploración el médico constata limitación para el movimiento activo de la abducción a más de 100º, de la flexión a 110º, rotación externa a 45º e interna lleva la mano al glúteo con dificultad. No presenta limitación en la movilidad pasiva de la extremidad. La orientación diagnóstica más probable y la actuación inicial es:', 'Tendinosis del manguito rotador. Crioterapia, AINEs tópicos y cabestrillo una semana.', 'Tendinosis cálcica del supraespinoso derecho. Crioterapia 3 veces al día e indicar fisioterapia.', 'Tendinosis del supraespinoso derecho. Infiltración, paracetamol cada 8 horas y solicitar resonancia magnética.', 'Tendinosis del supraespinoso derecho. Crioterapia, AINEs orales y ejercicios en su domicilio. Visita de control y si no mejora solicitar prueba de imagen.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 89, 'Sin clasificar', 'Jugador de baloncesto de 42 años que acude a urgencias por dolor de tres días de evolución en cara anterior de muslo derecho de tipo lancinante. Inicia el dolor tras mal gesto en flexión de la columna lumbar, presentando primero lumbalgia y después este dolor irradiado. En la exploración presenta un Lasegue invertido positivo, con un reflejo osteotendinoso rotuliano derecho 2/4. No hay déficit motor. La orientación diagnóstica más probable es:', 'Hernia discal L4-L5 migrada posterior que ocasiona una clínica de silla de montar.', 'Hernia discal foraminal L4-L5 derecha que comprime la raíz de L4.', 'Hernia discal foraminal L4-L5 derecha que comprime la raíz de L5.', 'Meralgia parestésica derecha.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 90, 'Sin clasificar', 'Paciente de 75 años con estancia prolongada en UCI. En una exploración rutinaria se observa dificultad para la flexión dorsal del pie izquierdo con un tibial anterior a 1/5, una dificultad para la extensión de los dedos 1/5 y dificultad para la eversión con peroneos 3/5. No presenta otro foco neurológico, ni dolor en la región lumbar ni en la extremidad. ¿Cuál de las siguientes es la actitud más correcta?:', 'Indicar férula antiequino y fisioterapia por sospecha de compresión del nervio ciático poplíteo externo.', 'Solicitar electromiograma urgente y dejarlo en reposo.', 'Realizar punción lumbar por sospecha de complicación por Guillain-Barre.', 'Solicitar resonancia magnética y pautar, si no está recibiendo, corticoides.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 91, 'Sin clasificar', 'Mujer de 19 años que, practicando patinaje sobre ruedas, sufre un traumatismo indirecto de la rodilla derecha, con luxación de rótula tratada en urgencias. Acude a revisión 2 meses más tarde y refiere que nota dolor y sensación de inestabilidad y subluxación frecuente con la actividad física. De los siguientes elementos, señale el que NO favorece la inestabilidad fémoro-patelar:', 'Anteversión femoral.', 'Torsión tibial interna.', 'Genu valgo.', 'Patela alta.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 92, 'Sin clasificar', 'Desde el punto de vista fisiopatológico la osteonecrosis de la cabeza femoral se puede desencadenar por todos los mecanismos aquí descritos EXCEPTO:', 'Anomalías en el flujo vascular por factores genéticos.', 'Oclusión intravascular por émbolos (lípidos, nitrógeno, hematíes anómalos).', 'Dehiscencia de la íntima arterial de los vasos.', 'Compresión extravascular a consecuencia de un acúmulo graso.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 93, 'Sin clasificar', 'Mujer de 68 años con IMC 28 kg/m2 que consulta por dolor crónico en rodilla derecha. Refiere que el dolor empeora con la actividad física, especialmente al subir y bajar escaleras, y mejora con el reposo. En la exploración física se observa crepitación en la rodilla derecha y leve deformidad en ambas. Una radiografía de rodilla derecha muestra estrechamiento del espacio articular y formación de osteofitos. ¿Cuál es la opción de tratamiento más adecuada en este caso?:', 'Inmovilización de la rodilla con rodillera de descarga rotuliana.', 'Pérdida de peso y ejercicio físico supervisado para fortalecer el cuádriceps.', 'Infiltración intraarticular de corticoides.', 'Tratamiento farmacológico con tramadol.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 94, 'Sin clasificar', 'Hombre de 30 años que acude a consulta por dolor lumbar crónico que empeora en la noche y mejora con el ejercicio. Refiere rigidez matutina de más de una hora. La exploración física revela una disminución de la movilidad en la columna lumbar y dolor a la palpación y exploración de las articulaciones sacroilíacas. La resonancia magnética muestra edema en las articulaciones sacroilíacas compatible con sacroileitis. ¿Cuál es el tratamiento inicial más indicado para este paciente?:', 'Metotrexate subcutáneo semanal.', 'Corticoides orales.', 'Fisioterapia y antiinflamatorios no esteroides (AINEs).', 'Terapia biológica con anti-TNF. Página: 1', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 95, 'Sin clasificar', 'Mujer de 83 años hospitalizada por neumonía adquirida en la comunidad por neumococo. Presenta una artritis aguda de carpo derecho. Sospechamos enfermedad por depósito de pirofosfato pero no se observa condrocalcinosis en la radiografía de carpos ni se ha conseguido obtener líquido sinovial durante la artrocentesis. ¿Qué radiografías añadiremos al cribado con el objetivo de identificar condrocalcinosis?:', 'Radiografía anteroposterior de rodillas y de sínfisis de pubis.', 'Radiografía anteroposterior de rodillas y de hombros.', 'Radiografía anteroposterior de sínfisis de pubis y de hombros.', 'Radiografía anteroposterior de rodillas y de codos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 96, 'Sin clasificar', 'Uno de estos hallazgos anatomopatológicos sugiere el diagnóstico de enfermedad por IgG4:', 'Trombosis arterial.', 'Proliferación de la íntima arterial sin datos de vasculitis.', 'Fibrosis estoriforme.', 'Infiltrado perivascular de polimorfonucleares.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 97, 'Sin clasificar', '¿Cuál de los siguientes hallazgos NO esperaría encontrar en una mujer de 28 años con una comunicación interauricular evolucionada?:', 'Soplo mesosistólico.', 'Aumento de la silueta cardíaca en la radiografía de tórax.', 'Bloqueo de rama derecha en el electrocardiograma.', 'Hipertrofia del ventrículo izquierdo.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 98, 'Sin clasificar', 'Joven de 16 años con astenia desde hace 1 mes, que durante un partido de fútbol sufre un síncope. A su llegada al hospital inconsciente y hemodinámicamente inestable presenta síntomas y signos de accidente cerebrovascular, de isquemia mesentérica y de isquemia arterial periférica, en miembro superior izquierdo y de ambos miembros inferiores. ¿Cuál cree que es el diagnóstico de sospecha?:', 'Bloqueo aurículo-ventricular de 3º grado.', 'Insuficiencia mitral aguda.', 'Mixoma de aurícula izquierda.', 'Rotura de aneurisma de arteria cerebral media.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 99, 'Sin clasificar', 'Hombre de 65 años, hipertenso desde hace 12 años, que acude por primera vez a la consulta de su médico de familia para una revisión rutinaria. La exploración física es normal y el electrocardiograma muestra ritmo sinusal a 68 lpm, con bloqueo de la rama izquierda del haz de His y duración del QRS de 150 ms. ¿Cuál de las siguientes situaciones implica este hallazgo?:', 'Asincronía ventricular.', 'Miocardiopatía dilatada.', 'Disociación aurículo-ventricular.', 'Isquemia miocárdica aguda.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 100, 'Sin clasificar', 'Un entrenamiento aeróbico intenso y prolongado produce una serie de adaptaciones cardiovasculares que suelen denominarse "corazón de deportista". Entre las siguientes adaptaciones fisiológicas, señale la respuesta INCORRECTA:', 'Bradicadia sinusal por aumento del tono vagal.', 'Bloqueo aurículo-ventricular de primer grado, de segundo grado Mobitz I e incluso de tercer grado durante el sueño.', 'Bloqueo completo de rama izquierda del haz de His por hipertrofia ventricular izquierda.', 'Bloqueo de rama derecha del haz de His por dilatación fisiológica ventricular derecha en deportes de resistencia.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 101, 'Sin clasificar', '¿Cuál de las siguientes complicaciones es más frecuente en el reemplazo valvular aórtico transcatéter (TAVI) respecto del reemplazo valvular quirúrgico?:', 'Atelectasia pulmonar.', 'Bloqueo aurículo-ventricular completo.', 'Derrame pericárdico.', 'Hemorragia grave.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 102, 'Sin clasificar', 'Señale cuál de las siguientes situaciones se considera indicación de cirugía para el tratamiento de endocarditis infecciosa (EI):', 'Aparición de insuficiencia renal aguda.', 'Hallazgo por imagen de émbolos esplénicos o renales en el momento del diagnóstico.', 'Presencia de vegetaciones mayores de 8 mm en válvula tricúspide en la EI derecha.', 'Hemocultivos positivos persistentes durante 7-10 días tras pauta antibiótica adecuada. Página: 1', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 103, 'Sin clasificar', 'Hombre de 68 años, hipertenso y fumador que acude a urgencias por dolor torácico y disnea desde hace 3 horas. Presenta mal estado general, presión arterial 118/45 mmHg, FC 105 lpm, saturación O2 96%. En la auscultación crepitantes basales finos, tonos cardíacos atenuados, que no permiten identificar soplos. Dímero D 16.000 ng/mL. El ECG muestra taquicardia sinusal y signos de hipertrofia ventricular izquierda. Un ecocardiograma urgente revela un ventrículo izquierdo hipertrófico, no dilatado, con disfunción sistólica global ligera, insuficiencia aórtica moderada, no conocida previamente y derrame pericárdico moderado-grave. Con estos datos, ¿qué patología debe descartar?:', 'Disección de aorta proximal.', 'Infarto agudo de miocardio complicado con rotura de músculo papilar.', 'Tromboembolismo pulmonar masivo.', 'Pericarditis efusivo-constrictiva.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 104, 'Sin clasificar', 'Hombre de 71 años portador de un marcapasos bicameral por bloqueo AV completo. Está en ritmo sinusal a 85 lpm con ritmo ventricular estimulado por el marcapasos. La interrogación del marcapasos muestra un porcentaje de estimulación ventricular del 99%. En el ecocardiograma tiene dilatación y disfunción sistólica de ambos ventrículos. La fracción de eyección del ventrículo izquierdo es del 30% y tiene insuficiencia mitral funcional grave. No tiene lesiones obstructivas en la coronariografía. Está en clase funcional III NYHA a pesar de tratamiento médico óptimo para la insuficiencia cardíaca con fracción de eyección reducida. ¿Cuál de las siguientes es la primera opción de tratamiento?:', 'Cirugía de reparación valvular.', 'Cirugía de sustitución valvular.', 'Terapia de resincronización cardíaca.', 'Mitra-Clip.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 105, 'Sin clasificar', 'Neonato de 10 días de vida que es traído por sus padres a los servicios de urgencias por presentar, desde hace 24 horas, rechazo de las tomas e hipotonía generalizada. Tras pruebas complementarias, se diagnostica de coartación de aorta preductal crítica. El paciente evoluciona en pocas horas hacia el shock cardiogénico. En este contexto, ¿cuál debe ser el primer tratamiento para mejorar la hemodinámica de este paciente?', 'Iniciar perfusión continua con prostaglandinas E1.', 'Administrar tratamiento con ibuprofeno.', 'Plantear cirugía de carácter emergente.', 'Realizar cateterismo y atrioseptostomía de Rashking urgente.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 106, 'Sin clasificar', 'Mujer de 46 años que tras 10 años de mastectomía derecha con vaciamiento ganglionar seguida de quimioterapia y radioterapia presenta linfedema de brazo derecho de larga evolución con importante edema y empastamiento, sin signos de celulitis. ¿Cuál de las siguientes medidas terapéuticas NO está recomendada?', 'Realización de actividad física con elevación del miembro superior derecho.', 'Terapia física con fisioterapia descongestiva.', 'Diuréticos para reducir edema.', 'Liposucción.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 107, 'Sin clasificar', 'En un paciente que tras una embolectomía por isquemia arterial aguda secundaria a un émbolo en la bifurcación aorto-ilíaca, presenta hipotensión, hipercalciuria, mioglobinuria e insuficiencia renal, ¿cuál de entre los siguientes es el diagnóstico más probable?', 'Trombosis arterial recurrente.', 'Síndrome de reperfusión.', 'Necrosis muscular.', 'Neuropatía isquémica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 108, 'Sin clasificar', 'Hombre de 55 años con HTA y dislipemia que consulta por disnea de esfuerzo. Presenta en la ecocardiografía válvula aórtica bicúspide con área valvular aórtica de 0,9 cm2, gradiente transvalvular de 45 mmHg, velocidad pico de 5,5 m/seg, raíz aórtica de 6 cm y fracción de eyección de ventrículo izquierdo de 45%. En la analítica, péptido natriurético tipo B el triple de lo normal. ¿Qué opción terapéutica le recomendaría?:', 'Seguimiento por médico de atención primaria mientras esté asintomático.', 'Implante de una prótesis valvular aórtica biológica transcatéter (TAVI).', 'Valvuloplastia aórtica.', 'Cirugía de sustitución valvular aórtica y raíz.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 109, 'Sin clasificar', 'En la respuesta inmune innata, las células más numerosas a nivel pulmonar, que conforman la primera línea defensiva, son:', 'Neutrófilos.', 'Macrófagos.', 'Eosinófilos.', 'Mastocitos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 110, 'Sin clasificar', 'Hombre de 60 años que acude a consulta por presentar tos y expectoración habitual mucosa, amarillenta, con más de 4-5 episodios de reagudizaciones al año, algunas veces con hemoptisis. ¿Cuál de los siguientes es el diagnóstico más probable?', 'Asma.', 'Fibrosis pulmonar idiopática.', 'Bronquiectasias.', 'Insuficiencia cardíaca. Página: 1', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 111, 'Sin clasificar', '¿Qué hallazgos de los descritos a continuación son MENOS probables en la exploración física de un paciente con fibrosis a nivel del intersticio pulmonar?:', 'Sibilancias bilaterales en la auscultación pulmonar.', 'Crepitantes teleinspiratorios bibasales.', 'Disminución del murmullo vesicular con acropaquia.', 'Vibraciones vocales disminuidas con crepitantes tipo velcro, de carácter "seco".', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 112, 'Sin clasificar', 'Paciente que en revisión en consulta refiere tos matutina diaria y disnea de moderados esfuerzos (MRC 2) habitual que limita sus actividades cotidianas en tratamiento con doble terapia broncodilatadora desde hace dos años. La espirometría presenta un FEV1 del 35% del teórico en situación basal con una respuesta broncodilatadora que muestra un incremento del FEV1 de 250 mL y un 13%. En el estudio por TC se identifican áreas de enfisema centroacinar y en la analítica 250 eosinófilos/µL. En el último año ha sufrido dos exacerbaciones respiratorias de las cuales una ha requerido ingreso hospitalario. Indique el tratamiento más adecuado:', 'Broncodilatador β-agonista de acción prolongada + broncodilatador antagonista muscarínico de acción prolongada + corticoide sistémico.', 'Añadir roflumilast a la terapia combinada.', 'Broncodilatador β-agonista de acción prolongada + broncodilatador antagonista muscarínico de acción prolongada + corticoide inhalado.', 'Broncodilatador β-agonista de acción prolongada + corticoide inhalado.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 114, 'Sin clasificar', 'En el estudio de las enfermedades intersticiales difusas del pulmón, señale en que entidad el lavado broncoalveolar posee valor diagnóstico:', 'Sarcoidosis.', 'Fibrosis pulmonar idiopática.', 'Neumonitis por hipersensibilidad.', 'Proteinosis alveolar.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 115, 'Sin clasificar', 'Hombre de 65 años, exfumador, en el que de forma incidental se identifica un nódulo pulmonar solitario (NPS) en radiografía simple de tórax. Diagnosticado de enfermedad pulmonar obstructiva crónica con un FEV1 del 30%. En el estudio por TC se describe un NPS en lóbulo superior derecho de 9 mm de diámetro con cola pleural y calcificaciones excéntricas. Se realiza tomografía por emisión de positrones con captación patológica indicativa de malignidad. ¿Cuál de las siguientes actitudes terapéuticas es la más adecuada?:', 'Es imprescindible la realización de una biopsia por cirugía torácica ante la elevada posibilidad de malignidad.', 'Al tratarse de un NPS de pequeño tamaño (< 1 cm) la actitud más adecuada es la de seguimiento radiológico estrecho con TC al mes y a los 3, 6 y 12 meses.', 'Ante la alta probabilidad de malignidad se recomienda realizar una prueba de esfuerzo cardiopulmonar y si el consumo máximo de oxígeno es <10 mL/kg/min remitir a cirugía torácica para resección.', 'Se debe realizar una prueba de esfuerzo cardiopulmonar y si el consumo máximo de oxígeno es <10 mL/kg/min el manejo terapéutico más seguro es por medio de radioterapia estereotáxica fraccionada.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 116, 'Sin clasificar', 'En una mujer de 72 años con litiasis biliar asintomática se indicaría colecistectomía laparoscópica en caso de:', 'Microlitiasis por alto riesgo de pancreatitis aguda.', 'Litiasis biliar de más de 2,5 cm de diámetro.', 'Vesícula con paredes calcificadas en porcelana.', 'Presencia de cálculos de bilirrubina.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 117, 'Sin clasificar', '¿En cuál de las siguientes técnicas quirúrgicas para la reparación de una hernia inguinal NO se emplea una malla protésica?', 'Shouldice.', 'Lichtenstein.', 'Reparación laparoscópica TEP (totalmente extraperitoneal).', 'Reparación laparoscópica TAPP (transabdominal preperitoneal). Página: 1', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 118, 'Sin clasificar', 'Mujer de 42 años que consulta por dolor rectal descrito como una sensación de peso u ocupación continua que se agrava con la deposición. En la exploración física el ano es normal y en el tacto rectal se palpa el músculo puborrectal hipertónico y doloroso a la tracción. ¿Cuál de los siguientes es el diagnóstico más probable?', 'Úlcera solitaria de recto.', 'Proctalgia fugax.', 'Proctalgia inespecífica.', 'Síndrome del elevador del ano.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 119, 'Sin clasificar', 'Un hombre con diagnóstico de melanoma avanzado y en tratamiento con nivolumab (fármaco anti-PD-1) desarrolla elevación de las transaminasas siete veces los valores normales, junto con elevación de la bilirrubina total (2,3 mg/dL). Se han descartado cuadros infecciosos y no ha mejorado tras suspender el fármaco. ¿Cuál de las siguientes afirmaciones es cierta?', 'Es una hepatitis inmunomediada por nivolumab y es indistinguible de una hepatitis autoinmune.', 'La reintroducción del fármaco una vez resuelta conlleva la reaparición del cuadro en la mayoría de los casos.', 'Los corticoides a dosis de 1 mg/kg de prednisona o equivalente son el tratamiento de elección en esta situación.', 'La aparición de esta entidad es tardía, generalmente meses después de iniciado el tratamiento.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 120, 'Sin clasificar', 'Un paciente con enfermedad de Crohn con antecedente de extirpación de un melanoma precisa iniciar un tratamiento avanzado por corticodependencia. ¿Cuál de los siguientes fármacos se debería evitar al estar descrito un aumento del riesgo de dicha neoplasia?', 'Azatioprina.', 'Infliximab.', 'Vedolizumab.', 'Ustekinumab.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 121, 'Sin clasificar', 'Respecto al divertículo faringoesofágico o divertículo de Zenker, es cierto que:', 'Es un divertículo por tracción y consta de todas las capas de la pared esofágica.', 'Es menos frecuente que los divertículos del tercio medio del esófago en la actualidad.', 'No se trata con miotomía del cricofaríngeo si el tamaño es igual o menor a 2 cm.', 'Cuando se interviene mediante abordaje abierto para practicar una diverticulectomía o una divertículopexia, la incisión se realiza en el lado izquierdo del cuello.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 122, 'Sin clasificar', 'Mujer de 67 años con antecedentes de infección por VHC que acude a urgencias por hematemesis. A la exploración observamos ascitis y ligera ictericia. ¿Cuál es la actitud diagnóstica y terapéutica más adecuada?', 'Estabilizar hemodinámicamente, hacer una endoscopia y colocar un TIPS si tiene hemorragia por varices.', 'Realizar una paracentesis, seguido de una endoscopia y ligadura de varices.', 'Estabilizar al paciente, iniciar un fármaco vasoactivo, realizar una endoscopia y practicar una ligadura si hay hemorragia por varices.', 'Esperar al resultado de la endoscopia para actuar en consecuencia.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 123, 'Sin clasificar', 'Mujer de 38 años que presenta nódulo tiroideo indoloro y creciente en el lóbulo derecho de 6 meses de evolución. Ha experimentado recientemente disfagia y cambios de la voz. Se diagnostica de carcinoma medular de tiroides en estadio III con extensión extratiroidea y compromiso de ganglios linfáticos cervicales. De entre los siguientes, ¿cuál es el tratamiento más adecuado?:', 'Tiroidectomía subtotal.', 'Hemitiroidectomía derecha.', 'Tiroidectomía total con extirpación de ganglios linfáticos cervicales.', 'Quimioterapia exclusiva.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 124, 'Sin clasificar', 'Mujer de 58 años que consulta por presentar desde hace varios meses dolor abdominal epigástrico intermitente, náuseas y pérdida de peso involuntaria de 8 kg. Refiere episodios ocasionales de vómitos biliosos, sin haber notado sangre en los vómitos ni en las heces. Ha estado tomando antiácidos sin mucho alivio. En la exploración física se aprecia abdomen blando, con dolor a la palpación profunda en el epigastrio, sin masas palpables ni signos de peritonitis. Los análisis muestran anemia microcítica e hipocrómica y ferropenia. En la gastroscopia lesión ulcerada en la segunda porción del duodeno, que se biopsia. El informe histológico confirma la presencia de adenocarcinoma duodenal. Una TC abdominal muestra la lesión limitada al duodeno, sin evidencia de diseminación a ganglios linfáticos o metástasis a distancia. ¿Cuál es el siguiente paso más adecuado en el manejo de esta paciente?', 'Observación y seguimiento periódico con endoscopia digestiva alta debido a la localización del tumor.', 'Quimioterapia neoadyuvante seguida de una nueva evaluación para posible resección quirúrgica.', 'Duodenopancreatectomía cefálica (procedimiento de Whipple) como tratamiento de elección.', 'Radioterapia dirigida al duodeno para controlar la enfermedad local antes de considerar la cirugía. Página: 1', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 125, 'Sin clasificar', 'Mujer de 60 años que tras un esfuerzo refiere la aparición de una tumoración en la zona inguinocrural derecha no reductible y muy dolorosa. Acude a urgencias con un cuadro de vómitos con dolor y distensión abdominal. ¿Cuál es el diagnóstico más probable?', 'Hernia inguinal directa.', 'Hernia inguinal indirecta.', 'Hernia obturatriz.', 'Hernia crural.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 126, 'Sin clasificar', 'Hombre de 77 años que acude a urgencias por prurito, ictericia y síndrome tóxico de un mes de evolución. Refiere ingesta de amoxicilinaclavulánico desde hace 10 días por un resfriado. A su llegada se realiza una ecografía que se informa de dilatación de la vía biliar intra y extrahepática con vesícula biliar distendida. ¿Cuál es la sospecha diagnóstica y la actitud a seguir?:', 'Colecistitis aguda e indicación de colecistectomía urgente.', 'Coledocolitiasis distal y solicitud de colangiorresonancia magnética.', 'Toxicidad por fármacos y suspensión de la medicación.', 'Tumoración maligna obstructiva de colédoco distal y solicitar TC abdominal.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 127, 'Sin clasificar', 'La forma más eficaz de evaluación preoperatoria de la función del cuerpo esofágico y del esfínter esofágico inferior en un paciente con sospecha de reflujo gastroesofágico es:', 'La monitorización ambulatoria del pH y la impedancia.', 'Manometría esofágica.', 'Esofagoduodenoscopia.', 'Esofagograma con bario.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 128, 'Sin clasificar', 'Mujer de 34 años con diagnóstico de púrpura trombocitopénica idiopática (PTI) refractaria al tratamiento médico remitida para evaluación quirúrgica. A pesar del tratamiento con corticosteroides y otros inmunosupresores, sus recuentos plaquetarios han permanecido bajos, con episodios recurrentes de sangrado leve. Se decide realizar una esplenectomía laparoscópica como siguiente paso terapéutico. En relación con la planificación y manejo de la esplenectomía laparoscópica, ¿cuál de las siguientes estrategias es la más adecuada?:', 'La ligadura temprana de la arteria esplénica es crucial para reducir el riesgo de sangrado intraoperatorio y debe realizarse antes de movilizar el bazo en todos los casos.', 'La preservación del polo inferior del bazo es recomendable en pacientes con PTI para mantener una función inmunológica parcial.', 'El abordaje lateral izquierdo es la única opción en esplenectomías laparoscópicas y debe emplearse independientemente del tamaño del bazo.', 'La vacunación preoperatoria contra neumococo, meningococo y Haemophilus influenzae es esencial para reducir el riesgo de infección postesplenectomía y debe completarse al menos dos semanas antes de la cirugía, siempre que sea posible.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 129, 'Sin clasificar', '¿Cuál de las siguientes medidas aconsejadas para reducir la infección de la herida quirúrgica es INCORRECTA?:', 'En caso de ser necesario eliminar el vello, está indicado rasurarlo con cortadora eléctrica o con cuchilla.', 'Es recomendable mantener la temperatura corporal del paciente >35,5ºC.', 'Es recomendable mantener la glucemia en cifras <180 mg/dL.', 'El intervalo de inicio de la infusión del antibiótico hasta la realización de la incisión debe ser menor de 60 minutos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 130, 'Sin clasificar', 'En un paciente diagnosticado de fracaso renal agudo, el tratamiento con hemodiálisis está indicado en todas las siguientes situaciones clínicas, EXCEPTO en una:', 'Acidosis metabólica que no responde a tratamiento con bicarbonato.', 'Sobrecarga de volumen con edema agudo de pulmón.', 'Hiperpotasemia refractaria a tratamiento médico.', 'Proteinuria de 1 gramo en la orina de 24 horas. Página: 2', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 131, 'Sin clasificar', 'Mujer de 54 años diagnosticada de diabetes mellitus tipo 2 hace tres años en tratamiento con metformina y lisinopril con buen control metabólico. Es enviada a consulta de Nefrología por creatinina sérica de 1,7 mg/dL, filtrado glomerular estimado de 49 mL/min/1,73m2 y cociente albumina/creatinina en orina de 250 mg/g. En los siguientes meses se confirma estabilidad de la función renal, las cifras de presión arterial se mantienen alrededor de 125/70 mmHg, en la ecografía se observan riñones de tamaño y morfología normal y en el estudio de fondo de ojo se objetiva una retinopatía diabética grado 2. ¿Cuál de las siguientes es la actitud a seguir?:', 'No hacer modificaciones en el tratamiento dada la estabilidad y buen control de su enfermedad.', 'Añadir un antagonista del receptor de la angiotensina II para lograr un mejor control de la presión arterial y disminuir la albuminuria.', 'Indicar la realización de una biopsia renal para confirmar la existencia de una enfermedad renal diabética.', 'Iniciar tratamiento con un inhibidor del cotransportador de sodio-glucosa tipo 2 que promueve la excreción urinaria de glucosa y tiene un efecto nefroprotector.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 132, 'Sin clasificar', 'El síndrome de secreción inadecuada de hormona antidiurética (SIADH), se caracteriza por:', 'Hiponatremia con osmolalidad sérica baja y osmolalidad urinaria elevada.', 'Hiponatremia hipovolémica con concentración urinaria de sodio y osmolalidad en orina elevadas.', 'Su tratamiento se basa en la restricción hídrica y la administración de fármacos agonistas del receptor de vasopresina.', 'En la mayoría de los casos se asocia con la administración de fármacos, especialmente antibióticos e inmunosupresores.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 133, 'Sin clasificar', 'Hombre de 37 años que se deriva a consulta de Nefrología para estudio de hematuria microscópica persistente. La exploración es normal salvo por presión arterial 160/100 mmHg. Hemograma sin alteraciones, urea 25 mg/dL, creatinina 0,8 mg/dL, Na 139 mEq/L, K 4,5 mEq/L, perfil hepático y lipídico normales, no hipoalbuminemia ni hipoproteinemia; estudio de autoinmunidad normal, complemento, inmunoglubulinas y proteinograma normales; serología vírica negativa; proteinuria de 0,75 g/24h; sedimento urinario con 30 eritrocitos por campo, 90% dismórficos, no leucocituria. Se realiza biopsia renal que muestra depósitos mesangiales de IgA, IgG y C3 con hipercelularidad mesangial (M1) y glomeruloesclerosis segmentaria (S1) pero sin proliferación endocapilar (E0) ni fibrosis túbulo-intersticial (T0) ni presencia de semilunas. ¿En este momento, cuál de entre los siguientes es el tratamiento más recomendado?:', 'Monoterapia con corticoides a 0,5 mg/kg/día con pauta descendente en 3 meses.', 'Control de la presión arterial y la proteinuria (añadir un antagonista de los receptores de angiotensina II).', 'Rituximab como primera opción y, si no hay respuesta, administrar ciclofosfamida.', 'Corticoides a altas dosis junto con ciclofosfamida como tratamiento de inducción.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 134, 'Sin clasificar', 'Hombre de 65 años que presenta un episodio de infección respiratoria y es tratado con amoxicilina/clavulánico. Una semana después comienza con fiebre y aparición de rash cutáneo por lo que acude a Urgencias. En la analítica se objetiva deterioro de función renal con creatinina sérica 3,2 mg/dL (previa 1,2 mg/dL), eosinofilia y presencia de proteinuria y microhematuria en el sistemático de orina. Indique cuál de estas actitudes es la más correcta:', 'Es necesario realizar una biopsia cutánea para establecer el diagnóstico.', 'Hay que aumentar la dosis de antibiótico pues probablemente se trate de una nefropatía tubulointersticial aguda de etiología infecciosa.', 'Se debe suspender el antibiótico y plantear tratamiento con esteroides si la función renal no mejora en 2-3 días.', 'Hay que iniciar tratamiento con bolus de esteroides a dosis altas y realizar una biopsia renal. Página: 2', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 135, 'Sin clasificar', 'Hombre de 72 años, remitido a consulta tras un hallazgo en una TC solicitada para el estudio de molestias digestivas inespecíficas. Se objetiva una lesión sólida, exofítica, heterogénea, con realce intenso tras la administración de contraste, de 4,9 cm de diámetro, dependiente del polo inferior renal derecho; en el riñón izquierdo litiasis piélica de 3 cm que condiciona hidronefrosis y atrofia cortical. Antecedentes personales de hipertensión, sobrepeso (mide 1,6 m y pesa 95 kg) y fumador habitual. En la analítica destaca creatinina sérica de 1,5 mg/dL. Señale de entre las siguientes opciones de tratamiento la que considera más adecuada:', 'Nefrectomía bilateral, con suprarrenalectomía derecha y linfadenectomía retroperitoneal.', 'Nefrectomía parcial derecha.', 'Biopsia percutánea. Quimioterapia neoadyuvante y nefrectomía radical derecha.', 'Nefrectomía radical derecha. Inmunoterapia adyuvante.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 136, 'Sin clasificar', 'Hombre de 53 años acude a urgencias por anuria de 48 horas de evolución. Presenta dolor abdominal difuso de varios días de evolución que no se modifica con la posición ni con la ingesta. No ha presentado fiebre pero sí náuseas con dos vómitos escasos biliosos sin productos patológicos, además de estreñimiento. En la analítica sanguínea presenta ligera leucocitosis con desviación izquierda, creatinina 7 mg/dL con FG<15mL/min, sodio 132 mmol/L y potasio 5,7 mmol/L, bilirrubina 1 mg/dL, amilasa 100 U/L, AST 30 U/L, ALT 45 U/L, fosfatasa alcalina 60 U/L, y GGT 70 U/L. En el sedimento de orina únicamente se evidencian 5-10 hematíes/campo y leve piuria. En la ecografía abdominal dilatación pielocalicial y ureteral moderada-severa bilateral con leve disminución del parénquima en el riñón izquierdo y múltiples imágenes hiperecoicas con sombra acústica posterior en todos los grupos caliciales así como en el uréter proximal izquierdo. ¿Cuál es la actitud más correcta a seguir?:', 'Analgesia iv y sueroterapia intensiva para forzar diuresis.', 'Diuréticos intravenosos.', 'Derivación de la vía urinaria de forma bilateral.', 'Solicitar TC ante la sospecha de abdomen agudo.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 137, 'Sin clasificar', 'Hombre de 28 años que consulta por haberse despertado por dolor en la región genital y tumefacción en el pene. No recuerda con detalle lo sucedido en las últimas 12 horas. En las últimas 48 h ha consumido alto volumen de alcohol, varias drogas (mefedrona, cocaína, anfetamina), junto con sildenafilo y se ha autoinyectado en el pene 20 µg de alprostadil. A la exploración destaca, pene flácido, glande no visible en su totalidad por edema y hematoma expansivo de partes blandas. Presenta restos hemáticos en el meato uretral. ¿Cuál de las siguientes opciones NO formaría parte de su plan terapéutico?:', 'Gasometría obtenida mediante punción del cuerpo cavernoso.', 'Revisión quirúrgica urgente.', 'Evitar el sondaje vesical.', 'Ecografía de pene.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 138, 'Sin clasificar', 'Hombre de 51 años que consulta preocupado por la aparición de leve goteo postmiccional. Tiene dislipemia, hipertensión arterial y alopecia androgénica incipiente. Sigue tratamiento con simvastatina, enalapril, minoxidil y dutasteride. Padre y hermano fallecidos por cáncer de próstata. En los reconocimientos de salud laboral realizados en 2.021 y 2.023 se observa PSA de 0,3 y de 3,8 ng/mL respectivamente (valores de referencia <4 ng/mL). Una RMN prostática multiparamétrica muestra una próstata de 55 mL y en secuencia T2 un nódulo hipointenso moderado y homogéneo de 1,7 cm, con restricción de la difusión y realce precoz en perfusión en el límite entre el estroma fibromuscular anterior y la zona transicional del lóbulo izquierdo prostático. Repetimos una nueva determinación de PSA 3,5 ng/mL. A la vista de estos hallazgos, ¿qué recomendación propondría al paciente como la más adecuada?:', 'Biopsia prostática transrectal sistemática.', 'Iniciar un tratamiento antibiótico empírico durante 10 días y realizar una biopsia prostática sistemática al finalizar.', 'Tranquilizar al paciente, ofrecer tratamiento sintomático alfa-bloqueante y seguimiento.', 'Biopsia prostática transperineal sistemática y dirigida mediante fusión de imágenes RMN.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 139, 'Sin clasificar', '¿Cuál de estas afirmaciones es cierta sobre los subtipos moleculares de cáncer de mama?:', 'El cáncer de mama triple negativo es el subtipo más frecuente.', 'El cáncer de mama HER2+ es el subtipo menos agresivo.', 'El cáncer de mama luminal A es el subtipo más raro.', 'El cáncer de mama triple negativo es el subtipo más agresivo. Página: 2', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 140, 'Sin clasificar', 'Mujer de 60 años con diagnóstico reciente de cáncer de mama metastásico con alta carga tumoral. Acude a Urgencias 48 horas después de haber recibido el primer ciclo de tratamiento, con cuadro de náuseas, vómitos, diarrea, dolor abdominal, astenia intensa y letargia. En la analítica sanguínea presenta alteración de la función renal. ¿Cuál de las siguientes alteraciones analíticas esperaría encontrar también?:', 'Hipouricemia.', 'Hiperpotasemia.', 'Hipofosfatemia.', 'Hipercalcemia.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 141, 'Sin clasificar', '¿A cuál de las siguientes proteínas presentes en la superficie celular se une el fármaco pembrolizumab?:', 'PD-1.', 'PD-L1.', 'CTLA-4.', 'HER2.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 142, 'Sin clasificar', '¿Cuál de estos pacientes en tratamiento con quimioterapia cumple criterios de neutropenia febril?:', 'Mujer de 38 años intervenida de cáncer de mama en curso de quimioterapia adyuvante que acude a urgencias por temperatura de 38,5ºC, odinofagia, rinorrea y buen estado general. Neutrófilos 400/mm3.', 'Mujer de 68 años intervenida de cáncer de colon estadio IV en curso de quimioterapia de primera línea que acude a urgencias por temperatura de 37,8ºC, diarrea y mucositis grado 2. Hemodinamicamente estable. Neutrófilos 300/mm3.', 'Hombre de 50 años intervenido de adenocarcinoma gástrico en curso de quimioterapia adyuvante que acude a urgencias por escalofríos y temperatura de 37,5ºC sin otra sintomatología acompañante. Neutrófilos 600/mm3.', 'Hombre de 65 años afecto de adenocarcinoma gástrico metastásico en curso de quimioterapia de segunda línea con ECOG 1 que acude a urgencias por temperatura de 38,6 ºC y diarrea grado 1. Neutrófilos 700/mm3.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 143, 'Sin clasificar', 'En un paciente con cáncer colorrectal metastásico irresecable RAS nativo y con pérdida de expresión de proteínas reparadoras del ADN (MSI-H). ¿Cuál debe ser el tratamiento de elección de primera línea?:', 'Quimioterapia + Anti-EGFR.', 'Inmunoterapia.', 'Quimioterapia.', 'Quimioterapia + Anti-VEGFR.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 144, 'Sin clasificar', 'Hombre de 48 años, exfumador hasta el 2.020, con antecedente de nefrectomía parcial izquierda en el 2.020 por carcinoma de células renales, tipo célula clara, grado 2/4, pT1b, que acude por autopalparse una adenopatía laterocervical alta hace 4 meses. En la ecografía de cuello se identifican 2 lesiones nodulares submaxilares y en el TC de cuello se informa de una lesión nodular de partes blandas derecha que corresponde probablemente a una adenopatía sospechosa. Se indica biopsia de la lesión donde se observa una proliferación neoplásica constituida por células con marcada atipia citológica que se disponen con un patrón de crecimiento difuso. El estudio inmunohistoquímico es positivo para CD20, y negativo para CD3, CD30, CD15 y CKAE1-AE3. En estos casos se completa el estudio con CD10, Bcl6 y MUM1 para indicar el fenotipo de la neoplasia. ¿Cuál es el diagnóstico anatomopatológico?:', 'Linfoma Hodgkin variante clásica.', 'Linfoma B difuso de célula grande.', 'Linfoma T periférico.', 'Metástasis de carcinoma.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 145, 'Sin clasificar', 'Hombre de 17 años con hemofilia A grave e inhibidor de alto título frente al FVIII que presenta sangrado agudo a nivel articular. ¿Cuál de los siguientes tratamientos es el más indicado para controlar la hemorragia?', 'Desmopresina.', 'Emicizumab.', 'Ácido tranexámico.', 'Factor VII activado recombinante.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 146, 'Sin clasificar', 'Hombre de 76 años que es intervenido por recambio protésico de cadera derecha tras traumatismo. Entre los antecedentes personales destaca hipertensión arterial en tratamiento fármacológico y recambio protésico de rodilla izquierda hace 3 meses por artrosis evolucionada. Al cuarto día del postoperatorio se detecta trombopenia de 52.000/mm3 con cifras de hemoglobina y leucocitos normales. El estudio de coagulación y la bioquímica es normal. ¿Cuál es el diagnóstico más probable?:', 'Púrpura trombótica trombocitopénica.', 'Coagulación intravascular diseminada.', 'Trombopenia inducida por heparina.', 'Síndrome hemolítico urémico.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 147, 'Sin clasificar', 'Los siguientes tipos de linfoma pueden ser originados por virus. ¿Cuál de ellos es producido por el virus herpes humano tipo 8 (KSHV/HHV8)?', 'Leucemia-linfoma T del adulto.', 'Linfoma primario de cavidades.', 'Linfoma de Burkitt.', 'Granulomatosis linfomatoide. Página: 2', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 148, 'Sin clasificar', 'Mujer de 50 años diagnosticada de síndrome mielodisplásico con monosomía del cromosoma 7 (45 XX -7 [20]) es sometida a un trasplante hematopoyético alogénico con sangre de cordón umbilical de un hombre compatible procedente de un banco de otro país. A los tres meses del trasplante con recuperación completa de las cifras hematológicas periféricas se realiza una punción de médula ósea, que no presenta alteraciones morfológicas y un estudio cromosómico con un cariotipo 47 XXY [20]. ¿Cuál es la explicación de estos hallazgos?:', 'El donante tiene un síndrome de Klinefelter no diagnosticado.', 'En la médula ósea coexisten células del donante y del receptor (quimerismo mixto).', 'Tras el trasplante ha existido un fenómeno de fusión celular entre las células del donante y receptor que ha originado el nuevo cariotipo.', 'En el cariotipo realizado precozmente tras un trasplante hematopoyético es habitual encontrar alteraciones cromosómicas transitorias de este tipo que carecen de significación clínica.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 149, 'Sin clasificar', 'Mujer de 90 años sin alergias medicamentosas conocidas, con HTA y gonalgia nocturna por gonartrosis derecha de intensidad leve-moderada de tres meses de evolución. Refiere que no toma ninguna medicación y se confirma que realiza las medidas higiénicas del sueño correctamente. Consulta a su médico de atención primaria por insomnio de conciliación y mantenimiento que le interfiere con sus actividades diarias. ¿Qué fármaco es más adecuado iniciar en este caso?:', 'Paracetamol.', 'Diazepam.', 'Mirtazapina.', 'Trazodona.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 150, 'Sin clasificar', 'En los pacientes mayores con síndrome de inmovilidad una de las siguientes manifestaciones clínicas o consecuencias NO es atribuible al mismo:', 'Déficit intelectual.', 'Aumento de la frecuencia cardíaca.', 'Reducción de la sensibilidad a la insulina.', 'Balance nitrogenado positivo.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 151, 'Sin clasificar', 'Hombre de 85 años diagnosticado de enfermedad de Alzheimer en tratamiento con donepezilo. Desde hace una semana y coincidiendo con una infección urinaria por germen sensible a amoxicilina/clavulánico, presenta un trastorno grave de conducta; por todo ello, recibe tratamiento con dicho antibiótico y con risperidona 1 mg cada 12 horas. Hoy la familia lo trae a su consulta porque a pesar de mejorar la infección de orina, está muy enlentecido, necesitando ayuda para comer y vestirse, no es capaz de deambular sin ayuda, duerme de día y presenta insomnio de madrugada. Ante esta situación clínica señale la respuesta CORRECTA:', 'Probablemente se trata de un efecto secundario de la risperidona, por lo que se debe retirar.', 'Se debe tratar el insomnio de madrugada añadiendo benzodiacepinas.', 'Hay que esperar a que se resuelva totalmente la infección urinaria para cambiar la medicación actual.', 'Ha empeorado la demencia y se debe añadir memantina al tratamiento de base con donepezilo.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 152, 'Sin clasificar', 'Los criterios STOPP/START tienen el objetivo de optimizar la medicación y minimizar las reacciones adversas a los medicamentos durante la revisión de la medicación en adultos mayores. En cuanto a los criterios START (versión 3, última versión), ¿cuál deberíamos valorar indicar?:', 'Estrógenos tópicos vaginales en la vaginitis atrófica sintomática.', 'Vacuna antitetánica ante una herida abierta.', 'Parche de lidocaína tópica para el dolor articular generalizado.', 'Corticoesteroides inhalados en el EPOC estadio GOLD 1-2.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 153, 'Sin clasificar', 'En la actualidad se definen varios estadios o etapas de la diabetes tipo 1 autoinmune. Señale cuál es la definición CORRECTA:', 'El estadio o etapa 3 se caracteriza por la autoinmunidad y tolerancia alterada de la glucosa (ya sea basal o tras test de sobrecarga con glucosa oral).', 'El estadio o etapa 1 se caracteriza por presencia única de autoinmunidad contra las células de los islotes sin aparición de alteraciones de la glucosa.', 'El estadio o etapa 2 se caracteriza por hiperglucemia con cifras que definen diabetes.', 'La luna de miel aparece en el estadio 2, con la hiperglucemia. Página: 2', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 154, 'Sin clasificar', 'Mujer que acude a consulta de endocrino por secreción láctea por el pezón y una cifra de prolactina en sangre de 45 µg/L (normal <20 µg/L). ¿Cuál es la actitud diagnóstica más apropiada?:', 'La primera medida a realizar es una resonancia cerebral porque lo más probable es que sea un macroadenoma secretor de prolactina.', 'Se debe interrogar sobre la toma de fármacos antagonistas del receptor de dopamina o un posible embarazo.', 'Las pruebas de laboratorio para su correcta caracterización consisten en la medición aislada de prolactina.', 'Se debe descartar un hipertiroidismo primario.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 155, 'Sin clasificar', 'La estrategia de cribado de diabetes gestacional en un solo paso consiste en:', 'Test de sobrecarga oral de glucosa con 50 gr de glucosa.', 'Test de sobrecarga oral de glucosa con 75 gr de glucosa.', 'Test de sobrecarga oral de glucosa con 90 gr de glucosa.', 'Test de sobrecarga oral de glucosa con 100 gr de glucosa.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 156, 'Sin clasificar', 'Está de guardia en urgencias y valora a un hombre de 45 años que consulta por vómitos de 2-3 días de evolución con disconfort abdominal y astenia intensa desde hace 1 mes. La presión arterial en triaje es 85/40 mmHg. Cuando lo explora objetiva hiperpigmentación parcheada en la cavidad oral y en la analítica destaca sodio de 134 mEq/L. ¿Cuál es su primera opción diagnóstica de las expuestas a continuación?:', 'Hemocromatosis.', 'Síndrome de Peutz Jeghers.', 'Enfermedad de Addison.', 'Síndrome Stevens-Johnson.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 157, 'Sin clasificar', '¿Qué fármaco de los mencionados a continuación ha de tenerse en cuenta cuando se evalúa a un paciente con hiperparatiroidismo?:', 'Hidroclorotiazida.', 'Losartán.', 'Amlodipino.', 'Doxazosina.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 158, 'Sin clasificar', '¿Cuál de las siguientes causas de hipertiroidismo puede cursar con TSH normal o elevada?:', 'Tirotoxicosis facticia.', 'Struma ovarii.', 'Adenoma hipofisario productor de TSH.', 'Hipertiroidismo por beta-HCG durante la gestación.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 159, 'Sin clasificar', 'Hombre de 58 años, fumador de 30 cigarrillos diarios desde los 19 años, con antecedentes de hipertensión arterial mal controlada, diabetes mellitus tipo 2 y obesidad grado I. En estudio por disnea de 5 meses de evolución, asociando pérdida de peso, astenia e hiporexia. Como parte del estudio se realiza TC toracoabdominal describiéndose la presencia de un nódulo pulmonar inespecífico de 1,1 cm en lóbulo superior derecho sin datos de malignidad y un nódulo en la glándula suprarrenal derecha de 1,9 cm. ¿Qué pruebas complementarias habría que solicitar para el estudio del incidentaloma suprarrenal?:', 'Test de supresión con 8 mg de dexametasona (DXM) nocturno, metanefrinas libres plasmáticas y resonancia magnética centrada en suprarrenales.', 'Metanefrinas fraccionadas en orina de 24 horas, test de supresión con 1 mg DXM nocturno, ratio renina/aldosterona y PET-TC con 18FDG.', 'Metanefrinas fraccionadas en orina de 24 horas, test de supresión con 1 mg DXM nocturno, ratio aldosterona/renina y TC centrada en adrenales.', 'Cortisol libre urinario, metanefrinas fraccionadas en muestra aislada de orina, ratio aldosterona/renina y resonancia magnética centrada en suprarrenales.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 160, 'Sin clasificar', 'Mujer de 25 años, sin enfermedades previas conocidas, que consulta por lesión en labio inferior. No es la primera vez que le sucede desde la adolescencia, siempre en la misma zona, inicia dolor y aparece una lesión vesiculosa que se autolimita en una semana aproximadamente. Respecto al abordaje de la enfermedad de esta paciente, es INCORRECTO que:', 'Si presenta más de tres episodios anuales está indicado realizar profilaxis con un antiviral como valaciclovir 500 mg cada 12 horas o 1 g al día, durante seis meses.', 'Si es una única lesión y es un cuadro leve puede no realizarse ningún tratamiento o bien realizar tratamiento tópico con fomentos de sulfato de zinc o de cobre.', 'Si existe riesgo de afectación oftálmica estaría indicado tratar con un antivírico como valaciclovir a razón de 1 g cada 8 horas durante 7 días vía oral.', 'Es necesario recomendarle una adecuada protección solar pues la exposición solar puede motivar recurrencias. Página: 2', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 161, 'Sin clasificar', 'Hombre de 50 años que presenta una erupción generalizada especialmente en el tronco. Refiere malestar general desde hace pocos días. Hoy acude porque ha tenido fiebre la noche anterior y se ha visto una mancha negra en la zona abdominal. A la exploración física, la mancha negra corresponde a una pequeña escara. El paciente es cazador y acudió recientemente a una batida. Sobre el abordaje del caso es cierto que:', 'Es una enfermedad de declaración obligatoria.', 'El tratamiento de elección es la amoxicilina, un gramo cada 8 horas durante 7 días.', 'Debe derivarse a un centro hospitalario.', 'En la mayoría de los casos, la fiebre precede al exantema y la escara.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 162, 'Sin clasificar', 'Respecto al tratamiento de la foliculitis, es correcto que:', 'El tratamiento de elección incluso en formas localizadas es la cloxacilina vía oral.', 'En caso de alergia a la penicilina, la opción más adecuada sería el ciprofloxacino oral.', 'Debe realizarse tratamiento oral en pacientes con valvulopatía reumática por el riesgo de endocarditis.', 'Es una infección fundamentalmente estreptocócica por Streptococcus pyogenes.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 163, 'Sin clasificar', 'Hombre de 62 años con antecedentes de hipertensión arterial, diabetes mellitus tipo 2 y en tratamiento con infliximab por artritis reumatoide, se presenta en urgencias con fiebre, tos seca, mialgias y disnea leve de 5 días de evolución. A la exploración física, la saturación de oxígeno es del 90% con aire ambiente. Se realiza una radiografía de tórax que muestra opacidades en vidrio deslustrado bilaterales. La PCR en frotis nasofaríngeo para SARS-CoV-2 resulta positiva. ¿Cuál de las siguientes opciones es la conducta más apropiada?:', 'Administrar plasma de convaleciente y anticoagulación profiláctica.', 'Iniciar tratamiento con antibióticos de amplio espectro y corticoides a dosis altas.', 'Monitorización ambulatoria con seguimiento telefónico y tratamiento sintomático.', 'Ingreso hospitalario para tratamiento con remdesivir y dexametasona.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 164, 'Sin clasificar', 'Hombre de 56 años, nacido en Paraguay, acude a consulta, remitido por su médico de familia, por disnea progresiva y palpitaciones. Tiene un ECG en el que se observa extrasístoles ventriculares y bloqueo completo de rama derecha. Aporta una serología por ELISA IgG positiva frente a Trypanosoma cruzy. ¿Cuál de las siguientes respuestas es INCORRECTA?:', 'Se debe realizar una prueba serológica con inmunofluorescencia para detectar IgG frente a T. cruzy.', 'La prueba de reacción en cadena de la polimerasa (PCR) tiene un valor diagnóstico limitado en esta fase de la enfermedad.', 'Debe iniciar tratamiento con benznidazol para modificar la evolución de la enfermedad.', 'Si se confirma el diagnóstico, debe estudiar a los familiares cercanos para identificar otros casos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 165, 'Sin clasificar', 'Una mujer de 45 años con antecedentes de pleuritis hace 3 años y episodios ocasionales de poliartritis en los últimos 8 meses, fue diagnosticada de LES hace un mes tras un ingreso por fatiga y dolor torácico opresivo de esfuerzo, donde se objetivó una Hb de 5,8 g/dL y VCM de 109 fL por una anemia hemolítica autoinmune. El resto de la analítica mostró una linfopenia de 900/mm3, plaquetas en rango de normalidad, función hepática, creatinina y ionograma normales, tiempo de protrombina 85%, TTPA se muestra prolongado (ratio de 1,8). Existe hipocomplementemia C3 y C4, ANA 1/640, con Anti-DNA +. Fue dada de alta con corticoides, hidroxicloroquina y belimumab semanal subcutáneo. A las tres semanas del alta refiere sensación disneica de 48 horas de evolución sin otros síntomas acompañantes, la Hb de urgencias es de 10,2 gr/dL. ¿Cuál de las siguientes determinaciones de laboratorio deberíamos realizar en primer lugar?:', 'Dímero D.', 'Proteínas en orina.', 'NT-proBNP.', 'Test de Coombs. Página: 2', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 166, 'Sin clasificar', 'Mujer de 72 años, procedente del medio rural que acude al servicio de urgencias por un cuadro de dolor abdominal, vómitos y diarrea líquida, que posteriormente se hace sanguinolenta, de 6 días de duración. No refiere fiebre ni tratamiento antibiótico previo. Se toman muestras para hemocultivo y estudio microbiológico de las heces y se inicia tratamiento con fluidoterapia intensiva. 48 horas después se observa disminución del nivel de conciencia y la presencia de anemia (hematocrito de 25%, hemoglobina de 7,9 g/dL), trombopenia (plaquetas de 60.000/mL), creatinina de 3,2 mg/dL, hematuria y hemoglobinuria. En el estudio de sangre periférica se aprecian abundantes esquistocitos circulantes (más del 10%). Señale la respuesta INCORRECTA:', 'Debe tratar de identificar infección por E. coli, serotipo 0157:H7 y detección por PCR de toxina Shiga (Stx1 y/o Stx2) y genes relacionados.', 'Debe iniciar tratamiento antibiótico.', 'El cuadro clínico y analítico descarta la posibilidad de infección por Clostridium diffícile.', 'La plasmaféresis no es útil en esta paciente.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 167, 'Sin clasificar', 'Mujer de 54 años de edad que acude a su consulta para estudio y evaluación del riesgo vascular. Entre sus antecedentes más relevantes, destacan un infarto agudo de miocardio a los 51 y a los 53 años de edad, hipertensión arterial controlada y un perfil lipídico con tratamiento hipolipemiante de alta intensidad de: colesterol total 120 mg/dL, cHDL 60 mg/dL cLDL 50 mg/dL, TG 128 mg/dL. HB1AC de 5.2% y glucemia plasmática en ayunas normal. Nunca ha fumado. Índice de masa corporal de 23 Kg/m2. De las siguientes pruebas o determinaciones que se exponen a continuación, ¿qué es más útil para determinar el riesgo y la etiología de eventos recurrentes en esta paciente?:', 'Determinación de ApoB.', 'Determinación de ApoA.', 'Determinación de Lp(a) o lipoproteína a.', 'Determinación de proteína C reactiva.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 168, 'Sin clasificar', 'Mujer de 28 años sin enfermedades previas, recién llegada de los Estados Unidos de América, donde ha estado practicando espeleología en el valle del Ohio durante un par de semanas, presenta clínica de infección respiratoria consistente en tos, fiebre, sensación disneica y artralgias, lesiones cutáneas nodulares y dolorosas, eritematosas y calientes en la zona pretibial. ¿En qué enfermedad hay que pensar?', 'Aspergilosis pulmonar.', 'Esporotricosis.', 'Criptococosis pulmonar.', 'Histoplasmosis.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 169, 'Sin clasificar', 'Hombre de 53 años, sin antecedentes patológicos, acude al hospital por fiebre de 10 días de evolución, con intensa cefalea retroorbitaria y una importante sensación de fatiga. No refiere dolor musculoesquelético, lesiones cutáneas ni ningún otro síntoma acompañante. A lo largo de 15 días de ingreso se objetiva fiebre persistente y la aparición de discreta ictericia conjuntival. La exploración respiratoria, cardíaca, abdominal y neurológica es normal. La analítica muestra VSG 97 mm/h, PCR 24,5 mg/dL, GOT 156 U/L, GPT 148 U/L, FA 410 U/L, GGT 794 U/L, bilirrubina total 5,5 mg/dL a expensas de la bilirrubina directa, hemoglobina 11,5 g/dL, recuento leucocitario normal, plaquetas 648.000/mm3, función renal e ionograma normales, tiempo de protrombina normal pero TTPA ratio 1,8. Los anticuerpos antinucleares (ANA) son positivos a títulos 1/160. Una ecografía abdominal no muestra ninguna alteración destacable. Desde el punto de vista clínico y a la vista de los datos analíticos, ¿cuál de las siguientes enfermedades es la que se ajusta mejor con nuestro paciente?:', 'COVID-19.', 'Fiebre Q aguda.', 'Leptospirosis grave (enfermedad de Weil).', 'Colangitis esclerosante primaria.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 170, 'Sin clasificar', 'Hombre de 38 años con dependencia alcohólica grave. Ha tenido varios ingresos por pancreatitis aguda en el contexto de ingesta de alcohol e hipertrigliceridemia grave. Acude a consulta 12 meses después del último episodio de pancreatitis. No presenta clínica que sugiera insuficiencia pancreática exocrina. Niega reiteradamente ingesta de alcohol. Sigue tratamiento con estatinas y fibratos que asegura tomárselos. Aporta un análisis básico reciente de su empresa con los siguientes datos: colesterol 300 mg/dL, cHDL 42 mg/dL, TG 1102 mg/dL, cLDL no calculable por Friedewald. Colesterol no-HDL 258 mg/dL, ApoB 90 mg/dL, Lp(a) 38 nmol/L (normal <125 nmol/L). En dicho análisis hay un dato, además de la hipertrigliceridemia, que sugiere que el paciente continúa ingiriendo alcohol. Señálelo.', 'ApoB.', 'cHDL.', 'Lp(a).', 'Colesterol total. Página: 2', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 171, 'Sin clasificar', 'Respecto a las infecciones de las heridas quirúrgicas, señale la respuesta INCORRECTA:', 'Diabetes mellitus, malnutrición, obesidad e inmunosupresión son factores de riesgo del paciente para desarrollar infecciones de las heridas quirúrgicas.', 'El control intensivo perioperatorio de la glucemia es una buena práctica de prevención de las infecciones de herida quirúrgica.', 'La mayoría de las recomendaciones sobre profilaxis antibiótica en cirugía cardíaca aconsejan mantener los antibióticos al menos 48 horas tras el procedimiento quirúrgico.', 'La antibioterapia local se emplea como método de profilaxis antimicrobiana y tratamiento antibiótico, sobre todo en la sustitución de prótesis articulares infectadas.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 172, 'Sin clasificar', 'Hombre de 37 años con infección VIH ha dejado de tomar el tratamiento por razones personales hace 3 meses; estaba tomando una combinación de dos inhibidores de transcriptasa inversa y un inhibidor de la integrasa. En la evaluación llevada a cabo en este momento tiene 120 linfocitos CD4/mm3 y una carga viral de VIH-1 de 80.000 copias/mL. Estamos pendientes del estudio de resistencias. ¿Qué debemos recomendarle en este momento?:', 'Reiniciar el tratamiento con lo mismo con lo que estaba previamente.', 'Esperar a tener el resultado del estudio de resistencias para orientar el tipo de tratamiento en función de las mutaciones identificadas.', 'Prescribir a partir de ahora un régimen basado en inhibidores de proteasa por su mayor barrera genética a las resistencias.', 'Iniciar doble terapia con inhibidores de integrasa.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 173, 'Sin clasificar', 'Hombre de 55 años con antecedentes de cáncer de pulmón (estadio IV). Su madre murió a los 65 años por un episodio de broncoaspiración. Consulta por debilidad muscular en los muslos y disfagia. Exploración física: fuerza en psoas 4+/5, cuádriceps 3/5, deltoides 5/5. Presenta ptosis palpebral bilateral y no tiene diplopía. Los valores de CPK eran 900 UI/L (normal <150 UI/L) y los de aldolasa, 7 UI/L (normal <6 UI/L). Se practicó una biopsia en el músculo vasto lateral externo del muslo derecho, en la cual se objetivó variabilidad en el tamaño de fibras, aumento del tejido conectivo, imágenes de pseudodivisión celular y vacuolas ribeteadas; no se observó infiltrado inflamatorio. ¿Qué es lo más probable que le suceda al paciente?:', 'Distrofia oculofaríngea.', 'Miopatía mitocondrial.', 'Miastenia gravis.', 'Miositis con cuerpos de inclusión.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 174, 'Sin clasificar', 'Mujer de 81 años consulta por cuadro de 1 mes de duración de astenia, febrícula, pérdida de unos 4 kg de peso, cefalea hemicraneal izquierda y dolor en la zona de los hombros y de las caderas, que le dificulta los movimientos después de estar en reposo. Se palpa una zona engrosada y dolorosa en el territorio de la arteria temporal izquierda. Respecto al proceso diagnóstico de esta paciente, señale la opción INCORRECTA:', 'La vasculitis sistémica que se sospecha con mayor probabilidad es una vasculitis de gran vaso.', 'En el análisis, la normalidad de la velocidad de sedimentación globular apoya el diagnóstico de esta vasculitis.', 'Es frecuente observar afectación de la pared arterial de la aorta y sus ramas principales mediante pruebas de imagen.', 'Una biopsia de la arteria temporal que muestre un infiltrado inflamatorio en la pared arterial confirmaría el diagnóstico de arteritis de células gigantes.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 175, 'Sin clasificar', '¿Cuál de las siguientes manifestaciones clínicas es la más característica de la miopatía de la dermatomiositis?:', 'Dificultad para andar.', 'Dificultad para subir escaleras.', 'Dificultad para abrocharse los botones.', 'Dolor muscular.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 176, 'Sin clasificar', 'Mujer de 38 años que consulta por la presencia de dolor ocular, ojo rojo bilateral, hipersensibilidad a la luz y disminución de la agudeza visual. La historia clínica se completa con antecedentes de aftas bucales dolorosas y recidivantes y un diagnóstico previo de eritema nodoso hace 2 años. En la exploración oftalmológica se observa panuveitis bilateral con signos de vasculitis retiniana bilateral. Señale la respuesta correcta sobre el diagnóstico y tratamiento de la enfermedad que sospecha en esta paciente:', 'El hallazgo de HLA B*51 confirma el diagnóstico de sospecha.', 'Las úlceras bucales dejan cicatriz en la mayoría de los casos.', 'Debe instaurar tratamiento precoz e intensivo con glucocorticoides sistémicos e inmunosupresión con azatioprina.', 'La adición al tratamiento de anticuerpos monoclonales anti TNF alfa o ciclosporina no mejora el control de la uveítis. Página: 2', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 177, 'Sin clasificar', 'Mujer de 80 años que ingresa en el hospital para estudio de anemia tras ser llevada por sus hijos a urgencias por rectorragia y decaimiento físico. Clínicamente se encuentra estable. Está diagnosticada de un deterioro cognitivo, con ideación y juicio frecuentemente incoherentes y alteraciones conductuales para lo que toma risperidona. Se sospecha neoplasia maligna de colon y se plantea realizar una colonoscopia. Usted verifica que la paciente es incapaz de entender adecuadamente lo que se le explica sobre tal prueba, su naturaleza, objetivos, posibles complicaciones, o sus consecuencias diagnósticas y eventualmente terapéuticas. En tal caso, ¿cuál de las siguientes respuestas es correcta?:', 'El médico queda eximido de plantear un proceso de consentimiento informado a la paciente, y se considera suficiente su criterio como médico para que se realice la colonoscopia.', 'El médico deberá solicitar la comparecencia del Juez, para que autorice la prueba, ante la incapacidad intelectual de la enferma para decidir convenientemente por sí misma.', 'Por no tener la paciente capacidad para decidir, deben hacerlo por ella sus familiares, debiendo quedar constancia escrita en el impreso de consentimiento informado.', 'Es jurídicamente aceptable un acuerdo entre el médico y los familiares de la enferma basado en un consentimiento informado verbal para que se practique la colonoscopia.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 178, 'Sin clasificar', 'Atiende a una paciente ingresada desde hace tres semanas en la unidad de cuidados intensivos por un cuadro de shock séptico respiratorio. Su evolución durante el ingreso no ha sido favorable y todavía continúa dependiente de ventilación mecánica invasiva. En los últimos días, tras recibir la información de que probablemente precise ventilación mecánica a medio-largo plazo, durante los periodos en que la paciente ha estado despierta, ha manifestado de forma clara su deseo de no continuar utilizando el ventilador. La paciente afirma comprender las consecuencias de esta decisión. Este caso habla de:', 'Rechazo al tratamiento.', 'Limitación del esfuerzo terapéutico o adecuación de medidas de tratamiento.', 'Suicidio asistido.', 'Eutanasia.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 179, 'Sin clasificar', 'Respecto al tratamiento del dolor en cuidados paliativos, indique, de las siguientes afirmaciones, cuál es correcta:', 'En la actualidad existen comercializados diferentes fármacos opioides para el tratamiento del dolor moderado o grave en personas que reciben cuidados paliativos, superando en perfil de efectos adversos y en efectividad a la morfina y relegándola a un papel testimonial.', 'La adicción es un problema creciente en pacientes que precisan morfina en su fase final de vida y es más frecuente cuando se emplean fármacos con efecto de larga duración (metadona o morfina de liberación prolongada).', 'El fentanilo oral transmucoso tiene un perfil de acción que lo hace útil en el dolor crónico no irruptivo y de carácter crónico.', 'La metadona es un fármaco analgésico con escasa excreción renal por lo que es útil en personas con aclaramiento renal disminuido.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 181, 'Sin clasificar', 'En relación con la marca producida por el paso de la corriente eléctrica a través de la piel (también conocida como lesión electroespecífica o “marca de Jellinek”), ¿cuál de las siguientes afirmaciones es cierta?:', 'La mayor parte de las lesiones producidas por la corriente eléctrica en medio doméstico y laboral proceden de fuentes de alto voltaje.', 'Las lesiones dérmicas dependen del efecto de un aumento de la temperatura generado sobre la dermis.', 'La corriente de bajo voltaje produce lesiones profundas, mientras que la de alto voltaje da lugar a lesiones superficiales adyacentes al punto de contacto con la corriente eléctrica.', 'La marca eléctrica es diagnóstica del lugar en el que se ha producido el contacto y, por tanto, el punto de entrada de la corriente en el cuerpo. Página: 2', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 182, 'Sin clasificar', 'Hombre de 85 años con enfermedad de Alzheimer de 6 años de evolución, actualmente en estadio GDS-FAST 7c. Está institucionalizado en centro sociosanitario desde hace 1 año. En los últimos 6 meses tiene frecuentes episodios de broncoaspiración por los que ha acudido a Urgencias y han sido tratados con antibioterapia de amplio espectro con mejoría clínica. Acude nuevamente a urgencias por disnea en relación con nuevo episodio de broncoaspiración y negativa a la ingesta. ¿Cuál debe ser la actitud a seguir?:', 'Evitar ingreso. Indicar sonda nasogástrica (SNG) con el fin de prevenir nuevas broncoaspiraciones y facilitar ingesta. Antibioterapia empírica con amoxicilina-clavulánico por SNG.', 'Ingresar para colocación de gastrostomía (PEG) con el fin de evitar nuevas broncoaspiraciones y facilitar ingesta. Antibioterapia empírica con piperacilina-tazobactam iv.', 'Evitar ingreso. No está indicada la colocación de sonda para nutrición enteral. Considerar adecuación del esfuerzo terapéutico evitando antibioterapia y dando cuidados de confort.', 'Ingresar para antibioterapia empírica con piperacilina-tazobactam, pero evitar la colocación de sonda para nutrición enteral. La curación del proceso infeccioso mejorará casi siempre la ingesta.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 183, 'Sin clasificar', 'La telemonitorización domiciliaria ha demostrado beneficios en pacientes con insuficiencia cardíaca. Una mujer de 82 años con insuficiencia cardíaca y diabetes tratada con insulina está en programa de telemonitorización y remite cada semana una serie de parámetros a su médico de familia. La semana pasada presentaba presión arterial 140/85 mmHg. Glucemia capilar basal 120 mg/dL. Glucemia postprandial 2 h tras la comida 160 mg/dL. Peso 83 kg. Frecuencia cardíaca 72 lpm. Al recibir los parámetros de esta semana que se exponen a continuación, su médico decide citar a la paciente en consulta. ¿Cuál de los siguientes parámetros ha motivado dicha decisión?:', 'Presión arterial 135/82 mmHg.', 'Peso 85 Kg.', 'Glucemia capilar basal 130 mg/dL.', 'Glucemia capilar postprandial 190 mg/dL.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 184, 'Sin clasificar', 'En un paciente con diabetes y obesidad en prevención secundaria cardiovascular, tratado con metformina y iSGLT2, que presenta mal control glucémico, ¿cuál es el fármaco de elección para mejorar dicho control?:', 'Insulina.', 'Análogos del receptor del péptido similar al glucagón tipo 1 (arGLP-1).', 'Sulfonilurea.', 'Repaglinida.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 185, 'Sin clasificar', 'Mujer de 61 años con adenocarcinoma rectal avanzado. Presenta dolor neuropático con irradiación perineal y molestias urinarias en relación con masa presacra. Mejoró con tratamiento con opioides (morfina 60 mg cada 12h) pero no tolera más aumento de dosis ni fármacos adyuvantes. ¿Cuál es el tratamiento de elección?:', 'Bloqueo del plexo celiaco.', 'Bloqueo del ganglio impar.', 'Bloqueo de nervios esplácnicos.', 'Bloqueo del nervio pudendo.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 186, 'Sin clasificar', 'En una guardia de centro de salud avisan para atender a un hombre de 63 años, que ha sido sometido a bajas temperaturas, sin precisar cuánto tiempo ha estado en exposición. A su llegada, tiene una temperatura corporal de 28ºC. ¿Cuál de los siguientes hallazgos NO cabría esperar en este cuadro?:', 'Taquipnea.', 'Fibrilación ventricular.', 'Alucinaciones.', 'Pupilas mióticas.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 187, 'Sin clasificar', 'En cuanto al uso de anticonceptivos en mujeres jóvenes en las consultas de Atención Primaria, es importante tener en cuenta diversos aspectos para la prescripción. ¿Cuál de las siguientes es INCORRECTA?:', 'Se ha de ofrecer consejo contraceptivo estructurado según los criterios de elegibilidad de la Organización Mundial de la Salud (OMS), e información tanto para la prevención de embarazos no planificados, como de enfermedades de transmisión sexual (ETS).', 'Como método anticonceptivo de urgencias, las opciones recomendadas son la toma de levonorgestrel, de acetato de ulipristal o la inserción de un DIU de cobre.', 'Ante la indicación de anticonceptivos orales se recomienda el cribado rutinario de trombofilia y dislipemia y citologías de control anuales.', 'El riesgo de tromboembolia venosa con el consumo de anticonceptivos orales es bajo, siendo el riesgo menor en los de segunda generación, frente al mayor riesgo en los de tercera y cuarta generación.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 188, 'Sin clasificar', '¿Cuál de los siguientes fármacos debería evitarse en un paciente que presenta diabetes y obesidad por ser un fármaco que puede inducir aumento de peso?', 'Metformina.', 'Sitagliptina.', 'Semaglutida.', 'Pioglitazona. Página: 3', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 189, 'Sin clasificar', 'Hombre de 69 años con adenocarcinoma de páncreas avanzado que presenta como principal sintomatología dolor de características mixtas tratado desde hace 3 meses con opioides con buen control (morfina 60 mg cada 12 horas) + adyuvantes (duloxetina 60 mg/día). Asocia astenia e hiporexia graves tratadas con corticoides desde hace 2 semanas (dexametasona 8 mg/día). Acude a consulta refiriendo somnolencia intensa y alucinaciones táctiles. En la analítica presenta como datos más destacables anemia de trastornos crónicos (Hb 10,6 g/dL) y empeoramiento de la función renal (CKD-EPI 26 mL/min). ¿Cuál es el diagnóstico más probable y la actitud a seguir?:', 'Clínica neurológica por metástasis cerebrales. Realizar TC cerebral y aumentar dosis de corticoides.', 'Psicosis inducida por corticoides. Retirar corticoides.', 'Síndrome confusional agudo hipoactivo. Iniciar tratamiento con neurolépticos.', 'Neurotoxicidad por opioides. Reducir la dosis de morfina a la mitad.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 190, 'Sin clasificar', 'Hombre de 36 años sin antecedentes de interés que ingresa en observación de urgencias en espera de intervención quirúrgica por fractura de fémur a nivel diafisario por accidente de tráfico. El paciente llega algo taquicárdico 102 lpm, con gafas nasales para mantener saturación de oxígeno en torno al 96%, 20 respiraciones por minuto y presión arterial 100/60 mmHg. Se procede a ajuste de analgesia y a las 20 horas de estancia en observación indican que el paciente puede ir a quirófano pero presenta un aumento de disnea con saturación del 89% con mascarilla tipo Venturi, 28 respiraciones por minuto, taquicardia a 110 lpm, fiebre de 38ºC y se encuentra algo obnubilado. En la analítica destaca anemia y trombocitopenia. No presenta aumento de volumen en ninguna de las 2 piernas. ¿Qué prueba complementaria tiene mayor sensibilidad y especificidad para la sospecha diagnóstica de este paciente?', 'AngioTC helicoidal con contraste.', 'Gammagrafía pulmonar de perfusión.', 'Radiografía de tórax.', 'Ecocardiografía.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 191, 'Sin clasificar', 'Hombre de 72 años sin alergias medicamentosas, no fumador y con antecedentes de hipertensión, dislipemia y diabetes. En tratamiento con ácido acetilsalicílico, atorvastatina, enalapril y metformina. Acude a urgencias por agudización de lumbalgia crónica de meses de evolución. Refiere que el dolor no es irradiado, y no mejora mucho en reposo. Ha tomado varios analgésicos sin ninguna mejoría. A la exploración no presenta dolor en espinosas dorsolumbares, el signo de Lasegue es negativo, no presenta limitación a la movilidad, reflejos normales y no hay alteración de sensibilidad o fuerza. Pulsos pedios ausentes y tibiales débiles. No edemas de miembros inferiores. Ante la sospecha diagnóstica, ¿qué prueba nos daría el diagnóstico más rápidamente con mayor sensibilidad y especificidad?:', 'Ecografía abdominal.', 'TC toraco-abdominal.', 'Resonancia magnética.', 'Radiografía de columna lumbosacra.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 192, 'Sin clasificar', 'Acude a urgencias un hombre de 34 años, sin diagnósticos previos, con antecedente de consumo de drogas por vía parenteral, con fiebre, tos no productiva y disnea progresiva de varias semanas de evolución. Se realiza radiografía de tórax que muestra infiltrado intersticial bilateral. En analítica sanguínea destaca linfopenia y lactato deshidrogenasa elevada. La saturación de oxígeno es del 88% respirando aire ambiente en reposo. ¿Cuál de las siguientes aseveraciones le parece INCORRECTA?:', 'Iniciaría tratamiento de soporte, oxigenoterapia y ceftriaxona.', 'Iniciaría tratamiento con Trimetropim/sulfametoxazol, corticoides y oxigenoterapia.', 'Solicitaría serología del virus de la inmunodeficiencia humana.', 'Solicitaría estudio microbiológico de esputo.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 193, 'Sin clasificar', 'Hombre de 46 años sufre accidente de tráfico a alta velocidad con varios vuelcos del vehículo y necesidad de extricación por parte del equipo de bomberos. El paciente es trasladado en una UVI móvil al servicio de urgencias más próximo, con inmovilización en colchón de vacío. A su llegada al hospital se encuentra inestable a pesar de sueroterapia intensiva. A la exploración presenta los siguientes signos vitales: frecuencia respiratoria 35 rpm. Saturación de oxígeno 100% con mascarilla reservorio. Frecuencia cardíaca 140 lpm. Presión arterial 60/30 mm Hg. Temperatura 35,5ºC y glucemia 110 mg/dL. De las siguientes, indique la exploración o prueba complementaria clave del árbol de decisión en este paciente:', 'Hemograma y bioquímica.', 'TC abdominal.', 'e-FAST (Extended Focused Abdominal Sonography for Trauma).', 'Punción lavado peritoneal. Página: 3', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 194, 'Sin clasificar', 'En un paciente diagnosticado de una lesión tumoral ósea maligna que ha recibido tratamiento neoadyuvante, se realiza resección de la pieza y posterior biopsia para su análisis anatomopatológico. Indique, de las siguientes, ¿cuál es la información más relevante para el pronóstico del paciente?:', 'Tasa de necrosis en la pieza por efecto de terapia neoadyuvante.', 'Número de células tumorales en fase G0 de no división o interfase.', 'Porcentaje de células gigantes que se encuentran en la lesión.', 'Cantidad de células no estromales que componen el tumor.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 195, 'Sin clasificar', 'Mujer de 60 años que acude al hospital por hematuria, mal estado general y fiebre. Se orienta clínicamente de insuficiencia renal progresiva y se decide realizarle una biopsia renal donde se observa una glomerulonefitis necrotizante con reacción extracapilar (semilunas) que afecta a más del 50% de los glomérulos. La inmunofluorescencia directa es negativa. Hay un dato del laboratorio de inmunología que nos ayudará a confirmar el diagnóstico, pero ¿cuál es el diagnóstico más probable?:', 'Glomerulonefritis pauciinmune.', 'Nefritis tubulointersticial.', 'Síndrome de Goodpasture.', 'Nefropatía IgA.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 196, 'Sin clasificar', 'Niño de 3 años de edad con antecedentes de dermatitis atópica leve, sin alergias conocidas. Acude a la consulta con su madre quien comenta que en la última semana le han aparecido unas lesiones en la piel de la cara y la región glútea. Estas lesiones comenzaroncomo pequeñas máculas eritematosas que en pocos días pasaron a vesículas y erosiones superficiales cubiertas por costras amarillentas y que han ido aumentando en número y tamaño, extendiéndose rápidamente a la piel de alrededor. Ha estado rascándose las lesiones, lo que parece haberlas empeorado. También comenta que en la guardería hay otros niños que han presentado lesiones similares en la piel. El niño tiene buen estado general y no tiene fiebre, sólo se queja de picor en las lesiones. Ante este cuadro clínico, ¿cuál es el diagnóstico más probable?:', 'Impétigo contagioso.', 'Molluscum contagioso.', 'Infección por herpes virus.', 'Candidiasis mucocutánea.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 197, 'Sin clasificar', 'Hombre de 50 años que acude a la consulta por una lesión pigmentada en su pierna derecha que ha cambiado de tamaño y color en los últimos 4 meses. La lesión es de 8 mm de diámetro, asimétrica, con bordes irregulares y con varias tonalidades de marrón y negro. Además, refiere prurito ocasional en la zona. No tiene antecedentes personales de cáncer, ni otros de interés, pero su madre fue diagnosticada de melanoma a los 60 años. Se realiza una dermatoscopia que revela un patrón de red irregular, puntos negros, áreas de regresión y vasos sanguíneos irregulares. ¿Cuál es el manejo más apropiado?:', 'Biopsia mediante punción de la parte más pigmentada de la lesión para confirmar el diagnóstico.', 'Biopsia mediante escisión completa con márgenes quirúrgicos de 2 mm y estudio histopatológico.', 'Monitorización de la lesión con dermatoscopia digital y seguimiento en 3 meses.', 'Terapia fotodinámica para reducir el tamaño de la lesión antes de realizar una biopsia.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 198, 'Sin clasificar', 'Una lactante prematura de 32 semanas, consulta al mes de nacimiento por 3 hemangiomas infantiles superficiales que han crecido en las 2 últimas semanas en el antebrazo derecho, en el tórax y en la espalda. Respecto a los hemangiomas infantiles que presenta la paciente, señale la respuesta INCORRECTA:', 'Tienen 3 fases evolutivas: una fase proliferativa en la que la lesión crece aceleradamente, un periodo de estabilidad y una fase involutiva.', 'Suponen la única lesión positiva para el marcador GLUT-1 (proteína transportadora de glucosa).', 'Es necesario realizar estudios de imagen (la ecografía sería la técnica de elección) por el riesgo aumentado de hemangiomas a nivel visceral.', 'La mayoría de los hemangiomas infantiles tiene un curso clínico predecible por lo que, si no hay compromiso funcional ni estético, una opción válida es no tratar a estos pacientes. Página: 3', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 199, 'Sin clasificar', 'Hombre de 45 años con antecedentes personales de hipertensión arterial, dislipemia, hígado graso y esclerosis múltiple y en tratamiento con fingolimod, enalapril y simvastatina, presenta una psoriasis con afectación de más del 10% de la superficie corporal y un índice de la severidad del área de psoriasis (PASI) de 14. Había realizado previamente tratamiento con acitretina durante 15 meses con escasa mejoría. El paciente pregunta por otra alternativa terapéutica que consiga mejorar su psoriasis. ¿Cuál considera que es la mejor opción de tratamiento?:', 'Fototerapia.', 'Biológico con mecanismo de acción anti-TNF (factor de necrosis tumoral).', 'Ciclosporina.', 'Biológico con mecanismo de acción anti- Interleucina 23.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 200, 'Sin clasificar', 'Indique, de los siguientes, ¿cuál es un criterio de malignidad radiológica de los tumores óseos?:', 'Esclerosis perilesional reactiva.', 'Presencia de calcificaciones puntiformes en el interior de la estructura ósea.', 'Rotura de la cortical ósea.', 'Localización epifisaria del tumor por la posibilidad de afectación de la articulación.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 201, 'Sin clasificar', 'En la enfermedad por arañazo de gato, señale la INCORRECTA:', 'En los casos sin manifestaciones sistémicas de la enfermedad es suficiente con tratamiento tópico.', 'Para el diagnóstico es necesaria la práctica de una serología.', 'Si se precisa tratamiento antibiótico, se recomienda azitromicina 500 mg. en una dosis inicial y 250 mg cada 24 horas durante 4 días más.', 'La mayoría de los casos curan de forma espontánea en semanas o meses sin tratamiento de ningún tipo.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 202, 'Sin clasificar', 'Hombre de 45 años que refiere desde hace 3 meses dolor en codo derecho irradiado a antebrazo, no asociado a parestesias ni sensación subjetiva de pérdida de fuerza. La intensidad del dolor va empeorando a lo largo del día, principalmente con trabajo de ordenador y con actividades deportivas. A la exploración física no se observan signos inflamatorios externos, presenta dolor a la palpación de epitróclea humeral y se reproduce su dolor al distender y resistir la musculatura flexora de antebrazo y mano. ¿Cuál de los siguientes es el diagnóstico más probable?:', 'Epicondilopatía medial.', 'Epicondilopatía lateral.', 'Síndrome compartimental crónico.', 'Neuropatía cubital por atrapamiento en canal epitrócleo-olecraniano.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 203, 'Sin clasificar', 'Hombre de 57 años con buen estado general, tiene un PSA de 13 ng/mL y tacto rectal pétreo. El estudio diagnóstico revela cáncer de próstata de alto riesgo, Gleason 9, metastásico, con afectación ósea (más de 8 lesiones en el esqueleto axial) y metástasis hepáticas. ¿Cuál de los siguientes es el tratamiento inicial indicado en la actualidad?:', 'Prostatectomía radical con linfadenectomía extendida y resección de las metástasis.', 'Radioterapia externa pélvica y radioterapia estereotáxica de las metástasis.', 'Braquiterapia pélvica de alta tasa.', 'Antiandrógenos inicialmente más análogos de la LHRH + enzalutamida + docetaxel.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 204, 'Sin clasificar', 'Gestante de 36 años primigesta sin factores de riesgo excepto índice de masa corporal de 32 pregestacional, que acude a urgencias a las 28 semanas y presenta una rotura prematura de membranas. En el momento del ingreso la analítica es normal, no presenta dinámica uterina y la longitud cervical es de 38 mm. ¿Cuál de las siguientes afirmaciones es INCORRECTA?', 'Iniciaremos maduración pulmonar fetal con corticoides.', 'Se realizará profilaxis de corioamnionitis mediante antibioterapia endovenosa.', 'Se iniciará neuroprotección fetal.', 'Se iniciará profilaxis tromboembólica con heparina de bajo peso molecular.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 205, 'Sin clasificar', '¿Qué autoanticuerpos en las miopatías inflamatorias debería alertarnos de un curso agresivo de una neumonía intersticial asociada?:', 'Anti-TIF-1.', 'Anti MDA-5.', 'Anti-Mi2.', 'Anti-PM/SCL.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 207, 'Sin clasificar', 'En relación con el estudio de la causalidad en epidemiología, solo uno de los siguientes es un criterio o consideración causal de Bradford Hill. Señálelo:', 'Gradiente biológico (relación dosis-respuesta).', 'Ausencia de sesgos.', 'Ausencia de confusión.', 'Significación estadística de la asociación.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 208, 'Sin clasificar', 'Hombre de 80 años con antecedentes de hipertensión arterial y diabetes mellitus, así como un accidente isquémico cerebral transitorio 2 años antes. Hospitalizado actualmente tras presentar un infarto de miocardio sin elevación del segmento ST (IAMSEST). En la coronariografía se observa enfermedad arterial coronaria multivaso no revascularizable. En la analítica la función renal es normal, sin anemia. ¿Cuál es el tratamiento antiagregante que debiera recomendarse como primera opción?:', 'Ácido acetil salicílico 100 mg/día de forma indefinida.', 'Ácido acetil salicílico 100 mg/día de forma indefinida y clopidogrel 75 mg/día durante 1 año.', 'Ácido acetil salicílico 100 mg/día de forma indefinida y ticagrelor 90 mg/día durante 1 año.', 'Ácido acetil salicílico 100 mg/día de forma indefinida y prasugrel 5 mg/día durante 1 año.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 209, 'Sin clasificar', 'Hombre de 34 años con poliposis intestinal y manifestaciones extraintestinales como hipertrofia congénita de retina y osteomas mandibulares. Para hacer el diagnóstico genético se debe analizar el gen:', 'Gen MYH.', 'Gen PTEN.', 'Gen APC.', 'Gen p53.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2024, 210, 'Sin clasificar', 'Acude por primera vez a la consulta una paciente de 17 años con anorexia nerviosa de un año de evolución. En la exploración física y analítica son característicos los siguientes signos EXCEPTO:', 'Lanugo.', 'Taquicardia.', 'Hipopotasemia si existen conductas purgativas como los vómitos o el uso de laxantes.', 'Disminución de hormonas gonadotróficas.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 1, 'Sin clasificar', 'En un adolescente de 17 años con dolor de rodilla de tres meses de evolución, antecedente de traumatismo leve y esta radiografía, ¿cuál de las siguientes entidades debe considerarse en el diagnóstico diferencial según la clínica y la imagen radiográfica (IMAGEN 1)?:', 'Osteosarcoma.', 'Osteomielitis subaguda.', 'Osteocondritis disecante.', 'Tumor de células gigantes.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 2, 'Sin clasificar', '¿Cuál de los siguientes hallazgos radiográficos es más útil para diferenciar osteosarcoma de otras causas de dolor crónico de rodilla en adolescentes (IMAGEN 2)?:', 'Lesión lítica con bordes bien definidos y sin reacción periostal.', 'Lesión con patrón mixto lítico-esclerótico y reacción periostal tipo triangulo de Codman.', 'Lesión subcondral con colapso de la placa ósea.', 'Lesión con calcificaciones puntiformes y sin masa de partes blandas.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 3, 'Sin clasificar', 'Ingresa una paciente de 83 años para tratamiento de aneurisma de aorta abdominal de 50mm de diámetro, por crecimiento rápido en los últimos 6 meses. Entre sus antecedentes destaca: hipertensión arterial, dislipemia, portadora de marcapasos por bloqueo auriculo-ventricular completo como antecedentes. Veinticuatro horas tras la cirugía la paciente presenta distensión, dolor abdominal y rectorragias, acompañado de leucocitosis 32.100μl, con el 95% de neutrófilos y 278 de LDH como únicas alteraciones analíticas, por lo que se realiza un angio-tomografia computerizada, con la siguiente imagen (IMAGEN 3). ¿Cuál es el diagnóstico más probable?:', 'Isquemia mesentérica aguda.', 'Isquemia mesentérica crónica.', 'Isquemia mesentérica no oclusiva.', 'Colitis isquémica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 4, 'Sin clasificar', 'Mujer de 36 años que acude a la consulta por una tumoración a nivel abdominal. Como antecedentes destaca que es alérgica a penicilinas, es exfumadora y que tuvo una diabetes gestacional durante un embarazo gemelar. A la exploración observas los siguientes hallazgos (IMAGEN 4). ¿Cuál es el diagnóstico más probable?:', 'Eventración con ‘pérdida de derecho a domicilio’.', 'Hernia epigástrica.', 'Hernia de Spiegel.', 'Diástasis de rectos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 5, 'Sin clasificar', 'Varón de 58 años con antecedente de colelitiasis en una ecografía abdominal que se hizo por otra causa. Refiere dolor abdominal continuo en epigastrio – hipocondrio derecho que irradia hacia la espalda. El dolor le ha comenzado tras la ingesta y ha cedido parcialmente tras tomar un espasmolítico. Así mismo refiere que se nota un poco amarillo y que la orina es muy oscura. Constantes: Tensión arterial 140/75mmHg; Frecuencia cardiaca 100lpm; Temperatura 36,8ºC. A la exploración presenta dolor a la palpación en hipocondrio derecho con signo de Murphy negativo. En la analítica de sangre: Bilirrubina total de 4 mg/dl con bilirrubina directa de 3,5 mg/dl, amilasa y lipasa normal, no tiene leucocitosis. ¿Cuál es la sospecha diagnóstica y tratamiento que aplicarías?: Usa las imágenes de ayuda (IMÁGENES 5a y 5b).', 'Cólico biliar por colelitiasis y Colecistectomía.', 'Cólico biliar por coledocolitiasis, CPRE (Colangiopancreatografia retrógrada endoscópica) y colecistectomía.', 'Colangitis y CPRE (Colangiopancreatografia retrógrada endoscópica).', 'Neoplasia de vía biliar extrahepática y cirugía oncológica.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 6, 'Sin clasificar', 'Según los árboles genealógicos representados, en relación a los patrones de herencia de las familias A, B y C, señale la opción correcta de las siguientes (IMAGEN 6):', 'En la familia A, el riesgo de un afectado/a de transmitir la enfermedad a su descendencia es del 25%.', 'En la familia B, la representación del árbol genealógico se corresponde claramente con el patrón hereditario típico de una enfermedad mitocondrial.', 'La familia C podría representar el patrón de herencia típico de una hemofilia A.', 'La consanguinidad está presente y representada en el árbol genealógico de la familia A.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 7, 'Sin clasificar', 'La mácula rojo cereza es un signo clínico que se observa en el contexto de engrosamiento y pérdida de transparencia de la retina del polo posterior. En el fondo de ojo se aprecia una mancha roja brillante en el centro de la mácula rodeada de una retina blanquecina (IMAGEN 7). ¿En cuál de las siguientes entidades NO es típico observarla?:', 'Enfermedad de Tay-Sachs.', 'Distrofia coroidea areolar central.', 'Oclusión de arteria central de la retina.', 'Enfermedad de Niemann-Pick.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 8, 'Sin clasificar', 'Un paciente presenta una audiometría normal de oído izquierdo, y la audiometría del oído derecho es como se muestra en la siguiente imagen (IMAGEN 8). ¿Cómo se comportará la acumetría realizada con un diapasón de 512 Hz?:', 'Rinne (+) en oído derecho y Weber lateraliza al oído derecho.', 'Rinne (–) en oído derecho y Weber lateraliza oído izquierdo.', 'Rinne (+) en oído derecho y Weber lateraliza oído izquierdo.', 'Rinne (–) en oído derecho y Weber lateraliza oído derecho.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 9, 'Sin clasificar', 'En agosto 2025 acude a su consulta del Centro de Salud Alejandro de 18 años acompañado por su madre, que un poco enfadada le dice: “Enséñale las manos al doctor. Dice que no sabe lo que le ha pasado, claro cómo está todo el día de fiesta a saber que ha hecho. El último fin de semana, fiesta de mojitos en la piscina con sus amigos”. El paciente le refiere que no tiene dolor, leve prurito y actualmente no toma ninguna medicación. Usted, tras la exploración física (IMAGEN 9) y la anamnesis cree haber llegado al diagnóstico. ¿Cuál de estas afirmaciones en base a su presunto diagnóstico es FALSA?:', 'Le preguntará si fue el encargado de exprimir la lima de los mojitos.', 'Le informará de la probable evolución favorable, aunque la hiperpigmentación residual podría ser muy persistente.', 'La prevención consiste, en evitar el contacto con la sustancia en cuestión y, cuando ello no sea posible, medidas fotoprotectoras.', 'El mecanismo fisiopatológico más probable en este caso sería una Hipersensibilidad tipo IV mediada por linfocitos T.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 10, 'Sin clasificar', 'Paciente de 70 años con antecedentes de infarto anterior hace 15 años tratado con stent coronario. Portador de marcapasos por antecedentes de bloqueo auriculoventricular, con ecocardiografía reciente con fracción de eyección del ventrículo izquierdo del 25%. Refiere la familia encontrarle más cansado y somnoliento desde hace dos días y con incremento de su disnea habitual. En urgencias las constantes son: frecuencia cardíaca 80 lpm, tensión arterial 75/45 mmHg, saturación de O2 basal 86% y la frecuencia respiratoria 35 rpm. A la exploración física llama la atención la frialdad de las extremidades que además presentan edemas con fóvea. El electrocardiograma es el siguiente (IMA- GEN 10a) y la radiografía de tórax es la siguiente (IMAGEN 10b). ¿Cuál de las siguientes medidas terapéuticas le parecen las más adecuadas en la fase aguda del paciente?:', 'Ventilación no invasiva tipo Bilevel Positive Airway Pressure (BIPAP), furosemida intravenosa, dobutamina o noradrenalina intravenosa.', 'Oxígeno en reservorio, furosemida intravenosa, nitroglicerina intravenosa y betabloqueantes.', 'BIPAP, furosemida intravenosa, dobutamina o noradrenalina intravenosa, Inhibidor de la Enzima Convertidora de Angiotensina (IECA), espironolactona, estatina y betabloqueante.', 'BIPAP, furosemida intravenosa, sacubitrilo-valsartán, empaglifozina, betabloqueante, espironolactona y estatina.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 11, 'Sin clasificar', 'Acude a urgencias un paciente con palpitaciones desde hace 3 horas y presenta el siguiente electrocardiograma (IMAGEN 11). ¿Cuál de las siguientes afirmaciones es verdadera?:', 'Se trata de una fibrilación auricular y realizaría cardioversión eléctrica si el paciente la tolerase mal hemodinámicamente.', 'Se trata de un flutter auricular común. Lo cardiovertiría si está mal tolerado y lo indicado es la ablación del istmo cavotricuspídeo como primera opción.', 'Se trata de una taquicardia por reentrada intranodal y administraría un bolo de adenosina intravenosa.', 'Se trata de una fibrilación auricular preexcitada y administraría un bolo de betabloqueante intravenoso.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 12, 'Sin clasificar', 'Paciente de 70 años fumador de 2 paquetes de cigarrillos al día. Acude a urgencias por disnea, plétora facial, edema en esclavina y cianosis. Se realiza una Tomografía axial computerizada (TAC) de tórax en el que se observan las siguientes imágenes (IMAGEN 12a y 12b). ¿Cuál es el diagnóstico más probable?:', 'Carcinoma microcítico de pulmón.', 'Linfoma de Hodgkin.', 'Metástasis de carcinoma no microcítico de pulmón.', 'Carcinoma tímico.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 13, 'Sin clasificar', 'Acude a urgencias un varón de 57 años, diagnosticado de una cirrosis etílica, sin descompensaciones previas, que mantiene un consumo de 2-3 cervezas al día. Ha comenzado con ictericia indolora en la última semana. En la exploración física únicamente destacan una franca ictericia cutánea y mucosa y ligeros edemas en ambas extremidades inferiores, sin ascitis. En la analítica encontramos hemoglobina: 11 g/dL, volumen corpuscular medio: 113 fL, Plaquetas 63*10⁹/L, AST: 90 UI/L, ALT: 35 UI/L, gamma-glutamiltransferasa: 60 UI/L, bilirrubina total: 10 mg/dL, bilirrubina conjugada: 2.5 mg/dL, albúmina: 36 g/L, gammaglobulinas: 16 g/dL, ferritina: 500 mcg/L, saturación de transferrina: 59%, haptoglobina menor de 8 mg/dL. La morfología de sangre periférica es la que se muestra en la imagen (IMAGEN 13). ¿Cuál es su diagnóstico?:', 'Hepatitis alcohólica.', 'Hemocromatosis.', 'Anemia hemolítica autoinmune.', 'Acantocitosis.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 14, 'Sin clasificar', 'Varón de 55 años con antecedentes de consumo de alcohol mayor de 100 g/día desde la juventud, diagnosticado de enfermedad hepática crónica. Ingresa por una hemorragia digestiva alta por varices esofágicas, falleciendo a las 48 horas. Se realiza una autopsia. Macroscópicamente el hígado es micronodular. En la imagen microscópica llama la atención la presencia de glóbulos que se tiñen de forma intensa con la tinción de PAS (IMAGEN 14). ¿A qué corresponden esos glóbulos de la imagen?:', 'Vacuolas lipídicas.', 'Hialina de Mallory.', 'Alfa-1-antitripsina.', 'Megamitocondrias.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 16, 'Sin clasificar', 'Mujer de 63 años de edad con diagnóstico de cáncer de endometrio estadio I. Ha sido intervenida mediante histerectomía radical más linfadenectomía pélvica y para-aórtica, finalizando con radioterapia. En la exploración física se objetiva un signo de Stemmer positivo. Tras visualizar la imagen (IMAGEN 16), ¿cuál de estas opciones considera que es la correcta?:', 'La paciente presenta una linfangitis, que se tratará mediante pauta de amoxicilinaclavulánico durante 10 días.', 'La paciente tiene un lipedema, que se tratará con actividad física de bajo impacto con el objetivo de mejorar la circulación.', 'La paciente presenta un linfedema, que se tratará mediante prenda de presoterapia a medida y drenaje linfático manual.', 'La paciente presenta una sospecha de trombosis venosa profunda en la extremidad, por lo que solicitaremos un estudio de imagen con doppler vascular para confirmar el diagnóstico.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 17, 'Sin clasificar', 'Un hombre de 67 años, exfumador y jubilado del entorno rural consulta por una lesión en el labio inferior, con dolor tanto espontáneo como a la palpación. Refiere que, aunque recuerda lesiones en los labios desde hace años, desde hace un mes y medio la lesión presenta el aspecto que se observa en la imagen (IMAGEN 17). ¿Cuál es la actitud más adecuada en este momento?:', 'Iniciar tratamiento supresor con aciclovir oral para reducir el número de recurrencias de herpes labial.', 'Iniciar tratamiento con imiquimod tópico y fotoprotección del labio inferior.', 'Tomar una biopsia de labio para descartar un carcinoma invasivo de células escamosas del labio inferior.', 'Sospechar una úlcera neuropática secundaria a neuropatía del trigémino y remitir para valoración por Neurología.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 18, 'Sin clasificar', 'Una mujer de 62 años, hipertensa y diabética, consulta por dos úlceras muy dolorosa localizadas en la pierna derecha de 6 meses de evolución. Las lesiones han sido tratadas con curas locales, antibióticos sistémicos de amplio espectro y analgesia, sin respuesta terapéutica y con crecimiento progresivo. A la exploración física, las lesiones muestran el aspecto que se observa en la imagen (IMAGEN 18). ¿Cuál es la actitud más adecuada en este momento?:', 'Realizar una biopsia de piel para estudio microbiológico de micobacterias y micosis profundas.', 'Realizar cultivos seriados, desbridamiento quirúrgico y antibioterapia intravenosa con ertapenem y medidas de compresión.', 'Realizar una eco-Doppler venosa y medidas de compresión.', 'Realizar biopsia de piel para confirmación diagnóstica y a continuación iniciar tratamiento con prednisona oral (0,5-1,5 mg/kg/día).', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 19, 'Sin clasificar', 'Hombre de 79 años, con insuficiencia cardíaca leve, hipertensión arterial, dislipemia y diabetes mellitus tipo II que trata con valsartán, simvastatina y metformina. Consulta por prurito intenso generalizado de más de 6 meses de evolución, que no cede con antihistamínicos a dosis habituales. El paciente presenta lesiones polimorfas, de aspecto urticariano y otras lesiones excoriadas y descamativas (IMAGEN 19), que se distribuyen fundamentalmente en el abdomen y en las extremidades, y sin lesiones en la cara. Se realiza una biopsia de piel en la que se observa un intenso infiltrado eosinofílico subepidérmico con algunos eosinófilos alineados en la unión dermo-epidérmica. Indique cuál considera la actitud más adecuada en este momento:', 'Consideraría aumentar la dosis de antihistamínicos hasta dosis cuádruple de lo recomendado en la ficha técnica.', 'Iniciaría tratamiento con prednisona oral a dosis de 0,5-0,75 mg/kg/día.', 'Iniciaría tratamiento con ivermectina oral.', 'Suspender inmediatamente los medicamentos que toma e iniciar tratamiento parenteral con metilprednisolona y dexclorfeniramina.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 20, 'Sin clasificar', 'Una mujer de 35 años que toma anticonceptivos orales presenta las lesiones que se observan en la imagen (IMAGEN 20). Estas lesiones se localizan en el dorso de las manos, en el cuello y aparecieron unos días después de un ingreso hospitalario por dolor abdominal sin diagnóstico, y que ha motivado ingresos anteriores. La paciente refiere historia previa de aparición de lesiones similares que cree relacionar con la exposición solar, así como lesiones ante cualquier mínimo traumatismo de la piel. Cuál de los siguientes es el diagnóstico más probable:', 'Porfiria aguda intermitente.', 'Porfiria variegata.', 'Porfiria cutánea tarda.', 'Déficit de ALA-deshidratasa.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 21, 'Sin clasificar', 'Un lactante de 8 meses presenta desde hace 2 semanas eritema de la zona del pañal (IMAGEN 21) que ha sido tratado durante los últimos días con emolientes y cremas barrera. ¿Cuál es el tratamiento más adecuado en este momento?:', 'Suspender las cremas actuales y aplicar corticoide tópico de potencia media.', 'Mantener la higiene habitual, dejar el área del pañal seca y ventilada, y aplicar antifúngico tópico (nistatina o imidazólico).', 'Mantener la higiene, con secado riguroso de la zona, aplicar una pasta al agua y cambiar el pañal con más frecuencia.', 'Aplicar corticoide tópico combinado con antibiótico y antifúngico de forma empírica durante 10-14 días.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 22, 'Sin clasificar', 'Varón de 56 años, fumador de 1 paquete/día desde los 14 hasta los 55 de edad, que acude por primera vez para estudio de clínica de disnea progresiva grado 2 de la modified Medical Research Councyldyspneascale (mMRC), junto con tos y expectoración crónica no purulenta. Refiere queen el año previo ha tenido dos agudizaciones que le han llevado a urgencias del hospital donde fue valorado, evitando el ingreso. En el hemograma de rutina presenta 305 eosinófilos/µl. La espirometría se presenta en la imagen adjunta (IMAGEN 22). ¿Cuál de las siguientes afirmaciones es correcta según el documento GOLD 2025?:', 'Se trata de un paciente con enfermedad pulmonar obstructiva crónica (EPOC), GOLD 3E y debe tratarse con doble terapia broncodilatadora.', 'Se trata de un paciente con EPOC, GOLD 3B y debe tratarse con triple terapia inhalada (LABA/LAMA/ICS).', 'Se trata de un paciente con EPOC, GOLD 3E y debe tratarse con triple terapia inhalada (LAMA/LABA/ICS).', 'Se trata de un paciente con EPOC, GOLD 3A y debe tratarse con un solo broncodilatador de acción prolongada (LAMA o LABA).', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 23, 'Sin clasificar', 'Paciente de 53 años sin antecedentes de interés que acude a urgencias por epigastralgia intensa que irradia difusamente al resto del abdomen. Había consultado en urgencias 3 días antes y se le dio el alta con paracetamol que fue efectivo. Reacude ahora por persistencia del dolor con sensación distérmica, náuseas y vómitos que condicionan la ingesta oral. En la exploración tiene un abdomen duro con dolor difuso que mejora con la flexión ventral del tronco. Se le realiza una radiografía de abdomen en la que se observa lo que muestra la imagen (IMAGEN 23). ¿Cuál es la principal sospecha diagnóstica?:', 'Obstrucción de intestino grueso.', 'Perforación gástrica.', 'Suboclusión de intestino delgado.', 'Íleo adinámico.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 24, 'Sin clasificar', 'Un varón de 69 años consulta por astenia y adelgazamiento. En la exploración física, presenta esplenomegalia de 5 cm por debajo del reborde costal. En el hemograma, hemoglobina de 10 g/dl y plaquetas de 630.000/mcrl, y presencia de leucoeritroblastosis en el frotis de sangre periférica. Revisando su historial analítico comprobamos que ya se observaba una cifra similar de plaquetas cinco años atrás, pero la hemoglobina y el frotis eran normales. Se realiza un aspirado de médula ósea que resulta seco. En la biopsia ósea de solicita una tinción con plata para medirreticulina (IMA- GEN 24). El estudio genético revela la presencia de la variantepatogénicaenJAK2 que genera el cambio V617F y unavariantepatogénicaenASXL1. ¿Cuál es el diagnóstico más probable de este paciente?:', 'Mielofibrosis post trombocitemia esencial.', 'Aplasia medular.', 'Leucemia mielomonocítica crónica.', 'Leucemia mieloide crónica.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 25, 'Sin clasificar', 'Paciente de 56 años, con antecedentes de Diabetes Mellitus tipo 2, obesidad y fumador de 20 cigarrillos diarios. Consulta en urgencias por un episodio de dolor torácico con mareo tras una discusión con un familiar. El electrocardiograma es normal y la primera troponina es de 14. Siguiendo el protocolo se le va a seriar la troponina por lo que está esperando en un box de urgencias monitorizado. Mientras espera comienza con mareo, por lo que avisa al personal de enfermería que cuando llega al box se lo encuentra inconsciente, sin respiración y con un ritmo en el monitor como el de la imagen (IMAGEN 25). Se comienza con compresiones y ventilaciones con una secuencia 30:2. ¿Cuál sería la siguiente acción?:', 'Administrar Adrenalina intravenosa.', 'Administrar Amiodarona intravenosa.', 'Realizar una desfibrilación.', 'Realizar una cardioversión eléctrica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 27, 'Sin clasificar', 'En relación con el sobrediagnóstico, señale la afirmación INCORRECTA:', 'Se considera un efecto indeseado de los cribados poblacionales.', 'Se debe principalmente a la obtención de resultados falsos positivos en pruebas diagnósticas.', 'Una de sus principales consecuencias es el sobretratamiento.', 'Su reducción es uno de los objetivos de la prevención cuaternaria.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 29, 'Sin clasificar', '¿Qué tipo de sesgo se comete cuando se asume que una asociación observada a nivel poblacional también existe a nivel individual?:', 'Sesgo o falacia ecológica.', 'Sesgo de atención o efecto Hawthorne.', 'Falacia de Neyman o sesgo de prevalencia o de incidencia.', 'Sesgo de regresión a la media.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 30, 'Sin clasificar', '¿Cuál de las siguientes NO se considera una infección relacionada con la asistencia sanitaria?:', 'Paciente hospitalizado que desarrolla una infección por Clostridium difficile con inicio de síntomas tras 48 horas de ingreso.', 'Paciente sometido a cirugía mayor ambulatoria que desarrolla una infección de localización quirúrgica con inicio de síntomas a los 25 días de la intervención.', 'Paciente hospitalizado, portador de sondaje vesical desde su colocación en urgencias, que desarrolla una infección del tracto urinario con inicio de síntomas a las 72 horas de ingreso.', 'Paciente hospitalizado que desarrolla una neumonía con inicio de síntomas a las 24 horas de su ingreso.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 31, 'Sin clasificar', '¿Cuál de los siguientes NO se considera un grupo de riesgo que requiera vacunación frente al Virus de la Hepatitis A?:', 'Pacientes diagnosticados de VIH.', 'Pacientes candidatos a trasplante hepático.', 'Pacientes diagnosticados de asplenia anatómica o disfunción esplénica grave.', 'Pacientes diagnosticados de enfermedad hepática crónica.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 32, 'Sin clasificar', 'En materia de calidad asistencial, un indicador es una medida que nos informa sobre el progreso hacia la consecución de determinados objetivos. Según el modelo de Donabedian, pueden clasificarse como indicadores de estructura, de proceso y de resultado ¿Cuál de los siguientes es un indicador de resultado?:', 'Ratio de camas hospitalarias en funcionamiento, por cada 1.000 habitantes.', 'Proporción de partos por cesárea.', 'Incidencia de infecciones relacionadas con la asistencia sanitaria.', 'Ratio de personal médico en atención primeria, por cada 1.000 habitantes.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 33, 'Sin clasificar', 'Señale el enunciado INCORRECTO:', 'La tasa de incidencia acumulada de una enfermedad depende tanto de la incidencia como de la duración del período de medición.', 'La tasa de incidencia acumulada es una aproximación útil de la incidencia cuando la tasa es alta o cuando el período de estudio es largo.', 'La tasa de incidencia requiere la utilización de una unidad de tiempo.', 'La prevalencia incrementa con una mayor duración de la enfermedad.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 34, 'Sin clasificar', '¿En cuál de las siguientes enfermedades debe indicarse precauciones exclusivamente de transmisión por gotas?:', 'Neumonía por Virus Respiratorio Sincitial.', 'Gripe.', 'Tuberculosis pulmonar activa.', 'Sarampión.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 35, 'Sin clasificar', 'Mujer de 73 años que ingresa en el hospital por cuadro de fiebre, dolor en hipocondrio derecho e hipotensión. Tras reanimación con fluidos se agrava la hipotensión y requiere intubación y conexión a ventilación mecánica. Se realiza una Tomografía axial computerizada (TAC) de abdomen observándose datos de colecistitis gangrenosa con gas y engrosamiento irregular de la pared. Se realiza colecistostomía de drenaje e ingresa en la Unidad de cuidados intensivos (UCI). Se inicia tratamiento con piperacilina-tazobactam. Dos días después la paciente se encuentra en disfunción multiorgánica (SOFA 11 puntos), conectada a ventilación mecánica y requiriendo noradrenalina y vasopresina. Se recibe el siguiente hemocultivo: ANTIBIOGRAMA: CMI (mg/L) Ampicilina R > 8 Amoxicilina-Clav R > 32 Piperacilina-Taz S 4 Cefotaxima R >2 Ceftazidima R > 8 Cefepime R > 8 Azteronam R > 4 Ertapenem S < 0,12 Imipenem S < 1 Meropenem S < 0,12 Gentamicina S < 2 Ciprofloxacino S 0,25 Con estos datos, ¿cuál es la respuesta CO- RRECTA respecto al tratamiento antibiótico de esta paciente?:', 'Mantener piperacilina-tazobactam.', 'Mantener piperacilina-tazobactam añadiendo un aminoglucósico.', 'Suspender piperacilina-tazobactam e iniciar meropenem.', 'Suspender piperacilina-tazobactam e iniciar ciprofloxacino.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 36, 'Sin clasificar', 'Mujer de 44 años con antecedentes de neoplasia de mama en tratamiento con quimioterapia que ingresa en la unidad de cuidados intensivos (UCl) con insuficiencia respiratoria. Requiere intubación y conexión a ventilación mecánica. Se realiza fibrobroncoscopia con lavado bronco-alveolar y se aísla Nocardia farcinica pendiente de antibiograma. ¿qué actitud terapéutica cree CORRECTA?:', 'Iniciar tratamiento con voriconazol más trimetroprin-sulfametoxazol.', 'Iniciar tratamiento con trimetroprin-sulfametoxazol.', 'Iniciar tratamiento con trimetroprin-sulfametoxazol más meropenem.', 'Iniciar tratamiento con trimetroprin-sulfametoxazol más imipenem más amikacina.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 37, 'Sin clasificar', 'Señale la respuesta CORRECTA respecto al manejo inicial de un paciente en shock séptico:', 'No debe iniciarse el tratamiento con un vasopresor hasta que se haya finalizado la reanimación con fluidos.', 'Hoy en día, la vasopresina es el primer vasopresor a emplear.', 'El objetivo es mantener una Presión arterial sistólica > 90 mmHg.', 'En caso de no disponer de un acceso venoso central y no lograr el objetivo hemodinámico podemos iniciar el tratamiento con vasopresores por un acceso venoso periférico.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 38, 'Sin clasificar', 'Respecto al diagnóstico de la enfermedad por citomegalovirus, señale la respuesta INCORRECTA:', 'La infección primaria en personas inmunocompetentes ocasiona una respuesta de anticuerpos IgM e IgG, estos últimos detectables de por vida en la mayoría de los pacientes, mientras que los anticuerpos IgM se negativizan en menos de 30 días.', 'El cultivo del CMV en fibroblastos humanos produce un efecto citopático característico entre los 7 y los 28 días.', 'La determinación periódica de la carga viral en sangre se realiza en los receptores de trasplante de alto riesgo de enfermedad como guía para el tratamiento anticipado.', 'Los métodos de reacción en cadena de la polimerasa (PCR) en tiempo real son de elección por sensibilidad y especificidad si bien el número de copias indicativas de infección activa varía según la técnica empleada y si se realiza en sangre total o plasma.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 39, 'Sin clasificar', 'En un paciente con infección por el virus de inmunodeficiencia humana (VIH) y alta sospecha de infección respiratoria por Micobacteria, una PCR negativa del complejo Micobacterium tuberculosis en un lavado broncoalveolar NO excluye infección por una de las siguientes especies. Señálela:', 'Micobacterium bovis.', 'Micobacterium tuberculosis.', 'Micobacterium kansasii.', 'Micobacterium africanum.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 40, 'Sin clasificar', '¿Cuál es la duración del tratamiento antifúngico en un paciente que sufre una candidemia no complicada (se han descartado endocarditis u otras causas de metástasis a distancia y el paciente ha quedado asintomático)?:', 'Dos semanas tras el primer hemocultivo negativo.', 'Dos semanas tras el hemocultivo en el que se aísla Candida spp.', 'Una semana tras el hemocultivo en el que se aísla Candida spp.', 'Tres semanas.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 41, 'Sin clasificar', '¿Cuál de las siguientes es una medida preventiva para reducir el riesgo del síndrome de muerte súbita del lactante?:', 'Se ha de promover la posición de decúbito lateral en la cuna para evitar aspiraciones accidentales durante el sueño.', 'En hermanos de niños fallecidos por este síndrome, se ha de retrasar la vacunación de los 2 a los 6 meses de edad.', 'Se recomienda el sueño del lactante sobre una superficie blanda y con la cabecera incorporada 30º sobre plano.', 'Se debe evitar el sobrecalentamiento de la habitación, así como la exposición al humo del tabaco.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 42, 'Sin clasificar', '¿Cuál es una manifestación de la fase febril aguda de la enfermedad de Kawasaki?:', 'Inyección ocular conjuntival bilateral no exudativa.', 'Descamación de los dedos de las manos y los pies.', 'Trombopenia menor de 100.000 plaquetas/mm3.', 'Aparición de los aneurismas coronarios.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 43, 'Sin clasificar', 'Lactante de 2 meses alimentado con lactancia materna exclusiva. ¿Con qué vitamina se recomienda suplementar su alimentación?:', 'No se recomienda ningún suplemento vitamínico en niños sanos a término.', 'Vitamina D.', 'Vitamina C.', 'Hierro oral desde los 2 meses.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 44, 'Sin clasificar', '¿Cuál de las siguientes afirmaciones sobre vacunas vivas atenuadas en edad pediátrica es correcta?:', 'Por su perfil de seguridad para el feto, pueden administrarse durante cualquier periodo del embarazo.', 'Se recomienda retrasar su administración en niños que han recibido recientemente inmunoglobulinas inespecíficas a altas dosis.', 'Dado que no se trata de virus salvajes, pueden administrarse en niños con inmunosupresión grave.', 'Ya no forman parte de los calendarios oficiales de vacunación pediátrica de nuestro país.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 45, 'Sin clasificar', '¿Cuál es la afirmación correcta con respecto al síndrome hemolítico urémico en edad pediátrica?:', 'El Campylobacter productor de toxina es el agente bacteriano más frecuentemente involucrado en las formas asociadas a diarrea.', 'La insuficiencia renal combinada con hemólisis puede provocar hiperpotasemia potencialmente grave.', 'Cuando está asociado a bacterias entéricas productoras de toxinas shiga o verotoxinas, es más frecuente en adolescentes que en menores de 5 años.', 'En los casos asociados a diarrea por E. coli O157:H7, el tratamiento antibiótico precoz con quinolonas mejora el pronóstico del paciente.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 46, 'Sin clasificar', '¿Cuál de las siguientes señales elevan la sospecha de un posible maltrato físico en urgencias pediátricas?:', 'Historia coherente con la lesión y el mecanismo lesional referido por su cuidador.', 'Hematomas u otras lesiones en diferentes estadios evolutivos, afectación de zonas no expuestas o protegidas, lesiones pares, simétricas o con forma de objeto.', 'Rasguños leves en zonas expuestas al juego.', 'Lesiones compatibles con molluscu contagiosum en tronco, axilas y miembros superiores.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 47, 'Sin clasificar', '¿Cuál de los siguientes enunciados es correcto respecto al síndrome de dificultad respiratoria del recién nacido prematuro (anteriormente denominado enfermedad de membrana hialina)?:', 'Existe un mayor riesgo de aparición por la administración de corticoides a la madre gestante.', 'Aparece con menor frecuencia en niños nacidos por cesárea.', 'Es más frecuente en embarazos únicos que en múltiples.', 'Existe una deficiencia de surfactante pulmonar por distintos mecanismos, muchos de ellos asociados a la prematuridad.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 48, 'Sin clasificar', '¿Cuál es el tratamiento de elección en lactantes hospitalizados por bronquiolitis aguda?:', 'Broncodilatadores inhalados rutinarios.', 'Anticuerpos monoclonales frente al virus respiratorio sincitial, como palivizumab o nirsevimab.', 'Manejo sintomático, vigilancia y medidas de soporte cuando estén indicadas, como la oxigenoterapia, la hidratación y aspiración de secreciones.', 'Corticoides sistémicos o nebulizados.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 49, 'Sin clasificar', '¿Cuál es la opción correcta con respecto al trastorno del espectro autista en edad pediátrica?:', 'Afecta por igual a ambos sexos.', 'La presencia de comorbilidades en edad pediátrica es excepcional.', 'Los síntomas aparecen ya en las primeras fases del de desarrollo, pero pueden no manifestarse totalmente hasta que la demanda social supera las capacidades limitadas.', 'No es posible su diagnóstico en menores de 36 meses, dadas las variabilidades fisiológicas del desarrollo psicomotor.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 50, 'Sin clasificar', 'Respecto al cáncer de mama:', 'Presenta una incidencia por edad con un pico entre los 50 y 60 años que se reduce a partir de esta edad.', 'El carcinoma ductal in situ se estadifica como estadio .', 'El tipo histológico más frecuente es el carcinoma lobulillar infiltrante.', 'La mayoría de los casos de cáncer de mama se desarrollan en mujeres con riesgo genético para padecerlo.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 51, 'Sin clasificar', 'Una mujer de 35 años consulta por baches amenorreicos de 3-6 meses en el último año y el estudio hormonal muestra los siguientes niveles séricos de gonadotropinas hipofisarias: FSH: 80 U/L y LH: 51 U/L ¿en qué diagnóstico deberíamos pensar?:', 'Insuficiencia o fallo ovárico prematuro.', 'Adenoma hipofisario primario.', 'Amenorrea hipotalámica.', 'Sospecha de síndrome de Kallman o síndrome de Prader-Willi requiriéndose diagnóstico diferencial según otros datos clínicos de la paciente.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 52, 'Sin clasificar', 'Una mujer de 40 años se detectó un nódulo mamario y es remitida tras el estudio de imagen (mamografía y ecografía), calificando el informe hallazgo como nódulo BI- RADS 4A. ¿Cuál sería la actitud más correcta?:', 'Realizar la exéresis del nódulo mamario.', 'Realizar pruebas de imagen cada 6 meses para comprobar si existe crecimiento y en ese caso ampliar el estudio con biopsia.', 'Realizar biopsia percutánea con aguja gruesa del nódulo para estudio histopatológico, estimando una probabilidad de malignidad menor o igual al 10%.', 'No es aplicable en este caso la catalogación porque el sistema Birads se definió para clasificar las microcalcificaciones, no los nódulos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 53, 'Sin clasificar', '¿Cuál de las siguientes determinaciones analíticas es más útil para valorar la reserva folicular ovárica de una mujer que consulta por esterilidad?:', 'Niveles séricos de estradiol en mitad de ciclo.', 'Niveles séricos de hormona folículo estimulante (FSH) en mitad de ciclo.', 'Niveles séricos de hormona antimulleriana (AMH) en cualquier momento del ciclo.', 'Determinación conjunta de FSH y estradiol en día 8 del ciclo.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 54, 'Sin clasificar', 'Una gestante de 32 semanas acude a urgencias por notarse mojada y se confirma rotura prematura de membranas. Está afebril, la analítica de sangre es normal y el registro cardiotocográfico muestra línea de base de la frecuencia cardiaca fetal de 130 latidos por minuto y ausencia de contracciones. ¿Qué actitud le parece la más correcta?:', 'Iniciar tratamiento tocolítico profiláctico y mantener actitud expectante con vigilancia maternofetal.', 'Iniciar tratamiento tocolítico y la pauta de maduración pulmonar con corticoides y mantener actitud expectante con vigilancia maternofetal.', 'Iniciar tratamiento antibiótico, la pauta de maduración pulmonar con corticoides y mantener actitud expectante con vigilancia maternofetal.', 'Iniciar tratamiento antibiótico y pauta de maduración pulmonar con corticoides y emprender medidas para finalizar la gestación en 48-72 horas.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 55, 'Sin clasificar', 'Respecto al cribado del primer trimestre en la gestante para estimar el riesgo de preeclampsia, señale la afirmación correcta:', 'La inclusión del Doppler de las arterias uterinas (valor del índice de pulsatilidad) en el cribado aumenta la tasa de detección.', 'El valor de sflt-1 incluido en el cribado indica mayor riesgo cuando está en concentraciones bajas.', 'La detección de gestantes con alto riesgo permite prevenir la preeclampsia con ácido acetilsalicílico 150 mg/noche, comenzando el tratamiento a partir de la semana 16.', 'Únicamente debe realizarse en centros que dispongan de un ecógrafo de alta resolución.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 57, 'Sin clasificar', '¿En cuál de los siguientes casos está claramente indicado iniciar el tratamiento tocolítico en una gestante de 30 semanas que acude a urgencias por dinámica uterina y se comprueban contracciones en el registro cardiotocográfico?:', 'Si la medida de la longitud cervical mediante ecografía vaginal es de 20 mm..', 'Si el test de fibronectina es negativo.', 'Debe administrarse en todos los casos, dada la edad gestacional.', 'Debe administrarse en todos los casos si la mujer es primigesta, dada la edad gestacional.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 58, 'Sin clasificar', 'En relación con el tratamiento con carbonato de litio de los pacientes con Trastorno Bipolar, señale la afirmación correcta:', 'El litio es altamente eficaz para reducir las tasas de suicidio.', 'El riesgo de malformaciones congénitas en recién nacidos es mayor cuando las madres reciben tratamiento con litio que cuando lo hacen con ácido valproico.', 'El tratamiento con litio durante 10-20 años puede provocar una hepatopatía crónica.', 'El litio es más eficaz que los fármacos anticonvulsivos para el tratamiento de los episodios mixtos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 59, 'Sin clasificar', 'Un estudiante de 22 años, sin antecedentes psiquiátricos, lleva dos meses sin asistir a clase y sin relacionarse con sus numerosos amigos. Su familia comenta que, durante los últimos siete meses, está distinto, más retraído, serio y callado. Han empeorado sus resultados académicos y ha abandonado sus aficiones. Cree que hay una conspiración, en la que involucra al entrevistador. Evita el contacto visual y se muestra suspicaz. Niega oír voces, pero con frecuencia se gira hacia un lado teniendo una actitud de escucha. ¿Cuál de los siguientes sería el diagnóstico más probable, una vez descartada patología orgánica y consumo de sustancias?:', 'Trastorno de depresión mayor con características psicóticas congruentes con el estado de ánimo.', 'Esquizofrenia.', 'Trastorno esquizotípico de la personalidad.', 'Trastorno Bipolar I, episodio actual maníaco, con características psicóticas congruentes con el estado de ánimo.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 60, 'Sin clasificar', 'En relación con las adicciones, ¿cuál es la afirmación INCORRECTA?:', 'Hay una asociación sólida y dependiente de la dosis entre consumo de cannabis de alta potencia y el desarrollo posterior de esquizofrenia.', 'Los pacientes con trastorno por consumo de alcohol presentan pocos trastornos psiquiátricos comórbidos.', 'El tratamiento farmacológico principal de la abstinencia alcohólica son las benzodiacepinas.', 'El consumo de cocaína aumenta el riesgo de eventos adversos cardiovasculares.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 61, 'Sin clasificar', 'Paciente de 32 años, sin antecedentes psiquiátricos, que ha tenido un hijo hace 50 días. A los 40 días del parto empezó a mostrarse irritable, decaída, inquieta y con insomnio. Comenta que ha pecado y debe morir. Refiere escuchar espíritus que le incitan a desaparecer y cree que la familia quiere envenenarla. Una vez descartada organicidad, se le ingresa y se pauta tratamiento antipsicótico, valorando la realización de Terapia Electroconvulsiva (TEC). De todos los datos recogidos en este caso clínico, cuál de estos NO es típico de la psicosis que padece esta paciente:', 'Este tipo de psicosis es una urgencia psiquiátrica que requiere hospitalización.', 'Antes de realizar el diagnóstico psiquiátrico, es necesario descartar organicidad.', 'La aparición típica de los síntomas se produce a partir de la cuarta semana después del parto.', 'Entre los tratamientos indicados se encuentran los antipsicóticos y el TEC.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 62, 'Sin clasificar', 'En lo que respecta a los pacientes con Trastorno de la personalidad límite, es correcta la siguiente afirmación:', 'Presentan un patrón de relaciones interpersonales estables.', 'Pueden experimentar cambios de humor repetidos y marcados a lo largo del día.', 'Es raro que se autolesionen.', 'En su tratamiento tiene más peso la terapia farmacológica que la psicoterapia.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 63, 'Sin clasificar', 'Una chica de 16 años acude a urgencias por pérdida de peso. Comenta que se ve gorda. Tiene amenorrea desde hace tres meses, y niega tener relaciones sexuales. Ha perdido 16 kg en los últimos ocho meses. Ahora hace ejercicio durante todo el día. En el examen físico, se constata que la paciente tiene un índice de masa corporal de 12,31 y está caquéctica. Una vez descartadas complicaciones médicas agudas, ¿cuál sería la actitud terapéutica aconsejable para esta paciente?:', 'Organizar un plan terapéutico ambulatorio, en el que se incluya la participación de psiquiatra y psicólogo.', 'Ingresar a la paciente en una Unidad de Psiquiatría para mejorar su estado nutricional en primer lugar y posteriormente proceder al desarrollo de una psicoterapia específica.', 'Enviar cuanto antes a la paciente a consulta de un Nutricionista para realizar un plan dietético adecuado.', 'Derivar a un Hospital de Día de Trastornos de la Conducta Alimentaria.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 64, 'Sin clasificar', 'En un ensayo clínico controlado, se ha comparado la eficacia de un nuevo colirio para ralentizar el desarrollo de catarata senil en hombres y mujeres sanos de 60 años. Tras 5 años de tratamiento, en el grupo control (placebo) la incidencia de catarata fue del 10% en mujeres y del 8% en hombres. En el grupo de intervención con el nuevo colirio, la incidencia de cataratas fue la mitad de la observada en el grupo control (placebo) tanto en mujeres como en hombres (5% y 4%, respectivamente). Señale la respuesta CORRECTA, en relación con la eficacia de este nuevo colirio según el género:', 'Es más eficaz en mujeres, porque el valor de NNT estimado en hombres es superior al de las mujeres.', 'Es más eficaz en hombres, porque el valor de NNT estimado en mujeres es inferior al de hombres.', 'Es igual de eficaz en mujeres y hombres, porque en ambos casos la incidencia es la mitad en el grupo de intervención con el colirio.', 'Es más eficaz en hombres, porque el valor de NNT estimado en mujeres es superior al de mujeres.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 65, 'Sin clasificar', 'Un hombre acude a la consulta para la revisión del tratamiento farmacológico de un síndrome coronario crónico. Si no existen comorbilidades, ni otro tipo de factores asociados, ¿qué fármaco de mantenimiento debería tomar este paciente para la prevención de complicaciones graves y mejora de la supervivencia?:', 'Nifedipino.', 'Acenocumarol.', 'Ácido acetilsalicílico.', 'Enalapril.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 66, 'Sin clasificar', 'Según normativa española vigente, ¿en qué situación debe estar un medicamento sometido a “prescripción médica restringida”?:', 'Cuando no es necesaria la intervención de ningún facultativo para realizar la receta del medicamento.', 'Cuando el preparado contiene alguna sustancia homeopática y sigue un procedimiento de fabricación descrito en la farmacopea oficial.', 'Cuando se prescribe para alguna enfermedad cuyo diagnóstico se debe realizar en un centro hospitalario.', 'Cuando puede producir algún riesgo considerable de abuso, dependencia o ser desviado para usos ilegales.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 67, 'Sin clasificar', '¿Cuál de las siguientes afirmaciones es correcta respecto al electrocardiograma (ECG) normal en la fisiología cardíaca?:', 'El complejo QRS representa la repolarización de los ventrículos.', 'La onda T indica la despolarización completa del músculo ventricular.', 'La onda P corresponde a la despolarización de las aurículas antes de la contracción auricular.', 'El electrodo ubicado cerca de la base del corazón registra una positividad durante la despolarización ventricular.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 68, 'Sin clasificar', '¿Cuál de las siguientes afirmaciones sobre la regulación intracelular del ion calcio es correcta?:', 'La concentración citosólica de calcio se mantiene baja gracias a bombas ATPasas que transportan calcio hacia el retículo endoplásmico.', 'El trifosfato de inositol (IP3) bloquea la liberación de calcio desde el retículo endoplásmico.', 'La entrada de calcio en la célula ocurre principalmente por difusión pasiva a través de la membrana.', 'El calcio intracelular no participa como segundo mensajero en la señalización celular.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 69, 'Sin clasificar', 'Una sustancia nefrotóxica se elimina por filtración glomerular y se reabsorbe pasivamente en el túbulo renal. Considerando que esta sustancia posee una pKa = 5 en el equilibrio ácido-base, ¿cuál de estas actuaciones consideras que puede reducir su nefrotoxicidad?:', 'Acidificaremos la orina con cloruro amónico, para aumentar la fracción ionizada de la sustancia y potenciar así la excreción renal de la sustancia.', 'Alcalinizaremos la orina con bicarbonato sódico, para aumentar la fracción ionizada de la sustancia y acelerar así su diuresis.', 'Acidificaremos la orina con cloruro amónico, para reducir la fracción ionizada de la sustancia y acelerar así la excreción renal de la sustancia.', 'No actuaremos de forma específica con el pH, porque la reabsorción y excreción renal de sustancias es independiente del pH urinario.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 70, 'Sin clasificar', 'En relación con el potencial de placa terminal en la unión neuromuscular, ¿cuál de las siguientes afirmaciones es correcta?:', 'Su amplitud depende de la suma temporal de los potenciales de acción en la fibra muscular.', 'Se origina principalmente por la apertura de receptores nicotínicos para acetilcolina que permiten el flujo de Na⁺ y, en menor cantidad, de K⁺.', 'Se genera cuando la acetilcolina activa conductos de Ca²⁺ dependientes de voltaje.', 'Se propaga a lo largo de toda la fibra muscular como un potencial de acción independiente.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 71, 'Sin clasificar', 'Un adulto toma comprimidos orales de morfina (60 mg/día) desde hace 9 meses por un dolor oncológico intenso. Como el dolor no está bien controlado, se decide sustituir la morfina por una dosis elevada de otro opioide que tiene una mayor potencia analgésica y una mayor afinidad por el receptor opioide que la propia morfina, pero una actividad intrínseca mucho más pequeña. Al día siguiente comienza con la nueva medicación. ¿Cuál será el efecto esperado de este cambio en el paciente?:', 'Un incremento del efecto analgésico y una mejora del control del dolor.', 'El desencadenamiento de un síndrome de abstinencia opioide.', 'La aparición de una marcada dificultad respiratoria.', 'El paciente no experimentará ningún cambio apreciable.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 72, 'Sin clasificar', 'En relación con la emisión del parte de lesiones, señale la afirmación correcta:', 'El parte de lesiones solo debe emitirse si la víctima solicita expresamente que se comunique a la autoridad.', 'Cuando el profesional sanitario atiende lesiones posiblemente derivadas de agresión, debe emitir parte y remitirlo al juzgado, incluso sin consentimiento de la víctima.', 'El parte de lesiones es obligatorio si existe ingreso hospitalario.', 'Si el paciente niega la agresión y solicita confidencialidad, el médico debe mantener el secreto profesional y no emitir el parte.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 73, 'Sin clasificar', 'Respecto a la Ley Orgánica 3/2021, de regulación de la eutanasia, señale la afirmación correcta:', 'Es necesario el consentimiento por representación para los menores de 18 años.', 'La prestación de ayuda para morir puede llevarse a cabo si está recogida por escrito en el Documento de Voluntades Anticipadas o instrucciones previas.', 'El médico responsable es quien decide el lugar en que debe producirse el fallecimiento.', 'La ley no contempla el ejercicio de la objeción de conciencia.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 74, 'Sin clasificar', 'La deliberación como proceso en situaciones clínicas complejas se define como:', 'Un método de toma de decisiones prudentes en condiciones de incertidumbre.', 'Un procedimiento de negociación para alcanzar un acuerdo entre partes.', 'La autorreflexión individual previa a la acción clínica.', 'La intervención de un mediador externo cuando existe conflicto de opiniones.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 75, 'Sin clasificar', 'En relación con la diferencia entre eutanasia y sedación paliativa, señale la afirmación correcta:', 'La sedación paliativa tiene como finalidad provocar deliberadamente la muerte para evitar el sufrimiento.', 'La eutanasia se realiza únicamente cuando el paciente está en situación de agonía inminente.', 'La sedación paliativa busca aliviar síntomas refractarios, aunque pueda acortar secundariamente la supervivencia.', 'En la eutanasia el alivio del sufrimiento es un efecto secundario no buscado.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 76, 'Sin clasificar', '¿Cuál de las siguientes afirmaciones sobre las quemaduras de espesor parcial profundo es correcta?:', 'Se caracterizan por dolor intenso y eritema marcado, sin formación de ampollas.', 'Afectan solo la epidermis y suelen sanar sin dejar cicatriz.', 'Presentan destrucción de la epidermis y dermis reticular, con pérdida de sensibilidad y mayor riesgo de infección.', 'No requieren injerto cutáneo ya que cicatrizan espontáneamente en menos de una semana.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 77, 'Sin clasificar', 'Respecto a la técnica de expansión tisular, la razón más frecuente de fallos es:', 'Bolsa pequeña respecto al expansor.', 'Llenado del expansor de forma muy lenta.', 'Mal cálculo de las medidas necesarias.', 'Llenado del expansor de forma rápida.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 78, 'Sin clasificar', 'Los tumores cerebrales metastásicos o secundarios son aquellas neoplasias que se diseminan e implantan en el cerebro, pero cuyo origen es un órgano de localización diferente a éste. Indique la respuesta CO- RRECTA acerca de estos tumores:', 'Las neoplasias secundarias son más infrecuentes que las neoplasias cerebrales primarias, representan sólo el 10% de los pacientes con diagnóstico de tumor cerebral.', 'Son tumores que típicamente se desarrollan durante la primera y segunda década de la vida.', 'Las neoplasias que con más frecuencia dan implantes cerebrales son aquellas originadas en el páncreas y en el hígado.', 'Cuando existen metástasis cerebrales múltiples, el tratamiento quirúrgico para lograr la extirpación completa de todas las lesiones no suele ser una opción posible.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 79, 'Sin clasificar', 'Con respecto al meningioma cerebral, indique la afirmación CORRECTA:', 'Son tumores bien definidos y de localización extraaxial, por lo que generalmente son extirpables quirúrgicamente de forma completa y esto puede ser curativo.', 'Los pacientes diagnosticados de meningioma deben realizarse un estudio genético a la hora de tener descendencia ante la herencia autosómica dominante de estos tumores.', 'Como son tumores de comportamiento benigno, no es necesario realizar un estudio anatomo-patológico completo puesto que el grado tumoral no influye en el tratamiento a realizar ni en el pronóstico posterior.', 'Las recidivas en estos tumores no dependen del grado tumoral y no son frecuentes.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 80, 'Sin clasificar', 'Paciente remitido a la consulta de cirugía torácica con el diagnóstico de un segundo episodio de neumotórax resuelto, tratados ambos con drenaje torácico. ¿Cuál sería la mejor recomendación?:', 'Reposo relativo y abstención de tabaco.', 'Colocación de un nuevo drenaje torácico.', 'Esperar a un tercer episodio para plantear cirugía.', 'Programar una intervención quirúrgica por videocirugía.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 81, 'Sin clasificar', 'El carcinoma adenoide quístico:', 'Es el tumor maligno más frecuente de las glándulas salivares.', 'Nunca afecta a las glándulas salivares menores a nivel del paladar.', 'Puede asociarse con parálisis facial debido a su neurotropismo.', 'Se debe tratar con radioterapia como primera opción terapéutica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 82, 'Sin clasificar', 'Respecto a la embolia y la trombosis en las extremidades inferiores, indica la correcta:', 'La trombosis arterial se da frecuentemente en pacientes con arritmia cardiaca.', 'Los pacientes con una embolia arterial refieren de forma habitual clínica de claudicación previa.', 'La embolia se trata habitualmente mediante anticoagulación.', 'En la angiografía de un paciente con trombosis arterial se objetiva mayor desarrollo de circulación colateral.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 83, 'Sin clasificar', 'En un paciente con estenosis de válvula aórtica, ¿Cuál te parece el tratamiento más adecuado?:', 'Recambio valvular en pacientes asintomáticos sin disfunción ventricular.', 'Recambio valvular en pacientes sintomáticos.', 'Reparación valvular en pacientes sintomáticos.', 'Valvuloplastia en estenosis aórtica grave y pacientes con bajo riesgo de reemplazo valvular.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 84, 'Sin clasificar', 'El síndrome de Stauffer es un síndrome paraneoplásico característico de (elija la correcta):', 'Cáncer de riñón.', 'Cáncer de próstata.', 'Cáncer de testículo.', 'Cáncer vesical.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 85, 'Sin clasificar', 'Varón de 57 años, sin comorbilidades asociadas. Presenta PSA 15 ng/ml y tacto rectal pétreo. La biopsia prostática revela adenocarcinoma de próstata Gleason 9 y el estudio de extensión muestra afectación ósea con más de 8 metástasis a nivel de esqueleto axial y metástasis hepáticas. Indique el tratamiento de elección:', 'Prostatectomía radical con linfadenectomía extendida y resección de las metástasis.', 'Radioterapia pélvica y radioterapia estereoatáxica de las metástasis.', 'Braquiterapia de alta tasa prostática.', 'Antiandrógenos inicialmente junto a análogos de LHRH y enzalutamida (nuevos antiandrógenos) y docetaxel.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 86, 'Sin clasificar', 'Indique la afirmación correcta sobre la cistectomía radical:', 'Es una cirugía que incluye la exéresis de vejiga, próstata (en el varón) y ganglios ilioobturatrices.', 'La morbimortalidad del procedimiento es muy baja comparada con procedimientos endoscópicos.', 'La derivación ureteral a piel o a intestino se realiza a los 5 días una vez el paciente se recupera del tiempo de exéresis.', 'Es el tratamiento de elección del cáncer de vejiga no musculo invasivo de alto grado.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 87, 'Sin clasificar', 'Paciente mujer de 61 años con Diabetes Mellitus II, colesterol elevado y con diagnóstico de vejiga hiperactiva desde 2021 por EUD (Estudio Urodinámico) sin más datos de interés. En tratamiento con Anticolinérgicos a dosis máximas desde 2022. En el último control en 2023 se le añade doble terapia anticolinérgicos + Agonista Beta 3. La paciente acude a la consulta y refiere no haber tenido mejoría en la sintomatología, ni con las medidas de uroterapia ni con los anticolinérgicos ni con la doble terapia de la última consulta. ¿Cuál es nuestro plan ahora?:', 'Retirar los anticolinérgicos y añadir Agonistas Beta 3 a dosis máximas.', 'Inyección de toxina botulínica intradetrusor.', 'Cateterismos intermitentes.', 'Enterocistoplastia de aumento.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 88, 'Sin clasificar', 'Mujer fumadora de 68 años, trabajadora de industria de caucho. Presenta polaquiuria, disuria y hematuria. Presenta urocultivo y ecografía sin alteraciones. Indique la afirmación correcta:', 'Dada la ausencia de patología tumoral en la ecografía es probable que presente vejiga hiperactiva por lo que se solicitará estudio urodinámico.', 'Ha de realizarse cistoscopia y citologías ante riesgo de carcinoma in situ vesical.', 'Lo más probable es que presente una pequeña litiasis vesical que expulsará espontáneamente dada la longitud y anchura de la uretra femenina.', 'La disuria descarta que la paciente presente patología tumoral.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 89, 'Sin clasificar', 'Joven de 33 años corredor habitual. Refiere dolor en cara externa de rodilla sobre todo en actividad deportiva, pero también al subir y bajar escaleras. El dolor se acentúa a la palpación del Epicóndilo Externo. ¿Cuál es la sospecha diagnóstica?:', 'Síndrome del Osgood-Schlatter.', 'Síndrome de la Cintilla Ilio-Tibial.', 'Enfermedad de Sever.', 'Trocanteritis.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 90, 'Sin clasificar', '¿Cuál de las siguientes es una red-flag durante la anamnesis y exploración física de una lumbalgia?:', 'Dolor lumbar de patrón mecánico.', 'Dolor a la palpación de espinosas.', 'Antecedentes personales de proceso neoplásico.', 'Paciente de 45 años.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 91, 'Sin clasificar', '¿Cuál de las siguientes lesiones traumáticas precisa, para evitar complicaciones locales, un tratamiento más precoz?:', 'Luxación traumática posterior de la cadera.', 'Fractura desplazada del cuello femoral del anciano.', 'Fractura trocantérica del anciano.', 'Fractura de cotilo.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 92, 'Sin clasificar', 'La fractura de Monteggia consiste en:', 'Fractura de cabeza radial con rotura de la membrana intraósea.', 'Fractura de cabeza radial con luxación de articulación radio-cubital distal.', 'Fractura de cubito proximal con luxación de la cabeza de radio.', 'Fractura de radio distal con luxación de articulación radio-cubital distal.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 93, 'Sin clasificar', 'En relación a las indicaciones de cirugía bariátrica, señale la correcta.', 'El IMC es la mejor medida de correlación entre exceso de peso y gravedad de la enfermedad.', 'El IMC es una medida útil, pero que no se utiliza para la indicación de cirugía bariátrica.', 'El punto de corte del IMC es de 55, independientemente de las enfermedades asociadas.', 'Paciente con IMC por debajo de 35 y enfermedades metabólicas poco controladas se pueden beneficiar de la cirugía bariátrica.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 94, 'Sin clasificar', 'La cirugía de elección en un paciente con un brote severo de colitis ulcerosa que desarrolla un megacolon tóxico es:', 'Proctocolectomía total + reservorio ileoanal+ ileostomía lateral.', 'Proctocolectomía total + ileostomía terminal.', 'Colectomía total + ileostomía terminal.', 'Colectomía total + anastomosis ileorrectal.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 95, 'Sin clasificar', 'La complicación más frecuente y grave de la duodenopancreatectomía cefálica es:', 'Hemorragia.', 'Absceso intrabdominal.', 'Fístula pancreática.', 'Infección herida.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 96, 'Sin clasificar', 'La estrategia de control de daños pretende evitar:', 'Hipertermia, acidosis y coagulopatía.', 'Acidosis, hipotermia y coagulopatía.', 'Hipotermia, alcalosis y coagulopatía.', 'Hipertermia, alcalosis y coagulopatía.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 97, 'Sin clasificar', 'Indica la afirmación FALSA en relación con la neoplasia mucinosa papilar intraductal (NPIM) del páncreas:', 'Se localiza en cabeza y cuerpo, pero el 10% es multifocal (skiplesions).', 'Se realiza una pancreatectomia total, ya que maligniza y es multifocal.', 'Existen tres tipos (I: ducto principal; II: rama secundaria III: mixto).', 'En el tipo I durante la CPRE (Colangiopancreatografía retrógrada endoscópica) se produce salida de moco de la papila.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 98, 'Sin clasificar', 'Varón de 83 años que acude a Urgencias Generales por cuadro de dolor a nivel inguinal izquierdo de 2 horas de evolución, con tumoración blanda y móvil asociada a la exploración. Se modifica con las maniobras de Valsalva y desaparece con el decúbito. Elija la respuesta CORRECTA:', 'El paciente presenta una hernia inguinal reductible a la exploración.', 'El paciente presenta una hernia inguinal incoercible a la exploración.', 'El paciente presenta una hernia inguinal con pérdida de derecho a domicilio en la exploración.', 'El paciente presenta una hernia inguinal estrangulada a la exploración.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 99, 'Sin clasificar', 'Entre los principios oncológicos en el tratamiento del cáncer de colon se encuentran todas las siguientes afirmaciones, EX- CEPTO:', 'Hay que realizar una resección intestinal con márgenes quirúrgicos amplios.', 'No hace falta hacer linfadenectomía.', 'Realizar resecciones en bloque si existe sospecha de infiltración de órganos vecinos.', 'En ocasiones se da tratamiento neoadyuvante con quimioterapia previa a la cirugía.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 100, 'Sin clasificar', '¿Cuál de las siguientes afirmaciones es correcta en relación al divertículo faringoesofágico de Zenker?:', 'Se trata de un divertículo por tracción.', 'Es más frecuente en pacientes jóvenes.', 'Entre sus síntomas se encuentran: disfagia, regurgitación y halitosis.', 'La localización especifica en la parte posterior de la faringe se denomina triángulo de Farabeuf.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 101, 'Sin clasificar', 'En un paciente con rinorrea acuosa unilateral y sospecha de fístula de líquido cefalorraquídeo, ¿cuál de las siguientes es una proteína que se considera marcador de líquido cefalorraquídeo?:', 'Albúmina.', 'Prealbúmina.', 'Beta 2 transferrina.', 'Mielina.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 102, 'Sin clasificar', 'Entre los siguientes tumores benignos de senos paranasales señale cuál de ellos se asocia con malignización:', 'Papiloma invertido.', 'Mucocele.', 'Schwannoma.', 'Osteoma.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 103, 'Sin clasificar', '¿Cuál de las siguientes afirmaciones sobre la otitis media secretoria es CIERTA?:', 'Es más frecuente en verano.', 'El tratamiento de elección es quirúrgico.', 'En la mayoría de los casos, la evolución natural es hacia la curación espontánea.', 'Los antihistamínicos son útiles para su resolución.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 104, 'Sin clasificar', 'En Neonatología ingresa desde paritorio un neonato grande para la edad gestacional con hemangioma facial, macroglosia y onfalocele, que desarrolla posteriormente crisis de hipoglucemia. ¿Cuál de las siguientes afirmaciones es FALSA?:', 'Se plantea el diagnóstico de Síndrome de Beckwith-Wiedemann.', 'La gestación por técnicas de reproducción asistida y/o detección ecográfica prenatal de polihidramnios puede estar entre sus antecedentes.', 'La causa más frecuente de este síndrome es la teratogénica.', 'No suele conllevar discapacidad intelectual, salvo complicaciones específicas asociadas como hipoxia o hipoglucemias no tratadas, entre otras.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 105, 'Sin clasificar', 'Una mujer de 37 años acude a consulta con su hijo de 14 años con discapacidad intelectual moderada-grave, sin otros hallazgos fenotípicos y conductuales significativos. Previamente le habían realizado al niño un Array-CGH y un estudio molecular de X Frágil, en los que no se detectó ninguna alteración. La señora desea planificar otra gestación y solicita asesoramiento genético previo. ¿Cuál de las siguientes afirmaciones es correcta?:', 'Dado que en los estudios genéticos de su hijo no se detectó ninguna alteración, no se sospecha causa genética subyacente y el riesgo de recurrencia de la discapacidad intelectual en su descendencia sería mínimo.', 'Con la información disponible se podría indicar un diagnóstico genético preimplantacional y/o prenatal específico para sus futuros embarazos.', 'Sería conveniente evaluar de nuevo al hijo y considerar previamente la realización de un estudio de secuenciación masiva, tipo exoma clínico.', 'Se le aconsejaría, dado el alto riesgo de recurrencia, que no planifique más embarazos.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 106, 'Sin clasificar', 'En un paciente diagnosticado de glaucoma de tensión normal, ¿Cuál de las siguientes características clínicas descartaría este diagnóstico?:', 'Presión intraocular < 21 mmHg.', 'Angulo de drenaje cerrado en la gonioscopia.', 'Excavación papilar glaucomatosa.', 'Hipotensión sistémica nocturna.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 107, 'Sin clasificar', '¿Qué hallazgo en el fondo del ojo sugiere más frecuentemente la existencia de una metástasis coroidea?:', 'Masa Pigmentada.', 'Drusas blandas.', 'Lesión amarillenta subretiniana.', 'Neovasos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 108, 'Sin clasificar', 'Nos avisan del mostrador por un paciente de nuestro cupo que refiere dificultad para respirar. El paciente pasa rápidamente a la sala de tratamientos donde enfermería realiza una primera evaluación con toma de constantes mientras nosotros vamos llegando. A la exploración se objetivan sibilantes, tos, habla conservada, frecuencia Cardíaca 96 lpm, presión Arterial 123/78, sin uso de musculatura accesoria, frecuencia Respiratoria 18 resp/min y saturación O2 96%. ¿Cuál sería la actuación más correcta?:', 'Estamos ante una crisis de asma leve, agonistas Beta -2 de acción corta con cámara entre 2 y 4 inhalaciones cada 20 minutos en la primera hora hasta mejoría. Si mejoría alta con prednisonavia oral 5-7 días y glucocorticoide inhalado más LABA, un plan de acción por escrito y revisión en consulta.', 'Estamos ante una crisis de asma moderada, agonistas Beta-2 de acción corta con ipatropio nebulizado y oxígeno en gafa nasal. Tras mejoría alta con glucocorticoide inhalado más LABA, prednisonavia oral 5-7 días, un plan de acción por escrito y revisión en consulta.', 'Estamos ante una crisis de asma moderada, agonistas Beta-2 de acción corta con ipatropio nebulizado y oxígeno en gafa nasal. Tras mejoría alta con amoxicilina 500 cada 12 horas pauta corta de 5 dias, glucocorticoide inhalado más LABA, prednisonavia oral 5-7 días, un plan de acción por escrito y revisión en consulta.', 'Estamos ante una crisis de asma moderada, agonistas Beta-2 de acción corta con ipatropio nebulizado y oxígeno en gafa nasal. Y traslado al hospital con ambulancia para tratamiento.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 109, 'Sin clasificar', 'El envejecimiento poblacional es uno de los grandes desafíos de nuestra sociedad. En la consulta del médico de familia debemos usar herramientas para intentar mejorar la calidad de vida de nuestros mayores. Debemos adaptarnos a esta realidad, ofreciendo una atención integral, centrada en la persona y orientada a la prevención, la autonomía y la calidad de vida de dichos pacientes. Si hablamos de atención al anciano en Atención Primaria, elige la respuesta INCO- RRECTA:', 'La prescripción en cascada ocurre cuando se prescribe un fármaco para tratar síntomas originados por otro fármaco pensando que tiene una condición clínica nueva y no pensando en una reacción adversa o secundaria del fármaco inicial.', 'El deterioro funcional y el aumento del riesgo de enfermedad podría considerarse algo normal con el paso de los años, pero la vejes es diversa y sus cambios están influidos por factores genéticos, ambientales o socioeconómicos.', 'Entre las pruebas para la detección de la fragilidad está la escala de Frail que evalúa cinco dominios: fatiga, resistencia, mide la incapacidad para bajar escaleras, la deambulación y el aumento de peso.', 'En la consulta podemos detectar la fragilidad con múltiples pruebas y test, entre ellos podemos realizar el test de la marcha o el de test de la silla (timed up-and-go).', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 110, 'Sin clasificar', 'En el cálculo del riesgo cardiovascular, si usamos el SCORE 2 para la zona de Europa bajo riesgo/España, nos hacen falta todas las siguientes variables, señala la verdadera:', 'Edad, sexo, tabaco, presión arterial sistólica, colesterol total y colesterol LDL.', 'Edad, sexo, tabaco, presión arterial sistólica, colesterol total y lipoproteína A.', 'Edad, sexo, tabaco, presión arterial sistólica, colesterol total y colesterol HDL.', 'Edad, sexo, tabaco, presión arterial sistólica, colesterol total, lipoproteína A, triglicéridos.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 111, 'Sin clasificar', 'Acude David, paciente de 21 años sin cita, a tu consulta. En su anamnesis refiere tos y odinofagia de 48 horas de evolución. En la exploración presenta exudado amigdalar, eritema en pilares posteriores faríngeos, temperatura de 38,3º C y adenopatía laterocervical derecha dolorosa. No es alérgico a ninguna medicación. Está preocupado por el tratamiento que le vas a recetar porque le cuesta mucho ‘tragar las pastillas’, señale la respuesta correcta:', 'Ante la presencia de cuatro criterios de Centor, realizar test rápido de Estreptococo e iniciar tratamiento con Amoxicilina.', 'Ante la presencia de tres criterios de Centor, realizar test rápido de Estreptococo y si es positivo iniciar tratamiento con Amoxicilina.', 'Presenta un cuadro típico de faringitis, no es necesario test rápido de Estreptococo y se debería iniciar tratamiento con Amoxicilina.', 'Ante la presencia de dos criterios de Centor realizar test rápido de Estreptococo y si es positivo iniciar tratamiento con Azitromicina 500 mg/24 h durante tres días.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 112, 'Sin clasificar', 'En el tratamiento de la Diabetes, sobre los beneficios y complicaciones de los fármacos, ¿Cuál de las siguientes afirmaciones es INCORRECTA?:', 'La metformina es el fármaco más usado, puede disminuir los niveles de vitamina B 12 y hay que vigilar el filtrado glomerular, si desciende por debajo de 30 ml/min hay que suspenderla.', 'Los iSGLT2 bajan peso y minimizan la progresión de la Enfermedad Renal Crónica y la Albuminuria.', 'Los iDPP4 pueden disminuir la glicada entre 0,6-0,9 %, tienen un efecto neutro sobre el peso pero son mal toleradas y se desaconsejan en los pacientes mayores.', 'La tirzepatida (agonista dual GIP + aGLP1) ha demostrado bajadas de peso importante y beneficio en la esteatosis hepática asociada a disfunción metabólica (MASH).', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 113, 'Sin clasificar', 'Acude Antonia acompañada de su hijo al Centro de Salud, solicitando ayuda para pedir la ley de dependencia. ¿Cuál de las siguientes escalas básicas para valorar el área cognitiva y sus actividades básicas de la vida diaria debería realizarle su médico de familia?:', 'Test de Zarit y Apgar familiar.', 'Escala de Goldberg y Rosemberg.', 'Escala de Barthel y test de Pfeiffer.', 'Escala de Norton y escala de Gijón.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 114, 'Sin clasificar', 'A tu consulta de Atención Primaria acude Fidel acompañado de su inseparable botellita de agua y su paquete de tabaco en el bolsillo de la camisa. Es un paciente conocido con EPOC. Está preocupado por su tratamiento. Su vecina Paqui le ha dicho “los corticoides son muy malos” por lo que ha decidido suspender su tratamiento inhalado. El paciente está con triple terapia, ha tenido un ingreso en el último año por reagudización de ENFERMEDAD PULMO- NAR OBSTRUCTIVA CRÓNICA, presenta una disnea mMRC 2 en la escala de disnea modificada y en sus analíticas presenta una eosinofilia media mayor de 300/mm3. ¿Qué deberíamos proponer a Fidel?:', 'Es un paciente categoría GOLD E de la guía Global Initiative for Chronic Obstructive Lung Disease y no necesita corticoides inhalados. Explicamos al paciente su enfermedad y el porqué de su tratamiento.', 'Es un paciente riesgo alto, no agudizador eosinofílico. Explicamos enfermedad y el porqué de su tratamiento y retiramos corticoide inhalado.', 'Es un paciente riesgo alto, retiramos corticoide inhalado y ponemos doble broncodilatación. Explicamos al paciente su enfermedad y el porqué de su tratamiento.', 'Es un paciente riesgo alto agudizador eosinofílico, debe mantener triple terapia, explicamos al paciente su enfermedad y el porqué de su tratamiento.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 115, 'Sin clasificar', 'Acude a urgencias un paciente que comenzó con dolor torácico hace 10 minutos estando comiendo en un restaurante cerca del hospital. El electrocardiograma muestra una elevación del segmento ST de 2 mm en derivaciones precordiales desde V1 a V4 ¿Cuál de las siguientes afirmaciones es correcta?:', 'Realizaremos una analítica de sangre con determinación de troponinas para determinar si es un infarto y así activar un cateterismo urgente.', 'Administraremos dosis de carga de aspirina lo antes posible.', 'El cateterismo ha de realizarse de forma urgente en menos de 2 horas siendo la vía femoral la primera opción por ser la más rápida.', 'Sospecharemos una lesión coronaria trombótica oclusiva en la arteria circunfleja.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 116, 'Sin clasificar', '¿En cuál de los siguientes escenarios NO ESTÁ INDICADO el implante de un DAI (desfibrilador automático implantable) ?:', 'Paciente con síndrome de Brugada y síncopes de repetición sin pródromos y recuperación rápida.', 'Paciente con miocardiopatía hipertrófica y puntuación de score de riesgo de muerte súbita Hypertrophic Cardiomyopathy – Sudden Cardiac Death (HCM-SCD) de 7%.', 'Paciente con miocardiopatía dilatada isquémica con infarto de todo el territorio anterior hace 3 meses, disnea de moderados esfuerzos a pesar del tratamiento médico y Fracción de Eyección del Ventrículo Izquierdo (FEVI) 30%.', 'Paciente ingresado seis días con infarto agudo de miocardio revascularizado con stent en el ingreso y FEVI del 35% antes del alta.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 117, 'Sin clasificar', '¿Cuál de las siguientes afirmaciones es FALSA en relación con los anticoagulantes orales de acción directa (ACODs)?:', 'Existen algunos ensayos clínicos que avalan su uso en pacientes en hemodiálisis.', 'Tienen menos riesgo de hemorragia intracraneal que los antagonistas de la vitamina K.', 'Pueden administrarse en pacientes con valvulopatías y portadores de todo tipo de prótesis cardíacas.', 'Son igual o más eficaces que los antagonistas de la vitamina K para prevenir ictus isquémicos.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 118, 'Sin clasificar', 'Respecto a la estenosis aórtica severa, ¿cuál de las siguientes afirmaciones es FALSA?:', 'Si en la auscultación existe un desdoblamiento normal del segundo ruido cardiaco, descartaremos una estenosis aórtica severa con bastante probabilidad.', 'En pacientes más jóvenes, la etiología más frecuente de la misma es la válvula unicúspide.', 'Si es sintomática y el paciente tiene más de 70 años se recomienda una prótesis percutánea tipo Transcatheter Aortic Valve Implantation (TAVI).', 'La estenosis aórtica severa de bajo flujo y bajo gradiente el TAC cardíaco con valoración del calcio valvular es de utilidad.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 119, 'Sin clasificar', '¿Cuál de los siguientes síncopes NO ingresaría en cardiología para completar estudio?:', 'Varón de 45 años con tres episodios de síncope precedido de cortejo vegetativo y recuperación lenta en el último año.', 'Varón de 75 años con fracción de eyección del ventrículo izquierdo del 40%.', 'Varón de 75 años con ECG con bloqueo completo de rama izquierda del haz de His.', 'Mujer de 37 años con síncope en reposo precedido de palpitaciones.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 120, 'Sin clasificar', 'En lo que respecta al diagnóstico de la estenosis aórtica, ¿qué afirmación es FALSA?:', 'La ergometría con intercambio de gases es una prueba que ha de realizarse a todos los pacientes con síntomas.', 'La ecocardiografía transesofágica puede ser útil si existen dudas de la severidad.', 'El TAC cardíaco es una prueba indispensable previa al implante de una prótesis biológica aórtica percutánea tipo Transcatheter Aortic Valve Implantation (TAVI).', 'En pacientes con estenosis aórtica de bajo flujo y bajo gradiente con función ventricular izquierda deprimida, la ecocardiografía de estrés con dobutamina estaría indicada.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 121, 'Sin clasificar', 'Varón de 56 años fumador sin otros factores de riesgo cardiovascular que acude a urgencias por dolor torácico opresivo desde hace 4 horas con un electrocardiograma inicial que muestra elevación del segmento ST en derivaciones II, II y aVF de 2 mm. A su llegada además se objetiva en la exploración física: tensión arterial 80/40 mmHg, frecuencia cardíaca 40 lpm e ingurgitación de la vena yugular, saturación de O2 basal del 95%. Auscultación cardíaca sin soplos destacables ni edemas. ¿Cuál es el diagnóstico más probable?:', 'Infarto agudo de miocardio con elevación del segmento ST inferior.', 'Infarto agudo de miocardio con elevación del segmento ST inferior con rotura del músculo papilar posterior-medial.', 'Infarto agudo de miocardio con elevación del segmento ST inferior y de ventrículo derecho.', 'Infarto con elevación del segmento ST inferior con rotura del septo interventricular.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 122, 'Sin clasificar', 'Respecto a la contracción global y segmentaria del ventrículo izquierdo, señale la respuesta CORRECTA:', 'Ante un paciente que ingresa por insuficiencia cardiaca y vemos en el estudio ecocardiográfico que presenta una miocardiopatía dilatada con disfunción ventricular y un aneurisma apical (con la pared adelgazada e hiperecogénica), debemos pensar en un infarto agudo de la descendente anterior (DA) y activar código infarto para un cateterismo urgente.', 'El diagnóstico de la miocardiopatía por estrés (Tako-Tsubo) es posible a partir del electrocardiograma y la ecocardiografía (discinesia/hipocinesia severa de todos los segmentos apicales del ventrículo izquierdo con contractilidad preservada de los segmentos basales).', 'Los trombos intraventriculares los veremos con más frecuencia adheridos a los segmentos del ventrículo izquierdo que mejor contracción presentan.', 'En la miocardiopatía arritmogénica no veremos afectada ni en la ecocardiografía ni en la resonancia cardíaca la contractilidad segmentaría del ventrículo izquierdo.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 123, 'Sin clasificar', '¿Cuál de estos signos o síntomas NO sugiere taponamiento en presencia de derrame pericárdico severo sin otra patología?:', 'Hipotensión arterial refractaria a fluidoterapia intensiva.', 'Variación de velocidades de llenado mitral y tricúspide menor del 25% con la inspiración.', 'Colapso de aurícula derecha y ventrículo derecho en diástole.', 'Situación de parada cardiorrespiratoria con actividad eléctrica sin pulso.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 124, 'Sin clasificar', 'Respecto a la miocardiopatía hipertrófica, ¿cuál es la respuesta CORRECTA?:', 'Para hacer un diagnóstico de miocardiopatía hipertrófica, no es necesario excluir otras causas cardiacas o sistémicas de sobrecarga del ventrículo izquierdo (hipertensión arterial, estenosis aórtica, enfermedades infiltrativas, etc..).', 'La obstrucción a nivel del tracto de salida del ventrículo izquierdo es típica, pero también la podemos encontrar en pacientes con hipertrofia por otro motivo, en el contexto de algún factor desencadenante como deshidratación o estados hiperdinámicos.', 'El patrón de realce con gadolinio en la resonancia cardíaca típicamente es en anillo subendocárdico.', 'La insuficiencia mitral que vemos característicamente en la miocardiopatía hipertrófica obstructiva suele ser central por dilatación del anillo.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 125, 'Sin clasificar', 'Mujer de 84 años con enfermedad de Alzheimer en fase terminal, institucionalizada desde hace tres años, dependiente para todas las actividades básicas y sin lenguaje comprensible. En los últimos seis meses ha requerido tres ingresos por neumonía por aspiración. Tras la última alta, ya en la residencia no acepta alimentos ni líquidos, mantiene la boca cerrada y rechaza la alimentación incluso con ayuda. Su hija, muy angustiada, pide “que se le ponga algo para alimentarla, aunque sea por una sonda”. ¿Cuál es la actuación más adecuada en esta situación?:', 'Colocar una gastrostomía para asegurar el aporte nutricional y explicarle a la hija que debe vigilar que su madre no se la retire.', 'Iniciar nutrición parenteral periférica y tranquilizar a la hija diciéndole que así su madre “seguirá recibiendo alimento, aunque no coma”.', 'Explicar a la hija que la falta de apetito y deglución son parte del proceso natural y ofrecer cuidados centrados en aliviar el malestar y proporcionar confort.', 'Intentar alimentación con espesantes y suplementos hipercalóricos durante unos días, animando a la hija a insistir en que su madre abra la boca y no tosa.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 126, 'Sin clasificar', 'Señale cuál de los siguientes se considera un “Hallmark” o marca del envejecimiento de tipo primario:', 'Desregulación en la señalización de nutrientes.', 'Acortamiento de los telómeros.', 'Disfunción mitocondrial.', 'Agotamiento de células madre.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 127, 'Sin clasificar', 'El Índice de Barthel de un paciente que presenta incontinencia urinaria ocasional, y supervisión física para deambular y subir escaleras, pero es independiente para el resto de las actividades básicas de la vida diaria, es:', '65', '75', '85', '95', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 128, 'Sin clasificar', 'Un paciente de 68 años con adenocarcinoma de páncreas metastásico en situación de últimos días de vida presenta en las últimas 24 horas agitación, desorientación y alucinaciones visuales. Recibe morfina subcutánea en perfusión continua, dexametasona y midazolam a demanda. En la exploración presenta ictericia y asterixis, sin fiebre ni signos de focalidad neurológica. Los análisis muestran bilirrubina 9 mg/dL, transaminasas x4 y amonio elevado. ¿Cuál de las siguientes medidas farmacológicas es más adecuada en este contexto?:', 'Aumentar la dosis de dexametasona y añadir midazolam.', 'Administrar haloperidol y valorar ajustar fármacos potencialmente implicados (como corticoides y morfina)', 'Iniciar lactulosa y rifaximina para tratar una posible encefalopatía hepática.', 'Sustituir la morfina por buprenorfina sublingual para reducir efectos neurotóxicos.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 129, 'Sin clasificar', 'Un paciente con carcinoma de pulmón avanzado recibe morfina oral de liberación prolongada, 120 mg cada 12 horas, con medicación extra frecuente, de hasta 3 ó 4 veces al día. A pesar de ello, refiere dolor persistente (EVA 7/10). En los últimos días ha presentado mioclonías, sueños vívidos y leve confusión intermitente, sin fiebre ni datos de progresión tumoral. La función renal muestra un filtrado glomerular estimado de 40 mL/min/1,73m². ¿Cuál de las siguientes estrategias es la más adecuada para optimizar el control del dolor y mejorar la sintomatología?:', 'Aumentar la dosis de morfina un 25–50 % y asociar benzodiacepinas para controlar las mioclonías.', 'Reducir la dosis de morfina a la mitad y añadir un coadyuvante no opioide (AINE).', 'Rotar a fentanilo transdérmico calculando la dosis equianalgésica y reduciéndola un 30–50 % por tolerancia cruzada incompleta.', 'Suspender el opioide oral y sustituirlo por buprenorfina sublingual a dosis bajas.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 130, 'Sin clasificar', 'Un hombre de 81 años, independiente para las actividades básicas, con hipertensión y diabetes bien controladas, es diagnosticado de adenocarcinoma de próstata oligometastásico, con un PSA de 42 ng/mL y una única lesión ósea asintomática en el sacro. Su estado funcional (ECOG 1) es bueno, aunque presenta fragilidad leve y polifarmacia. El equipo médico debate distintas estrategias terapéuticas (tratamiento hormonal, radioterapia dirigida o vigilancia). Antes de decidir la mejor opción terapéutica, ¿qué aspectos deben considerarse de forma prioritaria en este paciente?:', 'El nivel de PSA y el número de lesiones metastásicas detectadas.', 'La posibilidad de aplicar el tratamiento más agresivo disponible, dado que hay enfermedad metastásica.', 'Comorbilidades, el estado funcional y la expectativa de vida.', 'La edad cronológica del paciente como criterio principal para limitar el tratamiento.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 131, 'Sin clasificar', '¿Cuál es la técnica de elección para la determinación de la expresión de PDL1 en muestra tumoral?:', 'Secuenciación masiva.', 'Inmunohistoquímica.', 'Western blot.', 'Hibridación in situ (FISH).', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 132, 'Sin clasificar', 'Varón de 63 años con carcinoma de próstata resistente a la castración con metástasis ganglionares y óseas múltiples. Actualmente, se encuentra en tratamiento con Enzalutamida. Acude a consulta por dolor lumbar de reciente aparición, aunque refiere no haber tomado analgesia. Reconoce episodios de incontinencia urinaria. A la exploración se detecta un ligero déficit motor en extremidad inferior izquierda (3/5). ¿Cuál sería la mejor actitud a seguir con este paciente?:', 'Realización de resonancia magnética urgente.', 'Administración de dexametasona 10 mg.', 'Administración de AINEs y reevaluación en 48 horas.', 'Realización de radiografía simple de columna.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 133, 'Sin clasificar', 'Paciente varón de 63 años con antecedentes de miastenia gravis. Ha sido diagnosticado recientemente de melanoma estadio IV con extensa carga de enfermedad con afectación hepática múltiple, pulmonar bilateral y adenopatías generalizadas. Se realiza una determinación de BRAF por inmunohistoquímica siendo positiva para V600E. ¿Cuál sería el tratamiento más razonable teniendo en cuenta el riesgo beneficio?:', 'Pembrolizumab.', 'Nivolumab.', 'Dabrafenib-Trametinib.', 'Nivolumab-Ipilimumab.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 134, 'Sin clasificar', 'Paciente de 92 años que acude a la consulta de Atención Primaria y se le realiza una evaluación de fragilidad según los criterios de Linda P. Fried. Objetivamos los siguientes resultados: Pérdida de peso de 2kg el año previo, fuerza prensora normal para su IMC, no refiere baja resistencia o agotamiento, presenta lentitud de la marcha y un nivel normal de actividad física. ¿Cuál sería su nivel de fragilidad?:', 'Robusto.', 'Pre-frágil.', 'Frágil.', 'Discapacitado.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 135, 'Sin clasificar', 'Acude a urgencias un varón de 25 años con una uveítis anterior izquierda. En su historial clínico únicamente destaca que ha tenido úlceras orales dolorosas con cierta frecuencia en los últimos dos años. Refiere la aparición de una pápula eritematosa alrededor del sitio de punción de la vacuna antigripal, que recibió recientemente. ¿Cuál es el diagnóstico más probable?:', 'Sarcoidosis.', 'Sífilis.', 'Enfermedad de Behçet.', 'Enfermedad de Crohn.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 136, 'Sin clasificar', 'Acude a su consulta un varón de 70 años con rigidez matutina y dolor a la movilización de cintura escapular y pélvica bilateral, desde hace tres meses, sin afectación de otras articulaciones periféricas. En la analítica destacan una leve anemia normocítica normocrómica y una velocidad de sedimentación glomerular de 85 mm en la primera hora. El factor reumatoide y los anticuerpos antipeptídicos citrulinados son negativos. ¿Cuál es su diagnóstico?:', 'Artritis reumatoide seronegativa.', 'Polimialgia reumática.', 'Artritis indiferenciada.', 'Artrosis.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 137, 'Sin clasificar', 'En un paciente ingresado por un shock hipovolémico, con oliguria ¿cuál de los siguientes hallazgos sugiere el desarrollo de necrosis tubular aguda?:', 'Sodio urinario < 20 mEq/L.', 'Excreción fraccional de sodio <1%.', 'Cociente creatinina urinaria/creatinina plasmática mayor de 40.', 'Osmolalidad urinaria menor de 350 mOsmoles/Kg.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 138, 'Sin clasificar', 'Varón de 80 años con gonartrosis. Acude a estudio preoperatorio previo a prótesis de rodilla derecha. Su hemograma es normal. Los tests de coagulación muestran INR:1, tiempo de cefalina-caolín 47´´ (valor normal 27-37). La agregación plaquetaria con ristocetina está ligeramente alterada, pero es normal con colágeno y ADP. El paciente no refiere ninguna clínica hemorrágica. ¿Cuál es la causa de esta alteración en las pruebas de coagulación?:', 'Heterocigosis para hemofilia A.', 'Enfermedad de von Willebrand tipo I.', 'Anticoagulante lúpico.', 'Síndrome de Bernard-Soulier.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 139, 'Sin clasificar', 'Mujer de 55 años diagnosticada de lupus eritematoso sistémico. Consulta por astenia en los últimos tres meses. En la analítica destacan eritrocitos: 3x10¹²/L, Hemoglobina: 9,1 g/dL, volumen corpuscular medio: 81 fL, reticulocitos: 250x10⁹/L, leucocitos: 7.2x10⁹/L, plaquetas: 230x10⁹/L. Sideremia: 25 mcg/dL, saturación de transferrina: 19%. Ferritina: 400 ng/mL ¿Qué tipo de anemia tiene esta paciente?:', 'Anemia inflamatoria crónica.', 'Anemia ferropénica.', 'Anemia hemolítica.', 'Talasemia menor.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 140, 'Sin clasificar', 'Varón de 55 años que tuvo un síndrome coronario agudo hace un año. Acude a consulta de su médico de atención primaria para hacer una revisión, encontrándose asintomático. Su presión arterial es de 135/85 mmHg, sus niveles de colesterol- LDL son de 100 mg/dL. En relación con la prevención secundaria de la cardiopatía isquémica, ¿es necesario hacer algún ajuste terapéutico?:', 'Hay que optimizar el tratamiento antihipertensivo porque los niveles de presión arterial están por encima de los niveles objetivo.', 'Hay que optimizar el tratamiento hipolipemiante porque los niveles de colesterol- LDL están por encima de los niveles objetivo.', 'Tanto los niveles de presión arterial como los niveles de colesterol-LDL se encuentran dentro del rango objetivo.', 'Hay que optimizar el tratamiento de la presión arterial y el tratamiento hipolipemiante.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 141, 'Sin clasificar', 'Acude al servicio de urgencias una mujer de 67 años con astenia, náuseas y cefalea. Tiene antecedentes de hipertensión arterial actualmente en tratamiento con enalaprilhidroclorotiazida (20/12.5mg) y diabetes mellitus tipo 2 en tratamiento con metformina. Su tensión arterial es de 138/88 mmHg y su frecuencia cardíaca 80 latidos por minuto. La exploración física es normal, se encuentra bien hidratada y no tiene edemas. En la analítica realizada en urgencias encontramos: sodio 122 mEq/L, potasio: 4.3mEq/L, creatinina 0.8mg/dL. La osmolalidad plasmática es 257mOsm/kg y el sodio urinario 45 mEq/L. Hace un mes estuvo en la consulta de su médico de familia, quien le cambió el tratamiento antihipertensivo y le hizo una analítica general que fue normal. ¿Cuál es su diagnóstico?:', 'Hiponatremia inducida por tiazidas.', 'Insuficiencia suprarrenal.', 'Potomanía.', 'Pseudohiponatremia por hiperglucemia.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 142, 'Sin clasificar', 'Valora en la consulta a una paciente de 56 años por un cuadro de unos 10 días de febrícula, bocio de pequeño tamaño, levemente doloroso a la presión y que muestra un aumento de la vascularización tiroidea en la ecografía. Está ansiosa, levemente sudorosa. Su frecuencia cardíaca es de 100 latidos por minuto y su presión arterial de 145/75 mmHg ¿Cuál de las siguientes combinaciones de hallazgos complementarios esperaría según su sospecha diagnóstica?:', 'TSH baja, T4 libre elevada, anticuerpos estimulantes del tiroides negativos e hipocaptación de iodo en la gammagrafía tiroidea.', 'TSH baja, T4 libre elevada, anticuerpos estimulantes del tiroides positivos e hipercaptación de iodo en la gammagrafía tiroidea.', 'TSH elevada, T4 libre elevada, anticuerpos estimulantes del tiroides negativos e hipercaptación de iodo en la gammagrafía tiroidea.', 'TSH baja, T4 libre elevada, anticuerpos estimulantes del tiroides positivos e hipocaptación de iodo en la gammagrafía tiroidea.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 143, 'Sin clasificar', 'Un paciente de 39 años que presenta emisión recidivante de orina rojiza, episodios repetidos de dolor abdominal de etiología no diagnosticada, acude a urgencias con un nuevo episodio de dolor abdominal intenso. En los estudios realizados en urgencias se objetiva una trombosis venosa mesentérica. ¿Cuál es el diagnóstico de sospecha que considera más probable?:', 'Hemoglobinuria paroxística nocturna.', 'Síndrome antifosfolípido.', 'Coproporfiria eritropoyética.', 'Fiebre mediterránea familiar.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 144, 'Sin clasificar', 'Un paciente de 56 años ha perdido 10kg en el último año coincidiendo con un notable aumento de las deposiciones que son pastosas, amarillas y flotantes. Presenta dolor epigástrico-mesogástrico postprandial que limita la ingesta. Hace 4 años recibió tratamiento erradicador de Helicobacter Pylori por úlcera duodenal recidivante. ¿Cuál de las siguientes exploraciones en heces le parece más útil en el primer estudio para orientar el diagnóstico?:', 'Estudio coproparasitario.', 'Aclaramiento fecal de alfa-1-antitripsina.', 'Determinación de antígeno de Helicobacter Pylori en heces.', 'Cuantificación de elastasa fecal.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 145, 'Sin clasificar', 'Según el Real decreto 888/2022, ¿a partir de qué grado se reconoce oficialmente la condición de persona con discapacidad en España (anteriormente llamada “minusvalía”) ?:', '25%.', '30%.', '33%.', '45%.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 146, 'Sin clasificar', 'En la prescripción de ayudas para la marcha, es importante conocer qué músculos intervienen para potenciarlos en caso de que puedan estar deficitarios. ¿Cuál de los siguientes músculos NO es prioritario en el control de la marcha asistida?:', 'Flexores de dedos.', 'Extensores de muñecas.', 'Pronador redondo.', 'Tríceps braquial.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 147, 'Sin clasificar', 'Mujer de 72 años, con antecedentes personales de enfermedad pulmonar obstructiva crónica y artrosis. Toma antiinflamatorio no esteroideo clásico diario y ácido acetilsalicílico a baja dosis. Acude a urgencias por presentar melenas. En la endoscopia de urgencias se objetiva una úlcera gástrica Forrest III en curvatura menor, con biopsias negativas para malignidad y Helicobacter pylori negativo. Conducta más adecuada a medio plazo:', 'Reiniciar antiinflamatorio no esteroideo y ácido acetilsalicílico igual, con inhibidor de la bomba de protones 2 semanas.', 'Mantener inhibidor de la bomba de protones a dosis plenas, reevaluar la necesidad de antiinflamatorio no esteroideo y realizar endoscopia de control para confirmar cicatrización.', 'Cambiar inhibidor de la bomba de protones por antih2.', 'Cambiar antiinflamatorio no esteroideo por paracetamol e inhibidor de la bomba de protones a demanda.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 148, 'Sin clasificar', 'Paciente varón de 58 años, con historia de más de 15 años de pirosis y regurgitación, tratada de forma intermitente con inhibidores de la bomba de protones. No fumador, índice de masa corporal de 35 kg/m². Consulta por empeoramiento de los síntomas. Se realiza gastroscopia en la que se objetiva un segmento de mucosa columnar de 5 cm por encima de la unión esófago-gástrica (C3M5), sin lesiones nodulares. Se toman biopsias con el resultado siguiente: metaplasia intestinal con displasia de bajo grado en dos cilindros. La revisión por un patólogo experto en esófago de Barrett confirma la presencia de displasia de bajo grado verdadera. Según las recomendaciones actuales de manejo del Barrett con displasia confirmada, la actitud MÁS adecuada es:', 'Mantener inhibidor de la bomba de protones a demanda y repetir endoscopia de control a los 3 años.', 'Repetir endoscopia en 12 meses sin otras medidas, dado que es displasia de bajo grado.', 'Ofrecer ablación por radiofrecuencia mediante endoscopia en centro experto, manteniendo inhibidor de la bomba de protones.', 'Indicar esofaguectomía subtotal profiláctica por el riesgo acumulado de carcinoma.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 149, 'Sin clasificar', 'Paciente de 52 años, con pirosis y dolor retroesternal. Se le realiza una endoscopia alta en la que se observa esofagitis erosiva grado C de Los Ángeles. ¿Cuál de las siguientes afirmaciones es CORRECTA?:', 'Un ciclo corto de 2 semanas de inhibidor de la bomba de protones sería suficiente para asegurar la curación mucosa esofágica.', 'Debe plantearse tratamiento de mantenimiento con inhibidor de la bomba de protones a largo plazo.', 'Una vez curada la esofagitis, no existe riesgo aumentado de Barrett.', 'El tratamiento de elección son los anti-h2 nocturnos como monoterapia.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 150, 'Sin clasificar', 'Respecto a la diferenciación entre colitis ulcerosa y colitis de Crohn, señale la opción MÁS correcta:', 'La afectación parcheada y el recto respetado obligan siempre a diagnosticar Crohn.', 'La presencia de granulomas no caseificantes en biopsia colónica es fuertemente sugestiva de Crohn.', 'La afectación continua desde el recto hasta el ciego es típica de Crohn colónica pura.', 'La afectación del íleon terminal nunca aparece en la colitis ulcerosa.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 151, 'Sin clasificar', 'Paciente con 23 años, quiere saber si es celíaco, porque su madre lo es. Pregunta sobre el estudio genético. Respecto al papel del estudio genético HLA-DQ2/DQ8 en enfermedad celíaca, señale la opción CO- RRECTA:', 'Es una prueba diagnóstica confirmatoria cuando es positiva.', 'Un resultado negativo para HLA-DQ2 y HLA-DQ8 hace muy improbable el diagnóstico de enfermedad celíaca.', 'Solo es útil en el cribado poblacional general.', 'Debe solicitarse de rutina en todos los pacientes con serología positiva.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 152, 'Sin clasificar', 'Paciente con pancreatitis aguda grave por litiasis biliar, necrosis extensa estéril del cuerpo y cola. A las 3 semanas, fiebre, dolor persistente, PCR elevada. En el TAC de abdomen con contraste se observa una colección encapsulada con niveles líquidoaire y necrosis pancreática. ¿Cuál es la conducta MÁS adecuada?:', 'Laparotomía urgente con necrosectomía abierta.', 'Mantener tratamiento conservador, la presencia de gas no sugiere infección.', 'Abordaje escalonado: drenaje mínimamente invasivo (endoscópico/percutáneo) guiado y necrosectomía diferida si es necesario.', 'Esclerosis percutánea con alcohol absoluto.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 153, 'Sin clasificar', 'En relación con el cribado de cáncer colorrectal en el síndrome de Lynch (MLH1/MSH2), señale la opción CO- RRECTA:', 'El paciente debe hacerse colonoscopias cada 10 años desde los 50 años.', 'El paciente debe hacerse colonoscopias cada 5 años desde los 40 años o 10 años antes del caso más joven.', 'El paciente debe hacerse colonoscopias cada 1-2 años desde los 20-25 años o 2- 5 años antes del caso más joven en la familia.', 'El paciente debe hacerse colonoscopias solo si test de sangre oculta en heces es positivo.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 154, 'Sin clasificar', 'Mujer de 55 años con diarrea acuosa crónica, no sanguinolenta, de meses de evolución, con colonoscopia macroscópicamente normal. Las biopsias colónicas muestran infiltrado inflamatorio de la lámina propia con banda colágena subepitelial engrosada >10 μm. El diagnóstico MÁS probable es:', 'Colitis ulcerosa izquierda.', 'Enfermedad de Crohn colónica.', 'Colitis microscópica linfocítica.', 'Colitis microscópica colágena.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 155, 'Sin clasificar', 'Paciente de 32 años con colitis ulcerosa extensa de 10 años de evolución, en remisión clínica y endoscópica, sin displasia en colonoscopias previas. ¿Cree que debe realizarse colonoscopias de revisión para la vigilancia endoscópica del cáncer colorrectal?:', 'No precisa vigilancia hasta los 20 años de evolución.', 'Debe realizarse colonoscopia con cromoendoscopia dirigida cada 3-5 años.', 'Solo es necesario control si presenta antecedentes familiares de CCR.', 'La biopsia aleatoria en todos los segmentos ha sustituido completamente a la cromoendoscopia.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 156, 'Sin clasificar', '¿Cómo se define actualmente la hipertensión pulmonar?:', 'Presión media en arteria pulmonar en reposo medida por cateterismo cardíaco > 20 mmHg.', 'Presión media en arteria pulmonar en reposo medida por cateterismo cardíaco > 25 mmHg.', 'Presión sistólica en arteria pulmonar en reposo medida por ecocardiografía > 25 mmHg.', 'Presión sistólica en arteria pulmonar en reposo medida por cateterismo cardíaco > 20 mmHg.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 157, 'Sin clasificar', '¿En qué casos debe priorizarse la indicación de tratamiento con CPAP para la apnea obstructiva del sueño (AOS)?:', 'Pacientes con índice de apneas-hipopneas (IAH) ≥ 5 eventos/hora sin síntomas ni comorbilidades.', 'Todo paciente con AOS independientemente de la clínica o las comorbilidades.', 'Pacientes con IAH ≥ 30 eventos/hora asintomáticos.', 'Pacientes con IAH ≥ 15 eventos/hora y somnolencia diurna (Epworth> 10 puntos).', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 158, 'Sin clasificar', 'En el Síndrome de Distrés Respiratorio Agudo (SDRA), ¿cuál de las siguientes opciones es el hallazgo fisiopatológico característico?:', 'Aumento del espacio muerto anatómico sin alteración del intercambio gaseoso.', 'Hipoxemia con PaO₂/FiO₂ ≤ 300 asociada a shunt intrapulmonar y disminución de la distensibilidad.', 'Hipercapnia leve con aumento de la compliance pulmonar.', 'Aumento de la presión alveolar de CO₂ con distensibilidad normal.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 159, 'Sin clasificar', 'Un paciente con bronquitis crónica tabáquica ha desarrollado hipertensión pulmonar crónica secundaria. ¿Cuál es el mecanismo fisiopatológico principal que produce la hipertensión arterial pulmonar en esta situación?:', 'Microtromboembolismo pulmonar crónico múltiple por disfunción endotelial hipóxica.', 'Remodelado vascular por disfunción endotelial primaria.', 'Vasoconstricción hipóxica crónica.', 'Disfunción ventricular izquierda y aumento retrógrado de la presión.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 160, 'Sin clasificar', 'En el contexto de la Fibrosis Quística (FQ), ¿qué función principal tiene la proteína CFTR en el epitelio de las vías respiratorias?:', 'Actúa como un canal que transporta cloro y regula la hidratación de las secreciones.', 'Transporta glucosa al interior de las células epiteliales para obtener energía.', 'Es una enzima que degrada el moco espeso acumulado en los bronquios.', 'Estimula la contracción de los cilios para expulsar las secreciones bronquiales.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 161, 'Sin clasificar', 'Mujer de 73 años, exbebedora importante, con cuadros de palpitaciones ocasionales no estudiados, intervenida hace 2 años de una neoplasia de mama izquierda, con resección completa y vaciamiento ganglionar que acude a consulta para estudio por una tos seca de 3 meses de evolución que va aumentando progresivamente. El cuadro se acompaña de sensación disneica con los esfuerzos. En la radiografía simple del tórax se aprecia un derrame pleural izquierdo. Se realiza una toracocentesis diagnóstica y nos da un líquido ligeramente hemático con la siguiente bioquímica: pH 7,34, proteínas 6,8 gr/dl (en plasma 8 gr/dl), glucosa 73 mg/dl (plasma 70 mg/dl). ¿Cuál es la causa más probable del derrame pleural?:', 'Insuficiencia cardíaca de novo.', 'Cirrosis hepática.', 'Metástasis pleural de la neoplasia de mama.', 'Síndrome nefrótico La citrulina se condensa con glutamato para formar argininosuccinato en el citosol.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 163, 'Sin clasificar', '¿En cuál de las siguientes enfermedades el lavado broncoalveolar NO tiene un papel relevante para el diagnóstico?:', 'Histiocitosis de células de Langerhans pulmonar.', 'Neumonía eosinofílica crónica.', 'Neumonía intersticial usual idiopática.', 'Sarcoidosis.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 164, 'Sin clasificar', '¿Cuál de los siguientes hallazgos en el líquido cefalorraquídeo (LCR) hace cuestionar el diagnóstico de esclerosis múltiple?:', 'Presencia de bandas oligoclonales.', 'Pleocitosis leve linfocitaria.', 'Hiperproteinorraquia>100 mg/dl.', 'Índice IgG elevado.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 165, 'Sin clasificar', '¿Cuál es la tríada clínica característica de la hidrocefalia normotensiva del adulto?:', 'Trastorno de la marcha, incontinencia urinaria y deterioro cognitivo.', 'Cefalea, vómitos y rigidez de nuca.', 'Diplopía, papiledema y tinnitus pulsátil.', 'Vómitos, bradicardia y alteración del nivel de conciencia.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 166, 'Sin clasificar', 'En relación con la narcolepsia tipo 1, ¿cuál de las siguientes afirmaciones es correcta?:', 'Se asocia a deficiencia de hipocretina (orexina) en el líquido cefalorraquídeo.', 'No cursa con cataplejía ni alteraciones del sueño REM.', 'Es más frecuente en mujeres y se asocia a exceso de serotonina.', 'No se relaciona con ningún alelo HLA específico.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 167, 'Sin clasificar', 'Respecto al diagnóstico diferencial de las crisis epilépticas, ¿cuál de las siguientes afirmaciones es correcta?:', 'Los síncopes neuromediados tienen una fase tónica prolongada.', 'En las crisis psicógenas el electroencefalograma (EEG) muestra siempre descargas epileptiformes.', 'La amnesia global transitoria cursa con pérdida de conciencia prolongada.', 'Los síncopes presentan recuperación rápida sin confusión proscritica.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 168, 'Sin clasificar', '¿Cuál de las siguientes características es típica de la cefalea tensional?:', 'Dolor pulsátil bilateral con fotofobia.', 'Dolor pulsátil unilateral.', 'Dolor opresivo bilateral.', 'Dolor que empeora con el ejercicio físico.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 169, 'Sin clasificar', '¿Cuál de los siguientes hallazgos apoya el diagnóstico de enfermedad de Parkinson según los criterios de la Movement Disorder Society (MDS)?:', 'Ausencia de respuesta al tratamiento con levodopa.', 'Pérdida de olfato.', 'Caídas recurrentes en los primeros años.', 'Disfunción cerebelosa precoz.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 170, 'Sin clasificar', 'En la exploración del tono muscular, ¿qué caracteriza a la hipertonía espástica?:', 'Aumento de la resistencia constante durante todo el movimiento.', 'Aumento de la resistencia dependiente de la velocidad del movimiento.', 'Disminución del tono con ausencia de resistencia.', 'Resistencia irregular con fenómeno de rueda dentada.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 171, 'Sin clasificar', 'Una mujer de 53 años es diagnosticada de vólvulo de intestino medio e isquemia intestinal. Se realiza laparotomía para liberar la obstrucción intestinal. ¿Cuál de las siguientes estructuras se usa como punto de referencia anatómico para determinar la posición de la unión duodenoyeyunal?:', 'Ligamento de Treitz.', 'Arteria mesentérica superior.', 'Arteria mesentérica inferior.', 'Ligamento frenocólico', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 172, 'Sin clasificar', 'Recién nacido a término con macrosomía, macroglosia, onfalocele e hipoglucemias persistentes por hiperinsulinismo. Ecografía normal excepto visceromegalia. ¿Qué alteración molecular explica mejor este fenotipo clásico?:', 'Pérdida de metilación en IC2 (KCNQ1OT1) paterna.', 'Ganancia de metilación en IC1 (H19/IGF2) materna.', 'Mutación pérdida de sentido paterna en CDKN1C.', 'Deleción de IGF2 en alelo paterno.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 173, 'Sin clasificar', 'Respecto a los aminoácidos que participan en el ciclo de la urea, señale la opción correcta:', 'La citrulina se condensa con glutamato para formar arginino succinato en el citosol.', 'La ornitina aporta directamente el segundo nitrógeno que se elimina como urea.', 'La asparagina dona el primer nitrógeno a la carbamoil fosfato sintasa de la mitocondria.', 'El aspartato aporta el segundo nitrógeno de la urea al condensarse con citrulina para formar arginino succinato.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 174, 'Sin clasificar', 'Lactante varón de 10 meses llevado a urgencias por fiebre y dificultad respiratoria. Presenta otitis medias recurrentes desde los 6 meses y un episodio previo de neumonía bacteriana. La madre refiere que “nunca tuvo amígdalas grandes”. En el hemograma destaca leucocitosis neutrofílica. Inmunoglobulinas IgG, IgA e IgM muy disminuidas. La citometría de flujo muestra linfocitos T dentro de rango de normalidad y linfocitos B CD19+ prácticamente ausentes. ¿Cuál es la alteración genética más probable?:', 'Mutación en RAG1.', 'Deleción 22q11.2.', 'Mutación en BTK.', 'Deficiencia de ADA.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 175, 'Sin clasificar', 'En relación con el síndrome de liberación de citocinas relacionado con la terapia con células CAR-T (linfocitos T modificados para expresar un CAR o chimeric antigen receptor) contra el antígeno CD-19 para el tratamiento de linfomas agresivos, señale la opción verdadera:', 'Se considera una complicación tardía que suele presentarse a las 2-3 semanas de recibir el tratamiento.', 'Se produce por un incremento suprafisiológico de algunas citosinas tales como la interleucina 6 (IL-6) e interleucina 1 (IL-1).', 'Las manifestaciones clínicas características incluyen fiebre e hipertensión.', 'El tozilizumab se utiliza de forma excepcional para su tratamiento.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 176, 'Sin clasificar', 'Un varón de 11 meses de edad presenta irritabilidad y llanto al movilizar la extremidad inferior derecha. En la exploración física destaca una tumefacción de la rodilla derecha, que se muestra caliente y enrojecida. En el estudio básico de coagulación se observa: tiempo de protrombina (TP) de 11 segundos (rango: 9-15 segundos) y un tiempo de tromboplastina parcial activada (TTPA) de 80 segundos (rango: 20-40 segundos). Se solicita una prueba de mezclas que corrige la alteración de la coagulación. ¿Qué opción diagnóstica NO se ajusta a las alteraciones analíticas observadas?:', 'Déficit de factor VII.', 'Déficit de factor VIII.', 'Déficit de factor IX.', 'Enfermedad de von Willebrand tipo 3.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 177, 'Sin clasificar', 'La exanguinotransfusión es un procedimiento terapéutico que se utiliza de forma característica en el tratamiento de:', 'Púrpura trombótica trombocitopénica (PTT) inmunomediada.', 'Síndrome de Guillain-Barré.', 'Rechazo humoral agudo en trasplante renal.', 'Enfermedad hemolítica del recién nacido.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 178, 'Sin clasificar', 'Una mujer de 70 años consulta por astenia. Presenta una hemoglobina de 8.1 g/dl, VCM de 72 fl (rango: 84-100 fl) y CHCM de 25 g/dl (rango: 31.5-34.5 g/dl). En el hemograma, tiene una cifra de plaquetas de 530.000/mcrl. En la bioquímica, la LDH, la bilirrubina y la función renal son normales. Revisando sus analíticas previas, años atrás normales, observamos que las alteraciones han ido desarrollándose de forma progresiva en el último año. ¿Cuál es el diagnóstico más probable y qué prueba/s solicitaría para continuar el estudio de esta paciente?:', 'Trombocitemia esencial. Estudio de médula ósea.', 'Betatalasemia intermedia. Electroforesis de hemoglobinas y estudio genético.', 'Esferocitosis hereditaria. Prueba de unión con esosina-5’-maleimida (EMA).', 'Anemia ferropénica. Ferritina sérica y estudios digestivos.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 179, 'Sin clasificar', 'Hombre de 60 años con antecedentes personales de fumador de 30 paq/año, hipertensión arterial, dislipemia, hígado graso. Tratamiento con enalapril, simvastatina y 100 mg de ácido acetilsalicílico por ictus hace 5 años. Tiene una artritis psoriásica a tratamiento con metotrexato a dosis de 25 mg/semana a pesar de lo cual presenta mal control de la actividad y precisa cambio de tratamiento. ¿Cuál considera que NO es la mejor opción de tratamiento?:', 'Biológico con mecanismo de acción anti- TNF (Factor de Necrosis Tumoral).', 'Sintético con diana específica inhibidor de JAK.', 'Biológico con mecanismo de acción anti- IL17.', 'Biológico con mecanismo de acción anti- IL12/23.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 180, 'Sin clasificar', 'Varón de 58 años, sin antecedentes personales ni toma de fármacos que tras un control anual de empresa es diagnosticado de carcinoma renal por lo que se inicia tratamiento con Pembrolizumab (anti PD1). Acude a S de Reumatología por un cuadro de poliartritis, predominantemente rizomiélica, de 2 meses de evolución con marcada elevación de reactantes de fase aguda. El análisis de orina, el hemograma y la bioquímica son normales. El factor reumatoide y los anti péptido cíclico citrulinado son negativos. Los ANA positivos a títulos de 1/80 patrón homogéneo ¿Cuál de los siguientes diagnósticos sería el más probable?:', 'Vasculitis secundaria al carcinoma.', 'Síndrome paraneoplásico.', 'Enfermedad reumática secundaria al Pembrolizumab.', 'Lupus eritematoso sistémico.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 181, 'Sin clasificar', 'Paciente de 55 años que acude por cuadro de monoartritis aguda autolimitada de primera metatarsofalángica. Refiere episodios repetidos en los últimos 3 años que trató con analgésicos. Aporta analítica con uricemia de 11 mg/dl. Resto de estudios normales. ¿Cuál sería el tratamiento más indicado para el paciente?:', 'Colchicina y antiinflamatorios durante la crisis y luego suspender ambos.', 'Colchicina y antiinflamatorios y cuando esté asintomático suspender antiinflamatorios y añadir alopurinol.', 'Alopurinol y antiinflamatorios durante la crisis y después suspender ambos.', 'Colchicina y antiinflamatorios durante la crisis y después suspender antiinflamatorios y mantener colchicina.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 182, 'Sin clasificar', '¿Cuál de las siguientes afirmaciones sobre los anticuerpos antinucleares es correcta?:', 'Los pacientes con lupus inducido por fármacos suelen tener anticuerpos antihistonas y anti-DNA de doble cadena positivos.', 'Los anticuerpos anti-DNA de cadena única son específicos del lupus eritematoso sistémico.', 'El título de anticuerpos anti-DNA de doble cadena suele guardar correlación con la actividad de la glomérulo nefritis lúpica.', 'La positividad de anticuerpos anti-Sm orienta hacia el diagnostico de lupus inducido por fármacos.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 183, 'Sin clasificar', 'Una mujer de 50 años acude a consulta por dolor lumbar inflamatorio. La exploración denota limitación de la movilidad lumbar y tumefacción global del segundo y tercero dedo de pie derecho y cuarto dedo de pie izquierdo. No tiene lesiones cutáneas. La analítica demuestra elevación de reactantes de fase aguda. El Factor reumatoide (FR) y los anticuerpos contra péptido cíclico citrulinado (ACPA) son negativos. Los anticuerpos antinucleares (ANA) y el HLA- B27 también son negativos. Los estudios de imagen de ambos pies evidencian la presencia de erosión junto a neoformación ósea yuxta-articular. ¿Cuál sería su diagnóstico?:', 'Artritis reumatoide.', 'Enfermedad mixta del tejido conectivo.', 'Sarcoidosis.', 'Artritis psoriásica.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 184, 'Sin clasificar', '¿Cuál de estas afirmaciones es correcta sobre las vasculitis pulmonares?:', 'La granulomatosis eosinofílica con poliangitis (GEPA) tiene autoanticuerpos ANCA anti-PR3 elevados en el 80% de los casos.', 'La enfermedad anti-membrana basal glomerular comienza siempre con afectación pulmonar seguida en ocasiones de una afectación renal leve.', 'Poliangitis microscópica cursa como una forma de asma grave con escasa participación renal.', 'La granulomatosis con poliangitis (GPA) afecta frecuentemente a la vía aérea superior.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 185, 'Sin clasificar', 'Un paciente de 62 años acude para seguimiento tras un hallazgo incidental de una masa suprarrenal de 2.5 cm identificada en una ecografía realizada por dolor abdominal inespecífico. Está asintomático y sin antecedentes de cáncer. Según las guías actuales, ¿qué técnica de imagen sería la más indicada para caracterizar inicialmente el incidentaloma adrenal?:', 'Resonancia magnética con secuencias en fase y fuera de fase.', 'Tomografía computarizada (TC) sin contraste.', 'PET-TC con fluorodesoxiglucosa (FDG).', 'Tomografía computarizada (TC) con contraste.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 187, 'Sin clasificar', 'Paciente de 58 años con diagnóstico de diabetes tipo 2, HbA1c de 8,2 %, IMC de 33 kg/m2, antecedentes de infarto agudo de miocardio y Filtrado glomerular estudiado de 52 ml/min/1.73m², que actualmente recibe tratamiento con metformina. ¿Cuál sería el medicamento más apropiado para añadir a su terapia?:', 'Insulina basal.', 'Pioglitazona.', 'Inhibidor de DPP-4 (sitagliptina).', 'Inhibidor de SGLT2 (empaglifozina).', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 188, 'Sin clasificar', '¿Cuál es el rango de glucosa definido como Tiempo en Rango (TIR) durante el embarazo según el perfil glucémico ambulatorio (AGP)?:', '70-180 mg/dL.', '70-140 mg/dL.', '63-140 mg/dL.', '60-130 mg/dL.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 189, 'Sin clasificar', 'Un hombre de 35 años con diabetes mellitus tipo 1 (DM1) acude a su consulta. Refiere que, por su cuenta, ha solicitado una analítica a su hijo de 8 años, completamente asintomático. El resultado muestra anticuerpos anti-GAD y anti-tirosina fosfatasa (anti-IA2) positivos, con una glucemia basal de 88 mg/dL y una HbA1c de 5.2%. El padre, muy preocupado, le pregunta qué actitud se debe tomar a continuación. Según las recomendaciones actuales, ¿cuál sería la conducta más apropiada?:', 'Tranquilizar a la familia, ya que al estar el niño asintomático y con glucemias normales, solo requiere una vigilancia pasiva.', 'Iniciar tratamiento con metformina para intentar preservar la función de la célula beta.', 'Clasificar al niño como estadio 1 de DM1 y derivarlo a una unidad de endocrinología pediátrica para seguimiento y posible inclusión en ensayos clínicos de prevención.', 'Repetir la determinación de glucosa cada año, ya que el desarrollo de la enfermedad es improbable antes de la pubertad.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 190, 'Sin clasificar', '¿Cuál de estas patologías NO es causa de hipopotasemia?:', 'Hipomagnesemia.', 'Hipoaldosteronismo.', 'Vómitos.', 'Síndrome de Bartter.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 191, 'Sin clasificar', 'La enfermedad que más frecuentemente conduce a los programas de diálisis y trasplante en España es:', 'Pielonefritis crónica.', 'Nefroesclerosis.', 'Poliquistosis hepato-renal.', 'Enfermedad renal diabética.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 192, 'Sin clasificar', '¿Cuál es el mejor marcador bioquímico de función renal en la práctica clínica habitual?:', 'La Urea plasmática.', 'La Creatinina plasmática.', 'El Potasio sérico.', 'El filtrado glomerular estimado.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 193, 'Sin clasificar', 'Son características de la preclampsia:', 'Hipertensión arterial, microhematuria y edemas en la última parte del embarazo.', 'Hipertensión arterial, microhematuria y edemas en el primer trimestre del embarazo.', 'Hipertensión arterial, proteinuria y edemas en la segunda mitad del embarazo.', 'Hipertensión arterial, proteinuria y edemas en el primer trimestre del embarazo.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 194, 'Sin clasificar', 'Un paciente de 62 años con diabetes mellitus tipo 2, en tratamiento con metformina, enalapril a dosis máximas toleradas y 10 mg diarios de empagliflozina, mantiene un buen control tensional (130/78 mmHg) y una HbA1c de 6.3 %. A pesar de ello, persiste una albuminuria con un cociente albúmina/creatinina de 160 mg/g. Su tasa de filtrado glomerular es de 65 ml/min/1.73m² y su potasio sérico es de 4.4 mEq/L. ¿Cuál sería la siguiente medida terapéutica más adecuada para reducir la progresión de su enfermedad renal diabética?:', 'Sustituir el enalapril por un antagonista de los receptores de angiotensina II (ARA II).', 'Añadir un agonista del receptor de GLP-1.', 'Añadir finerenona (antagonista no esteroideo del receptor mineralcorticoide).', 'Aumentar la dosis de empaglifocina.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 195, 'Sin clasificar', 'La policía encuentra en la calle, inconsciente e inmóvil, a altas horas de la madrugada a un indigente que presente múltiples hematomas y fetor etílico. En el hospital se detecta urea de 200 mg/dl, creatinina de 6 mg/dl, ácido úrico de 10 mg/dl y CPK de 9000 U/L. El diagnóstico probable es:', 'Necrosis tubular aguda alcohólica.', 'Fracaso renal agudo por urato.', 'Fracaso renal agudo prerrenal por deshidratación.', 'Fracaso renal agudo por rabdomiolisis.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 196, 'Sin clasificar', 'Paciente de 23 años, que es llevado a un servicio de urgencias hospitalario por haber sido encontrado en calle con bajo nivel de conciencia. A su llegada el paciente responde a estímulos dolorosos intensos, tiene una frecuencia cardiaca de 40 latidos por minuto, unas cifras de presión arterial de 90/60 mmHg, sin fiebre y unas pupilas puntiformes. Ante la sospecha de una intoxicación, ¿cuál de los siguientes antídotos estaría más indicado?:', 'Naloxona.', 'Flumazenilo.', 'Atropina.', 'Pralidoxima.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 197, 'Sin clasificar', 'Paciente de 88 años con antecedentes de Hipertensión Arterial, Diabetes Mellitus y Cardiopatía Isquémica Crónica que acude a urgencias por disnea de aparición súbita, con ortopnea, disnea paroxística nocturna y edemas en miembros inferiores hasta raíz de muslo. En el triage de urgencias tiene unas cifras de presión arterial de 190/70, una frecuencia cardiaca de 123 latidos por minuto y una saturación capilar de oxígeno del 89%. ¿Cuál de las siguientes medidas terapéuticas NO está indicada de inicio en el manejo de este paciente?:', 'Oxigenoterapia.', 'Nitroglicerina intravenosa.', 'Morfina intravenosa.', 'Diuréticos intravenosos.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 198, 'Sin clasificar', 'Paciente de 18 años, politraumatizado grave tras caída de un patinete. En el manejo inicial, dentro de la evaluación primaria y soporte vital ¿Cuál es la primera acción que debemos realizar?:', 'Cohibir la hemorragia externa, exanguinante o masiva.', 'Asegurar la permeabilidad de la vía aérea.', 'Asegurar una correcta ventilación/oxigenación.', 'Identificar y tratar el shock.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 199, 'Sin clasificar', 'Paciente de 76 años, sin comorbilidad conocida que sufre una caída causal desde una escalera sufriendo un traumatismo craneal y cervical. Atendido inicialmente por un familiar, que le coloca en posición lateral de seguridad mientras espera la llegada de las asistencias sanitarias. A la llegada del personal del SAMU el paciente se encuentra inconsciente. ¿Cuál de las siguientes afirmaciones es FALSA sobre el manejo de la vía aérea?:', 'La apertura de la vía aérea mediante tracción mandibular es la maniobra de elección.', 'Lo prioritario es colocar un collarín cervical rígido.', 'La apertura de la vía aérea es prioritaria en un paciente con un traumatismo.', 'Una vez abierta la vía aérea, es recomendable usar un dispositivo orofaríngeo.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 200, 'Sin clasificar', 'En relación con la violencia de género, señale la afirmación correcta:', 'Se produce con mayor frecuencia en familias desestructuradas y con pocos recursos económicos.', 'Los agresores presentan con frecuencia trastornos psiquiátricos graves que explican la conducta violenta.', 'Las víctimas rara vez acuden a los servicios sanitarios por miedo a ser identificadas como víctimas.', 'El embarazo es un periodo de riesgo para el inicio o agravamiento de la violencia de género.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 201, 'Sin clasificar', '¿Cuál de las siguientes opciones es el tratamiento de primera línea más eficaz para aliviar la congestión nasal y los síntomas oculares establecidos en la rinitis alérgica persistente y moderada?:', 'Antihistamínicos orales de primera generación, como la difenhidramina, debido a su efecto rápido.', 'Descongestionantes nasales tópicos usados prolongadamente para un control sostenido de la congestión.', 'Corticosteroides intranasales de alta potencia, para aliviar síntomas nasales y oculares con menos efectos sistémicos.', 'Cromoglicato sódico por vía oral como único tratamiento en síntomas moderados persistentes.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 202, 'Sin clasificar', 'Respecto a la Trombosis Venosa Profunda, señale lo correcto:', 'Tras la sospecha clínica, el diagnóstico suele realizarse mediante ecografía doppler.', 'Los pacientes con factores de riesgo o trombosis venosas de repetición suelen precisar anticoagulación durante 12 meses.', 'Por norma general, la anticoagulación se suele mantener durante 3 semanas.', 'La tasa de recidiva es del 60%.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 203, 'Sin clasificar', '¿Cuál de los siguientes microorganismos no es habitual en las infecciones del tracto urinario?:', 'Clostridium perfringens.', 'Klebsiella pneumoniae.', 'Pseudomonas aeruginosa.', 'Staphylococcus saprophyticus.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 204, 'Sin clasificar', '¿Qué hallazgo clínico es más característico de una ParsPlanitis?:', 'Acumulo de material inflamatorio en el vitreo (vitritis).', 'Periflebitis periférica.', 'Aparición de bancos o copos de nieve en la base del vítreo.', 'Edema de papila.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 205, 'Sin clasificar', 'La participación activa en Atención Primaria es un concepto clave dentro del modelo de salud comunitaria y centrada en la persona. Se refiere a la implicación real y continua de los pacientes, sus familias y la comunidad en las decisiones y acciones relacionadas con su salud, tanto a nivel individual como colectivo. ¿Cuál de las siguientes afirmaciones, refleja mejor el concepto de participación activa en la Atención Primaria?:', 'Los profesionales de salud deben responder a las demandas explícitas de los pacientes cuando éstos acuden a consulta.', 'Los equipos de atención primaria deben ser proactivos, abordando tanto las necesidades expresadas por los pacientes como aquellas que no han sido verbalizadas.', 'Los pacientes son responsables de expresar todas sus necesidades para que el equipo de atención primaria pueda ofrecer la atención adecuada.', 'La participación activa se refiere exclusivamente a la implicación de la comunidad en las decisiones sobre políticas de salud.', NULL, 'B');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 206, 'Sin clasificar', 'Un hombre de 62 años es diagnosticado de adenocarcinoma de recto medio, confirmado por biopsia endoscópica. La tomografía computarizada toracoabdominopélvica no muestra metástasis a distancia. ¿Qué prueba de imagen es más adecuada para identificar la mejor opción terapéutica local en este paciente?:', 'Tomografía computerizada de abdomen y pelvis con contraste intravenoso y angiografía (angio TAC).', 'Tomografía por emisión de positrones de pelvis combinada con Tomografía computerizada (PET/TC).', 'Resonancia magnética pélvica (RMN) con secuencias de alta resolución del mesorrecto, con o sin contraste.', 'Ecografía combinada abdomino-pélvica y endorrectal.', NULL, 'D');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 207, 'Sin clasificar', 'Una paciente de 87 años acude a la consulta de su médico de Atención Primaria en el contexto de una evaluación geriátrica. Al cuantificar el SPPB (Short Physical Performance Battery o Prueba corta de desempeño físico) observamos que en el test de equilibrio aguanta más de 10 segundos en cada una de las tres pruebas (con los pies juntos, en semitándem y tándem). Además, al medir la velocidad de la marcha tarda menos de 4,82 segundos en recorrer 4 metros y en el test de levantarse de la silla 5 veces tarda menos de 11,2 segundos. Calcule su resultado en el SPPB:', '12 puntos.', '10 puntos.', '8 puntos.', '6 puntos.', NULL, 'A');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 209, 'Sin clasificar', 'En el abordaje terapéutico de un paciente adulto con lesión medular y presencia de espasticidad generalizada en la exploración, ¿cuál de estos fármacos NO utilizaría como tratamiento?:', 'Diazepam.', 'Lacosamida.', 'Tizanidina.', 'Baclofeno.', NULL, 'C');
INSERT INTO preguntas (año, numero, especialidad, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, opcion_e, correcta) VALUES (2025, 210, 'Sin clasificar', 'En relación con el pseudotumor cerebri o hipertensión intracraneal idiopática (HII), ¿cuál de las siguientes afirmaciones es correcta?:', 'Es más frecuente en hombres ancianos con índice de masa corporal (IMC) bajo.', 'Se caracteriza por aumento de la presión de apertura del LCR con composición anormal.', 'Afecta preferentemente a mujeres jóvenes obesas y puede causar pérdida visual.', 'El tratamiento inicial consiste en corticoides a dosis altas y restricción hídrica estricta.', NULL, 'B');
